  if (!root) return;
  const currentRow = root.querySelector(`[data-hub-row="${endedPostId}"]`);
  if (!currentRow) return;
  let nextRow = currentRow.nextElementSibling;
  while (nextRow && !nextRow.matches?.("[data-hub-row]")) {
    nextRow = nextRow.nextElementSibling;
  }
  if (!nextRow) return;
