  if (ok && isNativeShell()) {
    await ensureNativeApiBaseResolved();
  }
  if (_onesignalAppId) {
    try {
      await initPushNotifications();
    } catch (e) {
      console.warn("[push] init after config failed", e);
    }
  }
  return Boolean(SUPABASE_URL && SUPABASE_ANON_KEY);
