function updateNotificationsEntryBadges(unreadCount) {
  const unread = Math.max(0, Number(unreadCount || 0));
  _notificationsUnreadCount = unread;
  const hasUnread = unread > 0;
  const activityLabel = hasUnread
    ? `Activity, ${unread} unread ${unread === 1 ? "notification" : "notifications"}`
    : "Activity";
  try {
    els.activityTabLink?.classList?.toggle?.("hasNotice", hasUnread);
    els.activityTabLink?.setAttribute?.("aria-label", activityLabel);
    const dot = document.getElementById("activityTabDot");
    if (dot) dot.style.display = hasUnread ? "" : "none";
  } catch {}
  try {
    els.profileTabLink?.classList?.remove?.("hasNotice");
    els.profileTabLink?.setAttribute?.("aria-label", "Profile");
  } catch {}
}

async function refreshNotificationsUnreadBadge({ force = false } = {}) {
  if (!authSession?.user?.id) {
    updateNotificationsEntryBadges(0);
    return;
  }
  const route = String(document.body.getAttribute("data-route") || "");
  if (
    !force &&
    route === "activity" &&
    _activityFeedState.items.length
  ) {
    const unread = _activityFeedState.items.filter((n) => !n?.read_at).length;
    updateNotificationsEntryBadges(unread);
    return;
  }
  const now = Date.now();
  if (_notificationsUnreadFetchInFlight) return;
  if (!force && now - _notificationsUnreadLastFetchedAt < 60000) return;
  _notificationsUnreadFetchInFlight = true;
  try {
    const data = await socialApi("/api/social?type=notifications");
    const list = Array.isArray(data?.notifications) ? data.notifications : [];
    updateNotificationsEntryBadges(list.filter((n) => !n?.read_at).length);
    _notificationsUnreadLastFetchedAt = now;
  } catch (e) {
    console.warn("[notifications/badge]", e);
  } finally {
    _notificationsUnreadFetchInFlight = false;
  }
}

function resolveEmptyHashRoute() {
  ensureAuthSessionUserFromToken();
  if (isAppLoggedIn() || getSupabaseAuthToken()) return "discover";
  if (!shouldSkipIntroOrOnboardingRoute()) return "auth";
  if (isGuestModeEnabled()) return "discover";
  return "auth";
}

/** `/#/player?track=UUID` or `/s/:uuid` — WhatsApp share listeners must not hit auth walls. */
function parseSharedTrackIdFromLocation() {
  try {
    const hash = String(location.hash || "");
    if (hash.startsWith("#/player")) {
      const q = String(hash.split("?")[1] || "").split("#")[0];
      const id = String(new URLSearchParams(q).get("track") || "").trim();
      if (isShareUuid(id)) return id;
    }
    const m = String(location.pathname || "").match(
      /^\/s\/([0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12})\/?$/i,
    );
    if (m) return m[1];
  } catch {}
  return "";
}

/** Normalize `/s/:id` landing URLs into the in-app player route before routing. */
(() => {
  const shareId = parseSharedTrackIdFromLocation();
  if (!shareId) return;
  const hash = String(location.hash || "");
  if (hash.startsWith("#/player") && hash.includes("track=")) return;
  try {
    const target = `#/player?track=${encodeURIComponent(shareId)}`;
    if (location.hash !== target) location.replace(target);
  } catch {}
})();

/** Keep splash up while route is still settling (session restore / OAuth). */
function shouldHoldBootSplashForRoute(wanted) {
  if (!document.body.classList.contains("booting")) return false;
  if (parseSharedTrackIdFromLocation()) return false;
  if (!shouldSkipIntroOrOnboardingRoute() && wanted === "auth") return true;
  if (wanted === "auth" && getSupabaseAuthToken()) return true;
  if (wanted === "auth" && !_authBootDone) return true;
  return false;
}

function syncRoutePanelVisibility(wanted) {
  const route = String(wanted || "").trim();
  if (!route) return;
  document.body.setAttribute("data-route", route);
  try { document.body.dataset.route = route; } catch {}
  document.body.classList.toggle("isIntro", route === "intro");
  document.body.classList.toggle("isOnboarding", route === "onboarding");
  document.body.classList.toggle("isAuth", route === "auth");
  document.body.classList.toggle("isMusicPrefs", route === "music-preferences");
  document.querySelectorAll("[data-route]").forEach((el) => {
    const key = el.getAttribute("data-route");
    const show = key === route;
    if (show && (route === "onboarding" || route === "music-preferences")) {
      el.style.display = "flex";
    } else {
      el.style.display = show ? "" : "none";
    }
  });
  document.querySelectorAll("[data-route-link]").forEach((a) => {
    const link = a.getAttribute("data-route-link");
    const active = link === route
      || (route === "discover-playlist" && link === "discover")
      || (route === "generate" && link === "challenges")
      || (route === "mashup" && link === "challenges")
      || (route === "vocal" && link === "challenges");
    a.classList.toggle("active", active
      || (route === "messages" && link === "friends")
      || (route === "messages-thread" && link === "friends"));
  });
}

function routeApplyFallback(err) {
  console.error("[route] applyRoute failed", err);
  try { dismissBootSplash(); } catch {}
  const fb = authSession?.user?.id ? "discover" : "auth";
  syncRoutePanelVisibility(fb);
  document.body.classList.remove("pageTransitioning", "booting");
  const main = document.querySelector("main.grid");
  if (main) main.classList.remove("routeSwap");
}

let _applyRouteRaf = 0;
let _applyRouteInFlight = false;
let _applyRouteQueued = false;
let _applyRouteAfterLoginSettle = false;
let _applyRouteGen = 0;
let _tabNavFromClick = false;

function bumpApplyRouteGeneration() {
  _applyRouteGen += 1;
  return _applyRouteGen;
}

function routeApplyStale(passGen) {
  return passGen !== _applyRouteGen;
}

function invalidateInFlightRouteFeedWork(leavingRoute) {
  const left = tabBarRouteKey(String(leavingRoute || "").trim());
  if (left === "friends" || left === "discover") {
    _discoveryFollowingGen += 1;
    _discoveryFeedGen += 1;
  }
  if (left === "friends") _friendsRouteEnterToken += 1;
}

function tabBarRouteKey(route = "") {
  const r = String(route || "").trim();
  if (r === "generate" || r === "mashup" || r === "vocal") return "challenges";
  if (r === "discover-playlist") return "discover";
  if (r === "messages" || r === "messages-thread") return "friends";
  return r;
}

// ── Native-like page transitions ─────────────────────────────────────────────
// Forward navigation slides the new screen in from the right, back slides it in
// from the left, and lateral bottom-tab switches use a soft fade. We animate the
// individual [data-route] panel — never main.grid, because transforming
// main.grid breaks iOS touch handling on fixed overlays (mini-player, tab bar).
const NAV_TAB_ROOTS = new Set(["discover", "friends", "challenges", "activity", "profile"]);
// Screens that run their own bespoke transition or appear at boot/auth and
// should not get the generic slide/fade.
const NAV_ANIM_SKIP = new Set(["messages-thread", "auth", "intro", "onboarding", "music-preferences"]);
let _navStack = [];

function navPrefersReducedMotion() {
  try {
    return !!(window.matchMedia && window.matchMedia("(prefers-reduced-motion: reduce)").matches);
  } catch {
    return false;
  }
}

// Pick the transition direction and maintain a small route stack so "back" is
// detected structurally (returning to a route still on the stack) instead of
// relying on body[data-route], which the tab fast-path pre-sets before
// applyRoute runs. Returns "forward" | "back" | "tab" | "none".
function navDirectionFor(wanted) {
  const w = String(wanted || "").trim();
  const prev = _navStack.length ? _navStack[_navStack.length - 1] : "";
  if (!prev) {
    _navStack = [w];
    return "none";
  }
  if (prev === w) return "none";
  // The full-screen player is a "presented" screen (Apple Music / Spotify /
  // Instagram now-playing): it rises up from the bottom whenever we open it
  // from any other screen, regardless of forward/back classification.
  if (w === "player") {
    const pIdx = _navStack.lastIndexOf(w);
    if (pIdx >= 0 && pIdx < _navStack.length - 1) _navStack = _navStack.slice(0, pIdx + 1);
    else _navStack.push(w);
    return "present";
  }
  const idx = _navStack.lastIndexOf(w);
  if (idx >= 0 && idx < _navStack.length - 1) {
    _navStack = _navStack.slice(0, idx + 1);
    return "back";
  }
  if (NAV_TAB_ROOTS.has(w)) {
    _navStack = [w];
    return "tab";
  }
  _navStack.push(w);
  if (_navStack.length > 24) _navStack = _navStack.slice(-24);
  return "forward";
}

// Apply the enter animation to the freshly-shown panel. Must run synchronously
// right after syncRoutePanelVisibility so the class is present on first paint
// (no flash of the default state).
function animateRouteEnter(wanted, direction) {
  if (!direction || direction === "none") return;
  if (NAV_ANIM_SKIP.has(wanted)) return;
  if (navPrefersReducedMotion()) return;
  const cls =
    direction === "forward"
      ? "routeEnter--push"
      : direction === "back"
        ? "routeEnter--pop"
        : direction === "present"
          ? "routeEnter--present"
          : "routeEnter--fade";
  let panels;
  try {
    panels = document.querySelectorAll(`main.grid > [data-route="${wanted}"]`);
  } catch {
    return;
  }
  panels.forEach((el) => {
    if (!el || el.style.display === "none") return;
    el.classList.remove("routeEnter", "routeEnter--push", "routeEnter--pop", "routeEnter--fade", "routeEnter--present");
    void el.offsetWidth;
    el.classList.add("routeEnter", cls);
    let cleared = false;
    const done = () => {
      if (cleared) return;
      cleared = true;
      el.classList.remove("routeEnter", "routeEnter--push", "routeEnter--pop", "routeEnter--fade", "routeEnter--present");
      el.removeEventListener("animationend", done);
    };
    el.addEventListener("animationend", done);
    window.setTimeout(done, 420);
  });
}

function previewRouteFromHash(hash = "") {
  const raw = String(hash || "").replace(/^#\/?/, "");
  let route = raw.split(/[?#&]/)[0].trim();
  if (/^u\//.test(route)) return "user";
  if (route === "search" || /^discover\/playlist\//i.test(route)) return "discover";
  const aliases = {
    home: "discover",
    hub: "discover",
    start: "discover",
    sparks: "challenges",
    moment: "friends",
    notifications: "activity",
    library: "profile",
    more: "settings",
  };
  return aliases[route] || route;
}

function hashRouteKey() {
  return tabBarRouteKey(previewRouteFromHash(location.hash || ""));
}

function safeApplyRoute() {
  scheduleApplyRoute();
}

/** Coalesce hashchange + navigate so applyRoute does not run in a tight loop. */
function scheduleApplyRoute() {
  if (isLoginSettling()) {
    _applyRouteAfterLoginSettle = true;
    return;
  }
  if (_applyRouteRaf) cancelAnimationFrame(_applyRouteRaf);
  _applyRouteRaf = requestAnimationFrame(() => {
    _applyRouteRaf = 0;
    if (_applyRouteInFlight) {
      _applyRouteQueued = true;
      return;
    }
    void runApplyRouteOnce();
  });
}

async function runApplyRouteOnce() {
  if (_applyRouteInFlight) return;
  const passGen = _applyRouteGen;
  _applyRouteInFlight = true;
  try {
    loadAuthSession();
    ensureAuthSessionUserFromToken();
    if (!_authBootDone) {
      const hasToken = Boolean(getSupabaseAuthToken() || authSession?.access_token);
      if (hasToken) {
        void ensureAuthBoot({ fast: true });
      } else {
        await ensureAuthBoot();
      }
    }
    if (routeApplyStale(passGen)) return;
    applyRoute({ passGen });
    if (routeApplyStale(passGen)) return;
    try {
      const route = document.body.getAttribute("data-route") || "";
      if (!shouldHoldBootSplashForRoute(route)) dismissBootSplash();
    } catch {}
  } catch (e) {
    if (!routeApplyStale(passGen)) routeApplyFallback(e);
  } finally {
    _applyRouteInFlight = false;
    if (_applyRouteQueued) {
      _applyRouteQueued = false;
      scheduleApplyRoute();
    }
  }
}

function applyRoute({ passGen } = {}) {
  const gate = passGen ?? _applyRouteGen;
  const hash = String(location.hash || "");
  const rawRoute = hash.startsWith("#/") ? hash.slice(2) : resolveEmptyHashRoute();
  let route = rawRoute.split(/[?#&]/)[0].trim();
  const rawRouteQuery = String(rawRoute.split("?")[1] || "").split("#")[0];
  let pendingDiscoverPlaylistSlug = "";
  let pendingMessagesThreadId = "";
  let pendingMessagesThreadUserId = "";
  const playlistRouteMatch = route.match(/^discover\/playlist\/([a-z0-9_-]+)/i);
  if (playlistRouteMatch) {
    pendingDiscoverPlaylistSlug = decodeURIComponent(String(playlistRouteMatch[1] || "")).trim();
    route = "discover-playlist";
  }
  if (route === "discover/top-week" || route === "discover/weekly-chart") {
    _weeklyChartExpanded = true;
    try { sessionStorage.setItem(CHART_WEEK_EXPANDED_KEY, "1"); } catch {}
    route = "discover";
    try { history.replaceState(null, "", "#/discover"); } catch {}
  }
  if (route === "search") {
    try {
      const h = String(location.hash || "");
      if (/\/search\b/i.test(h)) {
        history.replaceState(null, "", h.replace(/#\/?search\b/i, "#/discover"));
      }
    } catch {}
    route = "discover";
  }
  // Public profile route: `#/u/USERNAME`. Treat as the dedicated `user`
  // route so it gets its own section + nav state. Username is preserved
  // separately so the renderer can pick it up after the route swap.
  let pendingPublicUsername = "";
  let pendingPublicUserId = "";
  let pendingFlowId = "";
  if (/^flow\//.test(route)) {
    pendingFlowId = decodeURIComponent(String(route.slice(5) || "").split(/[?#&]/)[0] || "").trim();
    route = "generate";
  }
  if (/^u\//.test(route)) {
    const rawPublicRoute = String(rawRoute.slice(2) || "");
    const [rawHandle, rawQuery = rawRouteQuery] = rawPublicRoute.split("?");
    pendingPublicUsername = decodeURIComponent(rawHandle || "").trim();
    try {
      pendingPublicUserId = String(new URLSearchParams(rawQuery).get("uid") || "").trim();
    } catch {
      pendingPublicUserId = "";
    }
  }
  if (route === "messages-thread") {
    try {
      const threadQs = new URLSearchParams(rawRouteQuery);
      pendingMessagesThreadId = String(threadQs.get("thread") || "").trim();
      pendingMessagesThreadUserId = String(threadQs.get("user") || "").trim();
    } catch {
      pendingMessagesThreadId = "";
      pendingMessagesThreadUserId = "";
    }
  }
  const allowedRoutes = new Set([
    "intro", "onboarding", "music-preferences", "start", "auth", "generate",
    ...(HUB_FEATURE_ENABLED ? ["hub"] : []),
    ...(MESSAGES_FEATURE_ENABLED ? ["messages", "messages-thread"] : []),
    "settings", "profile", "player", "discover", "discover-playlist", "friends", "challenges", "activity", "mashup", "mentor", "vocal", "stems", "advanced", "user", "credits", "sounds",
  ]);
  const onboardingParsed = parseOnboardingRoute(route);
  let normalized = pendingPublicUsername ? "user" : (route === "start" ? "auth" : route);
  if (onboardingParsed) normalized = "onboarding";
  if (normalized === "discover") {
    try {
      if (sessionStorage.getItem(DISCOVERY_SEGMENT_KEY) === "following") {
        history.replaceState(null, "", "#/friends");
        normalized = "friends";
      }
    } catch {}
  }
  if (normalized === "library") {
    try { history.replaceState(null, "", "#/profile?seg=all"); } catch {}
    normalized = "profile";
    try { sessionStorage.setItem(PROFILE_SONGS_SEGMENT_KEY, "all"); } catch {}
    _profileSongsSegment = "all";
  }
  if (normalized === "moment") {
    try { history.replaceState(null, "", "#/friends"); } catch {}
    normalized = "friends";
  }
  if (normalized === "sparks") {
    try { history.replaceState(null, "", "#/challenges"); } catch {}
    normalized = "challenges";
  }
  if (normalized === "home" || normalized === "hub" || normalized === "start") {
    try { history.replaceState(null, "", "#/discover"); } catch {}
    normalized = "discover";
  }
  if (normalized === "notifications") {
    try { history.replaceState(null, "", "#/activity"); } catch {}
    normalized = "activity";
  }
  if (normalized === "more") {
    try { history.replaceState(null, "", "#/settings"); } catch {}
    normalized = "settings";
  }
  let wanted = allowedRoutes.has(normalized) ? normalized : "generate";
  const isLoggedIn = isAppLoggedIn();
  ensureAuthSessionUserFromToken();
  const hasAuthToken = Boolean(getSupabaseAuthToken());
  if (isLoginSettling()) {
    if (hasAuthToken || isLoggedIn) {
      if (wanted === "auth" || wanted === "intro" || wanted === "onboarding") {
        wanted = "discover";
        try {
          history.replaceState(null, "", "#/discover");
        } catch {}
      }
    } else if (wanted !== "auth") {
      wanted = "auth";
      try {
        history.replaceState(null, "", "#/auth");
      } catch {}
    }
  }
  // Keychain/session often loads after first paint — never keep a signed-in user on #/auth.
  if (wanted === "auth" && (isLoggedIn || hasAuthToken)) {
    wanted = "discover";
    try {
      history.replaceState(null, "", "#/discover");
    } catch {}
  }
  if (wanted === "intro") {
    wanted = isLoggedIn ? "discover" : "auth";
    try {
      history.replaceState(null, "", `#/${wanted}`);
    } catch {}
  }
  if (shouldSkipIntroOrOnboardingRoute() && wanted === "onboarding") {
    wanted = isLoggedIn ? "discover" : "auth";
    try {
      history.replaceState(null, "", `#/${wanted}`);
    } catch {}
  }
  if (wanted === "music-preferences" && !isLoggedIn && !hasAuthToken) {
    wanted = "auth";
    try { history.replaceState(null, "", "#/auth"); } catch {}
  }
  if (!HUB_FEATURE_ENABLED && normalized === "hub") {
    wanted = isLoggedIn ? "discover" : "auth";
    try {
      history.replaceState(null, "", `#/${wanted}`);
    } catch {}
  }
  if (!MESSAGES_FEATURE_ENABLED && (normalized === "messages" || normalized === "messages-thread")) {
    wanted = isLoggedIn ? "friends" : "auth";
    try {
      history.replaceState(null, "", `#/${wanted}`);
    } catch {}
  }
  // Public profile is intentionally readable without auth so share-link
  // visitors don't hit a wall before discovering the rest of the product.
  const sharedTrackId = parseSharedTrackIdFromLocation();
  const protectedRoutes = new Set(["generate", "profile", "friends", "activity", "mashup", "player", "vocal", "stems", "advanced", "credits", "sounds", ...(MESSAGES_FEATURE_ENABLED ? ["messages", "messages-thread"] : [])]);
  if (!isLoggedIn && protectedRoutes.has(wanted)) {
    if (wanted === "player" && sharedTrackId) {
      // Listen-only share links — do not bounce guests to sign-in.
    } else {
      const intended = String(location.hash || "").trim();
      if (intended && intended !== "#/auth" && intended !== "#/settings") {
        setPostAuthReturnHash(intended);
      }
      if (wanted === "profile") {
        wanted = "settings";
        try { history.replaceState(null, "", "#/settings"); } catch {}
        try { showToast("Sign in to unlock your profile", { icon: "👤", durationMs: 2800 }); } catch {}
      } else {
        const tabLabels = {
          generate: "Create",
          friends: "Friends",
          activity: "Activity",
          mashup: "Mashup",
          player: "Player",
          vocal: "Vocal",
          stems: "Stems",
          advanced: "Advanced",
          credits: "Credits",
          sounds: "Sounds",
        };
        try {
          showToast(`Sign in to open ${tabLabels[wanted] || "this tab"}`, { icon: "👤", durationMs: 2800 });
        } catch {}
        wanted = "auth";
        try { history.replaceState(null, "", "#/auth"); } catch {}
      }
    }
  }
  if (sharedTrackId && (wanted === "intro" || wanted === "onboarding")) {
    wanted = "player";
    try {
      history.replaceState(null, "", `#/player?track=${encodeURIComponent(sharedTrackId)}`);
    } catch {}
  }
  const prevRoute = document.body.getAttribute("data-route") || "";
  if (prevRoute && prevRoute !== wanted) {
    captureRouteScroll(prevRoute);
  }
  if (prevRoute === "messages-thread" && wanted !== "messages-thread") {
    stopMessagesThreadRealtime();
    resetMessagesThreadRouteState();
    clearMessagesThreadComposerInset();
    document.body.classList.remove("messagesThreadEntering", "messagesThreadLeaving");
  }
  if (wanted === "challenges" && hasActiveCreateSession()) {
    wanted = "generate";
    try {
      if (!/^#\/generate\b/i.test(String(location.hash || ""))) {
        history.replaceState(null, "", "#/generate");
      }
    } catch {
      try { location.hash = "#/generate"; } catch {}
    }
  }
  if (prevRoute !== wanted) {
    closeCreateChooserSheet({ immediate: true });
    closeImageMoodSheet();
  }
  if ((prevRoute === "discover" || prevRoute === "discover-playlist") && wanted !== "discover" && wanted !== "discover-playlist") {
    try { onLeaveSearchRoute(); } catch {}
  }
  if (routeApplyStale(gate)) return;
  if (prevRoute !== wanted) invalidateInFlightRouteFeedWork(prevRoute);
  const navDir = navDirectionFor(wanted);
  syncRoutePanelVisibility(wanted);
  animateRouteEnter(wanted, navDir);
  if (wanted === "auth" && prevRoute !== "auth") {
    try { resetAuthEmailPanel(); } catch {}
  } else if (prevRoute === "auth" && wanted !== "auth") {
    try { resetAuthEmailPanel(); } catch {}
  }
  try {
    _appTourMod?.notifyAppRouteChanged?.(wanted);
  } catch {}
  if (routeApplyStale(gate)) return;
  if (!shouldHoldBootSplashForRoute(wanted)) {
    try { dismissBootSplash(); } catch {}
  }
  if (wanted !== "discover" && wanted !== "discover-playlist" && wanted !== "friends") {
    try { document.body.removeAttribute("data-discovery-segment"); } catch {}
  }
  if (prevRoute === "generate" && wanted !== "generate" && !hasActiveCreateSession()) {
    pendingSearchRemixMeta = null;
    clearCreateChallengeContext();
    setCreateChallengeHint(null);
    clearCreateChallengeFocus();
  }
  if (els.brandSecondary) {
    els.brandSecondary.textContent = wanted === "hub" ? "Hub" : wanted === "challenges" ? "Create" : "Music";
  }
  if (wanted === "onboarding") {
    try { onOnboardingRouteActive(route); } catch {}
  }
  if (wanted === "music-preferences") {
    try { onMusicPreferencesRouteActive(); } catch {}
  }

  try {
    const profileChrome = document.getElementById("profileAuraHeaderChromeRoot");
    if (profileChrome) {
      profileChrome.setAttribute("aria-hidden", wanted === "profile" ? "false" : "true");
    }
  } catch {}
  if (isLoggedIn) {
    void refreshNotificationsUnreadBadge({ force: wanted === "friends" || wanted === "settings" });
    if (MESSAGES_FEATURE_ENABLED) {
      void refreshMessagesUnreadBadge({ force: wanted === "friends" || wanted === "messages" || wanted === "messages-thread" });
    }
  } else {
    updateNotificationsEntryBadges(0);
    if (MESSAGES_FEATURE_ENABLED) updateMessagesUnreadBadge(0);
  }
  // Page enter transitions are handled by animateRouteEnter() above (per-panel
  // slide/fade). The old main.grid routeSwap is intentionally retired so we
  // don't double-animate and so we never transform main.grid (iOS touch bug).
  // Hub audio is bound to the Hub view only. Any route swap away from
  // Hub fully stops Hub playback so nothing keeps streaming silently
  // and no mini-player surfaces a Hub post outside the feed. Library/
  // generated tracks (other miniSource types) are unaffected.
  if (prevRoute === "hub" && wanted !== "hub") {
    try { pauseHubForRouteChange(); } catch {}
  }
  if (wanted === "hub") {
    markAllHubSeen();
    renderHubDots();
    renderHubUpdatedAt();
    updateHubAudioHint();
    try { renderHub(); } catch {}
    requestAnimationFrame(() => updateHubFocusedRow());
    // Smart-pick on tab entry was reverted (see hubTabLink click handler).
    // Clearing the flag here keeps it harmless in case anything else
    // sets it; the actual scroll behavior stays at "land on top".
    _hubPendingSmartScroll = false;
    // (No Hub resume: leaving Hub now fully stops Hub audio, so there
    //  is nothing to pick back up. Autoplay below re-engages from the
    //  viewport-centered row on entry.)
    // Kick autoplay on entry — but never override an already-active
    // pick. The Hub-tab click handler may have synchronously started
    // playback inside the gesture (the only way iOS reliably unlocks
    // audio); blindly flushing here would yank that choice away.
    setTimeout(() => {
      if (!hubAudioPostId) flushHubViewportAutoplay();
    }, 0);
    setTimeout(() => {
      if (!hubAudioPostId) flushHubViewportAutoplay();
    }, 240);
    // Always trigger a Supabase refresh on entering Hub. Boot already does
    // this once, but a cold visitor landing directly on `#/hub?post=ID`
    // (from a shared link) may render before boot's refresh resolves —
    // and that left them staring at an empty feed. This call is
    // idempotent (`hubSyncInFlight` guards re-entry).
    void refreshHubFromSupabase();
    // Honor a `?post=ID` query in the hash: scroll the post into view and,
    // if audio is already unlocked, kick off playback. Don't auto-play
    // before the user has tapped once — iOS/Safari would block it and
    // we'd just flash the play button. The Hub already handles the rest
    // via its scroll-driven autoplay.
    try {
      const q = String(hash).split("?")[1] || "";
      const sp = new URLSearchParams(q);
      const targetId = String(sp.get("post") || "").trim();
      if (targetId) {
        focusHubPostFromShare(targetId);
      }
    } catch {}
  }
  if (wanted === "settings") {
    renderPersonaSelect();
    try { refreshSettingsMusicPrefsRow(); } catch {}
    try { syncSettingsPushRow(); } catch {}
    if (!_onesignalAppId) {
      void loadPublicConfig().then(() => {
        try { syncSettingsPushRow(); } catch {}
      });
    }
  }
  if (wanted === "player") {
    try {
      const pq = new URLSearchParams(String(rawRouteQuery || ""));
      const trackId = String(pq.get("track") || "").trim();
      const hubId = String(pq.get("hub") || "").trim();
      if (trackId) void focusTrackFromShare(trackId);
      else if (hubId) void focusHubTrackFromShare(hubId);
    } catch {}
  }
  if (wanted === "generate" && pendingFlowId) {
    window.setTimeout(() => {
      try { applyChallengeStartById(pendingFlowId, null); } catch {}
    }, 80);
  }
  if (wanted === "profile") {
    try {
      const pq = new URLSearchParams(String(rawRouteQuery || ""));
      const segQ = pq.get("seg");
      if (segQ === "all" || segQ === "activities" || segQ === "playlist" || segQ === "public") {
        _profileSongsSegment = segQ === "public" ? "activities" : segQ;
        sessionStorage.setItem(PROFILE_SONGS_SEGMENT_KEY, _profileSongsSegment);
      } else {
        const stored = sessionStorage.getItem(PROFILE_SONGS_SEGMENT_KEY);
        _profileSongsSegment =
          stored === "public"
            ? "activities"
            : stored === "all" || stored === "activities" || stored === "playlist"
              ? stored
              : "activities";
      }
    } catch {
      _profileSongsSegment = "activities";
    }
    bindProfileSongsSegmentOnce();
    bindUserPlaylistPickerOnce();
    syncProfileSongsSegmentUi();
    const profileHeavy = !shouldSkipRouteHeavy("profile");
    if (profileHeavy) markRouteHeavy("profile");
    if (/persona=1|voices=1/i.test(rawRouteQuery)) {
      setProfilePersonaExpanded(true);
      setProfilePersonaVoicesOpen(true);
      try { renderSettingsVoicesHub(); } catch {}
      requestAnimationFrame(() => {
        try {
          els.profilePersonaRow?.scrollIntoView({ block: "nearest", behavior: "smooth" });
        } catch {}
      });
    } else {
      collapseProfilePersonaCard();
    }
    setProfileEditing(false);
    try { syncMobileTabbarProfileAvatar(); } catch {}
    if (profileHeavy) {
      markLibraryTabDot(false);
      if (authSession?.user?.id) {
        const run = () => {
          void mergeCloudSongsIntoLocalLibrary().then((publicChanged) => {
            if (publicChanged) try { refreshOwnSongsUi({ soft: false }); } catch {}
          });
        };
        if (typeof requestIdleCallback === "function") {
          requestIdleCallback(run, { timeout: 800 });
        } else {
          setTimeout(run, 0);
        }
      }
      void refreshMyCredits({ silent: true });
      void refreshMyHubPostsFast();
      void (async () => {
        if (isNativeShell()) await ensureNativeApiBaseResolved();
        await refreshOwnProfileSocialStats();
      })();
      renderPersonaSelect();
      renderProfileCallingCardHint();
      if (
        authSession?.user?.id &&
        (shouldShowProfileHeaderSkeleton() || profileNeedsCloudRefresh())
      ) {
        setProfileHeaderLoading(true);
        void (async () => {
          try {
            const merged = await mergeActiveProfileFromCloud();
            if (merged) {
              void ensurePersonalizedUsernameSyncedToCloud();
            }
          } catch {}
          try { setProfileHeaderLoading(false); } catch {}
        })();
      }
    } else {
      try { setProfileHeaderLoading(false); } catch {}
      try { renderProfilePreviewFromInputs(); } catch {}
      restoreRouteScroll("profile");
    }
    scheduleProfileSongsRender({ deferCloud: profileHeavy });
  }
  if (routeApplyStale(gate)) return;
  if (wanted === "credits" || wanted === "sounds") {
    void refreshMyCredits({ silent: true });
  }
  if (wanted === "friends") {
    try { onLeaveSearchRoute(); } catch {}
    bindFriendsPageOnce();
    wireFriendsComposeFabOnce();
    syncFollowingComposeUi();
    hydrateFriendsFeedSnapshotFromStorage();
    if (MESSAGES_FEATURE_ENABLED) syncFriendsMessagesBtn();
    if (!shouldSkipRouteHeavy("friends")) {
      markRouteHeavy("friends");
      enterFriendsRoute();
    } else {
      paintFriendsFeedSnapshotIfFresh();
      restoreRouteScroll("friends");
      markRouteHeavy("friends");
    }
  }
  if (MESSAGES_FEATURE_ENABLED && wanted === "messages") {
    bindMessagesPageOnce();
    enterMessagesRoute({ fromThread: prevRoute === "messages-thread" });
  }
  if (MESSAGES_FEATURE_ENABLED && wanted === "messages-thread") {
    bindMessagesPageOnce();
    enterMessagesThreadRoute(pendingMessagesThreadId, pendingMessagesThreadUserId);
  }
  if (wanted === "discover") {
    bindDiscoveryDiscoverControls();
    bindDiscoverPlaylistScreenOnce();
    bindDiscoverWeeklyChartSectionOnce();
    if (shouldSkipRouteHeavy("discover") && _discoveryFeedTracks.length) {
      restoreRouteScroll("discover");
      markRouteHeavy("discover");
    } else {
      markRouteHeavy("discover");
      void refreshDiscoverFeed();
    }
  }
  if (wanted === "discover-playlist") {
    bindDiscoveryDiscoverControls();
    bindDiscoverPlaylistScreenOnce();
    const openPlaylist = () => renderDiscoverPlaylistScreen(pendingDiscoverPlaylistSlug);
    if (!_discoveryFeedTracks.length) {
      void refreshDiscoverFeed().finally(openPlaylist);
    } else {
      openPlaylist();
    }
  }
  if (wanted === "challenges") {
    bindChallengesPageOnce();
    renderHomeDesk();
    void loadAppTourModule().then((m) => m.scheduleHomeTourIfNeeded());
  }
  if (wanted === "activity") {
    bindActivityPageOnce();
    const hasActivityCache = _activityFeedState.items.length > 0 || paintActivityFeedSnapshotIfFresh();
    if (shouldSkipRouteHeavy("activity") && hasActivityCache) {
      if (!paintActivityFeedSnapshotIfFresh() && _activityFeedState.items.length) {
        renderActivityFeedFromState();
      }
      restoreRouteScroll("activity");
      markRouteHeavy("activity");
    } else {
      markRouteHeavy("activity");
      void enterActivityRoute({ reset: !hasActivityCache });
    }
  }
  if (wanted === "mashup") {
    bindMashupPageOnce();
    enterMashupRoute();
    void ensureUserLibraryHydrated().then(() => renderMashupPage());
  }
  if (wanted === "user") {
    enterUserPublicRoute({
      username: pendingPublicUsername,
      userId: pendingPublicUserId,
      prevRoute,
    });
  } else if (prevRoute === "user") {
    syncUserPublicRouteChrome("");
  }
  if (wanted === "generate" && generationReadyNotice) {
    generationReadyNotice = false;
    renderGenerateReadyDot();
    setLoading(false);
    try {
      if (typeof _showResultCardHoisted === "function") _showResultCardHoisted(true);
    } catch {}
  }
  if (wanted === "generate") {
    try { renderPersonaSelect(); } catch {}
    try { restoreCreatePageOnRouteEnter(); } catch {}
  }
  syncGenerateOrbVisibility();
  renderGenerateReadyDot();
  updateProfilePersonaRow();
  try {
    updatePlayerSecondaryChrome();
  } catch {}
}

function updateBrandPulse() {
  if (!els.brandTitle) return;
  const isGenerating = Boolean(els.btnSunoGenerate?.disabled);
  const isPlaying = Boolean(playerEl && !playerEl.paused && !playerEl.ended);
  els.brandTitle.classList.toggle("isGenerating", isGenerating);
  els.brandTitle.classList.toggle("isPlaying", isPlaying);
}

// Hoisted so it's reachable from `resetCreateDraft` (which lives at top level).
// Previously this was defined as a `const` inside the big
// `if (els.btnSunoGenerate && els.btnSunoStems)` block, which made the call
// from `resetCreateDraft` throw a ReferenceError — leaving `body.generateLocked`
// stuck on after a successful generation, which in turn made the Lyrics/Hum/Photo
// tabs and every other button under `[data-route="generate"]` un-tappable until
// the app was force-closed.
/* Lyrics input mode — "write" (manual) or "generate" (describe → AI).
   Pure UI state: it only swaps the textarea placeholder/intent and
   reveals the Generate trigger. No generation logic changes. */
let lyricsInputMode = "write";

function syncLyricsPlaceholder() {
  if (!els.sunoPrompt) return;
  const instrumental = String(els.vocalInstrumentalOnly?.value || "0") === "1";
  if (instrumental) {
    els.sunoPrompt.placeholder =
      "Instrumental mode: lyrics will be ignored. Hum a melody or describe the mood in Style / Tags.";
    return;
  }
  els.sunoPrompt.placeholder =
    lyricsInputMode === "generate"
      ? "Describe the song you want to create…\n\ne.g. A romantic Arabic pop song about missing someone."
      : "Write your lyrics…";
}

function setLyricsInputMode(mode, opts = {}) {
  const next = mode === "generate" ? "generate" : "write";
  lyricsInputMode = next;
  if (els.lyricsFieldPanel) els.lyricsFieldPanel.setAttribute("data-lyrics-mode", next);
  if (els.lyricsModeWrite) {
    const on = next === "write";
    els.lyricsModeWrite.classList.toggle("isActive", on);
    els.lyricsModeWrite.setAttribute("aria-selected", on ? "true" : "false");
  }
  if (els.lyricsModeGenerate) {
    const on = next === "generate";
    els.lyricsModeGenerate.classList.toggle("isActive", on);
    els.lyricsModeGenerate.setAttribute("aria-selected", on ? "true" : "false");
  }
  syncLyricsPlaceholder();
  // Brief cross-fade of the textarea so the intent change feels smooth.
  if (!opts.silent && els.lyricsFieldPanel && els.sunoPrompt) {
    els.lyricsFieldPanel.classList.add("lyricsModeSwitching");
    window.setTimeout(() => {
      els.lyricsFieldPanel?.classList.remove("lyricsModeSwitching");
    }, 220);
    if (next === "generate") {
      try { els.sunoPrompt.focus({ preventScroll: true }); } catch {}
    }
  }
}

/* Lyrics language / dialect (Generate mode only).
   These guide how the AI WRITES the lyrics, not the music style. We map the
   selection into the existing hidden #sunoDialect field (a free-text accent/
   language hint the /api/lyrics prompt already honors) so no backend changes
   are needed and style stays fully independent (e.g. English + Dabke). */
let lyricsLanguage = "auto";
let lyricsDialect = "auto";
const LYRICS_LANGUAGE_VALUE = {
  english: "English",
  french: "French",
  spanish: "Spanish",
  turkish: "Turkish",
  italian: "Italian",
  german: "German",
};
const LYRICS_ARABIC_DIALECT_VALUE = {
  auto: "Arabic",
  lebanese: "Levantine Arabic",
  egyptian: "Egyptian Arabic",
  iraqi: "Iraqi Arabic",
  gulf: "Gulf Arabic",
  moroccan: "Maghrebi Arabic",
  syrian: "Syrian Arabic",
  palestinian: "Palestinian Arabic",
  tunisian: "Tunisian Arabic",
  sudanese: "Sudanese Arabic",
  msa: "Modern Standard Arabic",
};

function applyLyricsLanguageToDialect() {
  let val = "";
  if (lyricsLanguage === "arabic") {
    val = LYRICS_ARABIC_DIALECT_VALUE[lyricsDialect] || "Arabic";
  } else if (lyricsLanguage !== "auto") {
    val = LYRICS_LANGUAGE_VALUE[lyricsLanguage] || "";
  }
  if (els.sunoDialect) els.sunoDialect.value = val;
}

function syncLyricsLangPills() {
  if (els.lyricsLangRow) {
    els.lyricsLangRow.querySelectorAll("[data-lyrics-lang]").forEach((b) => {
      const on = b.getAttribute("data-lyrics-lang") === lyricsLanguage;
      b.classList.toggle("isActive", on);
      b.setAttribute("aria-pressed", on ? "true" : "false");
    });
  }
  if (els.lyricsDialectRow) {
    els.lyricsDialectRow.querySelectorAll("[data-lyrics-dialect]").forEach((b) => {
      const on = b.getAttribute("data-lyrics-dialect") === lyricsDialect;
      b.classList.toggle("isActive", on);
      b.setAttribute("aria-pressed", on ? "true" : "false");
    });
  }
  if (els.lyricsDialectGroup) els.lyricsDialectGroup.hidden = lyricsLanguage !== "arabic";
}

function setLyricsLanguage(lang) {
  lyricsLanguage = lang || "auto";
  if (lyricsLanguage !== "arabic") lyricsDialect = "auto";
  syncLyricsLangPills();
  applyLyricsLanguageToDialect();
}

function setLyricsDialect(dialect) {
  lyricsDialect = dialect || "auto";
  syncLyricsLangPills();
  applyLyricsLanguageToDialect();
}

(function bindLyricsLanguagePills() {
  const langRow = els.lyricsLangRow;
  if (langRow && !langRow.dataset.boundLang) {
    langRow.dataset.boundLang = "1";
    langRow.addEventListener("click", (e) => {
      const btn = e.target?.closest?.("button");
      if (!btn || !langRow.contains(btn)) return;
      haptic("light");
      if (btn.hasAttribute("data-lyrics-lang-more")) {
        const open = langRow.classList.toggle("showMore");
        btn.textContent = open ? "Less" : "More";
        return;
      }
      const lang = btn.getAttribute("data-lyrics-lang");
      if (lang) setLyricsLanguage(lang);
    });
  }
  const dialectRow = els.lyricsDialectRow;
  if (dialectRow && !dialectRow.dataset.boundDialect) {
    dialectRow.dataset.boundDialect = "1";
    dialectRow.addEventListener("click", (e) => {
      const btn = e.target?.closest?.("button");
      if (!btn || !dialectRow.contains(btn)) return;
      haptic("light");
      if (btn.hasAttribute("data-lyrics-dialect-more")) {
        const open = dialectRow.classList.toggle("showMore");
        btn.textContent = open ? "Less" : "More";
        return;
      }
      const d = btn.getAttribute("data-lyrics-dialect");
      if (d) setLyricsDialect(d);
    });
  }
  syncLyricsLangPills();
})();

function setCreateSongType(type) {
  const instrumental = type === "instrumental";
  if (els.vocalInstrumentalOnly) els.vocalInstrumentalOnly.value = instrumental ? "1" : "0";
  if (els.vocalModeFull) {
    els.vocalModeFull.classList.toggle("active", !instrumental);
    els.vocalModeFull.setAttribute("aria-pressed", instrumental ? "false" : "true");
  }
  if (els.vocalModeInstrumental) {
    els.vocalModeInstrumental.classList.toggle("active", instrumental);
    els.vocalModeInstrumental.setAttribute("aria-pressed", instrumental ? "true" : "false");
  }
  // Instrumental songs ignore lyrics, so the Write/Generate selector is
  // irrelevant there — disable it and fall back to the write placeholder.
  if (els.lyricsModeWrite) els.lyricsModeWrite.disabled = instrumental;
  if (els.lyricsModeGenerate) els.lyricsModeGenerate.disabled = instrumental;
  if (els.lyricsFieldPanel) els.lyricsFieldPanel.classList.toggle("lyricsModeLocked", instrumental);
  syncLyricsPlaceholder();
  if (els.btnLyricsMagic) els.btnLyricsMagic.disabled = instrumental;
}

function setGenerateFieldsLocked(locked) {
  const refFile = (typeof getVocalReferenceFile === "function") ? getVocalReferenceFile() : null;
  const lockPreviewAllowed = !locked && Boolean(refFile);
  const instrumentalOnly = String(els.vocalInstrumentalOnly?.value || "0") === "1";
  if (els.sunoPrompt) els.sunoPrompt.disabled = locked;
  if (els.sunoStyle) els.sunoStyle.disabled = locked;
  if (els.sunoAvoidTags) els.sunoAvoidTags.disabled = locked;
  if (els.btnBoostStyle) els.btnBoostStyle.disabled = locked;
  if (els.sunoTitle) els.sunoTitle.disabled = locked;
  if (els.sunoReferenceMode) els.sunoReferenceMode.disabled = locked;
  if (els.sunoVocalUpload) els.sunoVocalUpload.disabled = locked;
  if (els.btnLyricsMagic) els.btnLyricsMagic.disabled = locked || instrumentalOnly;
  if (els.btnMagicUploadVocal) els.btnMagicUploadVocal.disabled = locked;
  if (els.btnMagicRecordVocal) els.btnMagicRecordVocal.disabled = locked;
  if (els.vocalModeFull) els.vocalModeFull.disabled = locked;
  if (els.vocalModeInstrumental) els.vocalModeInstrumental.disabled = locked;
  if (els.btnClearVocalRef) els.btnClearVocalRef.disabled = locked;
  if (els.btnPreviewVocalRef) els.btnPreviewVocalRef.disabled = locked ? true : !lockPreviewAllowed;
  if (els.btnVocalRefStop) els.btnVocalRefStop.disabled = true;
  if (els.btnOpenAdvancedSheet) els.btnOpenAdvancedSheet.disabled = locked;
  if (els.btnGenerateOrb) els.btnGenerateOrb.disabled = locked;
  document.body.classList.toggle("generateLocked", Boolean(locked));
}

/** Mirror the hidden #sunoArabicAddress select onto the visible pills. */
function syncArabicAddressPills() {
  const v = String(els.sunoArabicAddress?.value || "").trim();
  document.querySelectorAll("#arabicAddressPills .addressPill").forEach((b) => {
    const on = String(b.getAttribute("data-address-value") || "") === v;
    b.classList.toggle("isActive", on);
    b.setAttribute("aria-pressed", on ? "true" : "false");
  });
}

/** Mirror the hidden #sunoSingerGender input onto the Singer pills, and dim
 *  them when a saved voice persona is active (the persona owns the voice). */
function syncSingerGenderPills() {
  const v = String(els.sunoSingerGender?.value || "").trim();
  document.querySelectorAll("#singerGenderPills .addressPill").forEach((b) => {
    const on = String(b.getAttribute("data-singer-value") || "") === v;
    b.classList.toggle("isActive", on);
    b.setAttribute("aria-pressed", on ? "true" : "false");
  });
  let overridden = false;
  try { overridden = Boolean(getActivePersonaId()); } catch {}
  const wrap = document.getElementById("singerGenderPills");
  if (wrap) wrap.classList.toggle("isOverridden", overridden);
}

/** Saved-voice chips under the Singer pills on Create: pick one of your
 *  personas (or Default), or jump to the voices panel to create one. */
function renderSingerPersonaRow() {
  const row = els.singerPersonaRow || document.getElementById("singerPersonaRow");
  if (!row) return;
  if (!authSession?.user?.id) {
    row.hidden = true;
    row.innerHTML = "";
    syncSingerGenderPills();
    return;
  }
  let list = [];
  try { list = loadPersonas(); } catch {}
  let active = "";
  try { active = getActivePersonaId(); } catch {}
  if (!list.length) {
    row.innerHTML = `
      <span class="singerPersonaNote">Persona</span>
      <button type="button" class="singerPersonaChip singerPersonaChip--create" data-singer-persona-create="1">＋ Create your persona</button>
    `;
  } else {
    // No "Default" chip: tapping the active persona again deselects it
    // and the song falls back to the default voice.
    const chips = [
      ...list.map((p) => {
        const id = escapeHtml(String(p.personaId || ""));
        const lab = escapeHtml(String(p.label || "Persona").trim().slice(0, 24) || "Persona");
        const on = String(p.personaId || "") === active;
        return `<button type="button" class="singerPersonaChip ${on ? "isActive" : ""}" data-singer-persona-id="${id}" aria-pressed="${on ? "true" : "false"}">${lab}</button>`;
      }),
      `<button type="button" class="singerPersonaChip singerPersonaChip--create" data-singer-persona-create="1" aria-label="Create a new persona">＋</button>`,
    ];
    row.innerHTML = `<span class="singerPersonaNote">Persona</span>${chips.join("")}`;
  }
  row.hidden = false;
  syncSingerGenderPills();
}

