/** Non-null when Supabase returned ≥1 active row; merged over `SEARCH_TEMPLATE_FALLBACK` by `id`. */
let searchTemplatesRemote = null;
let _searchPeopleFetchGen = 0;

async function supabaseSelectSearchTemplates() {
  if (!SUPABASE_URL || !SUPABASE_ANON_KEY) return null;
  const ctrl = new AbortController();
  const timer = setTimeout(() => ctrl.abort(), 10_000);
  try {
    const sel =
      "id,shelf,occasion,title,sub,chip,style,lyrics,keywords,cover_url,preview_url,sort_order,active";
    const r = await fetch(
      `${SUPABASE_URL}/rest/v1/search_templates?select=${encodeURIComponent(sel)}&active=eq.true&order=shelf.asc,sort_order.asc,id.asc`,
      {
        headers: { apikey: SUPABASE_ANON_KEY },
        signal: ctrl.signal,
      },
    );
    if (!r.ok) return null;
    const arr = await r.json().catch(() => null);
    return Array.isArray(arr) ? arr : null;
  } catch {
    return null;
  } finally {
    clearTimeout(timer);
  }
}

function mapSearchTemplateRowFromDb(r) {
  let keywords = [];
  if (Array.isArray(r?.keywords)) keywords = r.keywords.map((x) => String(x));
  else if (typeof r?.keywords === "string" && r.keywords) {
    try {
      const p = JSON.parse(r.keywords);
      if (Array.isArray(p)) keywords = p.map((x) => String(x));
    } catch {
      keywords = r.keywords.split(/[\s,]+/).filter(Boolean);
    }
  }
  return {
    id: String(r.id || ""),
    shelf: String(r.shelf || ""),
    occasion: String(r.occasion || ""),
    title: String(r.title || ""),
    sub: String(r.sub || ""),
    chip: String(r.chip || ""),
    style: String(r.style || ""),
    lyrics: String(r.lyrics || ""),
    keywords,
    coverUrl: String(r.cover_url || "").trim(),
    previewUrl: String(r.preview_url || "").trim(),
    sortOrder: Number(r.sort_order) || 0,
  };
}

async function refreshSearchTemplates() {
  const raw = await supabaseSelectSearchTemplates();
  if (Array.isArray(raw) && raw.length) {
    searchTemplatesRemote = raw.map(mapSearchTemplateRowFromDb).filter((t) => t.id && t.shelf);
  } else {
    searchTemplatesRemote = null;
  }
}

function getSearchTemplates() {
  const fb = SEARCH_TEMPLATE_FALLBACK;
  if (!searchTemplatesRemote?.length) return fb.slice();
  const byId = new Map(fb.map((t) => [t.id, { ...t }]));
  for (const o of searchTemplatesRemote) {
    if (!o.id) continue;
    const cur = byId.get(o.id) || {
      id: o.id,
      shelf: o.shelf,
      occasion: o.occasion,
      title: o.title,
      sub: o.sub,
      chip: o.chip,
      style: o.style,
      lyrics: o.lyrics,
      keywords: o.keywords || [],
    };
    byId.set(o.id, {
      ...cur,
      ...o,
      keywords: o.keywords && o.keywords.length ? o.keywords : cur.keywords || [],
    });
  }
  const shelfRank = (shelf) => {
    const i = SEARCH_SHELVES.findIndex((s) => s.id === shelf);
    return i >= 0 ? i : 99;
  };
  return Array.from(byId.values()).sort((a, b) => {
    const sr = shelfRank(a.shelf) - shelfRank(b.shelf);
    if (sr !== 0) return sr;
    const o = (a.sortOrder || 0) - (b.sortOrder || 0);
    if (o !== 0) return o;
    return String(a.id).localeCompare(String(b.id));
  });
}

function escapePostgrestIlikeToken(qNorm) {
  const t = String(qNorm || "")
    .trim()
    .toLowerCase()
    .replace(/,/g, " ")
    .replace(/\s+/g, " ")
    .slice(0, 36);
  if (t.length < 2) return "";
  return t.replace(/\\/g, "\\\\").replace(/%/g, "\\%").replace(/_/g, "\\_").replace(/\*/g, "");
}

async function supabaseSearchPublicProfiles(qNorm) {
  if (!SUPABASE_URL || !SUPABASE_ANON_KEY) return [];
  const token = escapePostgrestIlikeToken(qNorm);
  if (!token) return [];
  const wild = `*${token}*`;
  const orRaw = `(username.ilike.${wild},bio.ilike.${wild})`;
  const ctrl = new AbortController();
  const timer = setTimeout(() => ctrl.abort(), 8000);
  try {
    const url = `${SUPABASE_URL}/rest/v1/profiles?or=${encodeURIComponent(orRaw)}&select=username,avatar,user_id&limit=14`;
    const r = await fetch(url, {
      headers: { apikey: SUPABASE_ANON_KEY },
      signal: ctrl.signal,
    });
    if (!r.ok) return [];
    const rows = await r.json().catch(() => []);
    if (!Array.isArray(rows)) return [];
    return rows
      .map((row) => ({
        handle: String(row.username || "").trim(),
        avatar: String(row.avatar || "").trim() || "./assets/nabadai-logo.png",
        userId: String(row.user_id || "").trim(),
      }))
      .filter((u) => u.handle && u.handle.toLowerCase() !== "guest");
  } catch {
    return [];
  } finally {
    clearTimeout(timer);
  }
}

const SEARCH_HINT_EXAMPLES = [
  "birthday for sara",
  "wedding entrance",
  "samy_foun",
  "song for mom",
  "hype gym track",
  "anniversary in arabic",
  "thank you, friend",
  "heartbreak piano",
];

let _searchHintIdx = 0;
let _searchHintTimer = null;
let _searchPosterIdToTemplate = new Map();
let _searchActiveTemplate = null;
let _searchInited = false;
let _discoverSearchOpen = false;
/** Legacy: used only to redirect old Discover→Following segment to #/friends. */
const DISCOVERY_SEGMENT_KEY = "mas:discoverySegment:v1";
let _discoveryDiscoverBound = false;
let _friendsPageBound = false;
let _friendsStatusMenuDocBound = false;

function startSearchHintRotator() {
  const hintEl = document.getElementById("searchInputHint");
  const inputEl = document.getElementById("searchInput");
  if (!hintEl || !inputEl) return;
  stopSearchHintRotator();
  const rotate = () => {
    if (inputEl.value) return;
    hintEl.classList.add("swapping");
    setTimeout(() => {
      _searchHintIdx = (_searchHintIdx + 1) % SEARCH_HINT_EXAMPLES.length;
      hintEl.textContent = SEARCH_HINT_EXAMPLES[_searchHintIdx];
      hintEl.classList.remove("swapping");
    }, 220);
  };
  hintEl.textContent = SEARCH_HINT_EXAMPLES[_searchHintIdx];
  _searchHintTimer = setInterval(rotate, 2600);
}
function stopSearchHintRotator() {
  if (_searchHintTimer) { clearInterval(_searchHintTimer); _searchHintTimer = null; }
}

function searchTemplateMatchesQuery(tpl, qNorm) {
  if (!qNorm) return true;
  const haystack = [
    tpl.id, tpl.shelf, tpl.occasion, tpl.title, tpl.sub, tpl.chip,
    tpl.coverUrl, tpl.previewUrl,
    ...(tpl.keywords || []),
  ].join(" ").toLowerCase();
  return haystack.includes(qNorm);
}

function searchShelfMatchesQuery(shelfId, qNorm) {
  if (!qNorm) return true;
  return getSearchTemplates().some((t) => t.shelf === shelfId && searchTemplateMatchesQuery(t, qNorm));
}

function renderSearchPosterHTML(tpl) {
  const occ = String(tpl.occasion || "").split("·")[0]?.trim() || tpl.chip || "";
  const sub = String(tpl.occasion || "").split("·").slice(1).join("·").trim();
  const cover = String(tpl.coverUrl || "").trim();
  const artInner = cover
    ? `<img class="searchPosterArt" src="${escapeHtml(cover)}" alt="" loading="lazy" decoding="async" />`
    : `<div class="searchPosterArt" data-placeholder="1" aria-hidden="true"></div>`;
  return `
    <button class="searchPoster" type="button" data-search-poster="${tpl.id}" aria-label="${escapeHtml(tpl.title)}">
      ${artInner}
      <div class="searchPosterVignette" aria-hidden="true"></div>
      <span class="searchPosterChip">${escapeHtml(tpl.chip || occ)}</span>
      <div class="searchPosterText">
        <div class="searchPosterTitle">${escapeHtml(tpl.title)}</div>
        ${sub ? `<div class="searchPosterSub">${escapeHtml(sub)}</div>` : ""}
        <div class="searchPosterCta">Make it yours</div>
      </div>
    </button>
  `;
}

function renderSearchShelves(query) {
  const root = document.getElementById("searchShelves");
  const trendingEl = document.getElementById("searchTrendingLabel");
  if (!root) return;
  if (!DISCOVER_SEARCH_SHOW_IDEA_SHELVES) {
    root.innerHTML = "";
    root.hidden = true;
    root.setAttribute("aria-hidden", "true");
    if (trendingEl) trendingEl.hidden = true;
    return;
  }
  root.hidden = false;
  root.setAttribute("aria-hidden", "false");
  const qNorm = String(query || "").trim().toLowerCase();
  _searchPosterIdToTemplate = new Map();

  // Build shelf-by-shelf so the matching one floats to the top when there's a query.
  const shelves = SEARCH_SHELVES.map((shelf) => {
    const templates = getSearchTemplates().filter((t) => t.shelf === shelf.id);
    const matched = qNorm
      ? templates.filter((t) => searchTemplateMatchesQuery(t, qNorm))
      : templates;
    return { shelf, templates, matched, hasMatch: matched.length > 0 };
  });

  let anyMatch = false;
  let html = "";
  // Matching shelves first.
  shelves
    .filter((s) => qNorm ? s.hasMatch : true)
    .sort((a, b) => {
      if (!qNorm) return 0;
      return Number(b.hasMatch) - Number(a.hasMatch);
    })
    .forEach(({ shelf, templates, matched }) => {
      const toShow = qNorm ? matched : templates;
      if (!toShow.length) return;
      anyMatch = true;
      toShow.forEach((t) => _searchPosterIdToTemplate.set(t.id, t));
      html += `
        <section class="searchShelf" data-search-shelf="${shelf.id}">
          <header class="searchShelfHead">
            <h3 class="searchShelfTitle">${escapeHtml(shelf.title)}</h3>
          </header>
          <div class="searchShelfRow">
            ${toShow.map(renderSearchPosterHTML).join("")}
          </div>
        </section>
      `;
    });

  root.innerHTML = html;
  updateSearchEmptyState(query);

  root.querySelectorAll("[data-search-poster]").forEach((btn) => {
    btn.addEventListener("click", () => {
      const id = btn.getAttribute("data-search-poster");
      const tpl = _searchPosterIdToTemplate.get(id);
      if (tpl) openSearchRemixSheet(tpl);
    });
  });
}

function bindSearchPeopleRowClickHandlers(rowEl) {
  if (!rowEl) return;
  rowEl.querySelectorAll("[data-search-user]").forEach((btn) => {
    btn.addEventListener("click", () => {
      const handle = decodeURIComponent(btn.getAttribute("data-search-user") || "");
      if (handle) location.hash = `#/u/${encodeURIComponent(handle)}`;
    });
  });
}

function renderSearchPeople(query) {
  const stripEl = document.getElementById("searchPeopleStrip");
  const rowEl = document.getElementById("searchPeopleRow");
  if (!stripEl || !rowEl) return;
  const qNorm = String(query || "").trim().toLowerCase();
  if (!qNorm) {
    stripEl.hidden = true;
    rowEl.innerHTML = "";
    return;
  }
  const seq = ++_searchPeopleFetchGen;
  let posts = [];
  try { posts = loadHubFeed() || []; } catch { posts = []; }
  const seen = new Set();
  const hubPeople = [];
  for (const p of posts) {
    const handle = String(p?.creator || "").trim();
    if (!handle || isPlaceholderUsername(handle)) continue;
    const key = handle.toLowerCase();
    if (seen.has(key)) continue;
    if (!key.includes(qNorm)) continue;
    seen.add(key);
    hubPeople.push({
      handle,
      avatar: String(p?.creatorAvatar || "./assets/nabadai-logo.png"),
    });
    if (hubPeople.length >= 12) break;
  }
  const paint = (people) => {
    if (!people.length) {
      stripEl.hidden = true;
      rowEl.innerHTML = "";
      return;
    }
    stripEl.hidden = false;
    rowEl.innerHTML = people.map((u) => `
    <button class="searchPersonCard" type="button" data-search-user="${encodeURIComponent(u.handle)}">
      <img class="searchPersonAvatar" src="${escapeHtml(u.avatar)}" alt="" loading="lazy" />
      <div class="searchPersonName">@${escapeHtml(u.handle)}</div>
    </button>
  `).join("");
    bindSearchPeopleRowClickHandlers(rowEl);
  };
  paint(hubPeople);
  void (async () => {
    const cloud = await supabaseSearchPublicProfiles(qNorm);
    if (seq !== _searchPeopleFetchGen) return;
    const input = document.getElementById("searchInput");
    if (String(input?.value || "").trim().toLowerCase() !== qNorm) return;
    const merged = [...hubPeople];
    const seen2 = new Set(merged.map((h) => h.handle.toLowerCase()));
    for (const c of cloud) {
      const k = c.handle.toLowerCase();
      if (seen2.has(k)) continue;
      seen2.add(k);
      merged.push({ handle: c.handle, avatar: c.avatar });
      if (merged.length >= 12) break;
    }
    paint(merged);
  })();
}

function searchTrackMatchesQuery(track, qNorm) {
  if (!qNorm || !track) return false;
  const prof = _discoveryLastProfMap?.get?.(track.userId);
  const handle = String(prof?.username || "").trim();
  const hay = [
    track.title,
    track.creator,
    track.by,
    track.style,
    track.caption,
    handle,
    track.meta?.styleInput,
    track.meta?.finalPrompt,
    track.meta?.lyricsInput,
  ]
    .filter(Boolean)
    .join(" ")
    .toLowerCase();
  return hay.includes(qNorm);
}

function renderSearchTracks(query) {
  const section = document.getElementById("searchTracksSection");
  const grid = document.getElementById("searchTracksGrid");
  if (!section || !grid) return;
  const qNorm = String(query || "").trim().toLowerCase();
  if (!qNorm) {
    section.hidden = true;
    grid.innerHTML = "";
    return;
  }
  if (!_discoveryFeedTracks.length) {
    section.hidden = false;
    grid.innerHTML = `<div class="searchTracksLoading">Loading songs…</div>`;
    void refreshDiscoverFeed().then(() => renderSearchTracks(query));
    return;
  }
  const profMap = _discoveryLastProfMap || new Map();
  const matched = (_discoveryFeedTracks || []).filter((t) => searchTrackMatchesQuery(t, qNorm)).slice(0, 24);
  if (!matched.length) {
    section.hidden = true;
    grid.innerHTML = "";
    return;
  }
  section.hidden = false;
  grid.innerHTML = matched.map((t, i) => discoveryFeedCardHtml(t, profMap, i)).join("");
  try {
    wireDiscoverySpotCardImages(grid);
  } catch {}
  try {
    syncDiscoveryPlayingHighlights();
  } catch {}
}

function renderSearchDiscoverHints(query) {
  const wrap = document.getElementById("searchDiscoverHints");
  const row = document.getElementById("searchDiscoverHintsRow");
  if (!wrap || !row) return;
  const qNorm = String(query || "").trim();
  if (qNorm) {
    wrap.hidden = true;
    return;
  }
  wrap.hidden = false;
  if (row.dataset.boundHints !== "1") {
    row.dataset.boundHints = "1";
    row.addEventListener("click", (e) => {
      const chip = e.target?.closest?.("[data-search-hint]");
      if (!chip) return;
      const input = document.getElementById("searchInput");
      if (!input) return;
      const hint = String(chip.getAttribute("data-search-hint") || "").trim();
      if (!hint) return;
      haptic("light");
      input.value = hint;
      const bar = input.closest(".searchBar");
      if (bar) bar.classList.add("hasValue");
      const clearBtn = document.getElementById("searchInputClear");
      if (clearBtn) clearBtn.hidden = false;
      stopSearchHintRotator();
      runSearchQuery(hint);
    });
  }
  row.innerHTML = SEARCH_HINT_EXAMPLES.slice(0, 6)
    .map(
      (hint) =>
        `<button type="button" class="searchDiscoverHintChip" data-search-hint="${escapeHtml(hint)}">${escapeHtml(hint)}</button>`,
    )
    .join("");
}

function updateSearchEmptyState(query) {
  const emptyEl = document.getElementById("searchEmpty");
  const trendingEl = document.getElementById("searchTrendingLabel");
  if (!emptyEl) return;
  const qNorm = String(query || "").trim().toLowerCase();
  if (trendingEl) trendingEl.hidden = Boolean(qNorm) || !DISCOVER_SEARCH_SHOW_IDEA_SHELVES;
  if (!qNorm) {
    emptyEl.hidden = true;
    return;
  }
  const hasPeople = !document.getElementById("searchPeopleStrip")?.hidden;
  const hasTracks = !document.getElementById("searchTracksSection")?.hidden;
  const shelvesHtml = DISCOVER_SEARCH_SHOW_IDEA_SHELVES
    ? document.getElementById("searchShelves")?.innerHTML?.trim()
    : "";
  emptyEl.hidden = hasPeople || hasTracks || Boolean(shelvesHtml);
}

function runSearchQuery(query) {
  renderSearchDiscoverHints(query);
  renderSearchPeople(query);
  renderSearchTracks(query);
  renderSearchShelves(query);
  updateSearchEmptyState(query);
}

function applyDiscoveryIdeaToCreate(idea) {
  if (!idea) return;
  if (!authSession?.user?.id) {
    stashPendingDiscoveryIdea(idea);
    setPostAuthReturnHash("#/generate");
    setPendingCreateAction("song");
    try { showToast("Sign in to create from this idea", { icon: "♪", durationMs: 2600 }); } catch {}
    try { location.hash = "#/auth"; } catch {}
    scheduleApplyRoute();
    return;
  }
  const title = String(idea.title || "New Idea").trim();
  const useTemplateGuards = shouldApplyTemplateGuards(idea);
  if (els.sunoTitle) els.sunoTitle.value = title;
  if (els.sunoStyle) {
    els.sunoStyle.value = useTemplateGuards
      ? withTemplateStyleGuard(idea.style)
      : String(idea.style || "").trim();
  }
  if (Object.prototype.hasOwnProperty.call(idea, "dialect") && els.sunoDialect) els.sunoDialect.value = String(idea.dialect || "").trim();
  if (Object.prototype.hasOwnProperty.call(idea, "dialectHint") && els.sunoDialectHint) els.sunoDialectHint.value = String(idea.dialectHint || "").trim();
  if (els.sunoAvoidTags && (useTemplateGuards || Object.prototype.hasOwnProperty.call(idea, "avoidTags"))) {
    els.sunoAvoidTags.value = trimAvoidTagsForSuno(
      String(idea.avoidTags || (useTemplateGuards ? TEMPLATE_GENERATION_AVOID_TAGS : "")),
    );
  }
  if (els.sunoPrompt) {
    const focus = idea.createFocus
      || (idea.challenge?.id ? challengeCreateFocusForId(idea.challenge.id) : null);
    const voiceClipOnly = isVoiceClipChallengeId(idea.challenge?.id) || focus?.tab === "hum";
    const body = voiceClipOnly ? "" : String(idea.lyrics || idea.prompt || "").trim();
    els.sunoPrompt.value = body;
    try { autoResizeLyricsBox(); } catch {}
  }
  pendingSearchRemixMeta = {
    searchTemplateId: `idea:${String(idea.id || title).trim()}`,
    searchTemplateTitle: title,
    challengePromptPending: Boolean(idea.challenge),
    ...(idea.challenge ? { challenge: idea.challenge } : {}),
  };
  if (idea.challenge) persistCreateChallengeContext(pendingSearchRemixMeta);
  else clearCreateChallengeContext();
  const challenge = challengePromptContext();
  const sourceKind = challenge ? creationSourceKind(challenge) : null;
  setCreateChallengeHint(challenge);
  const focus = idea.createFocus
    || (idea.challenge?.id ? challengeCreateFocusForId(idea.challenge.id) : null);
  const voiceClipOnly = isVoiceClipChallengeId(idea.challenge?.id) || focus?.tab === "hum";
  if (focus) applyCreateChallengeFocus(focus);
  else clearCreateChallengeFocus();
  try {
    setStatus?.(
      voiceClipOnly
        ? `Spark: ${title}. Record on Hum, then Generate.`
        : sourceKind === "template"
          ? `Template: ${title}. Edit below, then Generate.`
          : sourceKind === "live"
            ? `Live event: ${title}. Drop your anthem.`
            : sourceKind === "spark"
              ? `Spark: ${title}. Edit the instructions or tap ✦.`
              : `Loaded idea: ${title}. Make it yours.`,
    );
  } catch {}
  try {
    showToast(
      voiceClipOnly
        ? "Record on Hum — lyrics optional"
        : sourceKind === "template"
          ? "Template ready — make it yours"
          : sourceKind === "live"
            ? "Live event loaded — drop your anthem"
            : sourceKind === "spark"
              ? "Spark ready — make your version"
              : "Idea loaded — make it yours",
      { icon: "♪", durationMs: 2600 },
    );
  } catch {}
  try { syncGenerateOrbVisibility?.(); } catch {}
  location.hash = "#/generate";
  scheduleApplyRoute();
}

let _homeDeskContinueTrack = null;
let _homeSeg = "start";
let _homeMakeSeg = "occasion";

function libraryTrackNeedsContinue(track) {
  if (!track) return false;
  if (String(track.url || "").trim()) return false;
  const meta = track.meta && typeof track.meta === "object" ? track.meta : {};
  return Boolean(
    String(meta.lyricsInput || meta.finalPrompt || meta.styleInput || meta.styleSent || "").trim(),
  );
}

function homeDeskQuickTagHtml(tags) {
  return (Array.isArray(tags) ? tags : [])
    .slice(0, 3)
    .map((tag) => `<span>${escapeHtml(tag)}</span>`)
    .join("");
}

function renderHomeDeskQuickStarts() {
  const grid = document.getElementById("homeDeskQuickGrid");
  if (!grid) return;
  grid.innerHTML = DISCOVERY_QUICK_IDEAS.map((idea) => `
    <button type="button" class="discoveryQuickIdea" data-discovery-idea="${escapeHtml(idea.id)}">
      <span>${escapeHtml(idea.title)}</span>
      <small>${homeDeskQuickTagHtml(idea.tags)}</small>
    </button>
  `).join("");
}

function readHomeSeg() {
  try {
    const s = String(sessionStorage.getItem(HOME_SEG_STORAGE_KEY) || "").trim();
    if (s === "start" || s === "sparks" || s === "templates") return s;
  } catch {}
  return "start";
}

function setHomeSeg(seg) {
  const next = String(seg || "").trim();
  if (next !== "start" && next !== "sparks" && next !== "templates") return;
  _homeSeg = next;
  try {
    sessionStorage.setItem(HOME_SEG_STORAGE_KEY, _homeSeg);
  } catch {}
  syncHomeSegUi();
}

function syncHomeSegUi() {
  const page = document.getElementById("homeDeskPage") || document.querySelector('[data-route="challenges"]');
  page?.querySelectorAll?.("[data-home-seg]")?.forEach?.((btn) => {
    const key = String(btn.getAttribute("data-home-seg") || "");
    const on = key === _homeSeg;
    btn.classList.toggle("is-active", on);
    btn.setAttribute("aria-selected", on ? "true" : "false");
  });
  page?.querySelectorAll?.("[data-home-panel]")?.forEach?.((panel) => {
    const on = String(panel.getAttribute("data-home-panel") || "") === _homeSeg;
    panel.classList.toggle("is-active", on);
    panel.hidden = !on;
  });
}

function wireHomeDeskSegOnce() {
  const nav = document.querySelector(".homeDeskSeg");
  if (!nav || nav.dataset.boundHomeSeg === "1") return;
  nav.dataset.boundHomeSeg = "1";
  nav.querySelectorAll("[data-home-seg]").forEach((btn) => {
    btn.addEventListener("click", (e) => {
      e.preventDefault();
      e.stopPropagation();
      const seg = String(btn.getAttribute("data-home-seg") || "start");
      if (seg === _homeSeg) return;
      haptic("light");
      setHomeSeg(seg);
    });
  });
}

function syncHomeMakeSegUi() {
  const page = document.querySelector('[data-route="challenges"]');
  const personal = document.getElementById("homeDeskMakePersonal");
  const versions = document.getElementById("homeDeskPresetVersions");
  const quick = document.getElementById("homeDeskOccasionQuick");
  const hint = document.getElementById("homeDeskMakeHint");
  const isPersonal = _homeMakeSeg === "personal";
  if (personal) personal.hidden = !isPersonal;
  if (versions) versions.hidden = !isPersonal;
  if (quick) quick.hidden = isPersonal;
  if (hint) {
    hint.textContent = isPersonal
      ? "Add their name, pick occasion and sound, then choose a version."
      : "Pick occasion and sound — no name needed.";
  }
  page?.querySelectorAll?.("[data-home-make-seg]")?.forEach?.((btn) => {
    const on = String(btn.getAttribute("data-home-make-seg") || "") === _homeMakeSeg;
    btn.classList.toggle("active", on);
    btn.setAttribute("aria-pressed", on ? "true" : "false");
  });
}

function homeDeskGreetingName() {
  const u = String(activeProfile?.username || "").trim();
  if (u && !isPlaceholderUsername(u)) return u.replace(/^@/, "");
  const email = String(authSession?.user?.email || "").split("@")[0].trim();
  return email || "there";
}

function homeDeskTimeAgo(ts) {
  const ms = Date.now() - Number(ts || 0);
  if (!Number.isFinite(ms) || ms < 0) return "Recently";
  if (ms < 60_000) return "Just now";
  if (ms < 3_600_000) return `${Math.max(1, Math.floor(ms / 60_000))}m ago`;
  if (ms < 86_400_000) return `${Math.floor(ms / 3_600_000)}h ago`;
  return `${Math.floor(ms / 86_400_000)}d ago`;
}

function continueIdeaFromLibraryTrack(track) {
  if (!track) {
    location.hash = "#/generate";
    return;
  }
  const meta = track.meta && typeof track.meta === "object" ? track.meta : {};
  applyDiscoveryIdeaToCreate({
    id: `continue:${String(track.id || "local")}`,
    title: String(track.title || "Continue song").trim(),
    style: String(meta.styleInput || meta.styleSent || meta.style || "").trim(),
    lyrics: String(meta.lyricsInput || meta.finalPrompt || meta.prompt || "").trim(),
    prompt: String(meta.lyricsInput || meta.finalPrompt || meta.prompt || track.title || "").trim(),
    dialect: String(meta.dialect || "").trim(),
    dialectHint: String(meta.dialectHint || "").trim(),
    ...(meta.challenge ? { challenge: meta.challenge } : {}),
  });
}

function renderHomeDeskContinue() {
  const wrap = document.getElementById("homeDeskContinue");
  const titleEl = document.getElementById("homeDeskContinueTitle");
  const metaEl = document.getElementById("homeDeskContinueMeta");
  const artEl = document.getElementById("homeDeskContinueArt");
  if (!wrap || !titleEl || !metaEl) return;
  const lib = loadLibrary()
    .filter((t) => libraryTrackNeedsContinue(t))
    .sort((a, b) => Number(b.ts || 0) - Number(a.ts || 0));
  const track = lib[0] || null;
  _homeDeskContinueTrack = track;
  if (!track) {
    wrap.hidden = true;
    return;
  }
  wrap.hidden = false;
  const challenge = challengeMetaForTrack(track);
  titleEl.textContent = String(track.title || "Untitled song").trim();
  metaEl.textContent = challenge
    ? `${challengeAttributionText(challenge)} · open in Create`
    : String(track.url || "").trim()
      ? "Resume editing in Create"
      : "Pick up where you left off";
  if (artEl) {
    artEl.src = trackCoverArtForFeed(track);
  }
}

function applyChallengeStartById(id, challengesMap) {
  const key = String(id || "").trim();
  const challenge =
    challengesMap?.get?.(key)
    || CHALLENGE_IDEAS.find((row) => String(row.id) === key)
    || DISCOVERY_IDEAS.find((row) => String(row.id) === key);
  if (!challenge) return;
  haptic("light");
  const focus = challengeCreateFocusForId(challenge.id);
  const idea = {
    ...challenge,
    id: `challenge:${challenge.id}`,
    title: String(challenge.title || "Spark").trim(),
    prompt: String(challenge.prompt || "").trim(),
    lyrics: isVoiceClipChallengeId(challenge.id) ? "" : String(challenge.lyrics || challenge.prompt || "").trim(),
    style: withTemplateStyleGuard(`${String(challenge.style || "").trim()}, ${challengeDurationStyleClause(challenge.id)}`),
    dialect: "",
    dialectHint: "",
    avoidTags: TEMPLATE_GENERATION_AVOID_TAGS,
    createFocus: focus,
    challenge: {
      id: challenge.id,
      title: challenge.title,
      type: "spark",
      occasion: "",
      genre: "",
      personName: "",
      variant: "spark",
    },
  };
  if (!authSession?.user?.id) {
    stashPendingDiscoveryIdea(idea);
    setPostAuthReturnHash("#/generate");
    setPendingCreateAction("song");
    try { showToast("Sign in to try this spark", { icon: "♪", durationMs: 2600 }); } catch {}
    try { location.hash = "#/auth"; } catch {}
    scheduleApplyRoute();
    return;
  }
  applyDiscoveryIdeaToCreate(idea);
}

function renderHomeDeskSparksDeck() {
  const deck = document.getElementById("homeDeskSparksDeck");
  if (!deck) return;
  const sparks = CHALLENGE_IDEAS.filter((c) => c.id !== "hook-rush");
  deck.innerHTML = sparks.map((c, i) => {
    const tone = CHALLENGE_SPARK_TONES[i % CHALLENGE_SPARK_TONES.length];
    const kicker = CHALLENGE_SPARK_KICKERS[c.id] || "Spark";
    const blurb = String(c.prompt || "").trim() || "Open Create with this challenge ready.";
    return `
      <article class="challengeMiniCard challengeMiniCard--${tone}">
        <span class="challengeMiniKicker">${escapeHtml(kicker)}</span>
        <h3>${escapeHtml(c.title)}</h3>
        <p>${escapeHtml(blurb)}</p>
        <span class="challengeMiniCount" data-challenge-count="${escapeHtml(c.id)}">0 joined</span>
        <button type="button" data-challenge-start="${escapeHtml(c.id)}">Join</button>
      </article>`;
  }).join("");
}

