function liveCampaignNow() {
  const c = LIVE_CAMPAIGN;
  if (!c) return null;
  const now = Date.now();
  if (now < Number(c.startTs || 0) || now > Number(c.endTs || 0)) return null;
  return c;
}

function campaignDaysLeftLabel(c) {
  const days = Math.max(0, Math.ceil((Number(c.endTs || 0) - Date.now()) / 86400000));
  if (days <= 0) return "last hours";
  if (days === 1) return "1 day left";
  return `${days} days left`;
}

function renderCampaignBanner() {
  const wrap = document.getElementById("campaignBanner");
  if (!wrap) return;
  const c = liveCampaignNow();
  if (!c) {
    wrap.hidden = true;
    return;
  }
  const set = (id, text) => {
    const el = document.getElementById(id);
    if (el) el.textContent = text;
  };
  set("campaignBannerTitle", c.title);
  set("campaignBannerSub", c.sub);
  set("campaignBannerCta", c.cta);
  set("campaignBannerDays", campaignDaysLeftLabel(c));
  set("campaignBannerEmoji", c.emoji);
  wrap.hidden = false;
}

// Sheet state
let _campaignTeam = "";
let _campaignVibe = "pop";
let _campaignLang = "en";
let _campaignSongsCache = { ts: 0, rows: [] };

/** Public campaign entries (songs whose challenge meta carries this
 *  campaign id), newest first. Cached for 5 minutes — shared between the
 *  Discover rail and the sheet leaderboard. */
async function fetchCampaignSongs(campaignId) {
  if (!SUPABASE_URL || !SUPABASE_ANON_KEY) return [];
  if (_campaignSongsCache.rows.length && Date.now() - _campaignSongsCache.ts < 5 * 60_000) {
    return _campaignSongsCache.rows;
  }
  const filter = `public_on_profile=eq.true&meta->challenge->>campaign=eq.${encodeURIComponent(campaignId)}`;
  const cols = "id,created_at,published_at,title,song_url,task_id,audio_id,kind,art_url,user_id,meta_challenge:meta->challenge";
  const colsLegacy = "id,created_at,title,song_url,task_id,audio_id,kind,art_url,user_id,meta_challenge:meta->challenge";
  try {
    let r = await fetch(
      `${SUPABASE_URL}/rest/v1/user_songs?${filter}&select=${cols}&order=published_at.desc.nullslast,created_at.desc&limit=200`,
      { headers: { apikey: SUPABASE_ANON_KEY, Accept: "application/json" }, cache: "no-store" },
    );
    if (!r.ok) {
      const txt = await r.clone().text().catch(() => "");
      if (/published_at|42703|column/i.test(txt)) {
        r = await fetch(
          `${SUPABASE_URL}/rest/v1/user_songs?${filter}&select=${colsLegacy}&order=created_at.desc&limit=200`,
          { headers: { apikey: SUPABASE_ANON_KEY, Accept: "application/json" }, cache: "no-store" },
        );
      }
    }
    if (!r.ok) return [];
    const arr = await r.json().catch(() => []);
    if (!Array.isArray(arr)) return [];
    const rows = dedupePublicSongRowsRaw(arr).map((s) => ({
      id: String(s.id || ""),
      ts: new Date(s.published_at || s.created_at || Date.now()).getTime(),
      title: s.title || "Anthem",
      artUrl: String(s.art_url || "").trim(),
      url: String(s.song_url || "").trim(),
      taskId: String(s.task_id || ""),
      audioId: String(s.audio_id || ""),
      kind: s.kind || "full",
      userId: String(s.user_id || "").trim(),
      meta: s.meta_challenge ? { challenge: s.meta_challenge } : {},
    }));
    _campaignSongsCache = { ts: Date.now(), rows };
    return rows;
  } catch {
    return [];
  }
}

function campaignTeamCounts(rows) {
  const counts = new Map();
  for (const t of rows || []) {
    const team = String(challengeMetaForTrack(t)?.team || "").trim();
    if (team) counts.set(team, (counts.get(team) || 0) + 1);
  }
  return [...counts.entries()].sort((a, b) => b[1] - a[1]);
}

function renderCampaignLeaderboard(rows) {
  const el = document.getElementById("campaignLeaderboard");
  const c = liveCampaignNow();
  if (!el || !c) return;
  const board = campaignTeamCounts(rows).slice(0, 3);
  if (!board.length) {
    el.hidden = true;
    el.innerHTML = "";
    return;
  }
  const medals = ["🥇", "🥈", "🥉"];
  el.innerHTML = board
    .map(([teamId, n], i) => {
      const team = c.teams.find((t) => t.id === teamId);
      if (!team) return "";
      return `<span class="campaignBoardItem">${medals[i] || ""} ${escapeHtml(team.flag)} ${escapeHtml(team.name)} <b>${n}</b></span>`;
    })
    .filter(Boolean)
    .join("");
  el.hidden = false;
}

function syncCampaignSheetSelections() {
  const c = liveCampaignNow();
  document.querySelectorAll("#campaignTeamGrid [data-campaign-team]").forEach((b) => {
    const on = String(b.getAttribute("data-campaign-team") || "") === _campaignTeam;
    b.classList.toggle("isActive", on);
    b.setAttribute("aria-pressed", on ? "true" : "false");
  });
  document.querySelectorAll("#campaignVibeRow [data-campaign-vibe]").forEach((b) => {
    const on = String(b.getAttribute("data-campaign-vibe") || "") === _campaignVibe;
    b.classList.toggle("isActive", on);
    b.setAttribute("aria-pressed", on ? "true" : "false");
  });
  document.querySelectorAll("#campaignLangRow [data-campaign-lang]").forEach((b) => {
    const on = String(b.getAttribute("data-campaign-lang") || "") === _campaignLang;
    b.classList.toggle("isActive", on);
    b.setAttribute("aria-pressed", on ? "true" : "false");
  });
  const cta = document.getElementById("btnCampaignCreate");
  if (cta && c) {
    const team = c.teams.find((t) => t.id === _campaignTeam);
    cta.disabled = !team;
    cta.textContent = team ? `Create my ${team.flag} ${team.name} anthem` : "Pick your team to start";
  }
}

function openCampaignSheet() {
  const c = liveCampaignNow();
  const sheet = document.getElementById("campaignSheet");
  if (!c || !sheet) return;
  const set = (id, text) => {
    const el = document.getElementById(id);
    if (el) el.textContent = text;
  };
  set("campaignSheetTitle", c.title);
  set("campaignSheetSub", c.sub);
  set("campaignSheetDays", campaignDaysLeftLabel(c));
  set("campaignSheetEmoji", c.emoji);
  const teamGrid = document.getElementById("campaignTeamGrid");
  if (teamGrid && !teamGrid.dataset.rendered) {
    teamGrid.dataset.rendered = "1";
    teamGrid.innerHTML = c.teams
      .map(
        (t) => `
        <button type="button" class="campaignTeamChip" data-campaign-team="${escapeHtml(t.id)}" aria-pressed="false">
          <span class="campaignTeamFlag">${escapeHtml(t.flag)}</span>
          <span class="campaignTeamName">${escapeHtml(t.name)}</span>
          <span class="campaignTeamAr">${escapeHtml(t.ar)}</span>
        </button>`,
      )
      .join("");
  }
  const vibeRow = document.getElementById("campaignVibeRow");
  if (vibeRow && !vibeRow.dataset.rendered) {
    vibeRow.dataset.rendered = "1";
    vibeRow.innerHTML = c.vibes
      .map(
        (v) =>
          `<button type="button" class="optChip" data-campaign-vibe="${escapeHtml(v.id)}" aria-pressed="false">${escapeHtml(v.emoji)} ${escapeHtml(v.label)}</button>`,
      )
      .join("");
  }
  syncCampaignSheetSelections();
  if (_campaignTeam) updateCampaignVibeRowForTeam(_campaignTeam);
  sheet.style.display = "";
  try { document.body.style.overflow = "hidden"; } catch {}
  void fetchCampaignSongs(c.id).then((rows) => renderCampaignLeaderboard(rows));
}

function closeCampaignSheet() {
  const sheet = document.getElementById("campaignSheet");
  if (sheet) sheet.style.display = "none";
  try { document.body.style.overflow = ""; } catch {}
}

function startCampaignCreate() {
  const c = liveCampaignNow();
  if (!c) return;
  const team = c.teams.find((t) => t.id === _campaignTeam);
  const vibe = c.vibes.find((v) => v.id === _campaignVibe) || c.vibes[0];
  if (!team || !vibe) return;
  const langCfg = campaignLangConfigForTeam(team.id);
  const lyricLang = _campaignLang === "ar" ? "ar" : "en";
  const teamDisplay = lyricLang === "ar" ? team.ar : team.name;
  const lyrics = String(vibe[lyricLang] || vibe.en || "").replaceAll("{team}", teamDisplay);
  const style = withTemplateStyleGuard(campaignStyleForTeamVibe(team.id, vibe.id));
  const useArabicDialect = lyricLang === "ar";
  closeCampaignSheet();
  applyDiscoveryIdeaToCreate({
    id: `campaign:${c.id}:${team.id}:${vibe.id}`,
    title: `${team.name} Anthem ${c.emoji}`,
    style,
    lyrics,
    prompt: lyrics,
    dialect: useArabicDialect ? langCfg.dialect : "",
    dialectHint: useArabicDialect ? langCfg.dialectHint : "",
    avoidTags: TEMPLATE_GENERATION_AVOID_TAGS,
    challenge: {
      id: `${c.id}:${team.id}`,
      title: `${c.shortTitle} Anthem`,
      type: "campaign",
      campaign: c.id,
      team: team.id,
      teamName: team.name,
      teamFlag: team.flag,
      occasion: c.shortTitle,
      genre: vibe.id === "dabke" ? campaignRootsLabelForTeam(team.id) : vibe.label,
      personName: "",
      variant: vibe.id,
    },
  });
}

function bindCampaignUiOnce() {
  const bannerBtn = document.getElementById("campaignBannerBtn");
  if (bannerBtn && !bannerBtn.dataset.bound) {
    bannerBtn.dataset.bound = "1";
    bannerBtn.addEventListener("click", () => {
      haptic("light");
      openCampaignSheet();
    });
  }
  const sheet = document.getElementById("campaignSheet");
  if (sheet && !sheet.dataset.bound) {
    sheet.dataset.bound = "1";
    document.getElementById("campaignSheetBackdrop")?.addEventListener("click", closeCampaignSheet);
    document.getElementById("btnCloseCampaignSheet")?.addEventListener("click", closeCampaignSheet);
    document.getElementById("btnCampaignCreate")?.addEventListener("click", () => {
      haptic("impact");
      startCampaignCreate();
    });
    sheet.addEventListener("click", (e) => {
      const teamBtn = e.target?.closest?.("[data-campaign-team]");
      if (teamBtn) {
        haptic("light");
        _campaignTeam = String(teamBtn.getAttribute("data-campaign-team") || "");
        applyCampaignTeamDefaults(_campaignTeam);
        syncCampaignSheetSelections();
        return;
      }
      const vibeBtn = e.target?.closest?.("[data-campaign-vibe]");
      if (vibeBtn) {
        haptic("light");
        _campaignVibe = String(vibeBtn.getAttribute("data-campaign-vibe") || "");
        syncCampaignSheetSelections();
        return;
      }
      const langBtn = e.target?.closest?.("[data-campaign-lang]");
      if (langBtn) {
        haptic("light");
        _campaignLang = String(langBtn.getAttribute("data-campaign-lang") || "");
        syncCampaignSheetSelections();
      }
    });
  }
  const railJoin = document.getElementById("discoverCampaignTitleBtn");
  if (railJoin && !railJoin.dataset.bound) {
    railJoin.dataset.bound = "1";
    railJoin.addEventListener("click", () => {
      haptic("light");
      openCampaignSheet();
    });
  }
}

// ─── Weekly chart (Top songs of the week) ───────────────────────────────
let _weeklyChartCache = { ts: 0, chart: null };
let _discoverWeeklyChartSectionBound = false;
const CHART_WEEK_EXPANDED_KEY = "nabad_chart_week_expanded";
let _weeklyChartExpanded = (() => {
  try { return sessionStorage.getItem(CHART_WEEK_EXPANDED_KEY) === "1"; } catch {}
  return false;
})();
/** Live challenge playlist rows (slug → tracks) from last Discover refresh. */
let _discoveryChallengeBuckets = new Map();

async function fetchWeeklyChart() {
  if (_weeklyChartCache.chart && Date.now() - _weeklyChartCache.ts < 5 * 60_000) {
    return _weeklyChartCache.chart;
  }
  try {
    const data = await socialApi("/api/social?type=weekly_chart");
    const chart = Array.isArray(data?.chart) ? data.chart : [];
    _weeklyChartCache = { ts: Date.now(), chart };
    return chart;
  } catch {
    return _weeklyChartCache.chart || [];
  }
}

function chartMovementHtml(entry) {
  const m = String(entry?.movement || "same");
  const delta = Math.max(1, Number(entry?.delta) || 1);
  if (m === "new") return `<span class="chartMove chartMove--new">NEW</span>`;
  if (m === "up") return `<span class="chartMove chartMove--up">+${delta}</span>`;
  if (m === "down") return `<span class="chartMove chartMove--down">−${delta}</span>`;
  return `<span class="chartMove chartMove--same">●</span>`;
}

function chartEntryPlayAttrs(e) {
  const artSafe = trackCoverArtForFeed({ artUrl: e.artUrl, meta: {} });
  const by = e.username ? `@${e.username}` : "Creator";
  return `data-challenge-entry-play="${encodeURIComponent(e.url || "")}" data-challenge-entry-title="${encodeURIComponent(e.title || "Song")}" data-challenge-entry-art="${encodeURIComponent(artSafe)}" data-challenge-entry-by="${encodeURIComponent(by)}" data-play-song-id="${encodeURIComponent(e.songId || "")}" data-play-owner-id="${encodeURIComponent(e.userId || "")}" data-play-task-id="${encodeURIComponent(e.taskId || "")}" data-play-audio-id="${encodeURIComponent(e.audioId || "")}"`;
}

/** Spring slide-up entrance for late-loading Discover sections (campaign
 *  rail, weekly chart). Plays only on the hidden→visible transition so
 *  background refreshes never re-trigger it. */
function playDiscoverSectionEnter(wrap) {
  if (!wrap) return;
  wrap.classList.remove("discoverSectionEnter");
  // Force reflow so re-adding the class restarts the keyframes.
  void wrap.offsetWidth;
  wrap.classList.add("discoverSectionEnter");
  setTimeout(() => {
    try { wrap.classList.remove("discoverSectionEnter"); } catch {}
  }, 1600);
}

function chartWeekTrendHtml(entry) {
  const m = String(entry?.movement || "same");
  const delta = Math.max(0, Number(entry?.delta) || 0);
  if (m === "new") return `<span class="chartWeekTrend chartWeekTrend--new">NEW</span>`;
  if (m === "up") return `<span class="chartWeekTrend chartWeekTrend--up">+${delta || 1}</span>`;
  if (m === "down") return `<span class="chartWeekTrend chartWeekTrend--down">−${delta || 1}</span>`;
  return `<span class="chartWeekTrend chartWeekTrend--same">0</span>`;
}

function chartWeekPlaysText(plays, compact = false) {
  const n = Math.max(0, Number(plays) || 0);
  if (!n) return "";
  const count = formatStatCount(n);
  if (compact) return `${count} play${n === 1 ? "" : "s"}`;
  return `${count} play${n === 1 ? "" : "s"} this week`;
}

function chartWeekWinnerHtml(hero) {
  const heroArt = trackCoverArtForFeed({ artUrl: hero.artUrl, meta: {} });
  const heroPlays = Number(hero.weeklyPlays || 0);
  const title = String(hero.title || "Untitled").trim();
  const menu = discoverSheetMenuBtnHtml(hero, null, { className: "discoverCardMenuBtn chartWeekMenuBtn" });
  return `
    <div class="chartWeekWinner">
      <button type="button" class="chartWeekWinnerTap" ${chartEntryPlayAttrs(hero)} aria-label="Play ${escapeHtml(title)}, number 1 this week">
        <span class="chartWeekWinnerArt">
          <img src="${escapeHtml(heroArt)}" alt="" loading="lazy" decoding="async" />
          ${discoverCoverPlayOverlayHtml({ hero: true })}
        </span>
        <span class="chartWeekWinnerBody">
          <span class="chartWeekWinnerHead">
            <span class="chartWeekWinnerRank">#1</span>
            ${chartWeekTrendHtml(hero)}
          </span>
          <strong class="chartWeekWinnerTitle">${escapeHtml(title)}</strong>
          ${hero.username ? `<span class="chartWeekWinnerBy">@${escapeHtml(hero.username)}</span>` : ""}
          ${heroPlays ? `<span class="chartWeekWinnerPlays">${escapeHtml(chartWeekPlaysText(heroPlays))}</span>` : ""}
        </span>
      </button>
      ${menu}
    </div>`;
}

function chartWeekRunnerHtml(e) {
  const art = trackCoverArtForFeed({ artUrl: e.artUrl, meta: {} });
  const plays = Number(e.weeklyPlays || 0);
  const rank = Number(e.rank) || 0;
  const title = String(e.title || "Untitled").trim();
  const menu = discoverSheetMenuBtnHtml(e, null, { className: "discoverCardMenuBtn chartWeekMenuBtn" });
  return `
    <div class="chartWeekRunner" role="listitem">
      <button type="button" class="chartWeekRunnerTap" ${chartEntryPlayAttrs(e)} aria-label="Play ${escapeHtml(title)}, rank ${rank}">
        <span class="chartWeekRunnerLead">
          <span class="chartWeekRunnerRank">#${rank}</span>
          ${chartWeekTrendHtml(e)}
        </span>
        <span class="chartWeekRunnerArt">
          <img src="${escapeHtml(art)}" alt="" loading="lazy" decoding="async" />
          ${discoverCoverPlayOverlayHtml()}
        </span>
        <span class="chartWeekRunnerMeta">
          <strong class="chartWeekRunnerTitle">${escapeHtml(title)}</strong>
          ${plays ? `<span class="chartWeekRunnerPlays">${escapeHtml(chartWeekPlaysText(plays, true))}</span>` : ""}
        </span>
      </button>
      ${menu}
    </div>`;
}

function chartWeekLeaderboardRowHtml(e) {
  const art = trackCoverArtForFeed({ artUrl: e.artUrl, meta: {} });
  const plays = Number(e.weeklyPlays || 0);
  const rank = Number(e.rank) || 0;
  const title = String(e.title || "Untitled").trim();
  const featured = rank === 1;
  return `
    <button type="button" class="chartWeekLeaderRow${featured ? " chartWeekLeaderRow--featured" : ""}" role="listitem" ${chartEntryPlayAttrs(e)} aria-label="Play ${escapeHtml(title)}, rank ${rank}">
      <span class="chartWeekLeaderLead">
        <span class="chartWeekLeaderRank">#${rank}</span>
        ${chartWeekTrendHtml(e)}
      </span>
      <span class="chartWeekLeaderArt">
        <img src="${escapeHtml(art)}" alt="" loading="lazy" decoding="async" />
      </span>
      <span class="chartWeekLeaderMeta">
        <strong class="chartWeekLeaderTitle">${escapeHtml(title)}</strong>
        ${e.username ? `<span class="chartWeekLeaderBy">@${escapeHtml(e.username)}</span>` : ""}
        ${plays ? `<span class="chartWeekLeaderPlays">${escapeHtml(featured ? chartWeekPlaysText(plays) : chartWeekPlaysText(plays, true))}</span>` : ""}
      </span>
      ${discoverListPlayBtnHtml("chartWeekLeaderPlay")}
    </button>`;
}

function setChartWeekExpanded(next) {
  _weeklyChartExpanded = !!next;
  try { sessionStorage.setItem(CHART_WEEK_EXPANDED_KEY, _weeklyChartExpanded ? "1" : "0"); } catch {}
}

function updateChartWeekExpandedUi(wrap) {
  if (!wrap) wrap = document.getElementById("discoverWeeklyChart");
  if (!wrap) return;
  const expanded = _weeklyChartExpanded;
  const rest = wrap.querySelector("#chartWeekRest");
  if (rest) rest.hidden = !expanded;
  wrap.querySelectorAll("[data-chart-week-toggle]").forEach((btn) => {
    btn.textContent = expanded ? "Show less" : (btn.classList.contains("chartWeekFullBtn") ? "View Full Top 10" : "View Top 10");
    btn.setAttribute("aria-expanded", expanded ? "true" : "false");
  });
}

function toggleChartWeekExpanded(wrap) {
  haptic("light");
  setChartWeekExpanded(!_weeklyChartExpanded);
  updateChartWeekExpandedUi(wrap);
}

function wireChartWeekToggleButtons(wrap) {
  if (!wrap) return;
  wrap.querySelectorAll("[data-chart-week-toggle]").forEach((btn) => {
    btn.addEventListener("click", (e) => {
      e.preventDefault();
      e.stopPropagation();
      toggleChartWeekExpanded(wrap);
    });
  });
}

function bindDiscoverWeeklyChartSectionOnce() {
  if (_discoverWeeklyChartSectionBound) return;
  const mount = document.getElementById("discoverFeedMount");
  if (!mount) return;
  _discoverWeeklyChartSectionBound = true;
  mount.addEventListener("click", (e) => {
    const toggle = e.target?.closest?.("[data-chart-week-toggle]");
    if (!toggle || !mount.contains(toggle)) return;
    e.preventDefault();
    e.stopPropagation();
    toggleChartWeekExpanded(document.getElementById("discoverWeeklyChart"));
  });
}

function paintDiscoverWeeklyChartLoading(wrap) {
  const el = wrap || document.getElementById("discoverWeeklyChart");
  if (!el) return;
  el.hidden = false;
  el.classList.add("isLoading");
  el.setAttribute("aria-busy", "true");
  el.innerHTML = discoverWeeklyChartSkeletonHtml();
}

async function refreshDiscoverWeeklyChart() {
  const wrap = document.getElementById("discoverWeeklyChart");
  if (!wrap) return;
  const hadContent = Boolean(wrap.querySelector(".chartWeekWinner:not(.chartWeekWinner--skel)"));
  const wasHidden = wrap.hidden;
  const wasLoading = wrap.classList.contains("isLoading");
  const cached = _weeklyChartCache.chart && Date.now() - _weeklyChartCache.ts < 5 * 60_000
    ? _weeklyChartCache.chart
    : null;
  if (!cached?.length && !wrap.classList.contains("isLoading")) {
    paintDiscoverWeeklyChartLoading(wrap);
  }
  try {
    const chart = cached || await fetchWeeklyChart();
    wrap.classList.remove("isLoading");
    wrap.removeAttribute("aria-busy");
    if (!chart.length) {
      wrap.hidden = true;
      wrap.innerHTML = "";
      return;
    }
    const topTen = chart.slice(0, 10);
    const [hero, ...rest] = topTen;
    const runnerEntries = rest.slice(0, 3);
    const restEntries = rest.slice(3);
    const showFullChart = restEntries.length > 0;
    const expanded = _weeklyChartExpanded;
    const heroHtml = chartWeekWinnerHtml(hero);
    const runnersHtml = runnerEntries.length
      ? `<div class="chartWeekRunners" role="list" aria-label="Top songs ranks 2 through 4">${runnerEntries.map((e) => chartWeekRunnerHtml(e)).join("")}</div>`
      : "";
    const restHtml = restEntries.length
      ? `<div class="chartWeekRest" id="chartWeekRest" role="list" aria-label="Top songs ranks 5 through 10" ${expanded ? "" : "hidden"}>${restEntries.map((e) => chartWeekRunnerHtml(e)).join("")}</div>`
      : "";
    const toggleLabel = expanded ? "Show less" : "View Top 10";
    const fullLabel = expanded ? "Show less" : "View Full Top 10";
    wrap.innerHTML = `
      <header class="discoverFeedSectionHead chartWeekHead">
        <h3 class="discoverFeedSectionTitle">Top This Week</h3>
        ${showFullChart ? `<button type="button" class="discoverFeedSectionLink" data-chart-week-toggle aria-expanded="${expanded ? "true" : "false"}">${escapeHtml(toggleLabel)}</button>` : ""}
      </header>
      ${heroHtml}
      ${runnersHtml}
      ${restHtml}
      ${showFullChart ? `<button type="button" class="chartWeekFullBtn" data-chart-week-toggle aria-expanded="${expanded ? "true" : "false"}">${escapeHtml(fullLabel)}</button>` : ""}`;
    wireChartWeekToggleButtons(wrap);
    wrap.hidden = false;
    const shouldAnimate = !hadContent && (wasHidden || wasLoading);
    if (shouldAnimate) playDiscoverSectionEnter(wrap);
  } catch {
    wrap.classList.remove("isLoading");
    wrap.removeAttribute("aria-busy");
    wrap.hidden = true;
    wrap.innerHTML = "";
  }
}

async function refreshDiscoverCampaignRail() {
  const wrap = document.getElementById("discoverCampaignRail");
  const row = document.getElementById("discoverCampaignRailRow");
  const countEl = document.getElementById("discoverCampaignCount");
  const titleEl = document.getElementById("discoverCampaignTitle");
  if (!wrap || !row) return;
  const c = liveCampaignNow();
  if (!c) {
    wrap.hidden = true;
    wrap.classList.remove("isLoading");
    wrap.removeAttribute("aria-busy");
    row.innerHTML = "";
    return;
  }
  if (titleEl) titleEl.textContent = `${c.emoji} ${c.title}`;
  const wasHidden = wrap.hidden;
  try {
    const rows = (await fetchCampaignSongs(c.id)).filter((t) => String(t.url || "").trim());
    wrap.classList.remove("isLoading");
    wrap.removeAttribute("aria-busy");
    if (countEl) countEl.textContent = rows.length ? `${rows.length} anthem${rows.length === 1 ? "" : "s"}` : "Be the first!";
    wrap.hidden = false;
    if (!rows.length) {
      row.innerHTML = "";
      if (wasHidden) playDiscoverSectionEnter(wrap);
      return;
    }
    const profMap = await fetchProfilesByUserIdsMap(rows.slice(0, 10).map((t) => t.userId));
    row.innerHTML = rows.slice(0, 10).map((track) => {
      const prof = resolveProfileForFeedCreator(track.userId, profMap);
      const handle = String(prof?.username || "").trim();
      const artSafe = trackCoverArtForFeed(track);
      const title = String(track.title || "Anthem").trim();
      const ch = challengeMetaForTrack(track);
      const flag = String(ch?.teamFlag || "").trim();
      return `
        <button type="button" class="discoverChallengeSpotCard" data-challenge-entry-play="${encodeURIComponent(track.url || "")}" data-challenge-entry-title="${encodeURIComponent(title)}" data-challenge-entry-art="${encodeURIComponent(artSafe)}" data-challenge-entry-by="${encodeURIComponent(handle ? `@${handle}` : "Creator")}" data-play-song-id="${encodeURIComponent(track.id || "")}" data-play-owner-id="${encodeURIComponent(track.userId || "")}" data-play-task-id="${encodeURIComponent(track.taskId || "")}" data-play-audio-id="${encodeURIComponent(track.audioId || "")}">
          <span class="discoverChallengeSpotArt">${flag ? `<span class="discoverCampaignFlag">${escapeHtml(flag)}</span>` : ""}<img src="${escapeHtml(artSafe)}" alt="" loading="lazy" decoding="async" /></span>
          <span class="discoverChallengeSpotMeta">
            <strong>${escapeHtml(title)}</strong>
            ${handle ? `<small>@${escapeHtml(handle)}</small>` : ""}
          </span>
        </button>`;
    }).join("");
    if (wasHidden) playDiscoverSectionEnter(wrap);
  } catch {
    wrap.classList.remove("isLoading");
    wrap.removeAttribute("aria-busy");
    wrap.hidden = true;
    row.innerHTML = "";
  }
}

