  return `<span class="${cls}" aria-hidden="true"><span class="coverArtPlayIco coverArtPlayIco--play">${discoverPlayBtnSvg(size)}</span><span class="coverArtPlayIco coverArtPlayIco--pause">${discoverPauseBtnSvg(size)}</span></span>`;
