async function paintDiscoverFeedFollowCards() {
  const mount = document.getElementById("discoverFeedMount");
  if (!mount) return;
  const buttons = mount.querySelectorAll("[data-discover-follow-user-id]");
  if (!buttons.length) return;
  let following = new Set();
  try {
    following = new Set(await fetchFollowingUserIdsForFeed());
  } catch {}
  buttons.forEach((btn) => {
    const uid = String(btn.getAttribute("data-discover-follow-user-id") || "").trim();
    const isFollowing = following.has(uid);
    btn.textContent = isFollowing ? "Following" : "Follow";
    btn.classList.toggle("isFollowing", isFollowing);
    btn.dataset.following = isFollowing ? "1" : "0";
  });
}

async function handleDiscoverFeedFollowClick(btn, targetUserId) {
  if (!authSession?.user?.id || !getSupabaseAuthToken()) {
    showToast("Sign in to follow creators.");
    location.hash = "#/auth";
    return;
  }
  const wasFollowing = btn.dataset.following === "1" || btn.classList.contains("isFollowing");
  const handle = String(btn.getAttribute("data-discover-follow-handle") || "").trim();
  if (wasFollowing) {
    const who = handle ? `@${handle}` : "this creator";
    let ok = true;
    try { ok = window.confirm(`Unfollow ${who}?`); } catch { ok = true; }
    if (!ok) return;
  }
  btn.disabled = true;
  try {
    await socialApi("/api/social", {
      method: "POST",
      body: JSON.stringify({
        action: wasFollowing ? "unfollow" : "follow",
        targetUserId,
      }),
    });
    _followingListCache = null;
    _followingListCacheAt = 0;
    const nowFollowing = !wasFollowing;
    btn.textContent = nowFollowing ? "Following" : "Follow";
    btn.classList.toggle("isFollowing", nowFollowing);
    btn.dataset.following = nowFollowing ? "1" : "0";
    showToast(nowFollowing ? (handle ? `Following @${handle}.` : "Following creator.") : "Unfollowed creator.");
  } catch (e) {
    showToast(e?.message || "Could not update follow.");
  } finally {
    btn.disabled = false;
  }
}

function discoverFeedTemplateCarouselRowsHtml(tracks, profMap, emptyNote = "", rows = 2) {
  const picks = tracks || [];
  if (!picks.length) {
    return emptyNote
      ? `<p class="discoverHubQuietNote">${escapeHtml(emptyNote)}</p>`
      : "";
  }
  const rowHtml = (items) => {
    const cards = items.map((t) => discoverFeedTemplateCardHtml(t, profMap)).join("");
    return `<div class="discoverFeedCarouselRow"><div class="discoverFeedCarouselRail">${cards}</div></div>`;
  };
  if (rows <= 1) {
    return `<div class="discoverFeedCommunityCarousel discoverFeedCommunityCarousel--single">${rowHtml(picks)}</div>`;
  }
  const mid = Math.ceil(picks.length / 2);
  return `
    <div class="discoverFeedCommunityCarousel">
      ${rowHtml(picks.slice(0, mid))}
      ${picks.length > 1 ? rowHtml(picks.slice(mid)) : ""}
    </div>`;
}

function discoverFeedCommunityPicksBlockHtml(tracks, profMap, prefs) {
  const picks = discoverCommunityPicksTracksPersonalized(tracks, prefs);
  const seeAllBtn = picks.length
    ? `<button type="button" class="discoverFeedSectionLink" data-discover-feed-tab-jump="all">See all</button>`
    : "";
  return `
    <section class="discoverFeedSection discoverFeedSection--communityPicks">
      ${discoverFeedSectionHeadHtml("Community picks", seeAllBtn)}
      ${discoverFeedTemplateCarouselRowsHtml(picks, profMap, "Community songs will show here as creators publish to Discover.")}
    </section>`;
}

function renderDiscoverFeedForYou(tracks, profMap) {
  const prefs = getUserMusicPreferenceLabels();
  const communityBlock = discoverFeedCommunityPicksBlockHtml(tracks, profMap, prefs);
  const remixTracks = discoverTracksSortedByPreferences(
    (tracks || []).filter((t) => remixAttributionForTrack(t) || mashupAttributionForTrack(t)),
    prefs,
    6,
  );
  const templateTracks = discoverTracksSortedByPreferences(
    (tracks || []).filter((t) => trackIsTemplateContent(t)),
    prefs,
    12,
  );
  const topChallengePack = discoverFeaturedChallengeForForYou(tracks, prefs);
  const challengeBlock = topChallengePack.challenge
    ? discoverFeedFeaturedChallengeBlockHtml(topChallengePack.challenge, tracks, profMap, {
      sectionTitle: "From challenges",
      viewAllSlug: "live-challenges",
      entries: topChallengePack.entries,
    })
    : "";
  const remixRowOpts = { rowClass: "discoverFeedSongRow--remix", compactMeta: true };
  const remixList = remixTracks.length
    ? remixTracks.map((t) => discoverFeedSongRowHtml(t, profMap, remixRowOpts)).join("")
    : `<p class="discoverHubQuietNote">Remixes and mashups will appear as creators publish.</p>`;
  const templateSeeAll = templateTracks.length
    ? `<button type="button" class="discoverFeedSectionLink" data-discover-feed-tab-jump="templates">See all</button>`
    : "";
  const templateCarousel = discoverFeedTemplateCarouselRowsHtml(
    templateTracks,
    profMap,
    "Songs made with templates will show here.",
    1,
  );
  const suggestedFollowBlock = discoverFeedSuggestedFollowBlockHtml(tracks, profMap);
  return `
    <section id="discoverWeeklyChart" class="discoverWeeklyChart discoverWeeklyChart--final isLoading" aria-busy="true" aria-label="Top songs this week">${discoverWeeklyChartSkeletonHtml()}</section>
    ${communityBlock}
    ${challengeBlock}
    <section class="discoverFeedSection">
      ${discoverFeedSectionHeadHtml("Remixes you'll love")}
      <div class="discoverFeedListStack discoverFeedListStack--remix">${remixList}</div>
    </section>
    <section class="discoverFeedSection">
      ${discoverFeedSectionHeadHtml("Created with templates", templateSeeAll)}
      ${templateCarousel}
    </section>
    ${suggestedFollowBlock}`;
}

function renderDiscoverFeedTabPanel(tab, tracks, profMap) {
  if (tab === "for-you") return renderDiscoverFeedForYou(tracks, profMap);
  if (tab === "challenges") {
    const blocks = discoverFeedChallengesForUser(getUserMusicPreferenceLabels())
      .map((c) => discoverFeedChallengeBlockHtml(c, tracks, profMap)).join("");
    return blocks || `<p class="discoverHubQuietNote discoverFeedEmpty">Sparks and live events will appear here as creators publish.</p>`;
  }
  if (tab === "templates") {
    return renderDiscoverTemplatesTab(tracks, profMap);
  }
  const filtered = discoverFeedFilterTracks(tab, tracks);
  if (!filtered.length) {
    const msg = tab === "remixes"
      ? "Remixes and mashups from the community will land here."
      : "Public songs will appear here as creators publish.";
    return `<p class="discoverHubQuietNote discoverFeedEmpty">${escapeHtml(msg)}</p>`;
  }
  if (tab === "remixes") {
    const remixRowOpts = { rowClass: "discoverFeedSongRow--remix", compactMeta: true };
    return `<div class="discoverFeedListStack discoverFeedListStack--remix">${filtered.map((t) => discoverFeedSongRowHtml(t, profMap, remixRowOpts)).join("")}</div>`;
  }
  return `<div class="discoverFeedListStack">${filtered.map((t) => discoverFeedSongRowHtml(t, profMap)).join("")}</div>`;
}

function paintDiscoverFeedTabsActive(tab) {
  const root = document.getElementById("discoverFeedTabs");
  if (!root) return;
  root.querySelectorAll("[data-discover-feed-tab]").forEach((btn) => {
    const active = String(btn.getAttribute("data-discover-feed-tab") || "") === tab;
    btn.classList.toggle("is-active", active);
    btn.setAttribute("aria-selected", active ? "true" : "false");
  });
}

function renderDiscoverFeed(tracks, profMap, tab = _discoverFeedTab) {
  const mount = document.getElementById("discoverFeedMount");
  if (!mount) return;
  _discoverFeedTab = DISCOVER_FEED_TABS.some((t) => t.id === tab) ? tab : "for-you";
  try { sessionStorage.setItem(DISCOVER_FEED_TAB_KEY, _discoverFeedTab); } catch {}
  rebuildDiscoveryChallengeBuckets(tracks);
  paintDiscoverFeedTabsActive(_discoverFeedTab);
  mount.innerHTML = renderDiscoverFeedTabPanel(_discoverFeedTab, tracks, profMap);
  mount.classList.remove("isLoading");
  mount.removeAttribute("aria-busy");
  if (_discoverFeedTab === "for-you") {
    void refreshDiscoverWeeklyChart();
    void paintDiscoverFeedFollowCards();
  }
  playDiscoverSectionEnter(mount);
}

function bindDiscoverFeedTabsOnce() {
  const root = document.getElementById("discoverFeedTabs");
  if (!root || root.dataset.boundDiscoverFeedTabs === "1") return;
  root.dataset.boundDiscoverFeedTabs = "1";
  root.addEventListener("click", (e) => {
    const tabBtn = e.target?.closest?.("[data-discover-feed-tab]");
    if (!tabBtn || !root.contains(tabBtn)) return;
    e.preventDefault();
    const tab = String(tabBtn.getAttribute("data-discover-feed-tab") || "").trim();
    if (!tab || tab === _discoverFeedTab) return;
    haptic("light");
    renderDiscoverFeed(_discoveryFeedTracksRaw || [], _discoveryLastProfMap || new Map(), tab);
    try {
      const mount = document.getElementById("discoverFeedMount");
      mount?.scrollIntoView?.({ block: "nearest", behavior: "smooth" });
    } catch {}
  });
  const feedMount = document.getElementById("discoverFeedMount");
  if (feedMount && feedMount.dataset.boundDiscoverFeedJump !== "1") {
    feedMount.dataset.boundDiscoverFeedJump = "1";
    feedMount.addEventListener("click", (e) => {
      const jumpBtn = e.target?.closest?.("[data-discover-feed-tab-jump]");
      if (!jumpBtn) return;
      e.preventDefault();
      const tab = String(jumpBtn.getAttribute("data-discover-feed-tab-jump") || "").trim();
      if (!tab || tab === _discoverFeedTab) return;
      haptic("light");
      renderDiscoverFeed(_discoveryFeedTracksRaw || [], _discoveryLastProfMap || new Map(), tab);
      try {
        root.scrollIntoView?.({ block: "nearest", behavior: "smooth" });
      } catch {}
    });
  }
}

