const FOLLOW_ACT_MEDIA_SEL = ".followActQuoteRow, .followActRemixPair, .followActMashup, .followActMediaWrap";

function profileActMediaSig(t, profMap) {
  const mashupOf = mashupAttributionForTrack(t);
  const a = t._mashupSourceA || mashupSourceFromMetaEntry(mashupOf?.a);
  const b = t._mashupSourceB || mashupSourceFromMetaEntry(mashupOf?.b);
  if (mashupOf && a && b) {
    return `mashup:${String(a.songId || a.url || "")}:${String(b.songId || b.url || "")}`;
  }
  const remixOf = remixAttributionForTrack(t);
  const orig =
    remixOf && t._remixOriginal && String(t._remixOriginal.url || "").trim() ? t._remixOriginal : null;
  if (orig) return `remixpair:${String(orig.songId || orig.url || "")}`;
  return "quote";
}

/** Patch play count text on existing feed rows — no list rebuild. */
function updatePlayCountsOnly(listEl, countsBySongId, patchLogFn) {
  if (!listEl) return 0;
  const entries =
    countsBySongId instanceof Map
      ? [...countsBySongId.entries()]
      : Object.entries(countsBySongId || {});
  let patched = 0;
  for (const [sidRaw, countRaw] of entries) {
    const sid = String(sidRaw || "").trim();
    if (!sid) continue;
    const n = Math.max(0, Number(countRaw) || 0);
    const article = listEl.querySelector(`[data-profile-act-song-id="${sid}"]`);
    if (!article) continue;
    const actRow =
      article.querySelector(".followActActions[data-friends-act-row]") ||
      listEl.querySelector(`.followActActions[data-friends-act-id="${sid}"]`);
    const playsBtn = actRow?.querySelector('[data-friends-act="plays"]');
    if (playsBtn) {
      const countEl = playsBtn.querySelector(".followActActCount");
      if (countEl) countEl.textContent = formatStatCount(n);
      playsBtn.setAttribute("aria-label", `${formatStatCount(n)} plays`);
      playsBtn.setAttribute("data-play-count-pending", "0");
      patched += 1;
    }
    const footStat = article.querySelector(".followActFootStat[data-play-foot-stat]");
    if (footStat) {
      footStat.textContent = `${formatStatCount(n)} ${n === 1 ? "play" : "plays"}`;
    }
  }
  if (patched > 0 && patchLogFn) patchLogFn("plays", patched);
  return patched;
}

/** Patch play counts on feed rows without rebuilding the whole list. */
function applyFollowActPlayCountsToDom(listEl, tracks, patchLogFn) {
  if (!listEl || !tracks?.length) return { ok: true, needsRebuild: false };
  const counts = new Map();
  for (const t of tracks) {
    const sid = String(t?.id || "").trim();
    if (!sid) continue;
    counts.set(sid, Math.max(0, Number(t.playCount) || 0));
  }
  updatePlayCountsOnly(listEl, counts, patchLogFn);
  return { ok: true, needsRebuild: false };
}

let _mergeCloudInFlight = false;
async function mergeCloudSongsIntoLocalLibrary() {
  if (!authSession?.user?.id) return false;
  if (_mergeCloudInFlight) return false;
  _mergeCloudInFlight = true;
  try {
  syncActiveProfileIdFromSession();
  if (!_libraryHydrateCompleted || _libraryHydrateInFlight) {
    await ensureUserLibraryHydrated();
  }
  const cloudRows = await supabaseLoadUserSongs();
  if (!Array.isArray(cloudRows) || !cloudRows.length) return false;
  const tombstones = loadLibraryTombstoneKeySet();
  const cloudFiltered = partitionCloudLibraryRows(cloudRows, tombstones);
  const { keep: cloudSongs, extras: dupExtras } = dedupeCloudSongRows(cloudFiltered);
  if (dupExtras.length) {
    void supabaseDeleteUserSongRowsByIds(
      dupExtras.map((extra) => extra?.cloudSongId || extra?.id),
    );
  }
  if (!cloudSongs.length) return false;

  const sigOf = librarySyncSigOf;
  const local = loadLibrary();
  const prevPublicSig = profilePublicPostsSig(local);
  const localBySig = new Map();
  for (const t of local) localBySig.set(sigOf(t), t);

  const merged = [];
  const seen = new Set();
  let changed = false;
  for (const c of cloudSongs) {
    const sig = sigOf(c);
    if (seen.has(sig)) continue;
    seen.add(sig);
    const localCopy = localBySig.get(sig);
    if (localCopy) {
      const next = mergeLibraryCloudWithLocal(c, localCopy);
      if (
        Boolean(next.publicOnProfile) !== Boolean(localCopy.publicOnProfile) ||
        String(next.url || "") !== String(localCopy.url || "") ||
        String(next.title || "") !== String(localCopy.title || "")
      ) {
        changed = true;
      }
      merged.push(next);
      continue;
    }
    merged.push(c);
    changed = true;
  }
  for (const t of local) {
    const sig = sigOf(t);
    if (seen.has(sig) || isTrackTombstoned(t, tombstones) || isTrackMarkedDeleted(t)) continue;
    seen.add(sig);
    merged.push(t);
  }
  if (!changed) return false;
  merged.sort((a, b) => Number(b?.ts || 0) - Number(a?.ts || 0));
  const nextPublicSig = profilePublicPostsSig(merged);
  saveLibrary(merged);
  if (prevPublicSig !== nextPublicSig) {
    invalidateProfileActivitiesCache();
    invalidateOwnerPublicPostsCache();
  }
  return prevPublicSig !== nextPublicSig;
  } finally {
    _mergeCloudInFlight = false;
  }
}

function profileSelfProfMap(uid) {
  const m = new Map();
  const id = String(uid || "").trim();
  if (!id) return m;
  m.set(id, {
    user_id: id,
    username: String(activeProfile?.username || "").trim(),
    avatar: String(activeProfile?.avatar || "").trim(),
  });
  return m;
}

/** Swap quote card / remix pair / mashup block inside an existing row — not the whole article. */
function patchFollowActRowMedia(article, track, profMap, idx) {
  if (!article || !track) return false;
  const wrap = document.createElement("div");
  wrap.innerHTML = followingActivityRowHtml(track, profMap, idx, { xstyle: true });
  const nextArticle = wrap.firstElementChild;
  if (!nextArticle) return false;
  const headStack = article.querySelector(".followActHeadStack");
  const nextHeadStack = nextArticle.querySelector(".followActHeadStack");
  if (!headStack || !nextHeadStack) return false;
  const actRow = article.querySelector(".followActActionsBar") || article.querySelector(".followActActions");
  const nextActRow = nextArticle.querySelector(".followActActionsBar") || nextArticle.querySelector(".followActActions");
  if (!actRow || !nextActRow) return false;

  const contentEl = article.querySelector(":scope > .followActContent") || headStack.querySelector(".followActContent");
  const nextContent = nextArticle.querySelector(":scope > .followActContent") || nextHeadStack.querySelector(".followActContent");
  const contentAnchor = article.querySelector(".followActTop") || headStack;
  if (nextContent) {
    const clone = nextContent.cloneNode(true);
    if (contentEl) contentEl.replaceWith(clone);
    else contentAnchor.after(clone);
  } else if (contentEl) {
    contentEl.remove();
  }

  article.querySelectorAll(FOLLOW_ACT_MEDIA_SEL).forEach((n) => n.remove());
  nextArticle.querySelectorAll(FOLLOW_ACT_MEDIA_SEL).forEach((node) => {
    actRow.before(node.cloneNode(true));
  });
  return true;
}

function patchFollowActMediaRows(listEl, items, profMap, logFn) {
  let patched = 0;
  items.forEach((item, i) => {
    if (item.kind !== "music") return;
    const sid = String(item.track?.id || "").trim();
    if (!sid) return;
    const article = listEl.querySelector(`[data-profile-act-song-id="${sid}"]`);
    if (!article) return;
    if (patchFollowActRowMedia(article, item.track, profMap, i)) patched += 1;
  });
  if (patched > 0 && logFn) logFn("media", patched);
  return patched;
}

/** Remix/mashup tiles after first paint — patch media blocks only. */
function patchProfileActivityMediaRows(listEl, feedItems, profMap) {
  return patchFollowActMediaRows(listEl, feedItems, profMap, logProfilePostsPatch);
}

async function enrichProfileActivitiesAfterPaint(libRows, feedItems, profMap, listEl, enrichGen) {
  if (!listEl || !feedItems.length) return;
  if (enrichGen !== _profileActEnrichGen) return;
  const mediaSigBefore = libRows.map((t) => profileActMediaSig(t, profMap)).join("|");
  try {
    const playCountMap = libRows.length
      ? await fetchDiscoverSongPlayCounts(libRows.map((t) => t.id))
      : new Map();
    if (enrichGen !== _profileActEnrichGen) return;
    if (
      String(document.body.getAttribute("data-route") || "") !== "profile" ||
      _profileSongsSegment !== "activities"
    ) {
      return;
    }
    for (const t of libRows) {
      t.playCount = playCountMap.get(String(t.id || "")) || 0;
      t._playCountPending = false;
    }
    updatePlayCountsOnly(listEl, playCountMap, logProfilePostsPatch);

    await Promise.all([
      hydrateRemixOriginalsForTracks(libRows),
      hydrateMashupSourcesForTracks(libRows),
    ]);
    if (enrichGen !== _profileActEnrichGen) return;
    if (
      String(document.body.getAttribute("data-route") || "") !== "profile" ||
      _profileSongsSegment !== "activities"
    ) {
      return;
    }
    const mediaSigAfter = libRows.map((t) => profileActMediaSig(t, profMap)).join("|");
    if (mediaSigBefore !== mediaSigAfter) {
      patchProfileActivityMediaRows(listEl, feedItems, profMap);
      _profileActSnapshot = { at: Date.now(), html: listEl.innerHTML };
      persistProfileActSnapshot();
      const totalPublic = loadLibrary().filter(
        (t) => String(t?.url || "").trim() && Boolean(t.publicOnProfile),
      ).length;
      syncProfileActivitiesLoadMoreUi(Math.max(0, totalPublic - _profileActivitiesShown));
    }
    try {
      syncDiscoveryPlayingHighlights();
    } catch {}
    applyFeedSocialStatsToDom(listEl);
    void hydrateFeedSocialStatsForFeed(listEl);
  } catch (e) {
    try {
      console.warn("[profile/activities enrich]", e);
    } catch {}
  }
}

async function renderProfileActivities(opts = {}) {
  const route = document.body.getAttribute("data-route") || "";
  if (route === "profile" && _profileSongsSegment !== "activities") {
    return;
  }
  const force = Boolean(opts.force);
  const extend = Boolean(opts.extend);
  const listEl = document.getElementById("profileActivitiesList");
  const libEl = document.getElementById("libraryList");
  const countEl = document.getElementById("profileActivitiesCount");
  if (!listEl) return;
  if (libEl) libEl.hidden = true;
  listEl.hidden = false;
  if (!authSession?.user?.id) {
    listEl.innerHTML = `
      <div class="profileActEmpty">
        <p class="profileActEmptyTitle">Sign in to see your posts</p>
        <p class="profileActEmptyText">Your published songs and challenge entries land here.</p>
      </div>`;
    if (countEl) countEl.hidden = true;
    syncProfileActivitiesLoadMoreUi(0);
    return;
  }
  const uid = String(authSession.user.id);
  if (!extend && !force) resetProfileActivitiesPagination();
  wireProfileActivitiesLoadMoreOnce();
  hydrateProfileActSnapshotFromStorage();
  const snap = _profileActSnapshot;
  const snapFresh =
    snap &&
    Date.now() - snap.at < PROFILE_ACT_SNAPSHOT_MS &&
    snap.html &&
    !snap.html.includes("followAct--skel");
  if (!opts.deferCloud) {
    await mergeCloudSongsIntoLocalLibrary();
    await refreshOwnerPublicPostsCache({ force: opts.force });
  } else if (!getOwnerPublicPostsSongs()) {
    void refreshOwnerPublicPostsCache().then(() => {
      if ((document.body.getAttribute("data-route") || "") === "profile" && _profileSongsSegment === "activities") {
        void renderProfileActivities({ deferCloud: true });
      }
    });
  }
  try {
  let libRows = (getOwnerPublicPostsSongs() || []).filter((t) => String(t?.url || "").trim());
  if (!libRows.length) {
    libRows = loadLibrary()
      .filter((t) => String(t?.url || "").trim() && Boolean(t.publicOnProfile))
      .map((t) => ({ ...t, userId: String(t.userId || uid) }));
  }
  const pubN = libRows.length;
  if (countEl) {
    countEl.textContent = pubN ? `${pubN} PUBLIC` : "";
    countEl.hidden = !pubN;
  }
  const profMap = profileSelfProfMap(uid);
  const musicItems = libRows.map((track) => ({
    kind: "music",
    ts: profileActivitiesFeedTs(track),
    track,
  }));
  // Songs you've reposted appear in your own activities alongside your songs.
  let repostItems = [];
  let effectiveProfMap = profMap;
  try {
    const myReposts = await fetchUserRepostsForProfile(uid, 40);
    if (myReposts.length) {
      const repIds = [...new Set(myReposts.map((r) => r.targetId))];
      const repSongs = await fetchPublicSongsByIds(repIds);
      repostItems = myReposts
        .map((rp) => {
          const track = repSongs.get(rp.targetId);
          if (!track || !String(track.url || "").trim()) return null;
          return { kind: "repost", ts: rp.ts, repost: rp, track };
        })
        .filter(Boolean);
      if (repostItems.length) {
        const authorIds = [...new Set(repostItems.map((it) => String(it.track.userId || "")).filter(Boolean))];
        effectiveProfMap = await fetchProfilesByUserIdsMap([uid, ...authorIds]);
      }
    }
  } catch {}
  const feedItems = [...musicItems, ...repostItems].sort((a, b) => b.ts - a.ts);
  const totalPosts = feedItems.length;
  _profileActivitiesShown = Math.min(
    totalPosts,
    Math.max(PROFILE_ACTIVITIES_PAGE_SIZE, _profileActivitiesShown),
  );
  const visibleFeedItems = feedItems.slice(0, _profileActivitiesShown);
  const visibleLibRows = visibleFeedItems.map((item) => item.track);
  const remainingPosts = Math.max(0, totalPosts - visibleFeedItems.length);
  const desiredKey = profileActivitiesFeedKey(visibleFeedItems);
  const domKey = readFollowActListDomKey(listEl);
  const hasSkeleton = Boolean(listEl.querySelector(".followAct--skel"));
  const hasRealFeed = domKey.length > 0 && !hasSkeleton;
  if (!feedItems.length) {
    listEl.innerHTML = `
      <div class="profileActEmpty">
        <p class="profileActEmptyTitle">No posts yet</p>
        <p class="profileActEmptyText">Publish a song from <strong>Create</strong> — releases and challenge entries show up here.</p>
        <button type="button" class="emptyStateCta" data-profile-songs-switch="all">View your songs</button>
      </div>`;
    _profileActSnapshot = { at: Date.now(), html: listEl.innerHTML };
    persistProfileActSnapshot();
    syncProfileActivitiesLoadMoreUi(0);
    return;
  }
  const skipListRebuild = desiredKey && domKey === desiredKey && !hasSkeleton;
  if (!skipListRebuild) {
    let listPainted = false;
    if (!extend && !hasRealFeed && snapFresh) {
      listEl.innerHTML = snap.html;
      if (readFollowActListDomKey(listEl) === desiredKey) {
        listPainted = true;
      }
    }
    if (!listPainted) {
      listEl.innerHTML = visibleFeedItems
        .map((item, i) => (item.kind === "repost"
          ? followingRepostRowHtml(item, effectiveProfMap, i)
          : followingActivityRowHtml(item.track, effectiveProfMap, i, { xstyle: true })))
        .join("");
      logProfilePostsListRender(visibleFeedItems.length);
    }
    _profileActSnapshot = { at: Date.now(), html: listEl.innerHTML };
    persistProfileActSnapshot();
  } else {
    try {
      console.info("[profile/posts] list rebuild skipped (dom matches)", desiredKey.split("|").length);
    } catch {}
  }
  syncProfileActivitiesLoadMoreUi(remainingPosts);
  try {
    syncDiscoveryPlayingHighlights();
  } catch {}
  applyFeedSocialStatsToDom(listEl);
  const enrichGen = ++_profileActEnrichGen;
  void enrichProfileActivitiesAfterPaint(visibleLibRows, visibleFeedItems, effectiveProfMap, listEl, enrichGen);
  } catch (e) {
    try {
      console.warn("[profile/activities]", e);
    } catch {}
    if (!listEl.querySelector(".followAct")) {
      listEl.innerHTML = `
        <div class="profileActEmpty">
          <p class="profileActEmptyTitle">Could not load posts</p>
          <p class="profileActEmptyText">Check your connection and try again.</p>
          <button type="button" class="emptyStateCta" id="profileActivitiesRetry">Retry</button>
        </div>`;
      const retry = document.getElementById("profileActivitiesRetry");
      if (retry && !retry.dataset.boundProfileActRetry) {
        retry.dataset.boundProfileActRetry = "1";
        retry.addEventListener("click", () => {
          invalidateProfileActivitiesCache();
          void renderProfileActivities({ force: true });
        });
      }
    }
  }
}

function normalizeStatusWaveformPeaks(raw) {
  if (!Array.isArray(raw)) return [];
  return raw
    .slice(0, 64)
    .map((n) => Math.max(0, Math.min(1, Number(n) || 0)));
}

function mapStatusPostFromSupabaseRow(p, prof) {
  const audioUrl = String(p?.audio_url || "").trim();
  return {
    id: p.id,
    userId: p.user_id,
    postType: p.post_type,
    body: p.body,
    audioUrl,
    durationMs: Number(p?.duration_ms) || 0,
    waveformPeaks: normalizeStatusWaveformPeaks(p?.waveform_peaks),
    createdAt: p.created_at,
    username: prof?.username || "",
    avatar: prof?.avatar || "",
  };
}

async function supabaseRestWithAuth(path, opts = {}) {
  const token = getSupabaseAuthToken();
  if (!token || !SUPABASE_URL || !SUPABASE_ANON_KEY) return null;
  const ctrl = new AbortController();
  const timer = setTimeout(
    () => ctrl.abort(),
    Math.max(4000, Number(opts.timeoutMs) || supabaseRestTimeoutMs()),
  );
  try {
    return await fetch(`${SUPABASE_URL}/rest/v1/${path}`, {
      method: opts.method || "GET",
      headers: {
        apikey: SUPABASE_ANON_KEY,
        Authorization: `Bearer ${token}`,
        Accept: "application/json",
        ...(opts.prefer ? { Prefer: opts.prefer } : {}),
        ...(opts.body ? { "Content-Type": "application/json" } : {}),
        ...(opts.headers || {}),
      },
      body: opts.body,
      cache: "no-store",
      signal: ctrl.signal,
    });
  } catch {
    return null;
  } finally {
    clearTimeout(timer);
  }
}

/** Following list from Supabase RLS (no Vercel /api). Returns null if auth/config missing. */
async function fetchFollowingListViaSupabase() {
  const uid = String(authSession?.user?.id || "").trim();
  if (!uid) return null;
  const r = await supabaseRestWithAuth(
    `social_follows?follower_user_id=eq.${encodeURIComponent(uid)}&select=following_user_id,created_at&order=created_at.desc&limit=100`,
  );
  if (!r) return null;
  if (!r.ok) return null;
  const rows = await r.json().catch(() => []);
  if (!Array.isArray(rows)) return [];
  const ids = rows.map((x) => String(x?.following_user_id || "").trim()).filter(Boolean);
  const profMap = await fetchProfilesByUserIdsMap(ids);
  return rows.map((row) => {
    const userId = String(row.following_user_id || "").trim();
    const prof = resolveProfileForFeedCreator(userId, profMap);
    return {
      userId,
      createdAt: row.created_at,
      username: prof?.username || "",
      avatar: prof?.avatar || "",
    };
  });
}

async function fetchFollowingListForFeed() {
  if (_followingListCache && Date.now() - _followingListCacheAt < FOLLOWING_LIST_CACHE_MS) {
    return _followingListCache;
  }
  const direct = await fetchFollowingListViaSupabase();
  if (direct !== null) {
    _followingListCache = direct;
    _followingListCacheAt = Date.now();
    return direct;
  }
  const data = await socialApi("/api/social?type=me");
  const list = Array.isArray(data?.following) ? data.following : [];
  _followingListCache = list;
  _followingListCacheAt = Date.now();
  return list;
}

/** Following user ids only — skips the profiles round-trip used by the full list. */
async function fetchFollowingUserIdsViaSupabase() {
  const uid = String(authSession?.user?.id || "").trim();
  if (!uid) return null;
  const r = await supabaseRestWithAuth(
    `social_follows?follower_user_id=eq.${encodeURIComponent(uid)}&select=following_user_id&order=created_at.desc&limit=100`,
  );
  if (!r || !r.ok) return null;
  const rows = await r.json().catch(() => []);
  if (!Array.isArray(rows)) return [];
  return rows.map((x) => String(x?.following_user_id || "").trim()).filter(Boolean);
}

async function fetchFollowingUserIdsForFeed() {
  if (_followingListCache && Date.now() - _followingListCacheAt < FOLLOWING_LIST_CACHE_MS) {
    return _followingListCache
      .map((f) => String(f?.userId || f?.user_id || f?.following_user_id || "").trim())
      .filter(Boolean);
  }
  const direct = await fetchFollowingUserIdsViaSupabase();
  if (direct !== null) return direct;
  const list = await fetchFollowingListForFeed();
  return list
    .map((f) => String(f?.userId || f?.user_id || f?.following_user_id || "").trim())
    .filter(Boolean);
}

function invalidateFollowingListCache() {
  _followingListCache = null;
  _followingListCacheAt = 0;
}

async function fetchFollowingStatusPostsFromSupabase(limit = 40, followingIn = null) {
  const following = followingIn ?? (await fetchFollowingListViaSupabase());
  if (following === null) return null;
  const authorIds = [...new Set(following.map((f) => f.userId).filter(Boolean))];
  if (!authorIds.length) return [];
  const lim = Math.min(60, Math.max(1, Number(limit) || 40));
  const inList = authorIds.map((id) => encodeURIComponent(id)).join(",");
  const cols = "id,user_id,post_type,body,audio_url,duration_ms,waveform_peaks,created_at";
  const r = await supabaseRestWithAuth(
    `social_status_posts?user_id=in.(${inList})&select=${cols}&order=created_at.desc&limit=${lim}`,
  );
  if (!r || !r.ok) return null;
  const rawPosts = await r.json().catch(() => []);
  if (!Array.isArray(rawPosts)) return [];
  const profMap = await fetchProfilesByUserIdsMap(
    rawPosts.map((p) => String(p?.user_id || "").trim()).filter(Boolean),
  );
  return rawPosts.map((p) =>
    mapStatusPostFromSupabaseRow(p, profMap.get(String(p?.user_id || "").trim())),
  );
}

async function fetchFollowingStatusPosts(limit = 40, followingIn = null) {
  if (!STATUS_POSTS_FEATURE_ENABLED) return [];
  const direct = await fetchFollowingStatusPostsFromSupabase(limit, followingIn);
  if (direct !== null) return direct;
  try {
    const data = await socialApi(`/api/social?type=following_status&limit=${limit}`);
    return Array.isArray(data?.posts) ? data.posts : [];
  } catch {
    return [];
  }
}

async function postStatusViaSupabase({ postType, body, audioUrl, durationMs, waveformPeaks }) {
  const uid = String(authSession?.user?.id || "").trim();
  if (!uid) return null;
  const allowed = new Set(["update", "advice", "brainstorm", "song_request", "recommend"]);
  const pt = allowed.has(String(postType || "").trim()) ? String(postType).trim() : "update";
  const text = String(body || "").trim().slice(0, 320);
  const audio = String(audioUrl || "").trim().slice(0, 2048);
  const dur = Math.min(60000, Math.max(0, Math.round(Number(durationMs) || 0)));
  const peaks = normalizeStatusWaveformPeaks(waveformPeaks);
  if (!text && !audio) throw new Error("Add a voice drop or write something to post");
  if (audio && !/^https?:\/\//i.test(audio)) throw new Error("Invalid voice audio URL");
  const finalBody = text || (audio ? STATUS_VOICE_DEFAULT_BODY : "");
  const r = await supabaseRestWithAuth("social_status_posts", {
    method: "POST",
    prefer: "return=representation",
    body: JSON.stringify({
      user_id: uid,
      post_type: pt,
      body: finalBody,
      audio_url: audio || null,
      duration_ms: audio ? (dur || null) : null,
      waveform_peaks: audio && peaks.length ? peaks : null,
    }),
  });
  if (!r || !r.ok) return null;
  const arr = await r.json().catch(() => []);
  const row = Array.isArray(arr) && arr[0] ? arr[0] : null;
  if (!row) return null;
  const profMap = await fetchProfilesByUserIdsMap([uid]);
  return { post: mapStatusPostFromSupabaseRow(row, profMap.get(uid)) };
}

async function postFriendsStatus(payload, opts = {}) {
  if (!STATUS_POSTS_FEATURE_ENABLED) throw new Error("Status posts are no longer available");
  const direct = await postStatusViaSupabase(payload);
  if (direct) return direct;
  return socialApi("/api/social", {
    method: "POST",
    timeoutMs: opts.timeoutMs || 12000,
    body: JSON.stringify({
      action: "post_status",
      postType: payload.postType,
      body: payload.body,
      audioUrl: payload.audioUrl,
      durationMs: payload.durationMs,
      waveformPeaks: payload.waveformPeaks,
    }),
  });
}

function lockPageForFriendsComposeSheet() {
  document.body.classList.add("friendsComposeSheetOpen");
}

function unlockPageForFriendsComposeSheet() {
  document.body.classList.remove("friendsComposeSheetOpen");
}

function shouldAutofocusFriendsComposeInput() {
  try {
    if (window.matchMedia("(max-width: 720px)").matches) return false;
    if (window.matchMedia("(pointer: coarse)").matches) return false;
  } catch {}
  return true;
}

function syncFriendsComposeSheetKeyboardInset() {
  const sheet = document.getElementById("friendsComposeSheet");
  if (!sheet?.classList.contains("isOpen")) {
    try { sheet?.style.removeProperty("--friends-keyboard-inset"); } catch {}
    return;
  }
  const vv = window.visualViewport;
  if (!vv) {
    sheet.style.setProperty("--friends-keyboard-inset", "0px");
    return;
  }
  const inset = Math.max(0, Math.round(window.innerHeight - vv.height - vv.offsetTop));
  sheet.style.setProperty("--friends-keyboard-inset", `${inset}px`);
}

function wireFriendsComposeSheetKeyboardOnce() {
  if (document.documentElement.dataset.friendsComposeKbWired) return;
  document.documentElement.dataset.friendsComposeKbWired = "1";
  const vv = window.visualViewport;
  if (!vv) return;
  const onViewportChange = () => syncFriendsComposeSheetKeyboardInset();
  vv.addEventListener("resize", onViewportChange);
  vv.addEventListener("scroll", onViewportChange);
}

function openFriendsComposeSheet() {
  if (!STATUS_POSTS_FEATURE_ENABLED) return;
  const sheet = document.getElementById("friendsComposeSheet");
  const openBtn = document.getElementById("friendsComposeOpenBtn");
  if (!sheet) return;
  wireFriendsComposeSheetKeyboardOnce();
  syncFollowingComposeUi();
  sheet.classList.remove("isClosing");
  sheet.hidden = false;
  sheet.setAttribute("aria-hidden", "false");
  if (openBtn) openBtn.setAttribute("aria-expanded", "true");
  lockPageForFriendsComposeSheet();
  sheet.style.setProperty("--friends-keyboard-inset", "0px");
  sheet.classList.add("isOpen");
  if (shouldAutofocusFriendsComposeInput()) {
    window.setTimeout(() => {
      try {
        document.getElementById("followComposeInput")?.focus?.({ preventScroll: true });
      } catch {}
    }, 380);
  }
}

const FIXED_OVERLAY_IDS = ["createChooserSheet", "friendsComposeSheet", "imageMoodModal"];

/** Keep full-screen overlays on `body` — `main.grid.routeSwap` transform breaks iOS touch on fixed children. */
function mountFixedOverlaysToBody() {
  for (const id of FIXED_OVERLAY_IDS) {
    const el = document.getElementById(id);
    if (!el || el.parentElement === document.body) continue;
    document.body.appendChild(el);
  }
}


function isCreateChooserOpen() {
  const sheet = document.getElementById("createChooserSheet");
  return Boolean(sheet && !sheet.hidden && sheet.classList.contains("isOpen"));
}

function lockPageForCreateChooserSheet() {
  document.body.classList.add("createChooserSheetOpen");
}

function unlockPageForCreateChooserSheet() {
  document.body.classList.remove("createChooserSheetOpen");
}

function openCreateChooserSheet() {
  mountFixedOverlaysToBody();
  wireCreateChooserSheetOnce();
  const sheet = document.getElementById("createChooserSheet");
  if (!sheet) return;
  if (!authSession?.user?.id) {
    try { showToast("Sign in to create", { icon: "👤", durationMs: 2400 }); } catch {}
    try { location.hash = "#/auth"; } catch {}
    return;
  }
  try { closeFriendsComposeSheet(); } catch {}
  sheet.hidden = false;
  sheet.setAttribute("aria-hidden", "false");
  lockPageForCreateChooserSheet();
  sheet.classList.add("isOpen");
}

function closeCreateChooserSheet({ immediate = false } = {}) {
  const sheet = document.getElementById("createChooserSheet");
  if (!sheet) return;
  sheet.classList.remove("isOpen");
  unlockPageForCreateChooserSheet();
  if (immediate) {
    sheet.classList.remove("isClosing");
    sheet.hidden = true;
    sheet.setAttribute("aria-hidden", "true");
    return;
  }
  sheet.classList.add("isClosing");
  window.setTimeout(() => {
    sheet.classList.remove("isClosing");
    sheet.hidden = true;
    sheet.setAttribute("aria-hidden", "true");
  }, 200);
}

const CREATE_ENTRY_INTENT_KEY = "nabadai_create_entry_intent_v1";
const PENDING_CREATE_ACTION_KEY = "nabadai_pending_create_action_v1";
const GUEST_MODE_KEY = "nabadai_guest_mode_v1";
const POST_AUTH_RETURN_HASH_KEY = "nabadai_post_auth_return_v1";
const PENDING_DISCOVERY_IDEA_KEY = "nabadai_pending_discovery_idea_v1";

const HUM_CHALLENGE_IDS = new Set(["voice-note-flip", "voice-note-remix"]);
const PHOTO_CHALLENGE_IDS = new Set(["last-photo-song"]);

function isVoiceClipChallengeId(challengeId) {
  return HUM_CHALLENGE_IDS.has(String(challengeId || "").trim());
}

function challengeCreateFocusForId(challengeId) {
  const id = String(challengeId || "").trim();
  if (HUM_CHALLENGE_IDS.has(id)) return { tab: "hum", tabs: ["hum", "lyrics"] };
  if (PHOTO_CHALLENGE_IDS.has(id)) return { tab: "photo", tabs: ["photo", "lyrics"] };
  return { tab: "lyrics", tabs: ["lyrics"] };
}

function challengeDurationStyleClause(challengeId) {
  const id = String(challengeId || "").trim();
  if (["tiktok-teaser", "hook-rush", "three-word-hook", "arabic-trend-byte"].includes(id)) {
    return "Short clip under 45 seconds, hook-focused, no full-length song";
  }
  if (HUM_CHALLENGE_IDS.has(id) || PHOTO_CHALLENGE_IDS.has(id)) {
    return "Short clip under 75 seconds, compact form, no full-length song";
  }
  return "Short clip under 2 minutes, compact form, no 4-minute arrangement";
}

function applyCreateChallengeFocus(focus) {
  const tabs = focus?.tabs?.length ? focus.tabs : focus?.tab ? [focus.tab] : null;
  if (!tabs?.length) {
    clearCreateChallengeFocus();
    return;
  }
  document.body.setAttribute("data-create-focus", String(focus.tab || tabs[0]));
  ["photo", "hum", "lyrics"].forEach((k) => {
    const el = document.getElementById(k === "photo" ? "createTabPhoto" : k === "hum" ? "createTabHum" : "createTabLyrics");
    if (!el) return;
    const show = tabs.includes(k);
    el.hidden = !show;
    el.style.display = show ? "" : "none";
  });
  try { setActiveCreateTab(String(focus.tab || tabs[0])); } catch {}
}

function clearCreateChallengeFocus() {
  document.body.removeAttribute("data-create-focus");
  ["createTabPhoto", "createTabHum", "createTabLyrics"].forEach((id) => {
    const el = document.getElementById(id);
    if (!el) return;
    el.hidden = false;
    el.style.display = "";
  });
}

function isGuestModeEnabled() {
  try { return localStorage.getItem(GUEST_MODE_KEY) === "1"; } catch {}
  return false;
}

function setGuestModeEnabled(on) {
  try {
    if (on) localStorage.setItem(GUEST_MODE_KEY, "1");
    else localStorage.removeItem(GUEST_MODE_KEY);
  } catch {}
}

function setPostAuthReturnHash(hash) {
  try {
    const h = String(hash || "").trim();
    if (!h) sessionStorage.removeItem(POST_AUTH_RETURN_HASH_KEY);
    else sessionStorage.setItem(POST_AUTH_RETURN_HASH_KEY, h);
  } catch {}
}

function consumePostAuthReturnHash() {
  try {
    const h = String(sessionStorage.getItem(POST_AUTH_RETURN_HASH_KEY) || "").trim();
    sessionStorage.removeItem(POST_AUTH_RETURN_HASH_KEY);
    return h;
  } catch {}
  return "";
}

function stashPendingDiscoveryIdea(idea) {
  try { sessionStorage.setItem(PENDING_DISCOVERY_IDEA_KEY, JSON.stringify(idea)); } catch {}
}

function consumePendingDiscoveryIdea() {
  try {
    const raw = sessionStorage.getItem(PENDING_DISCOVERY_IDEA_KEY);
    sessionStorage.removeItem(PENDING_DISCOVERY_IDEA_KEY);
    if (!raw) return null;
    return JSON.parse(raw);
  } catch {}
  return null;
}

function setCreateEntryIntent(intent) {
  try {
    if (!intent) sessionStorage.removeItem(CREATE_ENTRY_INTENT_KEY);
    else sessionStorage.setItem(CREATE_ENTRY_INTENT_KEY, String(intent));
  } catch {}
}

function getCreateEntryIntent() {
  try { return String(sessionStorage.getItem(CREATE_ENTRY_INTENT_KEY) || "").trim(); } catch {}
  return "";
}

function setPendingCreateAction(action) {
  try {
    const kind = String(action || "").trim();
    if (!kind) sessionStorage.removeItem(PENDING_CREATE_ACTION_KEY);
    else sessionStorage.setItem(PENDING_CREATE_ACTION_KEY, kind);
  } catch {}
}

function getPendingCreateAction() {
  try { return String(sessionStorage.getItem(PENDING_CREATE_ACTION_KEY) || "").trim(); } catch {}
  return "";
}

async function finishPostAuthNavigation() {
  const pending = getPendingCreateAction();
  setPendingCreateAction("");
  const returnHash = consumePostAuthReturnHash();
  const pendingPushRoute = consumePendingPushRoute();
  const pendingIdea = consumePendingDiscoveryIdea();
  setGuestModeEnabled(false);
  loadAuthSession();
  ensureAuthSessionUserFromToken();
  if (authSession?.user?.id) {
    try { markOnboardingComplete(); } catch {}
  }
  endLoginSettling({ minimum: true });
  if (
    authSession?.user?.id
    && !isMusicPreferencesComplete(authSession.user.id, activeProfile)
    && !isMusicPreferencesPending()
  ) {
    try {
      const cloud = await supabaseLoadProfile();
      if (!cloud) markMusicPreferencesPending();
      else if (parseMusicPreferencesFromProfile(cloud).length) {
        markMusicPreferencesComplete(authSession.user.id);
        activeProfile = { ...activeProfile, genres: cloud.genres || activeProfile.genres || "" };
        saveProfile(activeProfile);
      }
    } catch {}
  }
  if (pending === "song" || pending === "status" || pending === "echo") {
    window.setTimeout(() => {
      try { navigateFromCreateChooser(pending); } catch {}
    }, 80);
    void ensureAuthBoot({ force: true, fast: true });
    return;
  }
  if (returnHash && returnHash.startsWith("#/")) {
    try { location.hash = returnHash; } catch {}
    syncRoutePanelVisibility(returnHash.slice(2).split(/[?#&]/)[0].trim() || "challenges");
    try { applyRoute(); } catch { scheduleApplyRoute(); }
    if (pendingIdea && returnHash.includes("generate")) {
      window.setTimeout(() => {
        try { applyDiscoveryIdeaToCreate(pendingIdea); } catch {}
      }, 120);
    }
    void ensureAuthBoot({ force: true, fast: true });
    return;
  }
  if (pendingPushRoute) {
    const pushTarget = String(pendingPushRoute || "").trim().replace(/^\/+/, "");
    if (pushTarget) {
      try { location.hash = `#/${pushTarget}`; } catch {}
      syncRoutePanelVisibility(pushTarget.split(/[?#&]/)[0].trim() || "activity");
      try { applyRoute(); } catch { scheduleApplyRoute(); }
      void ensureAuthBoot({ force: true, fast: true });
      return;
    }
  }
  if (
    shouldShowMusicPreferencesScreen(authSession?.user?.id, activeProfile)
    && !returnHash
    && !pending
  ) {
    try { location.hash = "#/music-preferences"; } catch {}
    syncRoutePanelVisibility("music-preferences");
    try { applyRoute(); } catch { scheduleApplyRoute(); }
    void ensureAuthBoot({ force: true, fast: true });
    return;
  }
  const target = authSession?.user?.id ? "discover" : "auth";
  try {
    location.hash = `#/${target}`;
  } catch {}
  syncRoutePanelVisibility(target);
  try {
    applyRoute();
  } catch {
    scheduleApplyRoute();
  }
  void ensureAuthBoot({ force: true, fast: true });
  void (async () => {
    try {
      const cloud = await supabaseLoadProfile();
      if (cloud?.savedPersonas?.length) hydratePersonasFromCloud(cloud.savedPersonas);
      else if (loadPersonas().length) schedulePersonasCloudSync({ delayMs: 400 });
    } catch (e) {
      console.warn("[personas] post-login hydrate failed", e);
    }
  })();
}

function hasOAuthCodeInUrl() {
  try {
    return Boolean(new URLSearchParams(window.location.search || "").get("code"));
  } catch {
    return false;
  }
}

async function navigateFromPushRoute(route) {
  const clean = String(route || "").trim().replace(/^\/+/, "");
  if (!clean) return;
  stashPendingPushRoute(clean);
  try {
    await ensureAuthBoot({ fast: Boolean(getSupabaseAuthToken() || authSession?.access_token) });
    loadAuthSession();
    ensureAuthSessionUserFromToken();
    if (!isAppLoggedIn() && !getSupabaseAuthToken()) {
      setPostAuthReturnHash(`#/${clean}`);
      try { location.hash = "#/auth"; } catch {}
      scheduleApplyRoute();
      return;
    }
    try { location.hash = `#/${clean}`; } catch {}
    scheduleApplyRoute();
  } catch (e) {
    console.warn("[push] navigate failed", e);
    scheduleApplyRoute();
  }
}

function requireAuthForCreate(onAuthed, pendingAction = "") {
  if (authSession?.user?.id) {
    try { onAuthed?.(); } catch {}
    return true;
  }
  setPendingCreateAction(pendingAction);
  setPostAuthReturnHash(String(location.hash || "#/challenges").trim() || "#/challenges");
  closeCreateChooserSheet();
  try { showToast("Sign in to create", { icon: "👤", durationMs: 2400 }); } catch {}
  try { location.hash = "#/auth"; } catch {}
  return false;
}

let _createChooserNavLock = false;

/** Single router for Create chooser → existing engines (no new API routes). */
function navigateFromCreateChooser(action) {
  const kind = String(action || "").trim();
  if (!kind) return;
  if (_createChooserNavLock) return;
  if (!requireAuthForCreate(() => navigateFromCreateChooser(kind), kind)) return;

  _createChooserNavLock = true;

  try {
    if (kind === "echo") {
      openEchoFromCreateChooser();
      closeCreateChooserSheet({ immediate: true });
      return;
    }

    closeCreateChooserSheet({ immediate: true });

    if (kind === "song") {
      setCreateEntryIntent("song");
      const onGenerate = String(location.hash || "") === "#/generate";
      if (!onGenerate) try { location.hash = "#/generate"; } catch {}
      else scheduleApplyRoute();
      window.setTimeout(() => {
        try { if (typeof setActiveCreateTab === "function") setActiveCreateTab("lyrics"); } catch {}
        try { els.sunoPrompt?.focus?.({ preventScroll: true }); } catch {}
      }, 100);
      return;
    }

  } finally {
    window.setTimeout(() => {
      _createChooserNavLock = false;
    }, 320);
  }
}

function openFriendsForStatusCompose() {
  setCreateEntryIntent("");
  _friendsStatusComposePending = true;
  _followComposeType = "update";
  try { syncFollowingComposeUi(); } catch {}
  const onFriends = String(location.hash || "") === "#/friends";
  if (!onFriends) {
    try { location.hash = "#/friends"; } catch {}
  } else {
    enterFriendsRoute();
  }
}

function wireCreateChooserSheetOnce() {
  const sheet = document.getElementById("createChooserSheet");
  if (!sheet || sheet.dataset.wiredCreateChooserSheet) return;
  sheet.dataset.wiredCreateChooserSheet = "1";
  sheet.addEventListener("click", (e) => {
    const dismiss = e.target?.closest?.("[data-create-chooser-dismiss]");
    if (dismiss) {
      e.preventDefault();
      e.stopPropagation();
      closeCreateChooserSheet();
      return;
    }
    const btn = e.target?.closest?.("[data-create-chooser]");
    if (!btn || !sheet.contains(btn)) return;
    e.preventDefault();
    e.stopPropagation();
    navigateFromCreateChooser(btn.getAttribute("data-create-chooser"));
  });
}

function wireRouteLinkHapticsOnce() {
  if (document.documentElement.dataset.wiredRouteLinkHaptics) return;
  document.documentElement.dataset.wiredRouteLinkHaptics = "1";
  document.addEventListener(
    "click",
    (e) => {
      const a = e.target?.closest?.("a[data-route-link]");
      if (!a) return;
      if (!a.closest(".mobileTabbar") && !a.closest(".journeyBar")) return;
      if (document.body.classList.contains("echoComposeOpen")) return;
      haptic("light");
    },
    true,
  );
}


function closeFriendsComposeSheet({ immediate = false } = {}) {
  const sheet = document.getElementById("friendsComposeSheet");
  const openBtn = document.getElementById("friendsComposeOpenBtn");
  if (!sheet) return;
  resetStatusVoiceCompose();
  try {
    document.getElementById("followComposeInput")?.blur?.();
  } catch {}
  sheet.classList.remove("isOpen");
  unlockPageForFriendsComposeSheet();
  sheet.style.setProperty("--friends-keyboard-inset", "0px");
  if (openBtn) openBtn.setAttribute("aria-expanded", "false");
  if (immediate) {
    sheet.classList.remove("isClosing");
    sheet.hidden = true;
    sheet.setAttribute("aria-hidden", "true");
    return;
  }
  sheet.classList.add("isClosing");
  window.setTimeout(() => {
    sheet.classList.remove("isClosing");
    sheet.hidden = true;
    sheet.setAttribute("aria-hidden", "true");
  }, 220);
}

function wireFriendsComposeSheetOnce() {
  const sheet = document.getElementById("friendsComposeSheet");
  if (!sheet || sheet.dataset.wiredFriendsComposeSheet) return;
  sheet.dataset.wiredFriendsComposeSheet = "1";
  wireFriendsComposeSheetKeyboardOnce();
  const input = document.getElementById("followComposeInput");
  input?.addEventListener("focus", () => {
    syncFriendsComposeSheetKeyboardInset();
    window.setTimeout(syncFriendsComposeSheetKeyboardInset, 80);
    window.setTimeout(syncFriendsComposeSheetKeyboardInset, 320);
  });
  input?.addEventListener("blur", () => {
    window.setTimeout(syncFriendsComposeSheetKeyboardInset, 60);
  });
  sheet.addEventListener("click", (e) => {
    const t = e.target;
    if (t?.closest?.("[data-friends-compose-dismiss]")) {
      e.preventDefault();
      closeFriendsComposeSheet();
    }
  });
  document.addEventListener("keydown", (e) => {
    if (e.key !== "Escape") return;
    if (!sheet.classList.contains("isOpen")) return;
    closeFriendsComposeSheet();
  });
}

function syncFollowingComposeUi() {
  const compose = document.getElementById("discoveryFollowingCompose");
  const input = document.getElementById("followComposeInput");
  const postBtn = document.getElementById("followComposePost");
  const countEl = document.getElementById("followComposeCount");
  const promptEl = document.getElementById("followComposePrompt");
  const signHint = document.getElementById("followComposeSignInHint");
  const mic = document.getElementById("followComposeMic");
  const signedIn = Boolean(authSession?.user?.id);
  const hasText = Boolean(String(input?.value || "").trim());
  const hasVoice = Boolean(statusVoiceBlob?.size);
  const recording = statusVoiceRecState === "recording";
  if (compose) compose.classList.toggle("isSignedOut", !signedIn);
  if (signHint) signHint.hidden = signedIn;
  if (input) input.disabled = !signedIn || recording;
  if (mic) mic.disabled = !signedIn;
  if (postBtn) postBtn.disabled = !signedIn || (!hasText && !hasVoice) || recording;
  const meta = followingComposeMeta(_followComposeType);
  if (promptEl) {
    promptEl.textContent = hasVoice || recording ? "Voice drop — add an optional caption" : meta.prompt;
  }
  if (input && !input.matches(":focus")) {
    input.placeholder = hasVoice ? "Optional caption…" : meta.placeholder;
  }
  document.querySelectorAll("[data-follow-compose-type]").forEach((chip) => {
    const on = chip.getAttribute("data-follow-compose-type") === _followComposeType;
    chip.classList.toggle("isActive", on);
    chip.setAttribute("aria-selected", on ? "true" : "false");
  });
  const len = String(input?.value || "").length;
  if (countEl) countEl.textContent = `${len} / 320`;
  syncStatusVoiceComposeUi();
}

function bindFollowingComposeOnce() {
  if (_followComposeBound) return;
  _followComposeBound = true;
  const input = document.getElementById("followComposeInput");
  const postBtn = document.getElementById("followComposePost");
  document.querySelectorAll("[data-follow-compose-type]").forEach((chip) => {
    chip.addEventListener("click", () => {
      _followComposeType = String(chip.getAttribute("data-follow-compose-type") || "update");
      haptic("light");
      syncFollowingComposeUi();
      try { input?.focus?.({ preventScroll: true }); } catch {}
    });
  });
  input?.addEventListener("input", () => syncFollowingComposeUi());
  document.getElementById("followComposeMic")?.addEventListener("click", () => {
    toggleStatusVoiceMicTap();
  });
  document.getElementById("followComposeVoicePlay")?.addEventListener("click", () => {
    void previewStatusVoiceCompose();
  });
  document.getElementById("followComposeVoiceDiscard")?.addEventListener("click", () => {
    resetStatusVoiceCompose();
    syncFollowingComposeUi();
    try {
      haptic("light");
    } catch {}
  });
  postBtn?.addEventListener("click", async () => {
    if (!authSession?.user?.id) {
      closeFriendsComposeSheet();
      try { showToast("Sign in to post", { icon: "👤", durationMs: 2400 }); } catch {}
      setPostAuthReturnHash("#/friends");
      location.hash = "#/auth";
      return;
    }
    const text = String(input?.value || "").trim();
    const hasVoice = Boolean(statusVoiceBlob?.size);
    if (!text && !hasVoice) return;
    const prevPostLabel = postBtn.textContent || "Post";
    postBtn.disabled = true;
    postBtn.textContent = hasVoice ? "Uploading…" : "Posting…";
    try {
      let audioUrl = "";
      let durationMs = 0;
      let waveformPeaks = [];
      if (hasVoice) {
        const uploaded = await uploadStatusVoiceBlob(statusVoiceBlob);
        audioUrl = uploaded.url;
        durationMs = statusVoiceDurationMs;
        waveformPeaks = statusVoicePeaks.length ? statusVoicePeaks : await computeStatusWaveformPeaks(statusVoiceBlob);
      }
      const res = await postFriendsStatus(
        {
          postType: _followComposeType,
          body: text,
          audioUrl,
          durationMs,
          waveformPeaks,
        },
        { timeoutMs: hasVoice ? 45000 : 12000 },
      );
      const fallbackBody = text || (hasVoice ? STATUS_VOICE_DEFAULT_BODY : "");
      _friendsOwnPostPin = normalizeFriendsOwnPost(res?.post, fallbackBody, _followComposeType);
      if (input) input.value = "";
      resetStatusVoiceCompose();
      closeFriendsComposeSheet();
      haptic("success");
      try { showToast("Posted — followers will see it", { icon: "✓", durationMs: 2200 }); } catch {}
      await prependFriendsOwnPost(_friendsOwnPostPin);
      if (
        (document.body.getAttribute("data-route") || "") === "profile" &&
        _profileSongsSegment === "activities"
      ) {
        void renderProfileActivities();
      }
    } catch (e) {
      haptic("error");
      try {
        showToast(
          e?.message || "Could not post — run social_status_posts_voice.sql and status_audio_storage.sql in Supabase",
          { icon: "!", durationMs: 3200 },
        );
      } catch {}
    } finally {
      postBtn.textContent = prevPostLabel;
      syncFollowingComposeUi();
    }
  });
  wireStatusVoicePlaybackOnce();
  syncFollowingComposeUi();
}

function followingActivityPlayAttrs(t, profMap, byLine) {
  const artSafe = trackCoverArtForFeed(t);
  const rawTitle = String(t.title || "Untitled");
  const encUrl = encodeURIComponent(String(t.url || ""));
  const encTitle = encodeURIComponent(rawTitle);
  const encBy = encodeURIComponent(byLine || "");
  const encArt = encodeURIComponent(artSafe);
  const encSongId = encodeURIComponent(String(t.id || t.songId || ""));
  const encOwnerId = encodeURIComponent(String(t.userId || ""));
  const encTaskId = encodeURIComponent(String(t.taskId || ""));
  const encAudioId = encodeURIComponent(String(t.audioId || ""));
  const encReleaseCaption = encodeURIComponent(releaseCaptionForTrack(t));
  const playData = `data-play-song-id="${encSongId}" data-play-owner-id="${encOwnerId}" data-play-task-id="${encTaskId}" data-play-audio-id="${encAudioId}" data-play-release-caption="${encReleaseCaption}"`;
  return { artSafe, rawTitle, encUrl, encTitle, encBy, encArt, playData };
}

/**
 * X-style actions row: Reply / Like / Plays.
 *
 * Like + Reply are wired to the social API on tap. Counts and the
 * viewer's liked-state are loaded lazily after the feed renders by
 * `hydrateFeedSocialStatsForFeed()`, which then calls
 * `applyFeedSocialStatsToDom()` to fill in the counts and the filled
 * heart for items the viewer already liked.
 *
 * `kind` here is "music" or "status" (UI kind). The DB target kind is
 * derived: music → "song", status → "status".
 */
function followActActionsRowHtml({ kind, targetId, targetUserId, plays, playsPending = false } = {}) {
  const safeId = escapeHtml(String(targetId || ""));
  const safeUid = escapeHtml(String(targetUserId || ""));
  const safeKind = escapeHtml(String(kind || ""));
  const targetKind = kind === "music" ? "song" : kind === "status" ? "status" : (kind || "");
  const safeTargetKind = escapeHtml(targetKind);
  const pending = kind === "music" && (playsPending || plays == null);
  const n = Math.max(0, Number(plays) || 0);
  const playsLabel = pending ? "—" : formatStatCount(n);
  const playsAria = pending ? "Plays loading" : `${formatStatCount(n)} plays`;
  const playsBlock =
    kind === "music"
      ? `<span class="followActAct followActAct--stat" data-friends-act="plays" data-play-count-pending="${pending ? "1" : "0"}" aria-label="${escapeHtml(playsAria)}">
        <svg class="followActActIco" viewBox="0 0 24 24" aria-hidden="true"><path d="M5 4v16l14-8L5 4Z"/></svg>
        <span class="followActActCount">${escapeHtml(playsLabel)}</span>
      </span>`
      : `<span class="followActAct followActAct--stat" aria-hidden="true"></span>`;
  const myId = String(authSession?.user?.id || "").trim();
  const isOwner = !!myId && String(targetUserId || "") === myId;
  const analyticsBlock =
    kind === "music" && isOwner
      ? `<button type="button" class="followActAct followActAct--analytics" data-friends-act="analytics" aria-label="Song analytics">
        <svg class="followActActIco" viewBox="0 0 24 24" aria-hidden="true"><path d="M4 13h3v7H4zM10.5 8h3v12h-3zM17 4h3v16h-3z"/></svg>
      </button>`
      : "";
  // Repost is only meaningful on someone else's song — never your own.
  const repostBlock =
    kind === "music" && !isOwner
      ? `<button type="button" class="followActAct followActAct--repost" data-friends-act="repost" aria-label="Repost" aria-pressed="false">
        ${repostIconSvgHtml("followActActIco")}
        <span class="followActActCount" data-friends-act-count="repost"></span>
      </button>`
      : "";
  return `
    <div class="followActActions" data-friends-act-row="1" data-friends-act-kind="${safeKind}" data-friends-act-target-kind="${safeTargetKind}" data-friends-act-id="${safeId}" data-friends-act-uid="${safeUid}">
      <button type="button" class="followActAct" data-friends-act="reply" aria-label="Reply">
        <svg class="followActActIco" viewBox="0 0 24 24" aria-hidden="true"><path d="M4 5h16v10H8l-4 4V5Z"/></svg>
        <span class="followActActCount" data-friends-act-count="reply"></span>
      </button>
      <button type="button" class="followActAct" data-friends-act="like" aria-label="Like" aria-pressed="false">
        <svg class="followActActIco" viewBox="0 0 24 24" aria-hidden="true"><path d="M12 21s-7-4.5-9.5-9A5.5 5.5 0 0 1 12 6a5.5 5.5 0 0 1 9.5 6c-2.5 4.5-9.5 9-9.5 9Z"/></svg>
        <span class="followActActCount" data-friends-act-count="like"></span>
      </button>
      ${analyticsBlock}
      ${playsBlock}
      ${repostBlock}
    </div>`;
}

/* ---------------------------------------------------------------------
 * Feed social stats (likes + replies) — batched fetch, optimistic UI
 * ------------------------------------------------------------------- */

// Map<"kind:id", { likeCount, liked, replyCount }> — survives feed snapshot
// hydrations so when we re-paint from a cached snapshot the counts are
// re-applied immediately.
const _feedSocialStats = new Map();
let _feedSocialStatsGen = 0;
let _feedSocialStatsLastFetchAt = 0;
const FEED_SOCIAL_STATS_MIN_GAP_MS = 30000;

function feedSocialStatsKey(targetKind, targetId) {
  return `${targetKind}:${targetId}`;
}

const FEED_SOCIAL_STAT_DEFAULT = { likeCount: 0, liked: false, replyCount: 0, repostCount: 0, reposted: false };

function getFeedSocialStat(targetKind, targetId) {
  return (
    _feedSocialStats.get(feedSocialStatsKey(targetKind, targetId)) ||
    { ...FEED_SOCIAL_STAT_DEFAULT }
  );
}

function setFeedSocialStat(targetKind, targetId, partial) {
  const key = feedSocialStatsKey(targetKind, targetId);
  const prev = _feedSocialStats.get(key) || { ...FEED_SOCIAL_STAT_DEFAULT };
  _feedSocialStats.set(key, { ...prev, ...partial });
  return _feedSocialStats.get(key);
}

/**
 * Render the current stats into all `.followActActions` rows inside the
 * given scope. Safe to call multiple times — idempotent.
 */
function applyFeedSocialStatsToDom(scope) {
  const root = scope || document;
  const rows = root.querySelectorAll(".followActActions[data-friends-act-row]");
  rows.forEach((row) => {
    const targetKind = row.getAttribute("data-friends-act-target-kind") || "";
    const targetId = row.getAttribute("data-friends-act-id") || "";
    if (!targetKind || !targetId) return;
    const stat = getFeedSocialStat(targetKind, targetId);
    const likeBtn = row.querySelector('[data-friends-act="like"]');
    const likeCount = row.querySelector('[data-friends-act-count="like"]');
    const replyCount = row.querySelector('[data-friends-act-count="reply"]');
    const repostBtn = row.querySelector('[data-friends-act="repost"]');
    const repostCount = row.querySelector('[data-friends-act-count="repost"]');
    if (likeBtn) {
      likeBtn.classList.toggle("isLiked", Boolean(stat.liked));
      likeBtn.setAttribute("aria-pressed", stat.liked ? "true" : "false");
    }
    if (likeCount) likeCount.textContent = stat.likeCount > 0 ? formatStatCount(stat.likeCount) : "";
    if (replyCount) replyCount.textContent = stat.replyCount > 0 ? formatStatCount(stat.replyCount) : "";
    if (repostBtn) {
      repostBtn.classList.toggle("isReposted", Boolean(stat.reposted));
      repostBtn.setAttribute("aria-pressed", stat.reposted ? "true" : "false");
    }
    if (repostCount) repostCount.textContent = stat.repostCount > 0 ? formatStatCount(stat.repostCount) : "";
  });
}

/**
 * Collect ids in the current feed DOM, then batch-fetch stats from the
 * API and write them into the local map + DOM. Only the freshest call
 * mutates state (gen guard).
 */
async function hydrateFeedSocialStatsForFeed(listEl, opts = {}) {
  if (!listEl) return;
  const force = Boolean(opts.force);
  if (
    !force &&
    _feedSocialStatsLastFetchAt &&
    Date.now() - _feedSocialStatsLastFetchAt < FEED_SOCIAL_STATS_MIN_GAP_MS
  ) {
    applyFeedSocialStatsToDom(listEl);
    return;
  }
  const rows = listEl.querySelectorAll(".followActActions[data-friends-act-row]");
  const songIds = [];
  const statusIds = [];
  rows.forEach((row) => {
    const targetKind = row.getAttribute("data-friends-act-target-kind") || "";
    const targetId = row.getAttribute("data-friends-act-id") || "";
    if (!targetKind || !targetId) return;
    if (targetKind === "song") songIds.push(targetId);
    else if (targetKind === "status") statusIds.push(targetId);
  });
  if (!songIds.length && !statusIds.length) return;
  const gen = ++_feedSocialStatsGen;
  try {
    const params = new URLSearchParams();
    params.set("type", "feed_social_stats");
    if (songIds.length) params.set("song_ids", songIds.join(","));
    if (statusIds.length) params.set("status_ids", statusIds.join(","));
    const data = await socialApi(`/api/social?${params.toString()}`);
    if (gen !== _feedSocialStatsGen) return;
    if (data?.likes) {
      for (const [kind, bucket] of Object.entries(data.likes)) {
        for (const [id, info] of Object.entries(bucket || {})) {
          setFeedSocialStat(kind, id, {
            likeCount: Number(info?.count) || 0,
            liked: Boolean(info?.liked),
          });
        }
      }
    }
    if (data?.replies) {
      for (const [kind, bucket] of Object.entries(data.replies)) {
        for (const [id, info] of Object.entries(bucket || {})) {
          setFeedSocialStat(kind, id, {
            replyCount: Number(info?.count) || 0,
          });
        }
      }
    }
    if (data?.reposts) {
      for (const [kind, bucket] of Object.entries(data.reposts)) {
        for (const [id, info] of Object.entries(bucket || {})) {
          setFeedSocialStat(kind, id, {
            repostCount: Number(info?.count) || 0,
            reposted: Boolean(info?.reposted),
          });
        }
      }
    }
    _feedSocialStatsLastFetchAt = Date.now();
    applyFeedSocialStatsToDom(listEl);
  } catch {
    /* swallow — counts stay empty, taps still work */
  }
}

function feedHeroPlayerTimeLabels(durSec) {
  const totalSec = durSec > 0 ? durSec : 200;
  const curSec = Math.max(0, Math.min(Math.floor(totalSec * 0.38), totalSec - 1));
  return { cur: formatTime(curSec), total: formatTime(totalSec) };
}

function feedHeroPlayerTransportSvg(kind, size = 18) {
  const common = `viewBox="0 0 24 24" width="${size}" height="${size}" aria-hidden="true"`;
  if (kind === "shuffle") {
    return `<svg ${common}><path fill="currentColor" d="M16 3h5v5M4 20 21 3M21 16v5h-5M15 15l6 6M4 4l5 5"/></svg>`;
  }
  if (kind === "prev") {
    return `<svg ${common}><path fill="currentColor" d="M6 6h2v12H6V6Zm4 6 9-6v12l-9-6Z"/></svg>`;
  }
  if (kind === "next") {
    return `<svg ${common}><path fill="currentColor" d="M16 6h2v12h-2V6ZM4 12l9 6V6L4 12Z"/></svg>`;
  }
  if (kind === "repeat") {
    return `<svg ${common}><path fill="currentColor" d="M17 1l4 4-4 4V6H9a4 4 0 0 0-4 4v1H3v-1a6 6 0 0 1 6-6h8V1ZM7 23l-4-4 4-4v3h8a4 4 0 0 0 4-4v-1h2v1a6 6 0 0 1-6 6H7v3Z"/></svg>`;
  }
  return "";
}

function feedHeroPlayerControlsHtml() {
  return `<div class="feedHeroPlayerControls" aria-hidden="true">
    <span class="feedHeroPlayerCtrl">${feedHeroPlayerTransportSvg("shuffle", 17)}</span>
    <span class="feedHeroPlayerCtrl">${feedHeroPlayerTransportSvg("prev", 18)}</span>
    <span class="feedHeroPlayerCtrl feedHeroPlayerCtrl--main">${discoverPlayBtnSvg(20)}</span>
    <span class="feedHeroPlayerCtrl">${feedHeroPlayerTransportSvg("next", 18)}</span>
    <span class="feedHeroPlayerCtrl">${feedHeroPlayerTransportSvg("repeat", 17)}</span>
  </div>`;
}

