function followingActivityRowHtml(t, profMap, idx, opts = {}) {
  const xstyle = Boolean(opts && opts.xstyle);
  const type = followingActivityTypeForTrack(t);
  const prof = resolveProfileForFeedCreator(t.userId, profMap);
  const handle = String(prof?.username || "").trim();
  const byLine = handle ? `@${handle}` : "Creator";
  const rawTitle = String(t.title || "Untitled");
  const safeTitle = escapeHtml(rawTitle);
  const remixOf = remixAttributionForTrack(t);
  const mashupOf = mashupAttributionForTrack(t);
  const challenge = challengeMetaForTrack(t);
  const { artSafe, encUrl, encTitle, encBy, encArt, playData } = followingActivityPlayAttrs(t, profMap, byLine);
  const avatarRaw = String(prof?.avatar || "").trim();
  const avatarSrc = avatarRaw ? normalizeProfileAvatarForImg(avatarRaw) : "";
  const initials = (handle || "U").replace(/^@/, "").slice(0, 2).toUpperCase();
  const profileHref = handle ? `#/u/${encodeURIComponent(handle)}` : "#";
  // The feed event is the PUBLISH, so the main timestamp is the publish
  // moment (matches the row's position in the feed). When the song itself
  // is meaningfully older — e.g. published from the archive — a secondary
  // "created Xd ago" chip keeps the creation date honest.
  const postedTs = libraryTrackPublicTs(t) || Number(t.ts || 0);
  const createdTsRaw = Number(t.createdTs || t.ts || 0);
  const when = relativeTime(postedTs || t.ts);
  const CREATED_CHIP_MIN_GAP_MS = 48 * 60 * 60 * 1000;
  const createdChipHtml =
    createdTsRaw && postedTs && postedTs - createdTsRaw > CREATED_CHIP_MIN_GAP_MS
      ? `<span class="followActMetaDot" aria-hidden="true">·</span><span class="followActWhen followActWhenCreated">created ${escapeHtml(relativeTime(createdTsRaw))}</span>`
      : "";
  const playsPending = t.playCount == null && !Number.isFinite(Number(t.playCount));
  const plays = playsPending ? null : Math.max(0, Number(t.playCount) || 0);
  const caption = releaseCaptionForTrack(t);
  const captionHtml = caption
    ? `<p class="followActCaption">${escapeHtml(caption)}</p>`
    : "";
  const verbHtml = followingActivityBodyHtml(type, rawTitle, remixOf, challenge, mashupOf);
  const subtitle = handle ? `@${handle}` : "Musician";
  const mashupBlockHtml = followActMashupBlockHtml(t, profMap, {
    encUrl,
    encTitle,
    encArt,
    encBy,
    playData,
    artSafe,
    safeTitle,
    subtitle,
    xstyle,
  });
  // Remix posts with a playable public original render BOTH songs as two
  // square tiles side by side — original left, remix right.
  const orig = !mashupBlockHtml && t._remixOriginal && String(t._remixOriginal.url || "").trim() ? t._remixOriginal : null;
  let remixPairHtml = "";
  let showHeadLine = !mashupBlockHtml;
  if (orig) {
    if (xstyle) {
      remixPairHtml = feedRemixFlowPlayerHtml(t, profMap, orig, {
        encUrl,
        encTitle,
        encArt,
        encBy,
        playData,
        artSafe,
        safeTitle,
        subtitle,
      });
    } else {
      const origBy = orig.username ? `@${orig.username}` : "Original";
      const o = followingActivityPlayAttrs(orig, profMap, origBy);
      remixPairHtml = `
      <div class="followActRemixPair" role="group" aria-label="Original and remix">
        <button type="button" class="followActRemixTile" data-user-lib-play="1" data-user-lib-url="${o.encUrl}" data-user-lib-title="${o.encTitle}" data-user-lib-art="${o.encArt}" data-discovery-by="${encodeURIComponent(origBy)}" ${o.playData} aria-label="Play original ${escapeHtml(orig.title)}">
          <img class="followActRemixTileImg" src="${escapeHtml(o.artSafe)}" alt="" decoding="async" loading="lazy" />
          <span class="followActRemixTileChip">Original</span>
          <span class="followActRemixTilePlay" aria-hidden="true">
            <svg viewBox="0 0 24 24" width="13" height="13" aria-hidden="true"><path d="M5 4v16l14-8L5 4Z" fill="currentColor"/></svg>
          </span>
          <span class="followActRemixTileFoot">
            <span class="followActRemixTileTitle">${escapeHtml(orig.title)}</span>
            <span class="followActRemixTileBy">${escapeHtml(origBy)}</span>
          </span>
        </button>
        <button type="button" class="followActRemixTile followActRemixTile--remix" data-user-lib-play="1" data-user-lib-url="${encUrl}" data-user-lib-title="${encTitle}" data-user-lib-art="${encArt}" data-discovery-by="${encBy}" ${playData} aria-label="Play remix ${safeTitle}">
          <img class="followActRemixTileImg" src="${escapeHtml(artSafe)}" alt="" decoding="async" loading="lazy" />
          <span class="followActRemixTileChip followActRemixTileChip--remix">${remixIconSvgHtml()}<span>Remix</span></span>
          <span class="followActRemixTilePlay" aria-hidden="true">
            <svg viewBox="0 0 24 24" width="13" height="13" aria-hidden="true"><path d="M5 4v16l14-8L5 4Z" fill="currentColor"/></svg>
          </span>
          <span class="followActRemixTileFoot">
            <span class="followActRemixTileTitle">${safeTitle}</span>
            <span class="followActRemixTileBy">${escapeHtml(subtitle)}</span>
          </span>
        </button>
      </div>`;
    }
    showHeadLine = false;
  }
  const songMenuBtn = discoverSheetMenuBtnHtml(t, profMap, { className: "discoverCardMenuBtn followActQuoteMenuBtn" });
  const quoteCardHtml = feedHeroPlayerCardHtml({
    track: t,
    artSafe,
    encUrl,
    encTitle,
    encArt,
    encBy,
    playData,
    safeTitle,
    subtitle,
    titleHtml: titleWithNabadBadgeHtml(t, safeTitle, "followActQuoteTitle"),
    menuBtnHtml: songMenuBtn,
    ariaLabel: `Play ${rawTitle}`,
  });
  const mediaBlockHtml = `
          <div class="followActMediaWrap">
            <button type="button" class="followActMedia" data-user-lib-play="1" data-user-lib-url="${encUrl}" data-user-lib-title="${encTitle}" data-user-lib-art="${encArt}" data-discovery-by="${encBy}" ${playData} aria-label="Play ${safeTitle}">
              <img class="followActMediaImg" src="${escapeHtml(artSafe)}" alt="" decoding="async" loading="lazy" />
              <span class="followActMediaScrim" aria-hidden="true"></span>
              <span class="followActMediaPlayBtn" aria-hidden="true">
                <span class="coverArtPlayIco coverArtPlayIco--play">${discoverPlayBtnSvg(28)}</span>
                <span class="coverArtPlayIco coverArtPlayIco--pause">${discoverPauseBtnSvg(28)}</span>
              </span>
              <span class="followActMediaTitle" aria-hidden="true">${safeTitle}</span>
            </button>
            ${followActRealtimeProgressHtml(encUrl, safeTitle)}
          </div>`;
  const mediaBlockWithProgressHtml = mediaBlockHtml;
  const topMenuHtml = songMenuBtn ? `<div class="followActTopMenu">${songMenuBtn}</div>` : "";
  if (xstyle) {
    return `
      <article class="followAct followAct--music followAct--xstyle" data-follow-act="${type}" data-profile-act-song-id="${escapeHtml(String(t.id || ""))}" style="--i:${idx}" data-user-lib-url="${encUrl}" data-user-lib-title="${encTitle}" data-user-lib-art="${encArt}" data-discovery-by="${encBy}" ${playData}>
        <div class="followActTop">
          <a class="followActAvatar" href="${escapeHtml(profileHref)}" data-route-link="user" data-avatar-user-id="${escapeHtml(String(t.userId || ""))}" aria-label="${handle ? `@${escapeHtml(handle)} profile` : "Profile"}">
            <span class="followActAvatarRing" aria-hidden="true"></span>
            ${avatarSrc
              ? `<img src="${escapeHtml(avatarSrc)}" alt="" width="40" height="40" decoding="async" loading="lazy" />`
              : `<span class="followActAvatarFallback">${escapeHtml(initials)}</span>`}
          </a>
          <div class="followActHeadStack">
            <div class="followActMeta">
              <a class="followActUserLink" href="${escapeHtml(profileHref)}" data-route-link="user">${handle ? `<strong class="followActUser">@${escapeHtml(handle)}</strong>` : `<strong class="followActUser">A musician</strong>`}</a>
              <span class="followActMetaDot" aria-hidden="true">·</span>
              <span class="followActWhen">${escapeHtml(when)}</span>
              ${createdChipHtml}
              ${(() => {
                const badge = followingActivityBadgeHtml("music", type);
                return badge ? `<span class="followActMetaDot" aria-hidden="true">·</span>${badge}` : "";
              })()}
            </div>
          </div>
          ${topMenuHtml}
        </div>
        ${caption ? `<div class="followActContent">${captionHtml}</div>` : ""}
        ${mashupBlockHtml || remixPairHtml || mediaBlockWithProgressHtml}
        <div class="followActActionsBar">
          ${followActActionsRowHtml({
            kind: "music",
            targetId: t.id,
            targetUserId: t.userId,
            plays,
            playsPending,
          })}
        </div>
      </article>`;
  }
  const playFootLabel = playsPending
    ? "— plays"
    : `${formatStatCount(plays)} ${plays === 1 ? "play" : "plays"}`;
  const playFoot = `<div class="followActFoot"><span class="followActFootStat" data-play-foot-stat="1">${escapeHtml(playFootLabel)}</span></div>`;
  const who = handle
    ? `<strong class="followActUser">@${escapeHtml(handle)}</strong>`
    : `<strong class="followActUser">A musician</strong>`;
  return `
    <article class="followAct followAct--music" data-follow-act="${type}" style="--i:${idx}" data-user-lib-url="${encUrl}" data-user-lib-title="${encTitle}" data-user-lib-art="${encArt}" data-discovery-by="${encBy}" ${playData}>
      <div class="followActTop">
        <a class="followActAvatar" href="${escapeHtml(profileHref)}" data-route-link="user" data-avatar-user-id="${escapeHtml(String(t.userId || ""))}" aria-label="${handle ? `@${escapeHtml(handle)} profile` : "Profile"}">
          <span class="followActAvatarRing" aria-hidden="true"></span>
          ${avatarSrc
            ? `<img src="${escapeHtml(avatarSrc)}" alt="" width="40" height="40" decoding="async" loading="lazy" />`
            : `<span class="followActAvatarFallback">${escapeHtml(initials)}</span>`}
        </a>
        <div class="followActTopText">
          <div class="followActWhoLine">
            <a class="followActUserLink" href="${escapeHtml(profileHref)}" data-route-link="user">${who}</a>
            <span class="followActWhen">${escapeHtml(when)}</span>
            ${createdChipHtml}
          </div>
          ${followingActivityBadgeHtml("music", type)}
        </div>
        ${topMenuHtml}
      </div>
      ${showHeadLine || caption ? `<div class="followActContent">
        ${showHeadLine ? `<p class="followActHead">${followingActivityBodyHtml(type, rawTitle, remixOf, challenge, mashupOf)}</p>` : ""}
        ${captionHtml}
      </div>` : ""}
      ${mashupBlockHtml || remixPairHtml || mediaBlockWithProgressHtml}
      ${playFoot}
    </article>`;
}

