async function fetchFollowingEmptySuggestCreators(limit = 3, excludeUserIds = []) {
  const out = [];
  const blocked = new Set(
    [...(excludeUserIds || []), authSession?.user?.id]
      .map((u) => String(u || "").trim())
      .filter(Boolean),
  );
  try {
    const rows = await supabaseFetchDiscoveryPublicSongs(48);
    const profMap = await fetchProfilesByUserIdsMap(rows.map((r) => r.userId));
    const seen = new Set();
    for (const t of rows) {
      const uid = String(t.userId || "").trim();
      if (!uid || seen.has(uid) || blocked.has(uid)) continue;
      seen.add(uid);
      const prof = resolveProfileForFeedCreator(uid, profMap);
      const handle = String(prof?.username || "").trim();
      if (!handle) continue;
      const avatar = normalizeProfileAvatarForImg(String(prof?.avatar || "").trim());
      out.push({ userId: uid, handle, avatar });
      if (out.length >= limit) break;
    }
  } catch {}
  return out;
}

/**
 * End-of-list "Who to follow" — X-style vertical list with 3 rows visible
 * and a "Show more" link that routes to Discover for the long tail.
 */
function whoToFollowSectionHtml(creators) {
  if (!Array.isArray(creators) || !creators.length) return "";
  const rows = creators.slice(0, 3).map((c) => {
    const handle = String(c.handle || "").trim();
    const userId = String(c.userId || "").trim();
    if (!handle || !userId) return "";
    const safeHandle = escapeHtml(handle);
    const safeUid = escapeHtml(userId);
    const initials = handle.replace(/^@/, "").slice(0, 2).toUpperCase();
    const href = `#/u/${encodeURIComponent(handle)}`;
    const avatarHtml = c.avatar
      ? `<img src="${escapeHtml(c.avatar)}" alt="" width="44" height="44" decoding="async" loading="lazy" />`
      : `<span class="friendsWtfFallback">${escapeHtml(initials)}</span>`;
    return `
      <li class="friendsWtfRow" data-friends-wtf-row="${safeUid}">
        <a class="friendsWtfAvatar" href="${escapeHtml(href)}" data-route-link="user" aria-label="@${safeHandle} profile">
          ${avatarHtml}
        </a>
        <a class="friendsWtfText" href="${escapeHtml(href)}" data-route-link="user">
          <strong class="friendsWtfName">@${safeHandle}</strong>
          <span class="friendsWtfSub">Musician on Nabadai</span>
        </a>
        <button type="button" class="friendsWtfFollow" data-friends-follow="${safeUid}" data-friends-follow-handle="${safeHandle}">Follow</button>
      </li>`;
  }).filter(Boolean).join("");
  if (!rows) return "";
  return `
    <section class="friendsWhoToFollow" aria-label="Who to follow">
      <h3 class="friendsWtfTitle">Who to follow</h3>
      <ul class="friendsWtfList" role="list">${rows}</ul>
      <a class="friendsWtfMore" href="#/discover" data-route-link="discover">Show more</a>
    </section>`;
}

/**
 * Toggle the like state on a feed item. Optimistic UI: flip the heart
 * and bump the count immediately, POST in the background, revert if the
 * call fails. Bound to both Friends and Profile activity click handlers.
 */
async function handleFeedLikeTap(btn) {
  const row = btn.closest(".followActActions");
  if (!row) return;
  const targetKind = row.getAttribute("data-friends-act-target-kind") || "";
  const targetId = row.getAttribute("data-friends-act-id") || "";
  if (!targetKind || !targetId) return;
  if (!authSession?.user?.id || !getSupabaseAuthToken()) {
    showToast("Sign in to like posts.");
    location.hash = "#/auth";
    return;
  }
  if (btn.dataset.likeBusy === "1") return;
  btn.dataset.likeBusy = "1";

  const prev = getFeedSocialStat(targetKind, targetId);
  const nextLiked = !prev.liked;
  const nextCount = Math.max(0, prev.likeCount + (nextLiked ? 1 : -1));
  setFeedSocialStat(targetKind, targetId, { liked: nextLiked, likeCount: nextCount });
  // Apply optimistic UI to every row that displays this target.
  document.querySelectorAll(
    `.followActActions[data-friends-act-target-kind="${targetKind}"][data-friends-act-id="${targetId}"]`,
  ).forEach((r) => applyFeedSocialStatsToDom(r.parentElement || r));
  try { haptic("light"); } catch {}
  btn.classList.add("isPulse");
  window.setTimeout(() => btn.classList.remove("isPulse"), 320);

  try {
    const data = await socialApi("/api/social", {
      method: "POST",
      body: JSON.stringify({
        action: nextLiked ? "like" : "unlike",
        targetKind,
        targetId,
      }),
    });
    if (data?.ok && typeof data.count === "number") {
      setFeedSocialStat(targetKind, targetId, {
        liked: Boolean(data.liked),
        likeCount: Number(data.count) || 0,
      });
      applyFeedSocialStatsToDom(document);
    }
  } catch (e) {
    // Revert.
    setFeedSocialStat(targetKind, targetId, { liked: prev.liked, likeCount: prev.likeCount });
    applyFeedSocialStatsToDom(document);
    showToast(e?.message || "Could not update like.");
  } finally {
    delete btn.dataset.likeBusy;
  }
}

/* ---------------------------------------------------------------------
 * Repost (reshare a song into your followers' feed, with optional note)
 * ------------------------------------------------------------------- */

let _repostComposeContext = null;
let _repostComposeBound = false;

async function postRepostToggle(targetKind, targetId, { reposted, body = "" } = {}) {
  return socialApi("/api/social", {
    method: "POST",
    body: JSON.stringify({
      action: reposted ? "repost" : "unrepost",
      targetKind,
      targetId,
      ...(reposted && body ? { body } : {}),
    }),
  });
}

function applyRepostStatOptimistic(targetKind, targetId, reposted) {
  const prev = getFeedSocialStat(targetKind, targetId);
  const nextCount = Math.max(0, prev.repostCount + (reposted ? 1 : -1));
  setFeedSocialStat(targetKind, targetId, { reposted, repostCount: nextCount });
  applyFeedSocialStatsToDom(document);
}

async function handleFeedRepostTap(btn) {
  const row = btn.closest(".followActActions");
  if (!row) return;
  const targetKind = row.getAttribute("data-friends-act-target-kind") || "";
  const targetId = row.getAttribute("data-friends-act-id") || "";
  if (!targetKind || !targetId) return;
  if (!authSession?.user?.id || !getSupabaseAuthToken()) {
    showToast("Sign in to repost.");
    location.hash = "#/auth";
    return;
  }
  const stat = getFeedSocialStat(targetKind, targetId);
  // Tapping an active repost undoes it immediately (no sheet).
  if (stat.reposted) {
    if (btn.dataset.repostBusy === "1") return;
    btn.dataset.repostBusy = "1";
    try { haptic("light"); } catch {}
    applyRepostStatOptimistic(targetKind, targetId, false);
    try {
      const data = await postRepostToggle(targetKind, targetId, { reposted: false });
      if (data?.ok && typeof data.count === "number") {
        setFeedSocialStat(targetKind, targetId, { reposted: false, repostCount: Number(data.count) || 0 });
        applyFeedSocialStatsToDom(document);
      }
      if (String(document.body.getAttribute("data-route") || "") === "friends") {
        void refreshDiscoveryFollowingFeed({ force: true });
      }
    } catch (e) {
      applyRepostStatOptimistic(targetKind, targetId, true);
      showToast(e?.message || "Could not remove repost.");
    } finally {
      delete btn.dataset.repostBusy;
    }
    return;
  }
  // Otherwise open the compose sheet to optionally add a note.
  const article = btn.closest(".followAct");
  const title = String(article?.getAttribute("data-user-lib-title") || "").trim()
    ? decodeURIComponent(article.getAttribute("data-user-lib-title"))
    : String(article?.querySelector(".followActMediaTitle")?.textContent || "").trim();
  const art = String(article?.getAttribute("data-user-lib-art") || "").trim()
    ? decodeURIComponent(article.getAttribute("data-user-lib-art"))
    : String(article?.querySelector(".followActMediaImg")?.getAttribute("src") || "").trim();
  const handle = String(article?.querySelector(".followActUser")?.textContent || "").replace(/^@/, "").trim();
  openRepostComposeSheet({ targetKind, targetId, title, art, handle });
}

function bindRepostComposeSheetOnce() {
  if (_repostComposeBound) return;
  const sheet = document.getElementById("repostComposeSheet");
  if (!sheet) return;
  _repostComposeBound = true;
  sheet.addEventListener("click", (e) => {
    if (e.target.closest("[data-repost-dismiss]")) {
      e.preventDefault();
      closeRepostComposeSheet();
    }
  });
  const form = document.getElementById("repostComposeForm");
  if (form) {
    form.addEventListener("submit", (e) => {
      e.preventDefault();
      void submitRepost();
    });
  }
  const input = document.getElementById("repostComposeInput");
  if (input) {
    input.addEventListener("input", () => {
      const count = document.getElementById("repostComposeCount");
      if (count) count.textContent = `${input.value.length} / 320`;
    });
  }
}

function openRepostComposeSheet({ targetKind, targetId, title, art, handle }) {
  const sheet = document.getElementById("repostComposeSheet");
  if (!sheet) return;
  bindRepostComposeSheetOnce();
  _repostComposeContext = { targetKind, targetId };
  const artEl = document.getElementById("repostComposeArt");
  const titleEl = document.getElementById("repostComposeTitle");
  const subEl = document.getElementById("repostComposeSub");
  if (artEl) {
    artEl.innerHTML = art
      ? `<img src="${escapeHtml(art)}" alt="" decoding="async" />`
      : `<span class="repostComposeArtFallback" aria-hidden="true">♪</span>`;
  }
  if (titleEl) titleEl.textContent = title || "This song";
  if (subEl) subEl.textContent = handle ? `@${handle}` : "";
  const input = document.getElementById("repostComposeInput");
  if (input) input.value = "";
  const count = document.getElementById("repostComposeCount");
  if (count) count.textContent = "0 / 320";
  sheet.hidden = false;
  window.requestAnimationFrame(() => {
    sheet.setAttribute("aria-hidden", "false");
  });
}

function closeRepostComposeSheet() {
  const sheet = document.getElementById("repostComposeSheet");
  if (!sheet) return;
  sheet.setAttribute("aria-hidden", "true");
  window.setTimeout(() => {
    sheet.hidden = true;
    _repostComposeContext = null;
  }, 220);
}

async function submitRepost() {
  const ctx = _repostComposeContext;
  if (!ctx) return;
  const { targetKind, targetId } = ctx;
  const input = document.getElementById("repostComposeInput");
  const submitBtn = document.getElementById("repostComposeSubmit");
  const note = String(input?.value || "").trim().slice(0, 320);
  if (submitBtn) {
    submitBtn.disabled = true;
    submitBtn.setAttribute("aria-busy", "true");
  }
  try { haptic("light"); } catch {}
  try {
    const data = await postRepostToggle(targetKind, targetId, { reposted: true, body: note });
    setFeedSocialStat(targetKind, targetId, {
      reposted: true,
      repostCount: typeof data?.count === "number" ? Number(data.count) || 0 : getFeedSocialStat(targetKind, targetId).repostCount + 1,
    });
    applyFeedSocialStatsToDom(document);
    closeRepostComposeSheet();
    showToast("Reposted to your followers.");
    if (String(document.body.getAttribute("data-route") || "") === "friends") {
      void refreshDiscoveryFollowingFeed({ force: true });
    }
  } catch (e) {
    showToast(e?.message || "Could not repost.");
  } finally {
    if (submitBtn) {
      submitBtn.disabled = false;
      submitBtn.removeAttribute("aria-busy");
    }
  }
}

/* ---------------------------------------------------------------------
 * Feed Reply sheet (X-style thread modal)
 * ------------------------------------------------------------------- */

let _feedReplyContext = null;
let _feedReplyBound = false;

function openFeedReplySheetFromButton(btn) {
  const row = btn.closest(".followActActions");
  const article = btn.closest(".followAct");
  if (!row || !article) return;
  const targetKind = row.getAttribute("data-friends-act-target-kind") || "";
  const targetId = row.getAttribute("data-friends-act-id") || "";
  if (!targetKind || !targetId) return;

  const handleEl = article.querySelector(".followActUser");
  const handle = String(handleEl?.textContent || "").trim();
  const subEl =
    article.querySelector(".followActStatusText") ||
    article.querySelector(".followActQuoteTitle") ||
    article.querySelector(".followActHead");
  const sub = String(subEl?.textContent || "").trim();

  openFeedReplySheet({
    targetKind,
    targetId,
    handle,
    sub,
  });
}

function openFeedReplySheet({ targetKind, targetId, handle, sub }) {
  if (!authSession?.user?.id || !getSupabaseAuthToken()) {
    showToast("Sign in to reply.");
    location.hash = "#/auth";
    return;
  }
  const sheet = document.getElementById("feedReplySheet");
  if (!sheet) return;
  bindFeedReplySheetOnce();
  _feedReplyContext = { targetKind, targetId };

  const header = document.getElementById("feedReplyHeader");
  const subEl = document.getElementById("feedReplySub");
  if (header) header.textContent = handle ? `Reply to ${handle}` : "Replies";
  if (subEl) subEl.textContent = sub ? sub.slice(0, 200) : "";

  const list = document.getElementById("feedReplyList");
  if (list) list.innerHTML = `<div class="feedReplyRowLoading" aria-hidden="true" style="padding:24px;text-align:center;color:rgba(232,238,247,0.4);font-size:13px;">Loading…</div>`;

  const input = document.getElementById("feedReplyInput");
  if (input) input.value = "";
  updateFeedReplyFormState();

  sheet.hidden = false;
  // Allow the layout to settle before triggering the transition.
  window.requestAnimationFrame(() => {
    sheet.setAttribute("aria-hidden", "false");
    if (input) {
      try { input.focus({ preventScroll: false }); } catch { input.focus(); }
    }
  });

  void loadFeedReplyList();
}

function closeFeedReplySheet() {
  const sheet = document.getElementById("feedReplySheet");
  if (!sheet) return;
  sheet.setAttribute("aria-hidden", "true");
  window.setTimeout(() => {
    sheet.hidden = true;
    _feedReplyContext = null;
  }, 220);
}

async function loadFeedReplyList() {
  const ctx = _feedReplyContext;
  if (!ctx) return;
  const list = document.getElementById("feedReplyList");
  if (!list) return;
  try {
    const params = new URLSearchParams();
    params.set("type", "replies");
    params.set("targetKind", ctx.targetKind);
    params.set("targetId", ctx.targetId);
    params.set("limit", "100");
    const data = await socialApi(`/api/social?${params.toString()}`);
    if (!_feedReplyContext || _feedReplyContext.targetId !== ctx.targetId) return;
    const replies = Array.isArray(data?.replies) ? data.replies : [];
    list.innerHTML = replies.map((r) => feedReplyRowHtml(r)).join("");
    // Update count in the underlying feed row optimistically.
    setFeedSocialStat(ctx.targetKind, ctx.targetId, { replyCount: replies.length });
    applyFeedSocialStatsToDom(document);
  } catch (e) {
    list.innerHTML = `<div style="padding:24px;text-align:center;color:rgba(255,100,130,0.85);font-size:13px;">${escapeHtml(e?.message || "Could not load replies.")}</div>`;
  }
}

function feedReplyRowHtml(reply) {
  const handle = String(reply?.username || "").trim();
  const safeHandle = escapeHtml(handle);
  const initials = (handle || "U").replace(/^@/, "").slice(0, 2).toUpperCase();
  const avatarRaw = String(reply?.avatar || "").trim();
  const avatarSrc = avatarRaw ? normalizeProfileAvatarForImg(avatarRaw) : "";
  const href = handle ? `#/u/${encodeURIComponent(handle)}` : "#";
  const ts = reply?.createdAt ? new Date(reply.createdAt).getTime() : 0;
  const when = ts ? relativeTime(ts) : "Just now";
  const body = escapeHtml(String(reply?.body || "").trim());
  const replyId = escapeHtml(String(reply?.id || ""));
  const isOwn = Boolean(
    reply?.userId &&
    authSession?.user?.id &&
    String(reply.userId) === String(authSession.user.id),
  );
  const deleteBtn = isOwn
    ? `<button type="button" class="feedReplyDelete" data-feed-reply-delete="${replyId}">Remove</button>`
    : "";
  return `
    <article class="feedReplyRow" data-feed-reply-id="${replyId}">
      <a class="feedReplyAvatar" href="${escapeHtml(href)}" data-route-link="user" aria-label="${handle ? `@${safeHandle} profile` : "Profile"}">
        ${avatarSrc
          ? `<img src="${escapeHtml(avatarSrc)}" alt="" width="36" height="36" decoding="async" loading="lazy" />`
          : `<span class="feedReplyAvatarFallback">${escapeHtml(initials)}</span>`}
      </a>
      <div>
        <div class="feedReplyMeta">
          <a class="feedReplyName" href="${escapeHtml(href)}" data-route-link="user">${handle ? `@${safeHandle}` : "A musician"}</a>
          <span aria-hidden="true">·</span>
          <span class="feedReplyWhen">${escapeHtml(when)}</span>
        </div>
        <p class="feedReplyBody">${body}</p>
        ${deleteBtn}
      </div>
    </article>`;
}

/* ---------------------------------------------------------------------
 * Song analytics — owner-only "who played your song & how many times".
 * Data already exists in discover_play_counts; surfaced via
 * /api/music/song-listeners (provider-neutral path).
 * ------------------------------------------------------------------- */

let _songAnalyticsCtx = null;

function openSongAnalyticsSheet(btn) {
  const row = btn.closest(".followActActions");
  const article = btn.closest(".followAct");
  if (!row) return;
  const songId = row.getAttribute("data-friends-act-id") || "";
  if (!songId) return;
  if (!authSession?.user?.id || !getSupabaseAuthToken()) {
    showToast("Sign in to see analytics.");
    location.hash = "#/auth";
    return;
  }
  const title =
    decodeDiscoverDataAttr(article, "data-user-lib-title") ||
    String(article?.querySelector(".followActUser")?.textContent || "").trim() ||
    "Your song";

  const sheet = document.getElementById("songAnalyticsSheet");
  if (!sheet) return;
  bindSongAnalyticsSheetOnce();
  _songAnalyticsCtx = { songId };

  const titleEl = document.getElementById("songAnalyticsTitle");
  const subEl = document.getElementById("songAnalyticsSub");
  const statsEl = document.getElementById("songAnalyticsStats");
  const list = document.getElementById("songAnalyticsList");
  if (titleEl) titleEl.textContent = title.slice(0, 80);
  if (subEl) subEl.textContent = "Loading your listeners…";
  if (statsEl) statsEl.innerHTML = "";
  if (list)
    list.innerHTML = `<div class="songAnalyticsEmpty" aria-hidden="true">Loading…</div>`;

  sheet.hidden = false;
  window.requestAnimationFrame(() => {
    sheet.setAttribute("aria-hidden", "false");
  });
  void loadSongAnalytics(songId);
}

function closeSongAnalyticsSheet() {
  const sheet = document.getElementById("songAnalyticsSheet");
  if (!sheet) return;
  sheet.setAttribute("aria-hidden", "true");
  window.setTimeout(() => {
    sheet.hidden = true;
    _songAnalyticsCtx = null;
  }, 220);
}

let _songAnalyticsSheetBound = false;
function bindSongAnalyticsSheetOnce() {
  if (_songAnalyticsSheetBound) return;
  const sheet = document.getElementById("songAnalyticsSheet");
  if (!sheet) return;
  _songAnalyticsSheetBound = true;
  sheet.addEventListener("click", (e) => {
    if (e.target.closest("[data-song-analytics-dismiss]")) {
      e.preventDefault();
      closeSongAnalyticsSheet();
    }
  });
  document.addEventListener("keydown", (e) => {
    if (e.key !== "Escape") return;
    if (sheet.getAttribute("aria-hidden") === "false") closeSongAnalyticsSheet();
  });
}

async function loadSongAnalytics(songId) {
  const list = document.getElementById("songAnalyticsList");
  const subEl = document.getElementById("songAnalyticsSub");
  const statsEl = document.getElementById("songAnalyticsStats");
  if (!list) return;
  try {
    const tok = getSupabaseAuthToken();
    const r = await fetch(
      apiUrl(`/api/music/song-listeners?songId=${encodeURIComponent(songId)}`),
      {
        headers: { ...(tok ? { Authorization: `Bearer ${tok}` } : {}) },
        cache: "no-store",
      },
    );
    const d = await r.json().catch(() => ({}));
    if (!_songAnalyticsCtx || _songAnalyticsCtx.songId !== songId) return;
    if (!r.ok || !d?.ok) {
      throw new Error(d?.error || "Could not load analytics.");
    }
    const total = Number(d.totalPlays) || 0;
    const unique = Number(d.uniqueListeners) || 0;
    if (subEl) {
      subEl.textContent = unique
        ? "Only you can see who played this song."
        : "No plays yet — share it to get heard.";
    }
    if (statsEl) {
      statsEl.innerHTML = `
        <div class="songAnalyticsStat">
          <span class="songAnalyticsStatNum">${escapeHtml(formatStatCount(total))}</span>
          <span class="songAnalyticsStatLabel">${total === 1 ? "play" : "plays"}</span>
        </div>
        <div class="songAnalyticsStat">
          <span class="songAnalyticsStatNum">${escapeHtml(formatStatCount(unique))}</span>
          <span class="songAnalyticsStatLabel">${unique === 1 ? "listener" : "listeners"}</span>
        </div>`;
    }
    const listeners = Array.isArray(d.listeners) ? d.listeners : [];
    if (!listeners.length) {
      list.innerHTML = `<div class="songAnalyticsEmpty">When people play your song, they'll show up here.</div>`;
      return;
    }
    list.innerHTML = listeners.map((l) => songAnalyticsRowHtml(l)).join("");
  } catch (e) {
    if (!_songAnalyticsCtx || _songAnalyticsCtx.songId !== songId) return;
    if (subEl) subEl.textContent = "";
    list.innerHTML = `<div class="songAnalyticsEmpty songAnalyticsEmpty--err">${escapeHtml(e?.message || "Could not load analytics.")}</div>`;
  }
}

function songAnalyticsRowHtml(listener) {
  const handle = String(listener?.username || "").trim();
  const safeHandle = escapeHtml(handle);
  const initials = (handle || "U").replace(/^@/, "").slice(0, 2).toUpperCase();
  const avatarRaw = String(listener?.avatar || "").trim();
  const avatarSrc = avatarRaw ? normalizeProfileAvatarForImg(avatarRaw) : "";
  const href = handle ? `#/u/${encodeURIComponent(handle)}` : "#";
  const plays = Math.max(0, Number(listener?.plays) || 0);
  const playsLabel = `${plays} ${plays === 1 ? "play" : "plays"}`;
  return `
    <div class="songAnalyticsRow" role="listitem">
      <a class="songAnalyticsAvatar" href="${escapeHtml(href)}" data-route-link="user" aria-label="${handle ? `@${safeHandle} profile` : "Listener"}">
        ${avatarSrc
          ? `<img src="${escapeHtml(avatarSrc)}" alt="" width="40" height="40" decoding="async" loading="lazy" />`
          : `<span class="songAnalyticsAvatarFallback">${escapeHtml(initials)}</span>`}
      </a>
      <a class="songAnalyticsName" href="${escapeHtml(href)}" data-route-link="user">${handle ? `@${safeHandle}` : "A listener"}</a>
      <span class="songAnalyticsPlays">${escapeHtml(playsLabel)}</span>
    </div>`;
}

function updateFeedReplyFormState() {
  const input = document.getElementById("feedReplyInput");
  const submit = document.getElementById("feedReplySubmit");
  const counter = document.getElementById("feedReplyCount");
  if (!input || !submit || !counter) return;
  const len = (input.value || "").trim().length;
  const total = (input.value || "").length;
  submit.disabled = len === 0 || len > 280 || submit.dataset.busy === "1";
  counter.textContent = `${total} / 280`;
  counter.classList.toggle("isNear", total > 240 && total <= 280);
  counter.classList.toggle("isOver", total > 280);
}

async function submitFeedReply() {
  const ctx = _feedReplyContext;
  if (!ctx) return;
  const input = document.getElementById("feedReplyInput");
  const submit = document.getElementById("feedReplySubmit");
  if (!input || !submit) return;
  const body = String(input.value || "").trim();
  if (!body || body.length > 280) return;
  submit.dataset.busy = "1";
  submit.disabled = true;
  try {
    const data = await socialApi("/api/social", {
      method: "POST",
      body: JSON.stringify({
        action: "reply",
        targetKind: ctx.targetKind,
        targetId: ctx.targetId,
        body,
      }),
    });
    if (data?.ok && data.reply) {
      const list = document.getElementById("feedReplyList");
      if (list) list.insertAdjacentHTML("beforeend", feedReplyRowHtml(data.reply));
      input.value = "";
      setFeedSocialStat(ctx.targetKind, ctx.targetId, {
        replyCount: Number(data.count) || (getFeedSocialStat(ctx.targetKind, ctx.targetId).replyCount + 1),
      });
      applyFeedSocialStatsToDom(document);
      try { haptic("light"); } catch {}
      // Scroll list to the new reply.
      if (list) list.scrollTop = list.scrollHeight;
    }
  } catch (e) {
    showToast(e?.message || "Could not post reply.");
  } finally {
    delete submit.dataset.busy;
    updateFeedReplyFormState();
  }
}

async function deleteFeedReply(replyId) {
  const ctx = _feedReplyContext;
  if (!ctx || !replyId) return;
  let ok = true;
  try { ok = window.confirm("Remove this reply?"); } catch { ok = true; }
  if (!ok) return;
  try {
    const data = await socialApi("/api/social", {
      method: "POST",
      body: JSON.stringify({ action: "delete_reply", replyId }),
    });
    if (data?.ok) {
      const row = document.querySelector(`[data-feed-reply-id="${CSS.escape(String(replyId))}"]`);
      if (row) row.remove();
      const newCount = Number(data.count);
      if (Number.isFinite(newCount)) {
        setFeedSocialStat(ctx.targetKind, ctx.targetId, { replyCount: newCount });
        applyFeedSocialStatsToDom(document);
      }
    }
  } catch (e) {
    showToast(e?.message || "Could not remove reply.");
  }
}

function bindFeedReplySheetOnce() {
  if (_feedReplyBound) return;
  _feedReplyBound = true;
  const sheet = document.getElementById("feedReplySheet");
  const form = document.getElementById("feedReplyForm");
  const input = document.getElementById("feedReplyInput");
  const list = document.getElementById("feedReplyList");
  if (!sheet || !form || !input || !list) return;

  sheet.addEventListener("click", (e) => {
    if (e.target.closest("[data-feed-reply-dismiss]")) {
      e.preventDefault();
      closeFeedReplySheet();
    }
  });

  input.addEventListener("input", updateFeedReplyFormState);

  form.addEventListener("submit", (e) => {
    e.preventDefault();
    void submitFeedReply();
  });

  list.addEventListener("click", (e) => {
    const del = e.target.closest("[data-feed-reply-delete]");
    if (del) {
      e.preventDefault();
      void deleteFeedReply(del.getAttribute("data-feed-reply-delete"));
    }
  });

  document.addEventListener("keydown", (e) => {
    if (e.key !== "Escape") return;
    if (sheet.getAttribute("aria-hidden") === "false") closeFeedReplySheet();
  });
}

async function handleFriendsWtfFollow(btn) {
  const targetUserId = String(btn.getAttribute("data-friends-follow") || "").trim();
  const handle = String(btn.getAttribute("data-friends-follow-handle") || "").trim();
  if (!targetUserId) return;
  if (!authSession?.user?.id || !getSupabaseAuthToken()) {
    showToast("Sign in to follow creators.");
    location.hash = "#/auth";
    return;
  }
  if (btn.dataset.followBusy === "1") return;
  btn.dataset.followBusy = "1";
  btn.disabled = true;
  const prevLabel = btn.textContent;
  btn.textContent = "Following…";
  try {
    haptic("light");
  } catch {}
  try {
    await socialApi("/api/social", {
      method: "POST",
      body: JSON.stringify({ action: "follow", targetUserId }),
    });
    btn.textContent = "Following";
    btn.classList.add("isFollowed");
    // Slide the row out, then refresh the feed so the new follow gets
    // pulled into the timeline and a fresh suggestion takes its place.
    const row = btn.closest(".friendsWtfRow");
    if (row) {
      row.classList.add("isLeaving");
      window.setTimeout(() => {
        row.remove();
        void refreshDiscoveryFollowingFeed({ force: true });
      }, 280);
    } else {
      void refreshDiscoveryFollowingFeed({ force: true });
    }
    showToast(handle ? `Following @${handle}.` : "Following creator.");
  } catch (e) {
    btn.textContent = prevLabel || "Follow";
    btn.disabled = false;
    delete btn.dataset.followBusy;
    showToast(e?.message || "Could not follow.");
  }
}

function renderDiscoveryFollowingEmpty(statusEl, title, text, actionHtml = "") {
  if (!statusEl) return;
  statusEl.hidden = false;
  statusEl.innerHTML = `
    <div class="discoveryEmptyWrap">
      <div class="discoveryEmptyArt">${discoveryEmptyIllustrationSvg()}</div>
      <p class="discoveryEmptyTitle">${escapeHtml(title)}</p>
      <p class="discoveryEmptyText">${escapeHtml(text)}</p>
      ${actionHtml}
    </div>`;
}

let _friendsRouteEnterToken = 0;
let _enterFriendsDebounce = 0;
let _friendsStatusComposePending = false;
let _friendsFeedAuthRetry = 0;
let _followingListCache = null;
let _followingListCacheAt = 0;
let _friendsFeedSnapshot = null;
const FOLLOWING_LIST_CACHE_MS = 45000;
const FRIENDS_FEED_SNAPSHOT_MS = 90000;
const FRIENDS_MIN_FETCH_GAP_MS = 30000;
const FRIENDS_FEED_SNAPSHOT_KEY = "nabad_friends_feed_snap_v3";

let _profileActSnapshot = null;
let _profileActEnrichGen = 0;
const PROFILE_ACT_SNAPSHOT_MS = 120000;
const PROFILE_ACT_MIN_FETCH_GAP_MS = 45000;
const PROFILE_ACT_SNAPSHOT_KEY = "nabad_profile_act_snap_v3";
const PROFILE_ACTIVITIES_PAGE_SIZE = 6;
let _profileActivitiesShown = PROFILE_ACTIVITIES_PAGE_SIZE;
/** Max public posts fetched for profile stats, Posts tab, and public profile link. */
const PROFILE_PUBLIC_POSTS_LIMIT = 120;
const OWNER_PUBLIC_POSTS_CACHE_MS = 45000;
let _ownerPublicPostsCache = null;

function countFollowActsInHtml(html) {
  return (String(html || "").match(/class="followAct/g) || []).length;
}

/** Reject legacy snapshots that dumped the full feed with no Load more row. */
function profileActSnapshotValid(html, totalPublicPosts) {
  if (!html || html.includes("followAct--skel")) return false;
  if (html.includes("profileActEmpty")) return true;
  const shown = countFollowActsInHtml(html);
  const hasLoadMore = html.includes("profile-act-loadmore-sentinel");
  if (totalPublicPosts <= PROFILE_ACTIVITIES_PAGE_SIZE) {
    return shown === totalPublicPosts;
  }
  if (shown > PROFILE_ACTIVITIES_PAGE_SIZE && !hasLoadMore) return false;
  if (shown >= totalPublicPosts) return !hasLoadMore;
  return hasLoadMore && shown < totalPublicPosts;
}

function profileActivitiesFeedTs(track) {
  const published = libraryTrackPublicTs(track);
  if (published > 0) return published;
  const created = Number(track?.createdTs || 0);
  if (Number.isFinite(created) && created > 0) return created;
  const ts = Number(track?.ts || 0);
  return Number.isFinite(ts) && ts > 0 ? ts : 0;
}

function syncProfileActivitiesLoadMoreUi(remaining) {
  const wrap = document.getElementById("profileActivitiesLoadMoreWrap");
  const moreCount = document.getElementById("profileActivitiesLoadMoreCount");
  if (!wrap) return;
  const onActivities =
    (document.body.getAttribute("data-route") || "") === "profile" &&
    _profileSongsSegment === "activities";
  if (!onActivities || remaining <= 0) {
    wrap.hidden = true;
    wrap.setAttribute("aria-hidden", "true");
    return;
  }
  wrap.hidden = false;
  wrap.setAttribute("aria-hidden", "false");
  if (moreCount) moreCount.textContent = String(remaining);
}

function wireProfileActivitiesLoadMoreOnce() {
  const btn = document.getElementById("profileActivitiesLoadMore");
  if (!btn || btn.dataset.boundProfileActLoadMore) return;
  btn.dataset.boundProfileActLoadMore = "1";
  btn.addEventListener("click", (e) => {
    e.preventDefault();
    if (
      (document.body.getAttribute("data-route") || "") !== "profile" ||
      _profileSongsSegment !== "activities"
    ) {
      return;
    }
    haptic("light");
    const total = getOwnerPublicPostCount();
    _profileActivitiesShown = Math.min(total, _profileActivitiesShown + PROFILE_ACTIVITIES_PAGE_SIZE);
    void renderProfileActivities({ extend: true, deferCloud: true });
  });
}

function resetProfileActivitiesPagination() {
  _profileActivitiesShown = PROFILE_ACTIVITIES_PAGE_SIZE;
}

function profileActivitiesLoadMoreHtml(remaining) {
  return "";
}

function hydrateProfileActSnapshotFromStorage() {
  if (_profileActSnapshot) return;
  try {
    sessionStorage.removeItem("nabad_profile_act_snap_v2");
    const raw = sessionStorage.getItem(PROFILE_ACT_SNAPSHOT_KEY);
    if (!raw) return;
    const parsed = JSON.parse(raw);
    if (parsed?.at && Date.now() - parsed.at < PROFILE_ACT_SNAPSHOT_MS && parsed.html) {
      _profileActSnapshot = parsed;
    }
  } catch {}
}

function persistProfileActSnapshot() {
  if (!_profileActSnapshot) return;
  try {
    sessionStorage.setItem(PROFILE_ACT_SNAPSHOT_KEY, JSON.stringify(_profileActSnapshot));
  } catch {}
}

function invalidateProfileActivitiesCache() {
  _profileActSnapshot = null;
  resetProfileActivitiesPagination();
  try {
    sessionStorage.removeItem(PROFILE_ACT_SNAPSHOT_KEY);
  } catch {}
}

function clearSignedInUiCaches() {
  invalidateProfileActivitiesCache();
  invalidateOwnerPublicPostsCache();
  _friendsFeedSnapshot = null;
  try {
    sessionStorage.removeItem(FRIENDS_FEED_SNAPSHOT_KEY);
  } catch {}
  _followingListCache = null;
  _followingListCacheAt = 0;
  _ownSocialStatsLastUserId = "";
  _ownSocialStatsFollowers = null;
  _ownSocialStatsPlays = null;
  _ownSocialStatsLastFetchAt = 0;
  _ownSocialStatsInFlight = false;
}

function resetProfileActivitiesGuestUi() {
  const listEl = document.getElementById("profileActivitiesList");
  const countEl = document.getElementById("profileActivitiesCount");
  const libEl = document.getElementById("libraryList");
  if (listEl) {
    listEl.hidden = false;
    listEl.innerHTML = `
      <div class="profileActEmpty">
        <p class="profileActEmptyTitle">Sign in to see your posts</p>
        <p class="profileActEmptyText">Your published songs and challenge entries land here.</p>
      </div>`;
  }
  if (countEl) countEl.hidden = true;
  if (libEl) {
    libEl.hidden = true;
    libEl.innerHTML = "";
  }
}

function resetProfileStatsGuestUi() {
  if (els.profileStatPillSongsValue) els.profileStatPillSongsValue.textContent = "0";
  if (els.profileStatPillPublicValue) els.profileStatPillPublicValue.textContent = "0";
  if (els.profileStatPillLikesValue) els.profileStatPillLikesValue.textContent = "0";
  if (els.profileAuraSongsValue) els.profileAuraSongsValue.textContent = "0";
  if (els.profileAuraLikesValue) els.profileAuraLikesValue.textContent = "0";
  if (els.profileAuraStatLine) els.profileAuraStatLine.textContent = "No saves yet";
  if (els.profileOwnStats) els.profileOwnStats.innerHTML = "";
  if (els.profileOwnSongCount) {
    els.profileOwnSongCount.textContent = "";
    els.profileOwnSongCount.hidden = true;
  }
}
const FRIENDS_FEED_LIBRARY_USERS = 12;
const FRIENDS_FEED_LIBRARY_SONG_LIMIT = 24;

function hydrateFriendsFeedSnapshotFromStorage() {
  if (_friendsFeedSnapshot) return;
  try {
    sessionStorage.removeItem("nabad_friends_feed_snap_v2");
    sessionStorage.removeItem("nabad_friends_feed_snap_v1");
  } catch {}
  try {
    const raw = sessionStorage.getItem(FRIENDS_FEED_SNAPSHOT_KEY);
    if (!raw) return;
    const parsed = JSON.parse(raw);
    if (parsed?.at && Date.now() - parsed.at < FRIENDS_FEED_SNAPSHOT_MS && !parsed.html?.includes("followAct--status")) {
      _friendsFeedSnapshot = parsed;
    }
  } catch {}
}

function persistFriendsFeedSnapshot() {
  if (!_friendsFeedSnapshot) return;
  try {
    sessionStorage.setItem(FRIENDS_FEED_SNAPSHOT_KEY, JSON.stringify(_friendsFeedSnapshot));
  } catch {}
}

function paintFriendsFeedSnapshotIfFresh() {
  const listEl = document.getElementById("discoveryFollowingList");
  const statusEl = document.getElementById("discoveryFollowingStatus");
  if (!listEl || !statusEl) return false;
  hydrateFriendsFeedSnapshotFromStorage();
  const snap = _friendsFeedSnapshot;
  const snapFresh =
    snap &&
    Date.now() - snap.at < FRIENDS_FEED_SNAPSHOT_MS &&
    snap.html &&
    !snap.html.includes("followAct--skel") &&
    (!STATUS_POSTS_FEATURE_ENABLED || !snap.html.includes("followAct--status"));
  if (!snapFresh) return false;
  listEl.classList.remove("isDiscoveryLoading");
  listEl.hidden = false;
  listEl.innerHTML = snap.html;
  statusEl.hidden = true;
  statusEl.textContent = "";
  if (Array.isArray(snap.tracks)) _discoveryFeedTracks = snap.tracks;
  try {
    syncDiscoveryPlayingHighlights();
  } catch {}
  applyFeedSocialStatsToDom(listEl);
  return true;
}

let _friendsFeedRefreshInFlight = false;
let _friendsFeedRefreshQueued = false;

function runFriendsRouteRefresh(token) {
  if (token !== _friendsRouteEnterToken) return;
  if (String(document.body.getAttribute("data-route") || "") !== "friends") return;
  void refreshDiscoveryFollowingFeed();
}

function friendsFeedRowsHtml(mergedItems, profMap) {
  return mergedItems
    .map((item, i) => {
      if (item.kind === "status") return followingStatusRowHtml(item.post, profMap, i, { xstyle: true });
      if (item.kind === "repost") return followingRepostRowHtml(item, profMap, i);
      return followingActivityRowHtml(item.track, profMap, i, { xstyle: true });
    })
    .join("");
}

/** A repost: the original song card with a small "@user reposted" banner
 *  (and optional note) injected on top. Reusing followingActivityRowHtml keeps
 *  playback, seek, and the original author's header consistent — the actions
 *  row inside still targets the original song. */
function followingRepostRowHtml(item, profMap, idx) {
  const rp = item.repost || {};
  const base = followingActivityRowHtml(item.track, profMap, idx, { xstyle: true });
  const reposterId = String(rp.userId || "");
  const prof = resolveProfileForFeedCreator(reposterId, profMap);
  const handle = String(prof?.username || "").trim();
  const who = handle ? `@${escapeHtml(handle)}` : "Someone";
  const href = handle ? `#/u/${encodeURIComponent(handle)}` : "#";
  const when = relativeTime(Number(rp.ts || item.ts || 0));
  const note = String(rp.body || "").trim();
  const noteHtml = note ? `<p class="followActRepostNote">${escapeHtml(note)}</p>` : "";
  const banner = `
        <div class="followActRepostBanner">
          <span class="followActRepostIco" aria-hidden="true">${repostIconSvgHtml("followActRepostBannerIco")}</span>
          <a class="followActRepostByLink" href="${escapeHtml(href)}" data-route-link="user"><strong>${who}</strong> reposted</a>
          <span class="followActMetaDot" aria-hidden="true">·</span>
          <span class="followActWhen">${escapeHtml(when)}</span>
        </div>
        ${noteHtml}`;
  return base
    .replace(
      'class="followAct followAct--music followAct--xstyle"',
      `class="followAct followAct--music followAct--xstyle followAct--repost" data-repost-id="${escapeHtml(String(rp.id || ""))}" data-repost-by="${escapeHtml(reposterId)}"`,
    )
    .replace('<div class="followActTop">', `${banner}<div class="followActTop">`);
}

/** Remix pairs, mashup tiles, play counts, and Who-to-follow load after the first paint. */
function friendsFeedPlayableMediaSig(tracks, profMap) {
  const pm = profMap || new Map();
  return (tracks || [])
    .map((t) => `${String(t?.id || "")}:${profileActMediaSig(t, pm)}`)
    .join("|");
}

function patchFriendsFeedMediaRows(listEl, mergedItems, profMap) {
  return patchFollowActMediaRows(listEl, mergedItems, profMap, logFriendsFeedPatch);
}

async function enrichFriendsFeedAfterPaint({
  playable,
  mergedItems,
  profMap,
  listEl,
  followedIds,
  gen,
}) {
  try {
    const mediaSigBefore = friendsFeedPlayableMediaSig(playable, profMap);
    const playCountMap = playable.length
      ? await fetchDiscoverSongPlayCounts(playable.map((t) => t.id))
      : new Map();
    if (gen !== _discoveryFollowingGen) return;
    for (const t of playable) {
      t.playCount = playCountMap.get(String(t.id || "")) || 0;
    }
    await Promise.all([
      hydrateRemixOriginalsForTracks(playable),
      hydrateMashupSourcesForTracks(playable),
    ]);
    if (gen !== _discoveryFollowingGen) return;
    if (String(document.body.getAttribute("data-route") || "") !== "friends") return;
    const mediaSigAfter = friendsFeedPlayableMediaSig(playable, profMap);
    applyFollowActPlayCountsToDom(listEl, playable, logFriendsFeedPatch);
    if (mediaSigBefore !== mediaSigAfter) {
      patchFriendsFeedMediaRows(listEl, mergedItems, profMap);
    }
    _discoveryFeedTracks = playable.map((t) => discoveryTrackPlaybackMeta(t, profMap));
    applyFeedSocialStatsToDom(listEl);
    try {
      syncDiscoveryPlayingHighlights();
    } catch {}
    void hydrateFeedSocialStatsForFeed(listEl);

    const loadWhoToFollow = () => {
      void (async () => {
        const suggestList = await fetchFollowingEmptySuggestCreators(3, followedIds);
        if (gen !== _discoveryFollowingGen) return;
        const wtfHtml = whoToFollowSectionHtml(suggestList);
        if (!wtfHtml) return;
        if (String(document.body.getAttribute("data-route") || "") !== "friends") return;
        listEl.insertAdjacentHTML("beforeend", wtfHtml);
        _friendsFeedSnapshot = {
          at: Date.now(),
          html: listEl.innerHTML,
          tracks: _discoveryFeedTracks,
        };
        persistFriendsFeedSnapshot();
      })();
    };
    if (typeof requestIdleCallback === "function") {
      requestIdleCallback(loadWhoToFollow, { timeout: 2500 });
    } else {
      window.setTimeout(loadWhoToFollow, 600);
    }
  } catch {}
}

function enterFriendsRoute() {
  const token = ++_friendsRouteEnterToken;
  paintFriendsFeedSnapshotIfFresh();
  runFriendsRouteRefresh(token);
  if (_friendsStatusComposePending) {
    if (_enterFriendsDebounce) clearTimeout(_enterFriendsDebounce);
    _enterFriendsDebounce = window.setTimeout(() => {
      _enterFriendsDebounce = 0;
      if (token !== _friendsRouteEnterToken) return;
      _friendsStatusComposePending = false;
      try { openFriendsComposeSheet(); } catch {}
    }, 80);
  }
}

function wireFriendsComposeFabOnce() {
  if (document.documentElement.dataset.friendsComposeFabWired) return;
  document.documentElement.dataset.friendsComposeFabWired = "1";
  document.addEventListener(
    "click",
    (e) => {
      const btn = e.target.closest("#friendsComposeOpenBtn");
      if (!btn) return;
      if (String(document.body.getAttribute("data-route") || "") !== "friends") return;
      e.preventDefault();
      e.stopPropagation();
      haptic("light");
      const sheet = document.getElementById("friendsComposeSheet");
      if (sheet?.classList.contains("isOpen")) closeFriendsComposeSheet();
      else openFriendsComposeSheet();
    },
    true,
  );
}

async function refreshDiscoveryFollowingFeed(opts = {}) {
  if (_friendsFeedRefreshInFlight) {
    if (opts.force) _friendsFeedRefreshQueued = true;
    return;
  }
  _friendsFeedRefreshInFlight = true;
  try {
  const force = Boolean(opts.force);
  const gen = ++_discoveryFollowingGen;
  hydrateFriendsFeedSnapshotFromStorage();
  const statusEl = document.getElementById("discoveryFollowingStatus");
  const listEl = document.getElementById("discoveryFollowingList");
  if (!statusEl || !listEl) return;
  if (authSession?.user?.id) _friendsFeedAuthRetry = 0;

  const keepFeed = Boolean(STATUS_POSTS_FEATURE_ENABLED && _friendsOwnPostPin && listEl.querySelector(".followAct"));
  const snap = _friendsFeedSnapshot;
  const snapFresh =
    snap &&
    Date.now() - snap.at < FRIENDS_FEED_SNAPSHOT_MS &&
    snap.html &&
    !snap.html.includes("followAct--skel") &&
    (!STATUS_POSTS_FEATURE_ENABLED || !snap.html.includes("followAct--status"));
  if (snapFresh && !keepFeed) {
    listEl.classList.remove("isDiscoveryLoading");
    listEl.hidden = false;
    listEl.innerHTML = snap.html;
    statusEl.hidden = true;
    statusEl.textContent = "";
    if (Array.isArray(snap.tracks)) _discoveryFeedTracks = snap.tracks;
    try {
      syncDiscoveryPlayingHighlights();
    } catch {}
    applyFeedSocialStatsToDom(listEl);
    if (!force && Date.now() - snap.at < FRIENDS_MIN_FETCH_GAP_MS) {
      return;
    }
    void hydrateFeedSocialStatsForFeed(listEl);
  } else {
    listEl.classList.add("isDiscoveryLoading");
    listEl.hidden = false;
    if (!keepFeed) listEl.innerHTML = followingActivitySkeletonHtml();
    statusEl.hidden = true;
    statusEl.textContent = "";
  }

  const prereqReady = ensureFriendsFeedPrerequisites();
  if (!snapFresh) await prereqReady;
  else void prereqReady;
  if (gen !== _discoveryFollowingGen) return;
  const apiBlock = friendsFeedBlockedMessage();
  if (apiBlock) {
    listEl.classList.remove("isDiscoveryLoading");
    listEl.hidden = true;
    listEl.innerHTML = "";
    renderDiscoveryFollowingEmpty(
      statusEl,
      "Friends unavailable",
      apiBlock,
      `<button type="button" class="solid discoveryEmptyCta" id="friendsFeedRetryBtn">Try again</button>`,
    );
    const retry = document.getElementById("friendsFeedRetryBtn");
    if (retry && !retry.dataset.boundFriendsRetry) {
      retry.dataset.boundFriendsRetry = "1";
      retry.addEventListener("click", () => {
        try { haptic("light"); } catch {}
        lastPublicConfigError = "";
        lastPublicConfigStatus = 0;
        void loadPublicConfig().then(() => void refreshDiscoveryFollowingFeed());
      });
    }
    return;
  }

  if (!authSession?.user?.id) {
    const token = getSupabaseAuthToken();
    if (
      token &&
      String(document.body.getAttribute("data-route") || "") === "friends"
    ) {
      try {
        await refreshAuthStateFromSupabase();
      } catch {}
      if (authSession?.user?.id) {
        _friendsFeedAuthRetry = 0;
        /* fall through — session hydrated after login */
      } else if (_friendsFeedAuthRetry < 4) {
        _friendsFeedAuthRetry += 1;
        window.setTimeout(() => {
          if (gen !== _discoveryFollowingGen) return;
          if ((document.body.getAttribute("data-route") || "") !== "friends") return;
          void refreshDiscoveryFollowingFeed();
        }, 200);
        return;
      } else {
        _friendsFeedAuthRetry = 0;
        listEl.classList.remove("isDiscoveryLoading");
        listEl.hidden = true;
        listEl.innerHTML = "";
        renderDiscoveryFollowingEmpty(
          statusEl,
          "Sign in to see activity",
          "Follow musicians from Discover — their drops and remixes show up here.",
          `<a class="solid discoveryEmptyCta" href="#/auth">Sign in</a>`,
        );
        return;
      }
    } else {
      _friendsFeedAuthRetry = 0;
      listEl.classList.remove("isDiscoveryLoading");
      listEl.hidden = true;
      listEl.innerHTML = "";
      renderDiscoveryFollowingEmpty(
        statusEl,
        "Sign in to see activity",
        "Follow musicians from Discover — their drops and remixes show up here.",
          `<a class="solid discoveryEmptyCta" href="#/auth">Sign in</a>`,
      );
      return;
    }
  }

  try {
    const followingIds = await fetchFollowingUserIdsForFeed();
    if (gen !== _discoveryFollowingGen) return;
    if (!followingIds.length) {
      if (STATUS_POSTS_FEATURE_ENABLED && _friendsOwnPostPin) {
        if (gen !== _discoveryFollowingGen) return;
        const profMap = await fetchProfilesByUserIdsMap([String(authSession.user.id)]);
        listEl.classList.remove("isDiscoveryLoading");
        statusEl.hidden = true;
        listEl.hidden = false;
        listEl.innerHTML = followingStatusRowHtml(_friendsOwnPostPin, profMap, 0, { xstyle: true });
        return;
      }
      listEl.classList.remove("isDiscoveryLoading");
      listEl.hidden = true;
      listEl.innerHTML = "";
      renderDiscoveryFollowingEmpty(
        statusEl,
        "Follow musicians to see activity",
        "Pick a few creators on Discover — new songs, remixes, and challenges land here.",
        `<a class="solid discoveryEmptyCta" href="#/discover" data-route-link="discover">Browse Discover</a>`,
      );
      void (async () => {
        const suggests = await fetchFollowingEmptySuggestCreators(3);
        if (gen !== _discoveryFollowingGen) return;
        if (!suggests.length) return;
        const faces = `<div class="followActEmptyFaces">${suggests
          .map((c) => {
            const href = `#/u/${encodeURIComponent(c.handle)}`;
            const av = c.avatar
              ? `<img src="${escapeHtml(c.avatar)}" alt="" width="44" height="44" decoding="async" />`
              : `<span class="followActEmptyFaceFallback">${escapeHtml(c.handle.slice(0, 2).toUpperCase())}</span>`;
            return `<a class="followActEmptyFace" href="${escapeHtml(href)}" data-route-link="user" title="@${escapeHtml(c.handle)}">${av}</a>`;
          })
          .join("")}</div>`;
        const wrap = statusEl.querySelector(".discoveryEmptyWrap");
        if (!wrap) return;
        const cta = wrap.querySelector(".discoveryEmptyCta");
        if (cta) cta.insertAdjacentHTML("beforebegin", faces);
      })();
      return;
    }

    const libraryUserIds = followingIds.slice(0, FRIENDS_FEED_LIBRARY_USERS);
    const [statusPosts, tracksByUser, repostRows] = await Promise.all([
      STATUS_POSTS_FEATURE_ENABLED
        ? fetchFollowingStatusPosts(40, await fetchFollowingListForFeed())
        : Promise.resolve([]),
      supabaseFetchPublicLibraryForUserIds(libraryUserIds, FRIENDS_FEED_LIBRARY_SONG_LIMIT),
      fetchFollowingRepostsForFeed(libraryUserIds, 40),
    ]);
    const tracksNested = libraryUserIds.map((userId) =>
      (tracksByUser.get(userId) || []).map((row) => ({ ...row, userId })),
    );
    if (gen !== _discoveryFollowingGen) return;

    const playable = tracksNested
      .flat()
      .filter((t) => {
        if (!String(t.url || "").trim()) return false;
        if (t.publicOnProfile === false) return false;
        return isDiscoverFeedActive(t);
      })
      .sort((a, b) => Number(b.ts || 0) - Number(a.ts || 0))
      .slice(0, 60);

    // Reposts: hydrate the original songs, then build repost feed items.
    const repostTargetIds = [...new Set(repostRows.map((r) => r.targetId))];
    const repostSongs = repostTargetIds.length ? await fetchPublicSongsByIds(repostTargetIds) : new Map();
    if (gen !== _discoveryFollowingGen) return;
    const repostItems = repostRows
      .map((rp) => {
        const track = repostSongs.get(rp.targetId);
        if (!track || !String(track.url || "").trim()) return null;
        return { kind: "repost", ts: rp.ts, repost: rp, track };
      })
      .filter(Boolean);

    const profIds = [
      ...playable.map((t) => t.userId),
      ...statusPosts.map((p) => String(p?.userId || "").trim()).filter(Boolean),
      ...repostItems.map((it) => String(it.repost.userId || "")).filter(Boolean),
      ...repostItems.map((it) => String(it.track.userId || "")).filter(Boolean),
    ];
    const profMap = await fetchProfilesByUserIdsMap(profIds);
    if (gen !== _discoveryFollowingGen) return;

    // Repost originals join the enrich set so they get play counts, social
    // stats, and join the playback queue — without being patched as music rows.
    const enrichTracks = [...playable];
    const seenEnrich = new Set(playable.map((t) => String(t.id || "")));
    for (const it of repostItems) {
      const id = String(it.track.id || "");
      if (id && !seenEnrich.has(id)) {
        seenEnrich.add(id);
        enrichTracks.push(it.track);
      }
    }

    const feedItems = [
      ...statusPosts.map((post) => ({
        kind: "status",
        ts: new Date(post.createdAt || post.created_at || 0).getTime() || 0,
        post,
      })),
      ...playable.map((track) => ({
        kind: "music",
        ts: Number(track.ts || 0),
        track,
      })),
      ...repostItems,
    ]
      .filter((row) => row.ts > 0 || row.kind === "status")
      .sort((a, b) => b.ts - a.ts);
    const mergedItems = mergeFriendsOwnPostPin(feedItems).slice(0, 80);

    listEl.classList.remove("isDiscoveryLoading");
    if (!mergedItems.length) {
      listEl.hidden = true;
      listEl.innerHTML = "";
      renderDiscoveryFollowingEmpty(
        statusEl,
        "Quiet for now",
        "New song drops from people you follow will show up here.",
      );
      return;
    }

    statusEl.hidden = true;
    statusEl.textContent = "";
    _discoveryFeedTracks = enrichTracks.map((t) => discoveryTrackPlaybackMeta(t, profMap));
    listEl.hidden = false;
    const desiredKey = friendsFeedItemsKey(mergedItems);
    const domKey = readFollowActListDomKey(listEl);
    const hasSkeleton = Boolean(listEl.querySelector(".followAct--skel"));
    const skipListRebuild = desiredKey && domKey === desiredKey && !hasSkeleton;
    if (!skipListRebuild) {
      listEl.innerHTML = friendsFeedRowsHtml(mergedItems, profMap);
      logFriendsFeedListRender(mergedItems.length);
      _friendsFeedSnapshot = {
        at: Date.now(),
        html: listEl.innerHTML,
        tracks: _discoveryFeedTracks,
      };
      persistFriendsFeedSnapshot();
    } else {
      _friendsFeedSnapshot = {
        at: Date.now(),
        html: listEl.innerHTML,
        tracks: _discoveryFeedTracks,
      };
      persistFriendsFeedSnapshot();
      try {
        console.info("[friends/feed] list rebuild skipped (dom matches)", desiredKey.split("|").length);
      } catch {}
    }
    applyFeedSocialStatsToDom(listEl);
    try {
      syncDiscoveryPlayingHighlights();
    } catch {}
    void enrichFriendsFeedAfterPaint({
      playable: enrichTracks,
      mergedItems,
      profMap,
      listEl,
      followedIds: followingIds,
      gen,
    });
  } catch (e) {
    if (gen !== _discoveryFollowingGen) return;
    listEl.classList.remove("isDiscoveryLoading");
    listEl.hidden = true;
    listEl.innerHTML = "";
    renderDiscoveryFollowingEmpty(
      statusEl,
      "Could not load Friends",
      socialApiErrorMessage(e),
      `<button type="button" class="solid discoveryEmptyCta" id="friendsFeedRetryBtn">Try again</button>`,
    );
    const retry = document.getElementById("friendsFeedRetryBtn");
    if (retry && !retry.dataset.boundFriendsRetry) {
      retry.dataset.boundFriendsRetry = "1";
      retry.addEventListener("click", () => {
        try { haptic("light"); } catch {}
        void refreshDiscoveryFollowingFeed({ force: true });
      });
    }
  }
  } finally {
    _friendsFeedRefreshInFlight = false;
    if (_friendsFeedRefreshQueued) {
      _friendsFeedRefreshQueued = false;
      void refreshDiscoveryFollowingFeed(opts);
    }
  }
}

function bindDiscoveryDiscoverControls() {
  wirePlayerFeedbackUiOnce();
  wireUserPublicFeedRowsOnce();
  bindDiscoverHubV1Once();
  if (_discoveryDiscoverBound) return;
  _discoveryDiscoverBound = true;
  const searchBtn = document.getElementById("discoverySearchBtn");
  if (searchBtn && !searchBtn.dataset.boundDiscoverySearch) {
    searchBtn.dataset.boundDiscoverySearch = "1";
    searchBtn.addEventListener("click", () => {
      haptic("light");
      if (_discoverSearchOpen) closeDiscoverSearch();
      else openDiscoverSearch();
    });
  }
  const dPane = document.getElementById("discoveryPaneDiscover");
  if (dPane && !dPane.dataset.boundDiscoverPane) {
    dPane.dataset.boundDiscoverPane = "1";
    wireTrackOptionsSheetOnce();
    dPane.addEventListener("click", (e) => {
      const challengePlay = e.target.closest("[data-challenge-entry-play]");
      const hubRoot = document.getElementById("discoveryMainContent");
      if (
        challengePlay &&
        hubRoot?.contains(challengePlay)
      ) {
        const raw = decodeDiscoverDataAttr(challengePlay, "data-challenge-entry-play");
        const title = decodeDiscoverDataAttr(challengePlay, "data-challenge-entry-title") || "Song";
        const art = decodeDiscoverDataAttr(challengePlay, "data-challenge-entry-art") || "";
        const by = decodeDiscoverDataAttr(challengePlay, "data-challenge-entry-by") || "";
        if (!raw) return;
        e.preventDefault();
        haptic("light");
        void playLibraryUrlOnPlayer(raw, title, art, { discoverFeed: true, openPlayer: false, discoverBy: by, playSource: publicPlaySourceFromEl(challengePlay) });
        return;
      }
      const menuBtn = e.target.closest("[data-discovery-open-sheet]");
      if (menuBtn && dPane.contains(menuBtn)) {
        e.preventDefault();
        e.stopPropagation();
        haptic("light");
        openDiscoverTrackSheetFromEl(menuBtn);
        return;
      }
      const cardWrap = e.target.closest(".discoveryFeedCardWrap");
      if (cardWrap && dPane.contains(cardWrap) && !e.target.closest("[data-discovery-open-sheet]")) {
        const pl = cardWrap.querySelector("[data-user-lib-play]");
        if (pl) {
          e.preventDefault();
          playDiscoverTarget(pl);
          return;
        }
      }
      const inline = e.target.closest("[data-discovery-inline-play]");
      if (inline && dPane.contains(inline)) {
        e.preventDefault();
        playDiscoverTarget(inline);
        return;
      }
      const pl = e.target.closest("[data-user-lib-play]");
      if (!pl || !dPane.contains(pl)) return;
      e.preventDefault();
      playDiscoverTarget(pl);
    });
  }
}

