function getAuthEmailRedirectTo() {
  try {
    const o = String(location.origin || "").replace(/\/$/, "");
    if (/^https?:\/\//i.test(o) && !/localhost|127\.0\.0\.1|capacitor/i.test(o)) {
      return `${o}/`;
    }
  } catch {}
  return "https://nabadai.com/";
}

/** Sign-up with confirm-email may return `user` nested or flat `{ id, email }`. */
function supabaseSignupPendingUser(data) {
  if (!data || data.access_token) return null;
  const u = data.user && typeof data.user === "object" ? data.user : data;
  const email = String(u?.email || data?.email || "").trim();
  const id = String(u?.id || data?.id || "").trim();
  if (!email && !id) return null;
  return { id, email };
}

function parseSupabaseAuthError(data, status) {
  const raw =
    data?.error_description ||
    data?.msg ||
    data?.message ||
    data?.error ||
    "";
  const s = String(raw || "").trim();
  const lower = s.toLowerCase();
  if (status === 400 && lower.includes("invalid login")) {
    return "Wrong email or password.";
  }
  if (lower.includes("already registered") || lower.includes("already exists")) {
    return "That email already has an account — try Apple/Google sign-in or Sign in.";
  }
  if (
    lower.includes("error sending confirmation") ||
    lower.includes("sending confirmation email") ||
    lower.includes("smtp") ||
    lower.includes("mailer")
  ) {
    return "Could not send confirmation email. In Supabase enable SMTP (Auth → SMTP), or use Apple/Google sign-in.";
  }
  if (lower.includes("rate limit") || lower.includes("too many")) {
    return "Too many attempts — wait a minute and try again.";
  }
  if (lower.includes("password") && lower.includes("short")) {
    return "Use a password with at least 8 characters.";
  }
  if (lower.includes("email") && lower.includes("invalid")) {
    return "Enter a valid email address.";
  }
  if (lower.includes("email not confirmed")) {
    return "Confirm your email first (check your inbox), then sign in.";
  }
  if (lower.includes("invalid credentials")) {
    return "Wrong email or password — or use Apple/Google if you signed up that way.";
  }
  return s || `Sign-in failed (${status || "error"})`;
}

async function applySupabaseAuthTokenPayload(d) {
  if (!d?.access_token) return false;
  saveAuthSession({
    access_token: d.access_token,
    refresh_token: d.refresh_token || "",
    expires_in: Number(d.expires_in || 3600),
    token_type: d.token_type || "bearer",
    user: d.user || { id: "", email: "" },
    issued_at: Date.now(),
  });
  ensureAuthSessionUserFromToken();
  if (authSession) {
    void persistAuthSessionEverywhere(JSON.stringify(authSession));
  }
  renderAuthStatus();
  return true;
}

async function supabaseSignUpWithPassword(email, password) {
  if (!SUPABASE_URL || !SUPABASE_ANON_KEY) throw new Error("Supabase config missing");
  const ctrl = new AbortController();
  const timer = setTimeout(() => ctrl.abort(), authFetchTimeoutMs());
  let r;
  try {
    r = await fetch(`${SUPABASE_URL}/auth/v1/signup`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        apikey: SUPABASE_ANON_KEY,
      },
      body: JSON.stringify({
        email,
        password,
        options: { emailRedirectTo: getAuthEmailRedirectTo() },
      }),
      signal: ctrl.signal,
    });
  } finally {
    clearTimeout(timer);
  }
  const d = await r.json().catch(() => ({}));
  return { ok: r.ok, status: r.status, data: d };
}

