async function supabaseUpsertProfile(profile) {
  const token = getSupabaseAuthToken();
  if (!token) throw new Error("Login required");
  // Guard against pushing a placeholder handle ("guest" or
  // "user_xxxxxx") over a real one in the cloud. If the in-memory
  // profile is in a transient placeholder state (e.g. mid-merge,
  // mid-reset, debounced sync racing a fresh login), peek at the
  // existing cloud row first and keep its username. This is the
  // last line of defense for the "username keeps resetting" bug —
  // if anything sneaks through the boot merge, this stops it from
  // becoming permanent on the server.
  let outgoingUsername = profile.username || "";
  if (isPlaceholderUsername(outgoingUsername) && authSession?.user?.id) {
    try {
      const existing = await supabaseLoadProfile();
      if (existing && existing.username && !isPlaceholderUsername(existing.username)) {
        outgoingUsername = existing.username;
      }
    } catch {}
  }
  if (!outgoingUsername) outgoingUsername = "guest";
  // Never wipe a real cloud avatar/bio with empty local defaults — that
  // happened when boot couldn't reach Supabase and scheduleProfileCloudSync
  // pushed a blank shell over the stored row.
  let outgoingAvatar = String(profile.avatar || "").trim();
  let outgoingBio = String(profile.bio || "").trim();
  if ((!outgoingAvatar || !outgoingBio) && authSession?.user?.id) {
    try {
      const existing = await supabaseLoadProfile();
      if (existing) {
        if (!outgoingAvatar && String(existing.avatar || "").trim()) {
          outgoingAvatar = String(existing.avatar).trim();
        }
        if (!outgoingBio && String(existing.bio || "").trim()) {
          outgoingBio = String(existing.bio).trim();
        }
      }
    } catch {}
  }
  const payload = {
    user_id: authSession?.user?.id,
    username: outgoingUsername,
    email: profile.email || "",
    gender: profile.gender || "",
    voice_timbre: profile.voiceTimbre || "",
    bio: outgoingBio,
    avatar: outgoingAvatar,
    genres: profile.genres || "",
    instagram: profile.links?.instagram || "",
    youtube: profile.links?.youtube || "",
    tiktok: profile.links?.tiktok || "",
    is_public: profile.isPublic !== false,
    calling_card_url: profile.callingCardUrl || null,
    calling_card_updated_at: profile.callingCardUpdatedAt
      ? new Date(profile.callingCardUpdatedAt).toISOString()
      : null,
    updated_at: new Date().toISOString(),
  };
  const r = await fetch(`${SUPABASE_URL}/rest/v1/profiles`, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      apikey: SUPABASE_ANON_KEY,
      Authorization: `Bearer ${token}`,
      Prefer: "resolution=merge-duplicates,return=representation",
    },
    body: JSON.stringify(payload),
  });
  if (!r.ok) {
    const txt = await r.text().catch(() => "");
    throw new Error(`Cloud save failed (${r.status}): ${txt.slice(0, 140)}`);
  }
}
async function supabaseLoadProfile() {
  const token = getSupabaseAuthToken();
  if (!token || !authSession?.user?.id) return null;
  const uid = encodeURIComponent(authSession.user.id);
  // 8s timeout — same reasoning as supabaseFetchUser: a hung profile
  // fetch was the root cause of the "stuck loading + @guest" report.
  const ctrl = new AbortController();
  const timer = setTimeout(() => ctrl.abort(), 8000);
  let r;
  try {
    r = await fetch(`${SUPABASE_URL}/rest/v1/profiles?user_id=eq.${uid}&select=*`, {
      headers: {
        apikey: SUPABASE_ANON_KEY,
        Authorization: `Bearer ${token}`,
      },
      signal: ctrl.signal,
    });
  } catch {
    clearTimeout(timer);
    return null;
  }
  clearTimeout(timer);
  if (!r.ok) return null;
  const arr = await r.json().catch(() => []);
  if (!Array.isArray(arr) || !arr.length) return null;
  const p = arr[0];
  return {
    id: p.user_id || activeProfile.id,
    username: p.username || "guest",
    email: p.email || "",
    gender: p.gender || "",
    voiceTimbre: p.voice_timbre || "",
    bio: p.bio || "",
    avatar: p.avatar || "",
    genres: p.genres || "",
    links: {
      instagram: p.instagram || "",
      youtube: p.youtube || "",
      tiktok: p.tiktok || "",
    },
    isPublic: p.is_public !== false,
    callingCardUrl: p.calling_card_url || "",
    callingCardUpdatedAt: p.calling_card_updated_at
      ? Date.parse(p.calling_card_updated_at) || 0
      : 0,
    soundCertified: p.sound_certified === true || p.sound_certified === "t" || p.sound_certified === "true",
    savedPersonas: parseSavedPersonasFromCloud(p.saved_personas),
  };
}
/** Last status of the most recent `supabaseLoadUserSongs` call. The
 *  Library renderer uses this to differentiate between "cloud has
 *  zero rows" (user genuinely has nothing synced) and "fetch failed"
 *  (network / auth / RLS issue) so the empty state can show a
 *  different message in each case.
 */
let _lastUserSongsLoadStatus = "ok"; // "ok" | "auth" | "network" | "http"
let _lastUserSongsLoadDetails = "";
let _userSongsLoadPromise = null;
let _userSongsLoadCache = null;
let _userSongsLoadCacheAt = 0;
const USER_SONGS_LOAD_CACHE_MS = 30_000;
const _profileRowCache = new Map();
const PROFILE_ROW_CACHE_MS = 60_000;
const _songPlayCountCache = new Map();
const SONG_PLAY_COUNT_CACHE_MS = 60_000;
let _profileSongsRenderScheduled = false;
let _pendingProfileSongsRenderOpts = null;

function invalidateUserSongsLoadCache() {
  _userSongsLoadCache = null;
  _userSongsLoadCacheAt = 0;
  _userSongsLoadPromise = null;
}

function clearSocialFetchCaches() {
  _profileRowCache.clear();
  _songPlayCountCache.clear();
}

function scheduleProfileSongsRender(opts = {}) {
  _pendingProfileSongsRenderOpts = { ...(_pendingProfileSongsRenderOpts || {}), ...opts };
  if (_profileSongsRenderScheduled) return;
  _profileSongsRenderScheduled = true;
  requestAnimationFrame(() => {
    _profileSongsRenderScheduled = false;
    const o = _pendingProfileSongsRenderOpts || {};
    _pendingProfileSongsRenderOpts = null;
    renderProfileSongs(o);
  });
}

function userSongPublishedTs(row) {
  const raw = row?.published_at || row?.publishedAt || row?.created_at || "";
  const ts = raw ? new Date(raw).getTime() : 0;
  return Number.isFinite(ts) && ts > 0 ? ts : Date.now();
}

function userSongPublishedAtValue(row) {
  return String(row?.published_at || row?.publishedAt || "").trim();
}

function libraryTrackPublicTs(track) {
  const published = userSongPublishedAtValue(track);
  if (published) {
    const ts = new Date(published).getTime();
    if (Number.isFinite(ts) && ts > 0) return ts;
  }
  return Number(track?.ts || 0);
}

function ensurePublishReleaseSheet() {
  let sheet = document.getElementById("publishReleaseSheet");
  if (sheet) return sheet;
  sheet = document.createElement("div");
  sheet.id = "publishReleaseSheet";
  sheet.className = "publishReleaseSheet";
  sheet.hidden = true;
  sheet.innerHTML = `
    <div class="publishReleaseBackdrop" data-publish-release-close="1"></div>
    <div class="publishReleaseCard" role="dialog" aria-modal="true" aria-labelledby="publishReleaseTitle">
      <div class="publishReleaseGrab" aria-hidden="true"></div>
      <button type="button" class="publishReleaseClose" data-publish-release-close="1" aria-label="Close">×</button>
      <div class="publishReleaseHead">
        <img id="publishReleaseArt" class="publishReleaseArt" alt="" />
        <div class="publishReleaseHeadText">
          <div class="publishReleaseKicker">Publish Release</div>
          <div id="publishReleaseTitle" class="publishReleaseTitle">Release this song</div>
          <div id="publishReleaseSub" class="publishReleaseSub">This becomes part of your public sound.</div>
        </div>
      </div>
      <label class="publishReleaseLabel" for="publishReleaseCaption">Release note <span>(optional)</span></label>
      <textarea id="publishReleaseCaption" class="publishReleaseCaption" rows="3" maxlength="160" placeholder="Say something about the mood, story, or moment..."></textarea>
      <div class="publishReleasePermits" role="group" aria-label="Collaboration permissions">
        <label class="publishReleasePermit">
          <input id="publishAllowRemix" type="checkbox" checked />
          <span>Allow others to remix this song</span>
        </label>
        <label class="publishReleasePermit">
          <input id="publishAllowMashup" type="checkbox" checked />
          <span>Allow others to use it in mashups</span>
        </label>
      </div>
      <div id="publishReleaseMeta" class="publishReleaseMeta"></div>
      <div class="publishReleaseActions">
        <button type="button" class="ghost publishReleaseBtn" data-publish-release-close="1">Cancel</button>
        <button type="button" class="primary publishReleaseBtn publishReleaseBtn--primary" id="publishReleaseConfirm">Publish</button>
      </div>
    </div>
  `;
  document.body.appendChild(sheet);
  sheet.addEventListener("click", (e) => {
    if (e.target?.getAttribute?.("data-publish-release-close") === "1") closePublishReleaseSheet();
  });
  const confirm = sheet.querySelector("#publishReleaseConfirm");
  if (confirm) {
    confirm.addEventListener("click", () => {
      const id = String(sheet.dataset.trackId || "").trim();
      if (!id) return;
      const caption = String(sheet.querySelector("#publishReleaseCaption")?.value || "").trim();
      const allowRemix = sheet.querySelector("#publishAllowRemix")?.checked !== false;
      const allowMashup = sheet.querySelector("#publishAllowMashup")?.checked !== false;
      closePublishReleaseSheet();
      void setLibraryTrackPublicOnProfile(id, true, { releaseCaption: caption, allowRemix, allowMashup });
    });
  }
  return sheet;
}

function closePublishReleaseSheet() {
  const sheet = document.getElementById("publishReleaseSheet");
  if (!sheet) return;
  sheet.classList.remove("isOpen");
  setTimeout(() => {
    if (!sheet.classList.contains("isOpen")) sheet.hidden = true;
  }, 180);
}

function openPublishReleaseSheet(trackId, opts = {}) {
  const id = String(trackId || "").trim();
  const track = loadLibrary().find((x) => String(x.id) === id);
  if (!track) {
    showToast("Could not find this song in your Library.", { icon: "!", durationMs: 3200 });
    return;
  }
  if (track.publicOnProfile) {
    showToast("This song is already public.", { icon: "✓", durationMs: 2400 });
    return;
  }
  if (!String(track.url || "").trim()) {
    showToast("This track has no audio URL yet — try again after it finishes saving.", { icon: "!", durationMs: 3600 });
    return;
  }
  const sheet = ensurePublishReleaseSheet();
  sheet.dataset.trackId = id;
  const art =
    String((track.meta && (track.meta.imageThumb || track.meta.imageUrl)) || track.artUrl || "").trim() ||
    "./assets/nabadai-logo.png";
  const title = String(track.title || "Untitled").trim() || "Untitled";
  const remixOf = remixAttributionForTrack(track);
  const caption = sheet.querySelector("#publishReleaseCaption");
  const artEl = sheet.querySelector("#publishReleaseArt");
  const titleEl = sheet.querySelector("#publishReleaseTitle");
  const subEl = sheet.querySelector("#publishReleaseSub");
  const metaEl = sheet.querySelector("#publishReleaseMeta");
  if (artEl) artEl.src = art;
  if (titleEl) titleEl.textContent = title;
  if (subEl) subEl.textContent = "Move this from your private studio to your public sound.";
  if (caption) {
    caption.value = String(track?.meta?.releaseCaption || "").trim();
    caption.focus?.();
  }
  const remixToggle = sheet.querySelector("#publishAllowRemix");
  const mashupToggle = sheet.querySelector("#publishAllowMashup");
  if (remixToggle) remixToggle.checked = trackAllowsRemix(track);
  if (mashupToggle) mashupToggle.checked = trackAllowsMashup(track);
  if (metaEl) {
    metaEl.innerHTML = `
      <span>Public profile</span>
      <span>Stamped now</span>
      ${remixOf ? `<span>Remix of @${escapeHtml(remixOf.creatorUsername || "creator")}</span>` : ""}
    `;
  }
  sheet.hidden = false;
  requestAnimationFrame(() => sheet.classList.add("isOpen"));
}

async function supabaseLoadUserSongs(opts = {}) {
  const force = Boolean(opts.force);
  const now = Date.now();
  if (!force && _userSongsLoadCache && now - _userSongsLoadCacheAt < USER_SONGS_LOAD_CACHE_MS) {
    return _userSongsLoadCache;
  }
  if (!force && _userSongsLoadPromise) {
    return _userSongsLoadPromise;
  }
  const run = async () => {
    const rows = await fetchUserSongsFromNetwork();
    _userSongsLoadCache = rows;
    _userSongsLoadCacheAt = Date.now();
    return rows;
  };
  if (force) {
    invalidateUserSongsLoadCache();
    return run();
  }
  _userSongsLoadPromise = run();
  try {
    return await _userSongsLoadPromise;
  } finally {
    _userSongsLoadPromise = null;
  }
}

async function fetchUserSongsFromNetwork() {
  const token = getSupabaseAuthToken();
  if (!token || !authSession?.user?.id) {
    _lastUserSongsLoadStatus = "auth";
    _lastUserSongsLoadDetails = !token ? "no_token" : "no_user_id";
    return [];
  }
  const uid = encodeURIComponent(authSession.user.id);
  // Slim list: render-only columns. `meta` stays out (legacy rows could
  // carry base64 cover blobs in `meta.imageUrl`). `art_url` is included
  // again — without it, cloud rows arrive cover-less and the merge wipes
  // out the local CDN URL the user actually sees in Library. We pair the
  // select with a PostgREST guard that *skips rows whose `art_url`
  // happens to be a legacy `data:` URL*, same trick we use on `hub_posts`
  // for cover_url / creator_avatar. The cheap `art_url is null` branch
  // covers freshly inserted rows where we deliberately wrote null.
  const colsWithPublished = "id,created_at,published_at,title,song_url,task_id,audio_id,kind,art_url,public_on_profile,meta_remix_of:meta->remixOf,meta_mashup_of:meta->mashupOf,meta_release_caption:meta->>releaseCaption,meta_challenge:meta->challenge,meta_featured_on_profile:meta->>featuredOnProfile,meta_nabad_verification:meta->>nabadVerification,meta_has_reference:meta->hasReference,meta_vocal_ref:meta->>vocalRefOrigin,meta_mode:meta->>mode,meta_persona_id:meta->>personaId,meta_lyrics_edited:meta->lyricsEditedByUser,meta_lyrics_generated:meta->lyricsGeneratedInNabad,meta_lyrics:meta->>lyricsInput,meta_search_template:meta->>searchTemplateId,meta_deleted_at:meta->>deletedAt";
  const colsLegacy = "id,created_at,title,song_url,task_id,audio_id,kind,art_url,public_on_profile,meta_remix_of:meta->remixOf,meta_mashup_of:meta->mashupOf,meta_release_caption:meta->>releaseCaption,meta_challenge:meta->challenge,meta_featured_on_profile:meta->>featuredOnProfile,meta_nabad_verification:meta->>nabadVerification,meta_has_reference:meta->hasReference,meta_vocal_ref:meta->>vocalRefOrigin,meta_mode:meta->>mode,meta_persona_id:meta->>personaId,meta_lyrics_edited:meta->lyricsEditedByUser,meta_lyrics_generated:meta->lyricsGeneratedInNabad,meta_lyrics:meta->>lyricsInput,meta_search_template:meta->>searchTemplateId,meta_deleted_at:meta->>deletedAt";
  const artUrlGuard = `&or=${encodeURIComponent("(art_url.is.null,art_url.not.like.data:*)")}`;
  const ctrl = new AbortController();
  const timer = setTimeout(() => ctrl.abort(), 12000);
  let r;
  let selectedPublishedAt = true;
  try {
    r = await fetch(`${SUPABASE_URL}/rest/v1/user_songs?user_id=eq.${uid}&select=${colsWithPublished}&order=created_at.desc&limit=500${artUrlGuard}`, {
      headers: {
        apikey: SUPABASE_ANON_KEY,
        Authorization: `Bearer ${token}`,
      },
      signal: ctrl.signal,
      cache: "no-store",
    });
    if (!r.ok) {
      const txt = await r.clone().text().catch(() => "");
      if (/published_at|42703|column/i.test(txt)) {
        selectedPublishedAt = false;
        r = await fetch(`${SUPABASE_URL}/rest/v1/user_songs?user_id=eq.${uid}&select=${colsLegacy}&order=created_at.desc&limit=500${artUrlGuard}`, {
          headers: {
            apikey: SUPABASE_ANON_KEY,
            Authorization: `Bearer ${token}`,
          },
          signal: ctrl.signal,
          cache: "no-store",
        });
      }
    }
  } catch (e) {
    clearTimeout(timer);
    _lastUserSongsLoadStatus = "network";
    _lastUserSongsLoadDetails = String(e?.message || e || "fetch_aborted").slice(0, 120);
    return [];
  }
  clearTimeout(timer);
  if (!r.ok) {
    _lastUserSongsLoadStatus = "http";
    const txt = await r.text().catch(() => "");
    _lastUserSongsLoadDetails = `${r.status} ${String(txt).slice(0, 120)}`;
    return [];
  }
  const rows = await r.json().catch(() => []);
  if (!Array.isArray(rows)) {
    _lastUserSongsLoadStatus = "http";
    _lastUserSongsLoadDetails = "non_array_response";
    return [];
  }
  _lastUserSongsLoadStatus = "ok";
  _lastUserSongsLoadDetails = "";
  return rows
    .filter((s) => !String(s?.meta_deleted_at || "").trim())
    .map((s) => {
    const cid = String(s.id || "").trim();
    return {
      id: cid || `${Date.now()}_${Math.random().toString(36).slice(2, 8)}`,
      cloudSongId: cid,
      ts: new Date(s.created_at || Date.now()).getTime(),
      title: s.title || "Generated song",
      artUrl: s.art_url || "",
      url: s.song_url || "",
      taskId: s.task_id || "",
      audioId: s.audio_id || "",
      kind: s.kind || "full",
      meta: {
        ...(s.meta_remix_of ? { remixOf: s.meta_remix_of } : {}),
        ...(s.meta_mashup_of ? { mashupOf: s.meta_mashup_of } : {}),
        ...(String(s.meta_release_caption || "").trim() ? { releaseCaption: String(s.meta_release_caption).trim() } : {}),
        ...(s.meta_challenge ? { challenge: s.meta_challenge } : {}),
        ...(String(s.meta_featured_on_profile || "").toLowerCase() === "true" ? { featuredOnProfile: true } : {}),
        ...(String(s.meta_nabad_verification || "").trim() ? { nabadVerification: String(s.meta_nabad_verification).trim() } : {}),
        ...(s.meta_has_reference === true || s.meta_has_reference === "true" ? { hasReference: true } : {}),
        ...(String(s.meta_vocal_ref || "").trim() ? { vocalRefOrigin: String(s.meta_vocal_ref).trim() } : {}),
        ...(String(s.meta_mode || "").trim() ? { mode: String(s.meta_mode).trim() } : {}),
        ...(String(s.meta_persona_id || "").trim() ? { personaId: String(s.meta_persona_id).trim() } : {}),
        ...(s.meta_lyrics_edited === true || s.meta_lyrics_edited === "true" ? { lyricsEditedByUser: true } : {}),
        ...(s.meta_lyrics_generated === true || s.meta_lyrics_generated === "true" ? { lyricsGeneratedInNabad: true } : {}),
        ...(String(s.meta_lyrics || "").trim() ? { lyricsInput: String(s.meta_lyrics).trim() } : {}),
        ...(String(s.meta_search_template || "").trim() ? { searchTemplateId: String(s.meta_search_template).trim() } : {}),
      },
      publishedAt: selectedPublishedAt ? userSongPublishedAtValue(s) : "",
      publicOnProfile: Boolean(
        s.public_on_profile === true || s.public_on_profile === "t" || s.public_on_profile === "true",
      ),
    };
  });
}
/** Strip values that aren't safe / efficient to ship to a JSONB row in
 *  Supabase. v1 Library cloud sync intentionally leaves custom-cover
 *  data: URLs out of the payload — they're typically 200–500 KB each
 *  and would inflate every user_songs row by an order of magnitude.
 *  Phase C will upload custom covers to Supabase Storage and store the
 *  resulting public URL here instead.
 */
function sanitizeMetaForCloud(meta) {
  if (!meta || typeof meta !== "object") return meta || null;
  const out = { ...meta };
  for (const k of ["imageUrl", "imageThumb"]) {
    const v = out[k];
    if (typeof v === "string" && v.startsWith("data:")) delete out[k];
  }
  return out;
}

/** Last cloud insert failure for `user_songs` (RLS, missing table,
 *  schema mismatch). Cleared on a successful insert. The Library
 *  empty state surfaces this so "0 rows" isn't mistaken for "no songs"
 *  when the real issue is writes blocked server-side.
 */
let _lastUserSongInsertFailure = "";

function recordUserSongInsertResult(ins) {
  if (ins?.ok) {
    _lastUserSongInsertFailure = "";
    return;
  }
  const msg = `${ins?.reason || "fail"}${ins?.details ? `: ${ins.details}` : ""}`.slice(0, 280);
  _lastUserSongInsertFailure = msg;
  try {
    console.warn("[user_songs] insert failed:", msg);
  } catch {}
}

async function supabaseInsertUserSong(track) {
  if (!authSession?.user?.id) {
    return { ok: false, reason: "no_auth" };
  }
  // Never re-create a song the user deleted. (Explicit re-adds clear the
  // tombstone in addToLibrary before reaching this insert.)
  if (isTrackTombstoned(track)) {
    return { ok: false, reason: "tombstoned" };
  }
  const rawArt = String(track.artUrl || "");
  const payload = {
    user_id: authSession.user.id,
    title: track.title || "Generated song",
    // Skip data: URLs for the same reason as meta above. If the only
    // cover we have right now is a local upload, send empty and let
    // Phase C populate a real URL later.
    art_url: rawArt.startsWith("data:") ? "" : rawArt,
    song_url: track.url || "",
    task_id: track.taskId || "",
    audio_id: track.audioId || "",
    kind: track.kind || "full",
    meta: sanitizeMetaForCloud(track.meta || null),
    public_on_profile: Boolean(track.publicOnProfile),
    ...(track.publicOnProfile
      ? { published_at: userSongPublishedAtValue(track) || new Date().toISOString() }
      : {}),
  };
  const res = await supabaseAuthedFetch(`${SUPABASE_URL}/rest/v1/user_songs`, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      Prefer: "return=minimal",
    },
    body: JSON.stringify(payload),
  });
  if (res.reason === "network" || res.reason === "no_auth") {
    const fail = { ok: false, reason: res.reason || "network" };
    recordUserSongInsertResult(fail);
    return fail;
  }
  if (!res.ok) {
    const txt = res.text;
    // HTTP 409 / Postgres unique_violation (SQLSTATE 23505) means the
    // row already exists in the cloud — that's a success from the
    // app's perspective (the song is safely synced), not a failure.
    // Don't surface it as an error and don't poison the empty-state
    // "Last cloud save error" line.
    const looksDuplicate = res.status === 409 || /23505|duplicate key/i.test(txt);
    if (looksDuplicate) {
      recordUserSongInsertResult({ ok: true });
      invalidateUserSongsLoadCache();
      return { ok: true, reason: "duplicate" };
    }
    const fail = { ok: false, reason: `http_${res.status}`, details: String(txt).slice(0, 180) };
    recordUserSongInsertResult(fail);
    return fail;
  }
  recordUserSongInsertResult({ ok: true });
  invalidateUserSongsLoadCache();
  return { ok: true };
}
/** True when `v` looks like a Postgres `uuid` text form (REST `id=eq.` filters). */
function isPostgresUuidString(v) {
  return /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(String(v || "").trim());
}

/** Patch an existing `user_songs` row keyed by (user_id, song_url, kind).
 *  Used when a track changes locally — currently just custom-cover
 *  uploads from the Player. Fire-and-forget; failures fall back to
 *  localStorage being authoritative until the next reconcile.
 */
async function supabasePatchUserSong(track, patch) {
  if (!authSession?.user?.id) return { ok: false, reason: "no_auth" };
  const uid = encodeURIComponent(authSession.user.id);
  const songUrl = String(track?.url || "").trim();
  const url = encodeURIComponent(songUrl);
  const kind = encodeURIComponent(String(track?.kind || "full"));
  const audioId = String(track?.audioId || track?.audio_id || track?.meta?.audioId || "").trim();
  const taskId = String(track?.taskId || track?.task_id || track?.meta?.taskId || "").trim();
  const rowRef =
    String(track?.cloudSongId || "").trim() ||
    (isPostgresUuidString(track?.id) ? String(track.id).trim() : "");
  let filter;
  if (rowRef && isPostgresUuidString(rowRef)) {
    filter = `user_id=eq.${uid}&id=eq.${encodeURIComponent(rowRef)}`;
  } else if (audioId) {
    filter = `user_id=eq.${uid}&audio_id=eq.${encodeURIComponent(audioId)}&kind=eq.${kind}`;
  } else if (songUrl) {
    filter = `user_id=eq.${uid}&song_url=eq.${url}&kind=eq.${kind}`;
  } else if (taskId) {
    filter = `user_id=eq.${uid}&task_id=eq.${encodeURIComponent(taskId)}&kind=eq.${kind}`;
  } else {
    return { ok: false, reason: "no_row_ref", details: "missing cloudSongId, audio_id, task_id, and song_url" };
  }
  const body = {};
  if (typeof patch?.title === "string") body.title = patch.title;
  // Same reasoning as in supabaseInsertUserSong: don't ship a custom
  // cover data URL into a JSONB row, and don't overwrite an existing
  // remote art_url with empty just because the user uploaded a local
  // cover. We push only real (non-data:) URLs.
  if (typeof patch?.artUrl === "string" && patch.artUrl && !patch.artUrl.startsWith("data:")) {
    body.art_url = patch.artUrl;
  }
  if (patch?.meta && typeof patch.meta === "object") {
    let nextMeta = sanitizeMetaForCloud(patch.meta) || {};
    // PATCH replaces the whole JSONB. Local meta is usually the slim
    // hydrated copy (no lyricsInput/styleInput/…), and shipping it raw
    // used to wipe those creation-time keys from the cloud row. Pull the
    // current row and keep any heavy keys the patch doesn't carry.
    // UI flags (featuredOnProfile, releaseCaption, …) are NOT preserved
    // this way on purpose — deleting them locally must delete them in
    // the cloud too.
    try {
      const r0 = await supabaseAuthedFetch(`${SUPABASE_URL}/rest/v1/user_songs?${filter}&select=meta&limit=1`, {
        cache: "no-store",
      });
      if (r0.ok) {
        const rows = JSON.parse(r0.text || "[]");
        const cur = Array.isArray(rows) ? rows[0]?.meta : null;
        if (cur && typeof cur === "object") {
          const HEAVY_META_KEYS = [
            "lyricsInput", "finalPrompt", "prompt", "lyrics", "generatedLyrics",
            "styleInput", "styleSent", "style", "styleTags", "dialect", "tags",
            "mode", "voiceProfile", "timbre", "taskId", "audioId",
          ];
          for (const k of HEAVY_META_KEYS) {
            if (nextMeta[k] == null && cur[k] != null) nextMeta[k] = cur[k];
          }
        }
      }
    } catch {}
    body.meta = nextMeta;
  }
  if (typeof patch?.publicOnProfile === "boolean") {
    body.public_on_profile = patch.publicOnProfile;
  }
  if (typeof patch?.publishedAt === "string" && patch.publishedAt.trim()) {
    body.published_at = patch.publishedAt.trim();
  }
  if (patch?.publishedAt === null) {
    body.published_at = null;
  }
  if (typeof patch?.songUrl === "string" && patch.songUrl.trim()) {
    body.song_url = patch.songUrl.trim();
  }
  if (typeof patch?.discoverScore === "number" && Number.isFinite(patch.discoverScore)) {
    body.discover_score = Math.round(patch.discoverScore);
  }
  if (typeof patch?.discoverExpiresAt === "string" && patch.discoverExpiresAt.trim()) {
    body.discover_expires_at = patch.discoverExpiresAt.trim();
  }
  if (Object.keys(body).length === 0) return { ok: false, reason: "noop" };
  const sendPatch = (payload) =>
    supabaseAuthedFetch(`${SUPABASE_URL}/rest/v1/user_songs?${filter}`, {
      method: "PATCH",
      headers: {
        "Content-Type": "application/json",
        Prefer: "return=minimal",
      },
      body: JSON.stringify(payload),
    });
  let res = await sendPatch(body);
  if (res.reason === "network" || res.reason === "no_auth") {
    return { ok: false, reason: res.reason || "network" };
  }
  if (!res.ok) {
    const txt = res.text;
    const hasDiscoverCols =
      Object.prototype.hasOwnProperty.call(body, "discover_score") ||
      Object.prototype.hasOwnProperty.call(body, "discover_expires_at");
    if (hasDiscoverCols && /discover_score|discover_expires_at|PGRST204|schema cache/i.test(txt)) {
      const retryBody = { ...body };
      delete retryBody.discover_score;
      delete retryBody.discover_expires_at;
      if (Object.keys(retryBody).length > 0) {
        res = await sendPatch(retryBody);
        if (res.ok) {
          return { ok: true, reason: "discover_columns_pending", details: String(txt).slice(0, 280) };
        }
        if (res.reason === "network" || res.reason === "no_auth") {
          return { ok: false, reason: res.reason || "network" };
        }
        return { ok: false, reason: `http_${res.status}`, details: String(res.text || txt).slice(0, 280) };
      }
    }
    if (Object.prototype.hasOwnProperty.call(body, "published_at") && /published_at|42703|column/i.test(txt)) {
      const retryBody = { ...body };
      delete retryBody.published_at;
      if (Object.keys(retryBody).length > 0) {
        res = await sendPatch(retryBody);
        if (res.ok) return { ok: true, reason: "published_at_missing" };
        if (res.reason === "network" || res.reason === "no_auth") {
          return { ok: false, reason: res.reason || "network" };
        }
        return { ok: false, reason: `http_${res.status}`, details: String(res.text || txt).slice(0, 280) };
      }
    }
    return { ok: false, reason: `http_${res.status}`, details: String(txt).slice(0, 280) };
  }
  invalidateUserSongsLoadCache();
  return { ok: true };
}

async function supabaseSoftDeleteUserSong(track) {
  const deletedAt = new Date().toISOString();
  const meta = { ...(track?.meta && typeof track.meta === "object" ? track.meta : {}), deletedAt };
  return supabasePatchUserSong(track, {
    meta,
    publicOnProfile: false,
    publishedAt: null,
  });
}

async function supabaseDeleteUserSong(track) {
  const token = getSupabaseAuthToken();
  if (!token || !authSession?.user?.id) return;
  const uid = encodeURIComponent(authSession.user.id);
  const songUrl = String(track?.url || "").trim();
  const kind = encodeURIComponent(String(track?.kind || "full"));
  const rowRef =
    String(track?.cloudSongId || "").trim() ||
    (isPostgresUuidString(track?.id) ? String(track.id).trim() : "");
  // The same logical song can exist as several cloud rows (URL drift used
  // to duplicate them), so delete by EVERY identity we know: row id,
  // audio id, task id, raw URL, and the canonical (unwrapped) URL.
  const filters = [];
  if (rowRef && isPostgresUuidString(rowRef)) {
    filters.push(`user_id=eq.${uid}&id=eq.${encodeURIComponent(rowRef)}`);
  }
  const audioId = String(track?.audioId || "").trim();
  if (audioId) {
    filters.push(`user_id=eq.${uid}&audio_id=eq.${encodeURIComponent(audioId)}&kind=eq.${kind}`);
  }
  const taskId = String(track?.taskId || "").trim();
  if (taskId) {
    filters.push(`user_id=eq.${uid}&task_id=eq.${encodeURIComponent(taskId)}&kind=eq.${kind}`);
  }
  if (songUrl) {
    filters.push(`user_id=eq.${uid}&song_url=eq.${encodeURIComponent(songUrl)}&kind=eq.${kind}`);
    const leaf = libraryTrackCanonicalUrl(songUrl);
    if (leaf && leaf !== songUrl) {
      filters.push(`user_id=eq.${uid}&song_url=eq.${encodeURIComponent(leaf)}&kind=eq.${kind}`);
    }
  }
  if (!filters.length) return;
  await Promise.all(
    filters.map((filter) =>
      fetch(`${SUPABASE_URL}/rest/v1/user_songs?${filter}`, {
        method: "DELETE",
        headers: {
          apikey: SUPABASE_ANON_KEY,
          Authorization: `Bearer ${token}`,
          Prefer: "return=minimal",
        },
      }).catch(() => null),
    ),
  );
}

/** Delete ONE cloud row by id — used when only a single row must go. */
async function supabaseDeleteUserSongRowById(rowId) {
  await supabaseDeleteUserSongRowsByIds([rowId]);
}

/** Batch delete duplicate cloud rows (chunked `id=in.(…)` — one pool slot per chunk). */
async function supabaseDeleteUserSongRowsByIds(rowIds) {
  const token = getSupabaseAuthToken();
  if (!token || !authSession?.user?.id) return;
  const ids = [...new Set(
    (rowIds || []).map((x) => String(x || "").trim()).filter(isPostgresUuidString),
  )];
  if (!ids.length) return;
  const uid = encodeURIComponent(authSession.user.id);
  const CHUNK = 32;
  for (let i = 0; i < ids.length; i += CHUNK) {
    const chunk = ids.slice(i, i + CHUNK);
    const inList = chunk.map((id) => encodeURIComponent(id)).join(",");
    await fetch(
      `${SUPABASE_URL}/rest/v1/user_songs?user_id=eq.${uid}&id=in.(${inList})`,
      {
        method: "DELETE",
        headers: {
          apikey: SUPABASE_ANON_KEY,
          Authorization: `Bearer ${token}`,
          Prefer: "return=minimal",
        },
      },
    ).catch(() => null);
  }
  invalidateUserSongsLoadCache();
}

/** Escape `LIKE`/`ILIKE` wildcards so `username=ilike…` is an exact handle match (underscore is special in SQL). */
function escapeUsernameForIlikeExact(handle) {
  return String(handle || "")
    .trim()
    .replace(/\\/g, "\\\\")
    .replace(/%/g, "\\%")
    .replace(/_/g, "\\_");
}

async function fetchPublicProfileRowByUserId(userId) {
  const uid = String(userId || "").trim();
  if (!uid || !SUPABASE_URL || !SUPABASE_ANON_KEY) return null;
  const headers = { apikey: SUPABASE_ANON_KEY, Accept: "application/json" };
  const base = `${SUPABASE_URL}/rest/v1/profiles`;
  const selFull = "user_id,username,avatar,bio,voice_timbre,sound_certified";
  const selCore = "user_id,username,avatar,bio,voice_timbre";
  const filter = `user_id=eq.${encodeURIComponent(uid)}`;
  const tryOne = async (selectList) => {
    try {
      const r = await fetch(`${base}?${filter}&select=${selectList}&limit=1`, {
        headers,
        cache: "no-store",
      });
      if (!r.ok) return null;
      const arr = await r.json().catch(() => []);
      return Array.isArray(arr) && arr[0] ? arr[0] : null;
    } catch {
      return null;
    }
  };
  return (await tryOne(selFull)) || (await tryOne(selCore));
}

/** Public `profiles` row by handle — anon when `profiles_select_public_directory` exists. */
async function fetchPublicProfileRowByUsername(username) {
  const handle = String(username || "").replace(/^@/, "").trim();
  if (!handle || !SUPABASE_URL || !SUPABASE_ANON_KEY) return null;
  const headers = { apikey: SUPABASE_ANON_KEY, Accept: "application/json" };
  const base = `${SUPABASE_URL}/rest/v1/profiles`;
  const selFull = "user_id,username,avatar,bio,voice_timbre,sound_certified";
  const selCore = "user_id,username,avatar,bio,voice_timbre";
  const eq = `username=eq.${encodeURIComponent(handle)}`;
  const il = `username=ilike.${encodeURIComponent(escapeUsernameForIlikeExact(handle))}`;
  const tryOne = async (filter, selectList) => {
    try {
      const r = await fetch(`${base}?${filter}&select=${selectList}&limit=1`, {
        headers,
        cache: "no-store",
      });
      if (!r.ok) return null;
      const arr = await r.json().catch(() => []);
      return Array.isArray(arr) && arr[0] ? arr[0] : null;
    } catch {
      return null;
    }
  };
  // `sound_certified` breaks the whole request if the column is not migrated yet — fall back to `selCore`.
  // `eq` is case-sensitive — try escaped `ilike` second so `@Samy_CEO` still resolves.
  return (
    (await tryOne(eq, selFull)) ||
    (await tryOne(eq, selCore)) ||
    (await tryOne(il, selFull)) ||
    (await tryOne(il, selCore))
  );
}

function mapPublicLibrarySongRows(arr, selectedPublishedAt) {
  if (!Array.isArray(arr)) return [];
  return arr
    .map((s) =>
      attachDiscoverFieldsToTrack(
        {
          id: String(s.id || ""),
          ts: selectedPublishedAt ? userSongPublishedTs(s) : new Date(s.created_at || Date.now()).getTime(),
          createdTs: new Date(s.created_at || Date.now()).getTime(),
          publishedAt: selectedPublishedAt ? userSongPublishedAtValue(s) : "",
          title: s.title || "Generated song",
          artUrl: s.art_url || "",
          url: s.song_url || "",
          taskId: s.task_id || "",
          audioId: s.audio_id || "",
          kind: s.kind || "full",
          meta: {
            ...(s.meta_remix_of ? { remixOf: s.meta_remix_of } : {}),
            ...(s.meta_mashup_of ? { mashupOf: s.meta_mashup_of } : {}),
            ...(String(s.meta_release_caption || "").trim() ? { releaseCaption: String(s.meta_release_caption).trim() } : {}),
            ...(s.meta_challenge ? { challenge: s.meta_challenge } : {}),
            ...(String(s.meta_featured_on_profile || "").toLowerCase() === "true" ? { featuredOnProfile: true } : {}),
          },
          publicOnProfile: true,
        },
        s,
      ),
    )
    .filter((t) => isDiscoverFeedActive(t))
    .sort((a, b) => Number(b.ts || 0) - Number(a.ts || 0));
}

/** Fetch a set of public songs by id (for repost originals), keyed by song
 *  id. Returns playable track objects with userId attached. Safe if the
 *  table/columns are missing — resolves to an empty map. */
async function fetchPublicSongsByIds(ids) {
  const out = new Map();
  const uuids = [...new Set((ids || []).map((x) => String(x || "").trim()).filter(Boolean))].slice(0, 60);
  if (!uuids.length || !SUPABASE_URL || !SUPABASE_ANON_KEY) return out;
  const cols =
    "user_id,id,created_at,published_at,title,song_url,task_id,audio_id,kind,art_url,meta_remix_of:meta->remixOf,meta_mashup_of:meta->mashupOf,meta_release_caption:meta->>releaseCaption,meta_challenge:meta->challenge,meta_featured_on_profile:meta->>featuredOnProfile";
  const colsLegacy = cols.replace(",published_at", "");
  const inList = uuids.map((id) => `"${id}"`).join(",");
  const token = getSupabaseAuthToken();
  const headers = { apikey: SUPABASE_ANON_KEY, ...(token ? { Authorization: `Bearer ${token}` } : {}) };
  const guard = `&or=${encodeURIComponent("(art_url.is.null,art_url.not.like.data:*)")}`;
  try {
    let selectedPublishedAt = true;
    let r = await fetch(
      `${SUPABASE_URL}/rest/v1/user_songs?id=in.(${inList})&public_on_profile=eq.true&select=${cols}${guard}`,
      { headers, cache: "no-store" },
    );
    if (!r.ok) {
      const txt = await r.clone().text().catch(() => "");
      if (/published_at|42703|column/i.test(txt)) {
        selectedPublishedAt = false;
        r = await fetch(
          `${SUPABASE_URL}/rest/v1/user_songs?id=in.(${inList})&public_on_profile=eq.true&select=${colsLegacy}${guard}`,
          { headers, cache: "no-store" },
        );
      }
    }
    if (!r.ok) return out;
    const rows = await r.json().catch(() => []);
    const deduped = dedupePublicSongRowsRaw(Array.isArray(rows) ? rows : []);
    for (const s of deduped) {
      const mapped = mapPublicLibrarySongRows([s], selectedPublishedAt)[0];
      if (!mapped) continue;
      mapped.userId = String(s.user_id || "");
      out.set(String(s.id || ""), mapped);
    }
  } catch {}
  return out;
}

/** Reposts by the users you follow (newest first). Safe if the table is
 *  missing (returns []) so reposts degrade gracefully before the migration. */
async function fetchFollowingRepostsForFeed(followingIds, limit = 40) {
  const ids = (followingIds || [])
    .map((x) => String(x || "").trim())
    .filter(Boolean)
    .slice(0, FRIENDS_FEED_LIBRARY_USERS);
  if (!ids.length || !SUPABASE_URL || !SUPABASE_ANON_KEY) return [];
  const inList = ids.map((id) => `"${id}"`).join(",");
  const token = getSupabaseAuthToken();
  const headers = { apikey: SUPABASE_ANON_KEY, ...(token ? { Authorization: `Bearer ${token}` } : {}) };
  const lim = Math.min(60, Math.max(1, Number(limit) || 40));
  try {
    const r = await fetch(
      `${SUPABASE_URL}/rest/v1/social_reposts?user_id=in.(${inList})&target_kind=eq.song&select=id,user_id,target_id,body,created_at&order=created_at.desc&limit=${lim}`,
      { headers, cache: "no-store" },
    );
    if (!r.ok) return [];
    const rows = await r.json().catch(() => []);
    return (Array.isArray(rows) ? rows : [])
      .map((row) => ({
        id: String(row.id || ""),
        userId: String(row.user_id || ""),
        targetId: String(row.target_id || ""),
        body: String(row.body || ""),
        ts: new Date(row.created_at || 0).getTime() || 0,
      }))
      .filter((x) => x.id && x.targetId);
  } catch {
    return [];
  }
}

