/** Drop duplicate public rows of the same song (same audio_id + kind per
 *  user). Legacy URL-drift duplicates can linger in the cloud until the
 *  owner's app cleans them up — viewers should never see them twice.
 *  Rows arrive published-first, so the first occurrence wins. */
function dedupePublicSongRowsRaw(arr) {
  const seen = new Set();
  const out = [];
  for (const s of Array.isArray(arr) ? arr : []) {
    const uid = String(s?.user_id || "").trim();
    const aid = String(s?.audio_id || "").trim();
    const kind = String(s?.kind || "full").trim();
    const taskId = String(s?.task_id || "").trim();
    const url = libraryTrackCanonicalUrl(String(s?.song_url || "").trim());
    const key = aid && uid
      ? `aid:${aid}|${kind}|${uid}`
      : taskId && uid
        ? `tid:${taskId}|${kind}|${uid}`
        : url && uid
          ? `url:${url}|${kind}|${uid}`
          : `id:${String(s?.id || "")}`;
    if (!key.startsWith("id:") && seen.has(key)) continue;
    seen.add(key);
    out.push(s);
  }
  return out;
}

async function supabaseFetchPublicLibraryRowsForFilter(filterQuery, perUserLimit = 80) {
  if (!SUPABASE_URL || !SUPABASE_ANON_KEY || !filterQuery) return new Map();
  const lim = Math.min(120, Math.max(12, Number(perUserLimit) || 80));
  const colsWithPublished =
    "user_id,id,created_at,published_at,title,song_url,task_id,audio_id,kind,art_url,meta_remix_of:meta->remixOf,meta_mashup_of:meta->mashupOf,meta_release_caption:meta->>releaseCaption,meta_challenge:meta->challenge,meta_featured_on_profile:meta->>featuredOnProfile";
  const colsLegacy =
    "user_id,id,created_at,title,song_url,task_id,audio_id,kind,art_url,meta_remix_of:meta->remixOf,meta_mashup_of:meta->mashupOf,meta_release_caption:meta->>releaseCaption,meta_challenge:meta->challenge,meta_featured_on_profile:meta->>featuredOnProfile";
  const artUrlGuard = `&or=${encodeURIComponent("(art_url.is.null,art_url.not.like.data:*)")}`;
  const authHeaders = () => {
    const token = getSupabaseAuthToken();
    return {
      apikey: SUPABASE_ANON_KEY,
      ...(token ? { Authorization: `Bearer ${token}` } : {}),
    };
  };
  try {
    let r = await fetch(
      `${SUPABASE_URL}/rest/v1/user_songs?${filterQuery}&public_on_profile=eq.true&select=${colsWithPublished}&order=published_at.desc.nullslast,created_at.desc&limit=${lim}${artUrlGuard}`,
      { headers: authHeaders(), cache: "no-store" },
    );
    let selectedPublishedAt = true;
    if (!r.ok) {
      const txt = await r.clone().text().catch(() => "");
      if (/published_at|42703|column/i.test(txt)) {
        selectedPublishedAt = false;
        r = await fetch(
          `${SUPABASE_URL}/rest/v1/user_songs?${filterQuery}&public_on_profile=eq.true&select=${colsLegacy}&order=created_at.desc&limit=${lim}${artUrlGuard}`,
          { headers: authHeaders(), cache: "no-store" },
        );
      }
    }
    if (!r.ok) return new Map();
    const arr = dedupePublicSongRowsRaw(await r.json().catch(() => []));
    const byUser = new Map();
    for (const s of Array.isArray(arr) ? arr : []) {
      const uid = String(s.user_id || "").trim();
      if (!uid) continue;
      if (!byUser.has(uid)) byUser.set(uid, []);
      byUser.get(uid).push(s);
    }
    const out = new Map();
    for (const [uid, rows] of byUser) {
      out.set(uid, mapPublicLibrarySongRows(rows, selectedPublishedAt));
    }
    return out;
  } catch {
    return new Map();
  }
}

/** Library songs the owner marked `public_on_profile` (separate RLS policy). */
async function supabaseFetchPublicLibraryForUserId(userId) {
  const uid = String(userId || "").trim();
  if (!uid) return [];
  const batch = await supabaseFetchPublicLibraryRowsForFilter(
    `user_id=eq.${encodeURIComponent(uid)}`,
    PROFILE_PUBLIC_POSTS_LIMIT,
  );
  return batch.get(uid) || [];
}

function invalidateOwnerPublicPostsCache() {
  _ownerPublicPostsCache = null;
}

function enrichOwnerPublicPostsFromLibrary(cloudSongs) {
  const local = loadLibrary();
  const bySig = new Map();
  const byCloudId = new Map();
  for (const t of local) {
    bySig.set(librarySyncSigOf(t), t);
    const cid = String(t.cloudSongId || "").trim();
    if (cid) byCloudId.set(cid, t);
  }
  return (cloudSongs || []).map((c) => {
    let localCopy = byCloudId.get(String(c.id || "")) || bySig.get(librarySyncSigOf(c));
    if (!localCopy) {
      const taskId = String(c.taskId || "").trim();
      const audioId = String(c.audioId || "").trim();
      if (taskId && audioId) {
        localCopy = local.find(
          (t) => String(t.taskId || "").trim() === taskId && String(t.audioId || "").trim() === audioId,
        );
      }
    }
    if (localCopy) return mergeLibraryCloudWithLocal(c, localCopy);
    return { ...c, publicOnProfile: true };
  });
}

function getOwnerPublicPostsSongs() {
  return _ownerPublicPostsCache?.songs || null;
}

function getOwnerPublicPostCount() {
  const cached = _ownerPublicPostsCache?.songs;
  if (Array.isArray(cached)) return cached.length;
  return loadLibrary().filter((t) => String(t?.url || "").trim() && Boolean(t.publicOnProfile)).length;
}

/** Cloud is source of truth for public posts — same list visitors see on #/u/you. */
async function refreshOwnerPublicPostsCache(opts = {}) {
  const uid = authSession?.user?.id;
  if (!uid) {
    _ownerPublicPostsCache = { at: Date.now(), songs: [] };
    return [];
  }
  const force = Boolean(opts.force);
  if (
    !force &&
    _ownerPublicPostsCache &&
    Date.now() - _ownerPublicPostsCache.at < OWNER_PUBLIC_POSTS_CACHE_MS
  ) {
    return _ownerPublicPostsCache.songs;
  }
  try {
    const batch = await supabaseFetchPublicLibraryRowsForFilter(
      `user_id=eq.${encodeURIComponent(String(uid))}`,
      PROFILE_PUBLIC_POSTS_LIMIT,
    );
    const raw = batch.get(String(uid)) || [];
    const songs = enrichOwnerPublicPostsFromLibrary(raw).map((t) => ({
      ...t,
      userId: String(uid),
    }));
    const prevLen = _ownerPublicPostsCache?.songs?.length;
    _ownerPublicPostsCache = { at: Date.now(), songs };
    if (prevLen != null && prevLen !== songs.length) {
      _profileActSnapshot = null;
      try {
        sessionStorage.removeItem(PROFILE_ACT_SNAPSHOT_KEY);
      } catch {}
    }
    return songs;
  } catch {
    return _ownerPublicPostsCache?.songs || [];
  }
}

/** One request for many followed creators' public libraries (Friends feed). */
async function supabaseFetchPublicLibraryForUserIds(userIds, maxRows = null) {
  const ids = [...new Set((userIds || []).map((id) => String(id || "").trim()).filter(Boolean))];
  if (!ids.length) return new Map();
  const rowLimit = Math.min(
    120,
    Math.max(12, Number(maxRows) || ids.length * 12),
  );
  if (ids.length === 1) {
    return supabaseFetchPublicLibraryRowsForFilter(
      `user_id=eq.${encodeURIComponent(ids[0])}`,
      rowLimit,
    );
  }
  const inList = ids.map((id) => encodeURIComponent(id)).join(",");
  return supabaseFetchPublicLibraryRowsForFilter(`user_id=in.(${inList})`, rowLimit);
}

function remixMetaFromSongMeta(meta) {
  if (!meta || typeof meta !== "object") return { lyricsInput: "", styleInput: "" };
  const lyricsInput = String(meta.lyricsInput || meta.finalPrompt || meta.prompt || "").trim();
  const styleInput = String(meta.styleInput || meta.styleSent || meta.styleTags || meta.style || "").trim();
  return { lyricsInput, styleInput };
}

async function supabaseFetchPublicSongRemixMeta({ songId, ownerUserId }) {
  const sid = String(songId || "").trim();
  const uid = String(ownerUserId || "").trim();
  if (!sid || !uid || !SUPABASE_URL || !SUPABASE_ANON_KEY) return { lyricsInput: "", styleInput: "" };
  try {
    const token = getSupabaseAuthToken();
    const filter = `id=eq.${encodeURIComponent(sid)}&user_id=eq.${encodeURIComponent(uid)}&public_on_profile=eq.true`;
    const r = await fetch(
      `${SUPABASE_URL}/rest/v1/user_songs?${filter}&select=meta&limit=1`,
      {
        headers: {
          apikey: SUPABASE_ANON_KEY,
          ...(token ? { Authorization: `Bearer ${token}` } : {}),
        },
        cache: "no-store",
      },
    );
    if (!r.ok) return { lyricsInput: "", styleInput: "" };
    const arr = await r.json().catch(() => []);
    return remixMetaFromSongMeta(Array.isArray(arr) ? arr[0]?.meta : null);
  } catch {
    return { lyricsInput: "", styleInput: "" };
  }
}

let currentUserPublicProfileId = "";
let currentUserPublicSocialStats = { followers: 0, following: 0, isFollowing: false, followsViewer: false };

function socialApiErrorMessage(err) {
  const status = Number(err?.status || 0);
  const msg = String(err?.message || "").trim();
  if (status === 403 || /403|forbidden/i.test(msg)) {
    if (SUPABASE_URL && SUPABASE_ANON_KEY && getSupabaseAuthToken()) {
      return "Could not load Friends. Check your connection and try again.";
    }
    return "App settings could not load. Hard-refresh the page or reopen the app.";
  }
  if (/failed to fetch|load failed|networkerror|aborted/i.test(msg)) {
    if (!isNativeShell()) {
      return "Network error loading Friends. Hard-refresh the page (Cmd+Shift+R). If it persists, check docs/LOGIN_403_VERCEL.md.";
    }
    return "Network error loading Friends. If you use Vercel protection, the API may be blocked — check docs/LOGIN_403_VERCEL.md.";
  }
  return msg || "Please try again in a moment.";
}

async function socialApi(path, opts = {}) {
  const timeoutMs = Math.max(4000, Number(opts?.timeoutMs) || 12000);
  const { timeoutMs: _drop, ...fetchOpts } = opts;
  const run = async (signal) => {
    const token = getSupabaseAuthToken();
    const headers = {
      Accept: "application/json",
      ...(fetchOpts?.headers || {}),
    };
    if (token) headers.Authorization = `Bearer ${token}`;
    if (fetchOpts?.body && !headers["Content-Type"]) headers["Content-Type"] = "application/json";
    const r = await apiFetch(path, {
      ...fetchOpts,
      headers,
      cache: "no-store",
      signal,
    });
    const data = await r.json().catch(() => null);
    if (!r.ok) {
      const err = new Error(data?.error || `Social request failed (${r.status})`);
      err.status = r.status;
      throw err;
    }
    return data;
  };
  const ctrl = new AbortController();
  const timer = window.setTimeout(() => ctrl.abort(), timeoutMs);
  try {
    return await run(ctrl.signal);
  } catch (e) {
    if (e?.name === "AbortError") {
      throw new Error("Request timed out — check your connection and try again.");
    }
    if (isNativeShell() && !_resolvedApiBase) {
      const fixed = await ensureNativeApiBaseResolved();
      if (fixed) {
        const retry = new AbortController();
        const retryTimer = window.setTimeout(() => retry.abort(), timeoutMs);
        try {
          return await run(retry.signal);
        } finally {
          window.clearTimeout(retryTimer);
        }
      }
    }
    throw e;
  } finally {
    window.clearTimeout(timer);
  }
}

