async function messagesApi(path, opts = {}) {
  const timeoutMs = Math.max(4000, Number(opts?.timeoutMs) || 12000);
  const { timeoutMs: _drop, ...fetchOpts } = opts;
  const run = async (signal) => {
    const token = getSupabaseAuthToken();
    const headers = {
      Accept: "application/json",
      ...(fetchOpts?.headers || {}),
    };
    if (token) headers.Authorization = `Bearer ${token}`;
    if (fetchOpts?.body && !headers["Content-Type"]) headers["Content-Type"] = "application/json";
    const r = await apiFetch(path, {
      ...fetchOpts,
      headers,
      cache: "no-store",
      signal,
    });
    const data = await r.json().catch(() => null);
    if (!r.ok) {
      const err = new Error(data?.error || `Messages request failed (${r.status})`);
      err.status = r.status;
      throw err;
    }
    return data;
  };
  const ctrl = new AbortController();
  const timer = window.setTimeout(() => ctrl.abort(), timeoutMs);
  try {
    return await run(ctrl.signal);
  } catch (e) {
    if (e?.name === "AbortError") {
      throw new Error("Request timed out — check your connection and try again.");
    }
    if (isNativeShell() && !_resolvedApiBase) {
      const fixed = await ensureNativeApiBaseResolved();
      if (fixed) {
        const retry = new AbortController();
        const retryTimer = window.setTimeout(() => retry.abort(), timeoutMs);
        try {
          return await run(retry.signal);
        } finally {
          window.clearTimeout(retryTimer);
        }
      }
    }
    throw e;
  } finally {
    window.clearTimeout(timer);
  }
}

const DM_SONG_MARKER = "nabad_dm";

function dmShareKindFromTrack(t) {
  const meta = t?.meta || {};
  if (meta.mashupOf || String(t?.kind || "").toLowerCase() === "mashup") return "mashup";
  if (meta.remixOf || String(t?.kind || "").toLowerCase() === "remix") return "remix";
  return "song";
}

function dmShareEligibleTracks() {
  return loadLibrary()
    .filter((t) => String(t?.url || "").trim())
    .map((t) => {
      const ref = mashupRefFromLibraryTrack(t);
      if (!ref) return null;
      ref.shareKind = dmShareKindFromTrack(t);
      ref.ts = Number(t?.ts || 0);
      return ref;
    })
    .filter(Boolean)
    .sort((a, b) => Number(b?.ts || 0) - Number(a?.ts || 0));
}

function dmSongPayloadFromShareRef(ref) {
  const title = String(ref?.title || "Song").trim() || "Song";
  const url = String(ref?.url || "").trim();
  let art = String(ref?.artUrl || ref?.art || "").trim();
  if (!art && ref) {
    try { art = mashupCoverForTrack(ref) || ""; } catch {}
  }
  if (!art) art = "./assets/nabadai-logo.png";
  let by = String(ref?.byLine || ref?.by || "").replace(/^@/, "").trim();
  if (!by) {
    by = String(activeProfile?.username || authSession?.user?.user_metadata?.username || "").replace(/^@/, "").trim();
  }
  const kind = String(ref?.shareKind || dmShareKindFromTrack(ref) || ref?.kind || "song").trim().toLowerCase();
  const songId = String(ref?.songId || ref?.cloudSongId || ref?.id || "").trim();
  return JSON.stringify({
    [DM_SONG_MARKER]: "song",
    id: songId,
    t: title.slice(0, 120),
    u: url,
    a: art,
    b: by.slice(0, 80),
    k: kind === "mashup" || kind === "remix" ? kind : "song",
  });
}

function dmSongPayloadFromTrack(track) {
  const shareKind = dmShareKindFromTrack(track);
  return dmSongPayloadFromShareRef({ ...track, shareKind });
}

// A DM song message embeds the audio URL directly in the message body. Raw Suno
// CDN links are temporary and expire, so a recipient who opens the message later
// can't play the song (the proxy gets a dead upstream). Resolve to the permanent
// Supabase `song_archive` URL before sending: prefer an already-archived copy,
// otherwise archive the user's own Library track on demand. Falls back to the
// original URL if archiving isn't possible (e.g. someone else's public track),
// so sharing never gets blocked.
async function resolveShareableAudioUrl(ref) {
  const current = String(ref?.url || "").trim();
  if (!current || isArchivedSongStorageUrl(current)) return current;
  const localId = String(ref?.id || "").trim();
  if (localId) {
    try {
      const row = loadLibrary().find((r) => String(r?.id || "") === localId);
      if (row && isArchivedSongStorageUrl(row.url)) return String(row.url).trim();
    } catch {}
    try {
      const permanent = await archiveLibraryTrackToCloud(ref);
      if (permanent && isArchivedSongStorageUrl(permanent)) return permanent;
    } catch {}
  }
  return current;
}

function shareRefFromTrackSheetCtx(ctx) {
  if (!ctx) return null;
  const url = String(ctx.url || "").trim();
  if (!url) return null;
  const handle = String(ctx.handle || "").trim();
  const byLine = String(ctx.by || "").trim() || (handle ? `@${handle}` : "");
  return {
    url,
    title: String(ctx.title || "Song").trim() || "Song",
    artUrl: String(ctx.art || "").trim(),
    songId: String(ctx.songId || "").trim(),
    ownerUserId: String(ctx.ownerUserId || "").trim(),
    byLine,
    meta: ctx.meta || null,
    shareKind: dmShareKindFromTrack({ meta: ctx.meta, kind: ctx.kind }),
  };
}

