function closeMessagesShareSheet() {
  const sheet = document.getElementById("messagesShareSheet");
  if (!sheet) return;
  sheet.hidden = true;
  sheet.setAttribute("aria-hidden", "true");
  document.body.classList.remove("messagesShareSheetOpen");
  hideMessagesShareConfirm();
}

const MESSAGES_SHARE_LEAD_DEFAULT = "Pick a song, remix, or mashup from your Library.";
let _messagesShareConfirmTrack = null;

// Step 2 of the share flow: after the user taps a song, show a simple confirm
// card (cover + title) so they can double-check the exact song before it's sent.
function showMessagesShareConfirm(track) {
  const list = document.getElementById("messagesShareList");
  const confirm = document.getElementById("messagesShareConfirm");
  const lead = document.getElementById("messagesShareLead");
  if (!confirm || !track) return;
  _messagesShareConfirmTrack = track;
  const title = escapeHtml(String(track.title || "Song").trim() || "Song");
  const sub = escapeHtml(`${dmShareKindLabel(track.shareKind)} · ${mashupSlotSourceLabel(track)}`);
  const art = escapeHtml(mashupCoverForTrack(track));
  const handle = String(_chatHeaderUser?.username || "").replace(/^@/, "").trim();
  if (lead) lead.textContent = handle ? `Send this song to @${handle}?` : "Send this song?";
  confirm.innerHTML = `
    <div class="messagesShareConfirmCard">
      <img class="messagesShareConfirmArt" src="${art}" alt="" decoding="async" />
      <div class="messagesShareConfirmInfo">
        <strong class="messagesShareConfirmTitle">${title}</strong>
        <span class="messagesShareConfirmSub">${sub}</span>
      </div>
    </div>
    <div class="messagesShareConfirmActions">
      <button type="button" class="messagesShareConfirmBack" data-share-confirm-back>Choose another</button>
      <button type="button" class="messagesShareConfirmSend" data-share-confirm-send>Send</button>
    </div>`;
  if (list) list.hidden = true;
  confirm.hidden = false;
  confirm.setAttribute("aria-hidden", "false");
  // Pre-warm archiving so the permanent URL is usually ready by the time the
  // user taps Send (avoids sharing an expiring Suno CDN link).
  try {
    if (!isArchivedSongStorageUrl(track.url)) queueArchiveLibraryTrack(track);
  } catch {}
}

function hideMessagesShareConfirm() {
  const list = document.getElementById("messagesShareList");
  const confirm = document.getElementById("messagesShareConfirm");
  const lead = document.getElementById("messagesShareLead");
  _messagesShareConfirmTrack = null;
  if (confirm) {
    confirm.hidden = true;
    confirm.setAttribute("aria-hidden", "true");
    confirm.innerHTML = "";
  }
  if (list) list.hidden = false;
  if (lead) lead.textContent = MESSAGES_SHARE_LEAD_DEFAULT;
}

async function openMessagesShareSheet() {
  const sheet = document.getElementById("messagesShareSheet");
  const list = document.getElementById("messagesShareList");
  if (!sheet || !list) return;
  sheet.hidden = false;
  sheet.setAttribute("aria-hidden", "false");
  document.body.classList.add("messagesShareSheetOpen");
  hideMessagesShareConfirm();
  list.innerHTML = `<div class="messagesShareEmpty">Loading your Library…</div>`;
  await ensureUserLibraryHydrated();
  const tracks = dmShareEligibleTracks();
  if (!tracks.length) {
    list.innerHTML = `<div class="messagesShareEmpty">No songs in your Library yet. Create one first, then share it here.</div>`;
    return;
  }
  list.innerHTML = tracks.map((t, idx) => {
    const title = escapeHtml(String(t.title || "Song").trim() || "Song");
    const sub = escapeHtml(`${dmShareKindLabel(t.shareKind)} · ${mashupSlotSourceLabel(t)}`);
    const art = escapeHtml(mashupCoverForTrack(t));
    return `
      <button type="button" class="messagesShareRow" data-messages-share-idx="${idx}" role="option">
        <img class="messagesShareRowArt" src="${art}" alt="" loading="lazy" decoding="async" />
        <span class="messagesShareRowBody">
          <strong>${title}</strong>
          <span>${sub}</span>
        </span>
      </button>`;
  }).join("");
  _messagesShareCandidates = tracks;
}

let _messagesShareCandidates = [];

async function sendDmSongShare(track) {
  const threadId = String(_conversationId || "").trim();
  if (!threadId || !track) return;
  const shareUrl = await resolveShareableAudioUrl(track);
  const shareTrack = shareUrl && shareUrl !== track.url ? { ...track, url: shareUrl } : track;
  const body = dmSongPayloadFromTrack(shareTrack);
  if (body.length > 500) {
    try { showToast("Song is too large to share in one message.", { icon: "🎵", durationMs: 2800 }); } catch {}
    return;
  }
  try {
    const data = await messagesApi("/api/messages", {
      method: "POST",
      body: JSON.stringify({ action: "send_message", threadId, body }),
    });
    closeMessagesShareSheet();
    const msg = data?.message;
    if (msg) {
      appendThreadMessages([msg]);
    } else {
      await pollNewThreadMessages(threadId);
    }
    try { syncDiscoveryPlayingHighlights(); } catch {}
    void refreshMessagesUnreadBadge({ force: true });
  } catch (e) {
    try { showToast(String(e?.message || "Could not share song"), { icon: "🎵", durationMs: 2800 }); } catch {}
    const sendBtn = document.querySelector("[data-share-confirm-send]");
    if (sendBtn) {
      sendBtn.removeAttribute("aria-busy");
      sendBtn.textContent = "Send";
    }
  }
}

function messagesAvatarHtml(avatarUrl, username, cls = "messagesRowAvatar") {
  const raw = String(avatarUrl || "").trim();
  const handle = String(username || "").trim();
  if (isRealUserAvatarUrl(raw)) {
    return `<img class="${cls}" src="${escapeHtml(normalizeProfileAvatarForImg(raw))}" alt="" loading="lazy" decoding="async" />`;
  }
  const letter = handle.replace(/^@/, "").slice(0, 1).toUpperCase() || "?";
  return `<span class="${cls} messagesAvatarFallback" aria-hidden="true">${escapeHtml(letter)}</span>`;
}

function syncFriendsMessagesBtn() {
  const btn = document.getElementById("friendsMessagesBtn");
  if (!btn) return;
  btn.hidden = !(MESSAGES_FEATURE_ENABLED && Boolean(authSession?.user?.id));
}

function updateMessagesUnreadBadge(count) {
  _messagesUnreadCount = Math.max(0, Number(count || 0));
  const badge = document.getElementById("friendsMessagesBadge");
  const btn = document.getElementById("friendsMessagesBtn");
  const n = _messagesUnreadCount;
  const hasUnread = n > 0;
  if (badge) {
    if (n > 0) {
      badge.hidden = false;
      badge.textContent = n > 99 ? "99+" : String(n);
    } else {
      badge.hidden = true;
      badge.textContent = "";
    }
  }
  if (btn) {
    btn.classList.toggle("hasNotice", hasUnread);
    const label = hasUnread ? `Messages, ${n} unread` : "Messages";
    btn.setAttribute("aria-label", label);
  }
  try {
    els.friendsTabLink?.classList?.toggle?.("hasNotice", hasUnread);
    // `n` is the number of unread DM conversations (one per thread), not the
    // total unread messages — the API counts threads, not message rows.
    const friendsLabel = hasUnread
      ? `Friends, ${n} unread ${n === 1 ? "conversation" : "conversations"}`
      : "Friends";
    els.friendsTabLink?.setAttribute?.("aria-label", friendsLabel);
    if (els.friendsTabBadge) {
      if (!hasUnread) {
        els.friendsTabBadge.hidden = true;
        els.friendsTabBadge.classList.remove("friendsTabDmBadge--dots");
        els.friendsTabBadge.textContent = "";
      } else if (n === 1) {
        // Exactly one unread conversation: chat bubble with three dots, no number.
        els.friendsTabBadge.hidden = false;
        els.friendsTabBadge.classList.add("friendsTabDmBadge--dots");
        els.friendsTabBadge.innerHTML =
          '<span class="dmDots"><span class="dmDot"></span><span class="dmDot"></span><span class="dmDot"></span></span>';
      } else {
        // Two or more unread conversations: chat bubble with the count (9+ for 10+).
        els.friendsTabBadge.hidden = false;
        els.friendsTabBadge.classList.remove("friendsTabDmBadge--dots");
        els.friendsTabBadge.textContent = n > 9 ? "9+" : String(n);
      }
    }
  } catch {}
}

async function refreshMessagesUnreadBadge({ force = false } = {}) {
  if (!MESSAGES_FEATURE_ENABLED) {
    updateMessagesUnreadBadge(0);
    return;
  }
  syncFriendsMessagesBtn();
  if (!authSession?.user?.id) {
    updateMessagesUnreadBadge(0);
    return;
  }
  const now = Date.now();
  if (_messagesUnreadFetchInFlight) return;
  if (!force && now - _messagesUnreadLastFetchedAt < 45000) return;
  _messagesUnreadFetchInFlight = true;
  try {
    const data = await messagesApi("/api/messages?type=unread_count");
    updateMessagesUnreadBadge(data?.count || 0);
    _messagesUnreadLastFetchedAt = now;
  } catch (e) {
    console.warn("[messages/badge]", e);
  } finally {
    _messagesUnreadFetchInFlight = false;
  }
}

