function isRealUserAvatarUrl(raw) {
  const s = String(raw || "").trim();
  if (!s) return false;
  return !/nabadai-logo\.png/i.test(s);
}

/** Other-user profile avatar: real photo when available; person silhouette otherwise — never the app logo. */
function applyUserPublicAvatar(url, displayName = "") {
  const img = els.userPublicAvatar;
  if (!img) return;
  const normalized = normalizeProfileAvatarForImg(String(url || "").trim());
  const handle = String(displayName || "").trim();
  img.onerror = () => {
    try {
      img.removeAttribute("src");
      img.dataset.empty = "true";
    } catch {}
  };
  if (isRealUserAvatarUrl(normalized)) {
    img.dataset.empty = "false";
    img.src = normalized;
    img.alt = handle ? `${handle} avatar` : "Profile avatar";
  } else {
    img.removeAttribute("src");
    img.dataset.empty = "true";
    img.alt = handle ? `${handle} profile` : "Profile";
  }
}

function setUserPublicLoading(on, username = "") {
  const loading = Boolean(on);
  els.userPublicCard?.setAttribute?.("data-loading", loading ? "true" : "false");
  const handle = String(username || "").replace(/^@/, "").trim();
  if (loading) {
    if (els.userPublicName && handle) els.userPublicName.textContent = `@${handle}`;
    applyUserPublicAvatar("", handle);
    if (els.userPublicVoice) els.userPublicVoice.style.display = "none";
    if (els.userPublicBio) els.userPublicBio.style.display = "none";
    if (els.userPublicStats) {
      els.userPublicStats.innerHTML = userPublicStatsSkeletonHtml();
      els.userPublicStats.style.display = "";
    }
    if (els.userPublicSongsCount) {
      els.userPublicSongsCount.textContent = "";
      els.userPublicSongsCount.hidden = true;
    }
    if (els.userPublicSongs) els.userPublicSongs.innerHTML = followingActivitySkeletonHtml();
    if (els.userPublicEmpty) els.userPublicEmpty.style.display = "none";
  }
}

function userPublicRelationLabel(stats) {
  if (!stats) return "";
  const following = Boolean(stats.isFollowing);
  const followsYou = Boolean(stats.followsViewer);
  if (following && followsYou) return "Following each other";
  if (followsYou) return "Follows you";
  return "";
}

function renderUserPublicFollowButton() {
  const btn = els.btnUserPublicFollow;
  const msgBtn = els.btnUserPublicMessage;
  const relationEl = els.userPublicFollowsYou;
  const followRow = els.userPublicFollowRow;
  const targetId = String(currentUserPublicProfileId || "").trim();
  const mine = String(authSession?.user?.id || "").trim();
  const canShow = Boolean(targetId && mine && targetId !== mine);
  if (followRow) followRow.hidden = !canShow;
  if (msgBtn) msgBtn.hidden = !(canShow && MESSAGES_FEATURE_ENABLED);
  if (relationEl) {
    const label = canShow ? userPublicRelationLabel(currentUserPublicSocialStats) : "";
    relationEl.textContent = label;
    relationEl.hidden = !label;
  }
  if (!btn) return;
  btn.hidden = !canShow;
  if (!canShow) return;
  const isFollowing = Boolean(currentUserPublicSocialStats?.isFollowing);
  btn.textContent = isFollowing ? "Following" : "Follow";
  btn.dataset.following = isFollowing ? "true" : "false";
  btn.setAttribute("aria-label", isFollowing ? "Unfollow creator" : "Follow creator");
  btn.title = isFollowing ? "Tap again to unfollow" : "Follow creator";
}

async function refreshUserPublicSocial({ username, userId, songCount }) {
  const data = await fetchSocialStatsForProfile({ username, userId });
  const targetId = data?.profile?.user_id || userId || "";
  currentUserPublicProfileId = String(targetId || "");
  currentUserPublicSocialStats = data?.stats || { followers: 0, following: 0, isFollowing: false, followsViewer: false };
  renderUserPublicSocialStats({ songCount, stats: currentUserPublicSocialStats });
  renderUserPublicFollowButton();
}

async function toggleCurrentUserPublicFollow() {
  const targetUserId = String(currentUserPublicProfileId || "").trim();
  if (!targetUserId) return;
  if (!authSession?.user?.id || !getSupabaseAuthToken()) {
    showToast("Sign in to follow creators.");
    location.hash = "#/auth";
    return;
  }
  const btn = els.btnUserPublicFollow;
  const wasFollowing = Boolean(currentUserPublicSocialStats?.isFollowing);
  if (wasFollowing) {
    const handle = String(els.userPublicName?.textContent || "").trim() || "this creator";
    let ok = true;
    try {
      ok = window.confirm(`Unfollow ${handle}?`);
    } catch {
      ok = true;
    }
    if (!ok) return;
  }
  if (btn) btn.disabled = true;
  try {
    const data = await socialApi("/api/social", {
      method: "POST",
      body: JSON.stringify({
        action: wasFollowing ? "unfollow" : "follow",
        targetUserId,
      }),
    });
    currentUserPublicSocialStats = data?.stats || {
      ...currentUserPublicSocialStats,
      isFollowing: !wasFollowing,
    };
    renderUserPublicSocialStats({
      songCount: parseInt(String(els.userPublicSongsCount?.textContent || "0"), 10) || 0,
      stats: currentUserPublicSocialStats,
    });
    renderUserPublicFollowButton();
    showToast(wasFollowing ? "Unfollowed creator." : "Following creator.");
    if (wasFollowing && (document.body.getAttribute("data-route") || "") === "friends") {
      void refreshDiscoveryFollowingFeed();
    }
  } catch (e) {
    showToast(e?.message || "Could not update follow.");
  } finally {
    if (btn) btn.disabled = false;
  }
}

async function showFollowingSummary() {
  if (!authSession?.user?.id) {
    showToast("Sign in to manage followed creators.");
    return;
  }
  try {
    const list = await fetchFollowingListForFeed();
    if (!list.length) {
      alert("Following\n\nYou are not following any creators yet.");
      return;
    }
    alert(`Following\n\n${list.map((x) => `@${x.username || x.userId}`).join("\n")}`);
  } catch (e) {
    showToast(e?.message || "Could not load following.");
  }
}

function notificationIconForType(type) {
  const t = String(type || "").trim();
  if (t === "follow") return "+";
  if (t === "remix") return "R";
  if (t === "song_feedback") return "♪";
  if (t === "social_like") return "♥";
  if (t === "social_reply") return "↩";
  if (t === "social_repost") return "↻";
  if (t === "play_milestone") return "▶";
  if (t === "chart_rank") return "★";
  if (t === "public_song") return "P";
  return "•";
}

function activityTypeBadgeSvg(type) {
  const t = String(type || "").trim();
  if (t === "chart_rank") {
    return `<svg viewBox="0 0 24 24" width="11" height="11" aria-hidden="true"><path fill="currentColor" d="M12 2.5 14.8 8l6.2.9-4.5 4.4 1.1 6.1L12 16.8 6.4 19.4l1.1-6.1L3 8.9 9.2 8 12 2.5Z"/></svg>`;
  }
  if (t === "social_like") {
    return `<svg viewBox="0 0 24 24" width="11" height="11" aria-hidden="true"><path fill="currentColor" d="M12 21s-7.2-4.35-9.6-8.55C.6 9.15 2.1 5.7 5.4 5.1c1.8-.3 3.45.45 4.35 1.95.9-1.5 2.55-2.25 4.35-1.95 3.3.6 4.8 4.05 3 7.35C19.2 16.65 12 21 12 21Z"/></svg>`;
  }
  if (t === "remix") {
    return `<svg viewBox="0 0 24 24" width="11" height="11" aria-hidden="true"><path fill="currentColor" d="M9 18V5l12-2v13"/><circle cx="6" cy="18" r="3" fill="currentColor"/><circle cx="18" cy="16" r="3" fill="currentColor"/></svg>`;
  }
  if (t === "follow") {
    return `<svg viewBox="0 0 24 24" width="11" height="11" aria-hidden="true"><circle cx="12" cy="8" r="3.5" fill="currentColor"/><path fill="currentColor" d="M4 20c.8-3.8 3.6-6 8-6s7.2 2.2 8 6H4Z"/></svg>`;
  }
  if (t === "play_milestone") {
    return `<svg viewBox="0 0 24 24" width="11" height="11" aria-hidden="true"><path fill="currentColor" d="M20 12v5H4v-5H2v7h20v-7h-2Zm-6 .5-7-4v8l7-4ZM4 9h16V4H4v5Z"/></svg>`;
  }
  if (t === "social_reply") {
    return `<svg viewBox="0 0 24 24" width="11" height="11" aria-hidden="true"><path fill="currentColor" d="M10 9V5l-7 7 7 7v-4.1c5 0 8.5 1.6 11 5.1-1-5.4-4-10.9-11-11Z"/></svg>`;
  }
  if (t === "social_repost") {
    return `<svg viewBox="0 0 24 24" width="11" height="11" aria-hidden="true"><path fill="currentColor" d="M17 1l4 4-4 4V6H9a4 4 0 0 0-4 4v1H3v-1a6 6 0 0 1 6-6h8V1ZM7 23l-4-4 4-4v3h8a4 4 0 0 0 4-4v-1h2v1a6 6 0 0 1-6 6H7v3Z"/></svg>`;
  }
  return `<svg viewBox="0 0 24 24" width="11" height="11" aria-hidden="true"><path fill="currentColor" d="M20 12v5H4v-5H2v7h20v-7h-2Zm-6 .5-7-4v8l7-4ZM4 9h16V4H4v5Z"/></svg>`;
}

function activityTypeBadgeHtml(type) {
  const t = String(type || "").trim() || "default";
  return `<span class="activityRowBadge activityRowBadge--${escapeHtml(t)}" aria-hidden="true">${activityTypeBadgeSvg(t)}</span>`;
}

function notificationTargetLabel(metadata) {
  const kind = String(metadata?.target_kind || "").trim();
  const title = String(metadata?.target_title || "").trim();
  if (title) {
    if (kind === "song") return `your song "${title}"`;
    if (kind === "echo") return `your echo`;
    if (kind === "status") return `your post: "${title.slice(0, 60)}${title.length > 60 ? "…" : ""}"`;
  }
  if (kind === "song") return "your song";
  if (kind === "echo") return "your echo";
  if (kind === "status") return "your post";
  return "your post";
}

function notificationMessage(n) {
  const username = String(n?.metadata?.actor_username || "").replace(/^@/, "").trim();
  if (n?.type === "follow") {
    return {
      title: username ? `@${username} started following you` : "Someone started following you",
      body: "They can now find your public songs in their Following feed.",
      action: username ? "View profile" : "",
    };
  }
  if (n?.type === "remix") {
    const original = String(n?.metadata?.original_title || "your song").trim();
    const remix = String(n?.metadata?.remix_title || "a new remix").trim();
    return {
      title: username ? `@${username} remixed your song` : "Someone remixed your song",
      body: `${remix} · from ${original}`,
      action: username ? "View creator" : "",
    };
  }
  if (n?.type === "song_feedback") {
    const title = String(n?.metadata?.song_title || "your song").trim();
    const label = String(n?.metadata?.feedback_label || "sent private feedback").trim();
    return {
      title: username ? `@${username} sent private feedback` : "Someone sent private feedback",
      body: `${label} · ${title}`,
      action: username ? "View song" : "",
    };
  }
  if (n?.type === "play_milestone") {
    const count = Number(n?.metadata?.play_count || 0);
    const title = String(n?.metadata?.song_title || "Your song").trim();
    return {
      title,
      body: count ? `${formatStatCount(count)} plays` : "Play milestone",
      action: "",
    };
  }
  if (n?.type === "chart_rank") {
    const rank = Number(n?.metadata?.rank || 0);
    const title = String(n?.metadata?.song_title || "Your song").trim();
    return {
      title: rank ? `${title} hit #${rank} on Top Songs this week` : `${title} charted on Top Songs this week`,
      body: "",
      action: "",
    };
  }
  if (n?.type === "public_song") {
    const title = String(n?.metadata?.song_title || "a new public song").trim();
    return {
      title: username ? `@${username} published a song` : "A creator published a song",
      body: title,
      action: username ? "View profile" : "",
    };
  }
  if (n?.type === "social_like") {
    const target = notificationTargetLabel(n?.metadata);
    return {
      title: username ? `@${username} liked ${target}` : `Someone liked ${target}`,
      body: "",
      action: username ? "View profile" : "",
    };
  }
  if (n?.type === "social_reply") {
    const target = notificationTargetLabel(n?.metadata);
    const preview = String(n?.metadata?.reply_preview || "").trim();
    return {
      title: username ? `@${username} replied to ${target}` : `Someone replied to ${target}`,
      body: preview ? `"${preview.slice(0, 140)}${preview.length > 140 ? "…" : ""}"` : "Open the thread to read the reply.",
      action: username ? "View profile" : "",
    };
  }
  if (n?.type === "social_repost") {
    const target = notificationTargetLabel(n?.metadata);
    return {
      title: username ? `@${username} reposted ${target}` : `Someone reposted ${target}`,
      body: "It went out to their followers' Friends feed.",
      action: username ? "View profile" : "",
    };
  }
  return {
    title: "New notification",
    body: "You have a fresh app update.",
    action: "",
  };
}

function renderNotificationRows(list) {
  if (!els.notificationsCenterList) return;
  if (!list.length) {
    els.notificationsCenterList.innerHTML = `
      <div class="notificationsEmpty">
        <div class="notificationsEmptyIcon" aria-hidden="true">♪</div>
        <strong>No notifications yet</strong>
        <span>When someone follows you or creator updates arrive, they will collect here.</span>
      </div>`;
    return;
  }
  els.notificationsCenterList.innerHTML = list.slice(0, 40).map((n) => {
    const msg = notificationMessage(n);
    const username = String(n?.metadata?.actor_username || "").replace(/^@/, "").trim();
    const actorUserId = String(n?.actor_user_id || "").trim();
    const icon = notificationIconForType(n?.type);
    const unread = !n?.read_at;
    const time = relativeTime(new Date(n?.created_at || Date.now()).getTime());
    const href = username
      ? `#/u/${encodeURIComponent(username)}${actorUserId ? `?uid=${encodeURIComponent(actorUserId)}` : ""}`
      : "";
    const actionHtml = href
      ? `<a class="notificationsItemAction" href="${href}" data-notifications-close="1">${escapeHtml(msg.action || "Open")}</a>`
      : "";
    return `
      <article class="notificationsItem${unread ? " isUnread" : ""}">
        <div class="notificationsItemAvatarWrap">
          ${activityActorAvatarHtml(n, "notificationsItemAvatar")}
          <span class="notificationsItemBadge" aria-hidden="true">${escapeHtml(icon)}</span>
        </div>
        <div class="notificationsItemBody">
          <div class="notificationsItemTop">
            <strong>${escapeHtml(msg.title)}</strong>
            <span>${escapeHtml(time)}</span>
          </div>
          <p>${escapeHtml(msg.body)}</p>
          ${actionHtml}
        </div>
        ${unread ? `<span class="notificationsUnreadDot" aria-label="Unread"></span>` : ""}
      </article>`;
  }).join("");
}

const ACTIVITY_FEED_SNAPSHOT_MS = 120000;
const ACTIVITY_FEED_SNAPSHOT_KEY = "nabad_activity_feed_snap_v3";
const ACTIVITY_FILTER_TAB_KEY = "nabad_activity_filter_tab_v1";
let _activityFilterTab = (() => {
  try {
    const saved = String(sessionStorage.getItem(ACTIVITY_FILTER_TAB_KEY) || "").trim();
    if (["all", "social", "achievements"].includes(saved)) return saved;
  } catch {}
  return "all";
})();
let _activityFeedSnapshot = null;

function hydrateActivityFeedSnapshotFromStorage() {
  if (_activityFeedSnapshot) return;
  try {
    const raw = sessionStorage.getItem(ACTIVITY_FEED_SNAPSHOT_KEY);
    if (!raw) return;
    const parsed = JSON.parse(raw);
    if (parsed?.at && Date.now() - parsed.at < ACTIVITY_FEED_SNAPSHOT_MS && parsed.html) {
      _activityFeedSnapshot = parsed;
    }
  } catch {}
}

function persistActivityFeedSnapshot(html) {
  if (!html) return;
  _activityFeedSnapshot = { at: Date.now(), html };
  try {
    sessionStorage.setItem(ACTIVITY_FEED_SNAPSHOT_KEY, JSON.stringify(_activityFeedSnapshot));
  } catch {}
}

function paintActivityFeedSnapshotIfFresh() {
  hydrateActivityFeedSnapshotFromStorage();
  const snap = _activityFeedSnapshot;
  if (!snap?.html || Date.now() - snap.at >= ACTIVITY_FEED_SNAPSHOT_MS) return false;
  if (!els.activityFeed) return false;
  els.activityFeed.innerHTML = snap.html;
  paintActivityFilterTabsActive();
  if (els.activityStatus) {
    els.activityStatus.hidden = true;
    els.activityStatus.textContent = "";
  }
  return true;
}

const ACTIVITY_PAGE_SIZE = 20;
const ACTIVITY_MIN_FETCH_GAP_MS = 800;
let _activityFeedLastFetchAt = 0;
let _activityFeedState = {
  items: [],
  offset: 0,
  hasMore: true,
  loading: false,
  bound: false,
  observer: null,
};

function activityDayBucket(ts) {
  const d = new Date(ts);
  if (Number.isNaN(d.getTime())) return "earlier";
  const now = new Date();
  const startToday = new Date(now.getFullYear(), now.getMonth(), now.getDate());
  if (d >= startToday) return "today";
  return "earlier";
}

function activityDayLabel(bucket) {
  return bucket === "today" ? "Today" : "Earlier";
}

function activityNotificationMatchesFilter(n, tab = _activityFilterTab) {
  if (tab === "all") return true;
  const t = String(n?.type || "").trim();
  if (tab === "achievements") return t === "chart_rank" || t === "play_milestone";
  if (tab === "social") {
    return ["follow", "remix", "social_like", "social_reply", "social_repost", "public_song", "song_feedback"].includes(t);
  }
  return true;
}

function paintActivityFilterTabsActive(tab = _activityFilterTab) {
  const root = document.getElementById("activityFilterTabs");
  if (!root) return;
  root.querySelectorAll("[data-activity-filter]").forEach((btn) => {
    const active = String(btn.getAttribute("data-activity-filter") || "") === tab;
    btn.classList.toggle("is-active", active);
    btn.setAttribute("aria-selected", active ? "true" : "false");
  });
}

/** Avatar for an activity/notification row. Real photo when the actor has
 *  one; otherwise a neutral person silhouette — never the app logo (that
 *  read as "NabadAi did this" and looked like a placeholder bug). */
function activityActorAvatarHtml(n, cls) {
  const raw = String(n?.metadata?.actor_avatar || "").trim();
  if (raw) {
    return `<img class="${cls}" src="${escapeHtml(normalizeProfileAvatarForImg(raw))}" alt="" loading="lazy" decoding="async" />`;
  }
  return `<span class="${cls} activityAvatarSilhouette" aria-hidden="true"><svg viewBox="0 0 24 24"><circle cx="12" cy="8.4" r="3.7" fill="currentColor"/><path d="M4.4 19.6c.9-3.6 4-5.8 7.6-5.8s6.7 2.2 7.6 5.8c.1.5-.3.9-.8.9H5.2c-.5 0-.9-.4-.8-.9Z" fill="currentColor"/></svg></span>`;
}

/** Milestone rows are about your songs — lead with cover art, not a blank silhouette. */
function activityRowUsesSongLeadVisual(n) {
  const t = String(n?.type || "").trim();
  return t === "chart_rank" || t === "play_milestone";
}

function activityNotificationShowRightCover(n) {
  if (activityRowUsesSongLeadVisual(n)) return false;
  return activityNotificationHasSongCover(n);
}

function activityRowLeadVisualHtml(n, cls) {
  if (activityRowUsesSongLeadVisual(n)) {
    const url = activitySongCoverUrl(n);
    if (url) {
      return `<img class="${cls}" src="${escapeHtml(url)}" alt="" loading="lazy" decoding="async" />`;
    }
    return `<span class="${cls} activityRowCover activityRowCoverPlaceholder activityRowLeadPlaceholder" aria-hidden="true">♪</span>`;
  }
  return activityActorAvatarHtml(n, cls);
}

/** Skeleton rows for the initial Activity load (replaces the old floating
 *  spinner — the bottom infinite-scroll spinner stays for paging only). */
function activitySkeletonHtml(count = 4) {
  return Array.from({ length: count }, () => `
    <div class="activityRow activityRowSkel" aria-hidden="true">
      <span class="activityRowArtWrap activitySkelBlock">
        <span class="activityRowArt activitySkelBlock"></span>
      </span>
      <div class="activityRowBody">
        <span class="activitySkelLine activitySkelLine--cat"></span>
        <span class="activitySkelLine"></span>
        <span class="activitySkelLine short"></span>
      </div>
    </div>`).join("");
}

const _activitySongArtCache = new Map();
const _activityUnavailableKeys = new Set();

function activityUnavailableKey(kind, id) {
  return `${kind}:${String(id || "").trim()}`;
}

function activityNotificationIsUnavailable(n) {
  const t = String(n?.type || "").trim();
  const meta = n?.metadata || {};
  const sid = activitySongIdForNotification(n);
  if (sid && _activityUnavailableKeys.has(activityUnavailableKey("song", sid))) return true;
  const remixPostId = String(meta.remix_post_id || "").trim();
  if (t === "remix" && remixPostId && _activityUnavailableKeys.has(activityUnavailableKey("hub", remixPostId))) {
    return true;
  }
  return false;
}

async function validateActivityNotificationsAvailability(notifications) {
  const songIds = new Set();
  const hubIds = new Set();
  for (const n of notifications) {
    const t = String(n?.type || "").trim();
    const meta = n?.metadata || {};
    const sid = activitySongIdForNotification(n);
    const songLinked =
      sid &&
      isShareUuid(sid) &&
      (t === "chart_rank" ||
        t === "play_milestone" ||
        t === "song_feedback" ||
        t === "remix" ||
        ((t === "social_like" || t === "social_reply" || t === "social_repost") && String(meta.target_kind || "") === "song"));
    if (songLinked) songIds.add(sid);
    if (t === "remix") {
      const remixPostId = String(meta.remix_post_id || "").trim();
      const remixSongId = String(meta.remix_song_id || meta.song_id || "").trim();
      if (remixPostId && isShareUuid(remixPostId) && !remixSongId) hubIds.add(remixPostId);
    }
  }
  if (!songIds.size && !hubIds.size) return false;
  let changed = false;
  if (songIds.size && SUPABASE_URL && SUPABASE_ANON_KEY) {
    try {
      const inList = [...songIds].slice(0, 32).map((id) => encodeURIComponent(id)).join(",");
      const headers = { apikey: SUPABASE_ANON_KEY, Accept: "application/json" };
      const token = getSupabaseAuthToken();
      if (token) headers.Authorization = `Bearer ${token}`;
      const r = await fetch(
        `${SUPABASE_URL}/rest/v1/user_songs?id=in.(${inList})&select=id,song_url,task_id,meta`,
        { headers, cache: "no-store" },
      );
      if (r.ok) {
        const rows = await r.json().catch(() => []);
        const live = new Map();
        for (const row of Array.isArray(rows) ? rows : []) {
          const id = String(row?.id || "").trim();
          if (!id) continue;
          const meta = row?.meta && typeof row.meta === "object" ? row.meta : {};
          if (String(meta.deletedAt || meta.deleted_at || "").trim()) continue;
          const hasAudio = String(row?.song_url || "").trim() || String(row?.task_id || "").trim();
          if (hasAudio) live.set(id, true);
        }
        for (const sid of songIds) {
          if (!live.has(sid) && !_activityUnavailableKeys.has(activityUnavailableKey("song", sid))) {
            _activityUnavailableKeys.add(activityUnavailableKey("song", sid));
            changed = true;
          }
        }
      }
    } catch {}
  }
  for (const hid of [...hubIds].slice(0, 16)) {
    const row = await fetchHubPostRowById(hid);
    if (!row || !String(row.song_url || "").trim()) {
      if (!_activityUnavailableKeys.has(activityUnavailableKey("hub", hid))) {
        _activityUnavailableKeys.add(activityUnavailableKey("hub", hid));
        changed = true;
      }
    }
  }
  return changed;
}

function cacheActivitySongArtFromNotification(n) {
  const sid = activitySongIdForNotification(n);
  const art = String(n?.metadata?.song_art_url || n?.metadata?.target_art_url || "").trim();
  if (sid && art && /^https?:\/\//i.test(art)) _activitySongArtCache.set(sid, art);
}

function findLibraryTrackByCloudOrLocalId(songId) {
  const sid = String(songId || "").trim();
  if (!sid) return null;
  return loadLibrary().find((x) => x.id === sid || trackCloudShareId(x) === sid) || null;
}

function activitySongIdForNotification(n) {
  const meta = n?.metadata || {};
  const t = String(n?.type || "").trim();
  const songId = String(meta.song_id || "").trim();
  if (songId) return songId;
  if (t === "remix") {
    return String(meta.remix_song_id || meta.remix_post_id || "").trim();
  }
  if ((t === "social_like" || t === "social_reply" || t === "social_repost") && String(meta.target_kind || "") === "song") {
    return String(meta.target_id || "").trim();
  }
  return "";
}

function activityNotificationHasSongCover(n) {
  const t = String(n?.type || "").trim();
  if (t === "follow") return false;
  if (t === "social_like" || t === "social_reply" || t === "social_repost") {
    return String(n?.metadata?.target_kind || "") === "song";
  }
  return ["play_milestone", "chart_rank", "song_feedback", "public_song", "remix"].includes(t);
}

function activitySongArtFromLocalPools(songId) {
  const sid = String(songId || "").trim();
  if (!sid) return "";
  if (_activitySongArtCache.has(sid)) return _activitySongArtCache.get(sid);
  const pools = [loadLibrary(), _discoveryFeedTracks || [], _userPublicFeedTracks || []];
  for (const pool of pools) {
    const hit = pool.find((t) => String(t?.id || "") === sid || trackCloudShareId(t) === sid);
    const art = String(hit?.artUrl || hit?.art_url || hit?.coverUrl || "").trim();
    if (art && /^https?:\/\//i.test(art)) {
      _activitySongArtCache.set(sid, art);
      return art;
    }
  }
  return "";
}

function activitySongCoverUrl(n) {
  const meta = n?.metadata || {};
  const fromMeta = String(meta.song_art_url || meta.target_art_url || "").trim();
  if (fromMeta && /^https?:\/\//i.test(fromMeta)) return fromMeta;
  return activitySongArtFromLocalPools(activitySongIdForNotification(n));
}

function activitySongCoverHtml(n) {
  if (!activityNotificationShowRightCover(n)) return "";
  const url = activitySongCoverUrl(n);
  if (url) {
    return `<img class="activityRowCover" src="${escapeHtml(url)}" alt="" loading="lazy" decoding="async" />`;
  }
  return `<span class="activityRowCover activityRowCoverPlaceholder" aria-hidden="true">♪</span>`;
}

async function enrichActivitySongArt(notifications) {
  const wanted = new Set();
  for (const n of notifications) {
    if (!activityNotificationHasSongCover(n)) continue;
    if (activitySongCoverUrl(n)) continue;
    const sid = activitySongIdForNotification(n);
    if (sid) wanted.add(sid);
  }
  if (!wanted.size || !SUPABASE_URL || !SUPABASE_ANON_KEY) return false;
  try {
    const inList = [...wanted].slice(0, 32).map((id) => encodeURIComponent(id)).join(",");
    const headers = { apikey: SUPABASE_ANON_KEY, Accept: "application/json" };
    const token = getSupabaseAuthToken();
    if (token) headers.Authorization = `Bearer ${token}`;
    const r = await fetch(
      `${SUPABASE_URL}/rest/v1/user_songs?id=in.(${inList})&select=id,art_url`,
      { headers, cache: "no-store" },
    );
    if (!r.ok) return false;
    const rows = await r.json().catch(() => []);
    let added = false;
    for (const row of Array.isArray(rows) ? rows : []) {
      const art = String(row?.art_url || "").trim();
      if (art && /^https?:\/\//i.test(art)) {
        _activitySongArtCache.set(String(row.id), art);
        added = true;
      }
    }
    return added;
  } catch {
    return false;
  }
}

/** Collapse bursts of near-identical rows inside one day bucket so the
 *  feed reads like a digest instead of a raw event log:
 *  - several "published a song" from the same creator → one row listing titles
 *  - several reactions/replies from the same person on the same target →
 *    one row with the messages joined.
 *  Rows arrive newest-first, so the kept row carries the newest timestamp;
 *  it stays unread if ANY member was unread. */
function collapseActivityRows(rows) {
  const out = [];
  const byKey = new Map();
  for (const n of rows) {
    const t = String(n?.type || "").trim();
    const actor = String(n?.actor_user_id || n?.metadata?.actor_username || "").trim();
    let key = "";
    if (t === "public_song" && actor) key = `pub|${actor}`;
    else if (t === "chart_rank") {
      key = `chart|${String(n?.metadata?.week_key || "").trim()}|${String(n?.metadata?.song_id || "").trim()}`;
    }
    else if ((t === "song_feedback" || t === "social_like" || t === "social_reply" || t === "social_repost") && actor) {
      key = `${t}|${actor}|${String(n?.metadata?.target_id || n?.metadata?.song_id || "").trim()}`;
    }
    if (!key) {
      out.push(n);
      continue;
    }
    const detail =
      t === "song_feedback"
        ? String(n?.metadata?.feedback_label || "").trim()
        : String(n?.metadata?.reply_preview || "").trim();
    const songTitle = String(n?.metadata?.song_title || "").trim();
    const existing = byKey.get(key);
    if (!existing) {
      const g = {
        ...n,
        _groupCount: 1,
        _groupTitles: songTitle ? [songTitle] : [],
        _groupDetails: detail ? [detail] : [],
        _groupBestRank: t === "chart_rank" ? Number(n?.metadata?.rank || 0) || 0 : 0,
      };
      byKey.set(key, g);
      out.push(g);
    } else {
      existing._groupCount += 1;
      if (songTitle && !existing._groupTitles.includes(songTitle)) existing._groupTitles.push(songTitle);
      if (detail) existing._groupDetails.push(detail);
      if (t === "chart_rank") {
        const rank = Number(n?.metadata?.rank || 0);
        if (rank && (!existing._groupBestRank || rank < existing._groupBestRank)) {
          existing._groupBestRank = rank;
          existing.metadata = { ...(existing.metadata || {}), rank };
        }
      }
      if (!n?.read_at) existing.read_at = null;
    }
  }
  return out;
}

function notificationActivityHref(n) {
  const meta = n?.metadata || {};
  const username = String(meta.actor_username || "").replace(/^@/, "").trim();
  const actorUserId = String(n?.actor_user_id || "").trim();
  const songId = String(meta.song_id || "").trim();
  const targetKind = String(meta.target_kind || "").trim();
  const targetId = String(meta.target_id || "").trim();
  const t = String(n?.type || "").trim();

  if (t === "play_milestone" && songId) return `#/player?track=${encodeURIComponent(songId)}`;
  if (t === "chart_rank" && songId) return `#/player?track=${encodeURIComponent(songId)}`;
  if (t === "song_feedback" && songId) return `#/player?track=${encodeURIComponent(songId)}`;
  if (t === "remix") {
    const remixSongId = String(meta.remix_song_id || meta.song_id || "").trim();
    if (remixSongId && isShareUuid(remixSongId)) {
      return `#/player?track=${encodeURIComponent(remixSongId)}`;
    }
    const remixPostId = String(meta.remix_post_id || "").trim();
    if (remixPostId && isShareUuid(remixPostId)) {
      return `#/player?hub=${encodeURIComponent(remixPostId)}`;
    }
  }
  if ((t === "social_like" || t === "social_reply" || t === "social_repost") && targetKind === "song" && targetId) {
    return `#/player?track=${encodeURIComponent(targetId)}`;
  }
  if ((t === "social_like" || t === "social_reply" || t === "social_repost") && (targetKind === "echo" || targetKind === "status")) {
    return "#/friends";
  }
  if ((t === "follow" || t === "public_song") && username) {
    return `#/u/${encodeURIComponent(username)}${actorUserId ? `?uid=${encodeURIComponent(actorUserId)}` : ""}`;
  }
  if (username) {
    return `#/u/${encodeURIComponent(username)}${actorUserId ? `?uid=${encodeURIComponent(actorUserId)}` : ""}`;
  }
  return "";
}

async function openActivityNotificationTarget(n) {
  if (activityNotificationIsUnavailable(n)) {
    showToast("This post is not available anymore.", { icon: "!", durationMs: 3800 });
    return;
  }
  const href = notificationActivityHref(n);
  if (!href) return;
  const t = String(n?.type || "").trim();
  const meta = n?.metadata || {};

  if (t === "remix") {
    const remixSongId = String(meta.remix_song_id || meta.song_id || "").trim();
    const remixPostId = String(meta.remix_post_id || "").trim();
    if (remixSongId && isShareUuid(remixSongId)) {
      if (await resolveAndPlayActivityTrack(remixSongId)) return;
    }
    if (remixPostId && isShareUuid(remixPostId)) {
      if (await resolveAndPlayHubPost(remixPostId)) return;
    }
    const username = String(meta.actor_username || "").replace(/^@/, "").trim();
    if (username) {
      _userPublicReturnHash = "#/activity";
      location.hash = href.startsWith("#") ? href : `#${href}`;
      showToast("Could not load this remix — open it from the creator's profile.", {
        icon: "!",
        durationMs: 4200,
      });
    }
    return;
  }

  const songId = activitySongIdForNotification(n);
  const songLinked =
    songId &&
    isShareUuid(songId) &&
    (t === "chart_rank" ||
      t === "play_milestone" ||
      t === "song_feedback" ||
      ((t === "social_like" || t === "social_reply" || t === "social_repost") && String(meta.target_kind || "") === "song"));

  if (songLinked) {
    if (await resolveAndPlayActivityTrack(songId)) return;
    _userPublicReturnHash = "#/activity";
    location.hash = href.startsWith("#") ? href : `#${href}`;
    void focusTrackFromShare(songId);
    return;
  }

  if (href.includes("#/u/")) _userPublicReturnHash = "#/activity";
  location.hash = href.startsWith("#") ? href : `#${href}`;
}

/** Fallback when the feed row lost its notification object (e.g. regrouped DOM). */
async function openActivityTargetFromHref(href) {
  const raw = String(href || "").trim();
  if (!raw) return;
  const hash = raw.startsWith("#") ? raw.slice(1) : raw;
  const qIdx = hash.indexOf("?");
  const query = qIdx >= 0 ? hash.slice(qIdx + 1) : "";
  const sp = new URLSearchParams(query);
  const trackId = String(sp.get("track") || "").trim();
  const hubId = String(sp.get("hub") || "").trim();
  if (trackId && isShareUuid(trackId)) {
    if (await resolveAndPlayActivityTrack(trackId)) return;
    location.hash = raw.startsWith("#") ? raw : `#${raw}`;
    void focusTrackFromShare(trackId);
    return;
  }
  if (hubId && isShareUuid(hubId)) {
    if (await resolveAndPlayHubPost(hubId)) return;
    _userPublicReturnHash = "#/activity";
    location.hash = raw.startsWith("#") ? raw : `#${raw}`;
    void focusHubTrackFromShare(hubId);
    return;
  }
  if (raw.includes("/u/")) _userPublicReturnHash = "#/activity";
  location.hash = raw.startsWith("#") ? raw : `#${raw}`;
}

function activityRowArtworkHtml(n) {
  const t = String(n?.type || "").trim();
  const preferSong = activityRowUsesSongLeadVisual(n) || activityNotificationHasSongCover(n);
  const songUrl = activitySongCoverUrl(n);
  if (preferSong && songUrl) {
    return `<img class="activityRowArt" src="${escapeHtml(songUrl)}" alt="" loading="lazy" decoding="async" />`;
  }
  if (t === "follow" || t === "social_like" || t === "social_reply" || t === "social_repost" || t === "public_song" || t === "remix") {
    const actorArt = String(n?.metadata?.actor_avatar || "").trim();
    if (isRealUserAvatarUrl(actorArt)) {
      return `<img class="activityRowArt activityRowArt--avatar" src="${escapeHtml(normalizeProfileAvatarForImg(actorArt))}" alt="" loading="lazy" decoding="async" />`;
    }
    return activityActorAvatarHtml(n, "activityRowArt activityRowArt--avatar");
  }
  if (songUrl) {
    return `<img class="activityRowArt" src="${escapeHtml(songUrl)}" alt="" loading="lazy" decoding="async" />`;
  }
  if (activityRowUsesSongLeadVisual(n)) {
    return `<span class="activityRowArt activityRowArt--placeholder" aria-hidden="true">♪</span>`;
  }
  return activityActorAvatarHtml(n, "activityRowArt activityRowArt--avatar");
}

function activityItemDisplayParts(n, msg) {
  const t = String(n?.type || "").trim();
  const meta = n?.metadata || {};
  const username = String(meta.actor_username || "").replace(/^@/, "").trim();
  const gc = Number(n?._groupCount || 0);

  if (t === "chart_rank") {
    const rank = Number(n?._groupBestRank || meta.rank || 0);
    const title = String(meta.song_title || "Your song").trim();
    return {
      category: "Top Songs",
      title,
      description: rank ? `Reached #${rank} on Top Songs this week` : "Charted on Top Songs this week",
    };
  }
  if (t === "play_milestone") {
    const count = Number(meta.play_count || 0);
    const title = String(meta.song_title || "Your song").trim();
    return {
      category: "Milestone",
      title,
      description: count ? `${formatStatCount(count)} plays and counting` : "Your song is picking up steam",
    };
  }
  if (t === "social_like") {
    const songTitle = String(meta.target_title || meta.song_title || "").trim();
    if (gc > 1) {
      return {
        category: "New Like",
        title: `${gc} new likes`,
        description: songTitle || "On one of your songs",
      };
    }
    return {
      category: "New Like",
      title: username ? `${username} liked your song` : "Someone liked your song",
      description: songTitle || "Open to see what they enjoyed",
    };
  }
  if (t === "social_reply") {
    const preview = String(meta.reply_preview || msg.body || "").trim();
    return {
      category: "New Reply",
      title: username ? `${username} replied` : "New reply",
      description: preview ? `"${preview.slice(0, 100)}${preview.length > 100 ? "…" : ""}"` : (msg.body || "Open the thread"),
    };
  }
  if (t === "social_repost") {
    const songTitle = String(meta.target_title || meta.song_title || "").trim();
    if (gc > 1) {
      return {
        category: "Repost",
        title: `${gc} new reposts`,
        description: songTitle || "On one of your songs",
      };
    }
    return {
      category: "Repost",
      title: username ? `${username} reposted your song` : "Someone reposted your song",
      description: songTitle || "It reached their followers",
    };
  }
  if (t === "follow") {
    return {
      category: "New Follower",
      title: username ? `${username} started following you` : "Someone started following you",
      description: "They can see your public songs in their feed",
    };
  }
  if (t === "remix") {
    const remix = String(meta.remix_title || "a new remix").trim();
    const original = String(meta.original_title || "your song").trim();
    return {
      category: "Remix Created",
      title: username ? `${username} created a remix` : "Someone created a remix",
      description: remix && remix !== original ? remix : `Based on ${original}`,
    };
  }
  if (t === "public_song") {
    if (gc > 1) {
      const titles = (n._groupTitles || []).slice(0, 2).join(" · ");
      const more = (n._groupTitles || []).length > 2 ? ` +${n._groupTitles.length - 2} more` : "";
      return {
        category: "New Song",
        title: username ? `${username} published ${gc} songs` : `${gc} new songs`,
        description: titles ? `${titles}${more}` : "From someone you follow",
      };
    }
    const songTitle = String(meta.song_title || "a new song").trim();
    return {
      category: "New Song",
      title: username ? `${username} published a song` : "A creator published a song",
      description: songTitle,
    };
  }
  if (t === "song_feedback") {
    const songTitle = String(meta.song_title || "your song").trim();
    const label = String(meta.feedback_label || "Private feedback").trim();
    return {
      category: "Feedback",
      title: username ? `${username} sent feedback` : "New feedback",
      description: `${label} · ${songTitle}`,
    };
  }
  return {
    category: "Activity",
    title: String(msg?.title || "Update").trim(),
    description: String(msg?.body || "").trim(),
  };
}

function activityItemHtml(n) {
  const msg = notificationMessage(n);
  const unavailable = activityNotificationIsUnavailable(n);
  const gc = Number(n?._groupCount || 0);
  if (gc > 1) {
    const username = String(n?.metadata?.actor_username || "").replace(/^@/, "").trim();
    const t = String(n?.type || "").trim();
    if (t === "public_song") {
      msg.title = username ? `@${username} published ${gc} songs` : `A creator published ${gc} songs`;
      const titles = (n._groupTitles || []).slice(0, 3).join(" · ");
      const more = (n._groupTitles || []).length > 3 ? ` +${n._groupTitles.length - 3} more` : "";
      msg.body = titles ? `${titles}${more}` : `${gc} new songs in your Following feed.`;
    } else if (t === "song_feedback" || t === "social_reply") {
      const details = (n._groupDetails || []).slice(0, 3).map((d) => `"${d.slice(0, 60)}${d.length > 60 ? "…" : ""}"`);
      if (details.length) msg.body = details.join(" · ");
    } else if (t === "social_like") {
      msg.body = `${gc} likes on this.`;
    } else if (t === "social_repost") {
      msg.body = `${gc} reposts of this.`;
    }
  }
  const parts = unavailable
    ? { category: "Unavailable", title: "This post is not available anymore", description: "It may have been removed or made private." }
    : activityItemDisplayParts(n, msg);
  const unread = !n?.read_at;
  const time = relativeTime(new Date(n?.created_at || Date.now()).getTime());
  const href = unavailable ? "" : notificationActivityHref(n);
  const tag = href ? "button" : "article";
  const typeAttr = href ? ' type="button"' : "";
  const notifType = String(n?.type || "").trim() || "default";
  const notifId = String(n?.id || "").trim();
  const dataHref = href
    ? ` data-activity-href="${escapeHtml(href)}"${notifId ? ` data-activity-id="${escapeHtml(notifId)}"` : ""}`
    : "";
  const descHtml = parts.description
    ? `<p class="activityRowDesc">${escapeHtml(parts.description)}</p>`
    : "";
  return `
    <${tag} class="activityRow activityRow--${escapeHtml(notifType)}${unread ? " isUnread" : ""}${unavailable ? " activityRow--unavailable" : ""}"${typeAttr}${dataHref}>
      <div class="activityRowArtWrap">
        ${activityRowArtworkHtml(n)}
        ${activityTypeBadgeHtml(notifType)}
      </div>
      <div class="activityRowBody">
        <div class="activityRowMetaTop">
          <span class="activityRowCategory">${escapeHtml(parts.category)}</span>
          <span class="activityRowTime">${escapeHtml(time)}</span>
        </div>
        <strong class="activityRowTitle">${escapeHtml(parts.title)}</strong>
        ${descHtml}
      </div>
    </${tag}>`;
}

function activityEmptyHtml(filter = _activityFilterTab) {
  if (filter === "social") {
    return `
      <div class="activityEmpty">
        <div class="activityEmptyIcon" aria-hidden="true"><svg viewBox="0 0 24 24" width="24" height="24"><path fill="currentColor" d="M12 21s-7.2-4.35-9.6-8.55C.6 9.15 2.1 5.7 5.4 5.1c1.8-.3 3.45.45 4.35 1.95.9-1.5 2.55-2.25 4.35-1.95 3.3.6 4.8 4.05 3 7.35C19.2 16.65 12 21 12 21Z"/></svg></div>
        <strong>No social activity yet</strong>
        <span>Likes, followers, remixes, and replies will show up here.</span>
      </div>`;
  }
  if (filter === "achievements") {
    return `
      <div class="activityEmpty">
        <div class="activityEmptyIcon" aria-hidden="true"><svg viewBox="0 0 24 24" width="24" height="24"><path fill="currentColor" d="M12 2.5 14.8 8l6.2.9-4.5 4.4 1.1 6.1L12 16.8 6.4 19.4l1.1-6.1L3 8.9 9.2 8 12 2.5Z"/></svg></div>
        <strong>No achievements yet</strong>
        <span>Chart rankings and play milestones will appear here.</span>
      </div>`;
  }
  return `
    <div class="activityEmpty">
      <div class="activityEmptyIcon" aria-hidden="true"><svg viewBox="0 0 24 24" width="24" height="24"><path fill="currentColor" d="M9 18V5l12-2v13"/><circle cx="6" cy="18" r="3"/><circle cx="18" cy="16" r="3"/></svg></div>
      <strong>No activity yet</strong>
      <span>Your likes, rankings, followers and remix activity will appear here.</span>
    </div>`;
}

function renderActivityFeedFromState() {
  const feed = els.activityFeed;
  if (!feed) return;
  paintActivityFilterTabsActive();
  const list = _activityFeedState.items.filter((n) => activityNotificationMatchesFilter(n));
  if (!list.length) {
    feed.innerHTML = _activityFeedState.items.length
      ? activityEmptyHtml(_activityFilterTab)
      : activityEmptyHtml("all");
    if (!_activityFeedState.items.length) persistActivityFeedSnapshot(feed.innerHTML);
    return;
  }
  const buckets = ["today", "earlier"];
  const grouped = { today: [], earlier: [] };
  list.forEach((n) => {
    grouped[activityDayBucket(new Date(n?.created_at || 0).getTime())].push(n);
  });
  feed.innerHTML = buckets.filter((b) => grouped[b].length).map((b) => `
    <section class="activityDayGroup" aria-label="${activityDayLabel(b)}">
      <h3 class="activityDayLabel">${activityDayLabel(b)}</h3>
      <div class="activityDayRows">
        ${collapseActivityRows(grouped[b]).map((n) => activityItemHtml(n)).join("")}
      </div>
    </section>`).join("");
  persistActivityFeedSnapshot(feed.innerHTML);
}

/** Spinner only while a page fetch is in flight; sentinel stays for scroll paging. */
function syncActivityLoadMoreUi() {
  const wrap = els.activityLoadMore;
  if (!wrap) return;
  const spinner = wrap.querySelector(".activityLoadMoreSpinner");
  const hasItems = _activityFeedState.items.length > 0;
  const needsPager = hasItems && _activityFeedState.hasMore;
  wrap.hidden = !needsPager;
  wrap.setAttribute("aria-hidden", needsPager ? "false" : "true");
  wrap.classList.toggle("isLoading", Boolean(_activityFeedState.loading));
  if (spinner) {
    spinner.hidden = !_activityFeedState.loading;
  }
}

async function fetchActivityBatch() {
  if (_activityFeedState.loading || !_activityFeedState.hasMore) return;
  _activityFeedState.loading = true;
  _activityFeedLastFetchAt = Date.now();
  syncActivityLoadMoreUi();
  try {
    const limit = ACTIVITY_PAGE_SIZE;
    const offset = _activityFeedState.offset;
    const data = await socialApi(`/api/social?type=notifications&limit=${limit}&offset=${offset}`);
    const batch = Array.isArray(data?.notifications) ? data.notifications : [];
    if (!batch.length) {
      _activityFeedState.hasMore = false;
    } else {
      const seen = new Set(_activityFeedState.items.map((n) => String(n?.id || "")));
      const fresh = batch.filter((n) => {
        const id = String(n?.id || "");
        return id && !seen.has(id);
      });
      if (!fresh.length) {
        _activityFeedState.hasMore = false;
      } else {
        _activityFeedState.items.push(...fresh);
        _activityFeedState.offset += batch.length;
        fresh.forEach((n) => cacheActivitySongArtFromNotification(n));
        await enrichActivitySongArt(fresh);
        await validateActivityNotificationsAvailability(fresh);
        if (batch.length < limit) _activityFeedState.hasMore = false;
      }
    }
    renderActivityFeedFromState();
    const unread = _activityFeedState.items.filter((n) => !n?.read_at).length;
    if (els.activityLead) {
      els.activityLead.textContent = unread
        ? `${unread} unread ${unread === 1 ? "update" : "updates"} from your music circle.`
        : "Follows, likes, comments, milestones, and remixes.";
    }
    updateNotificationsEntryBadges(unread);
  } catch (e) {
    if (els.activityStatus) {
      els.activityStatus.hidden = false;
      els.activityStatus.textContent = e?.message || "Could not load activity.";
    }
    // Don't leave the loading skeleton up under an error message.
    if (!_activityFeedState.items.length && els.activityFeed) {
      els.activityFeed.innerHTML = "";
    }
  } finally {
    _activityFeedState.loading = false;
    syncActivityLoadMoreUi();
  }
}

async function enterActivityRoute({ reset = false } = {}) {
  if (!authSession?.user?.id) {
    location.hash = "#/auth";
    return;
  }
  if (reset) {
    _activityFeedState.items = [];
    _activityFeedState.offset = 0;
    _activityFeedState.hasMore = true;
    _activityFeedState.loading = false;
    _activityUnavailableKeys.clear();
    if (els.activityFeed) {
      els.activityFeed.innerHTML = activitySkeletonHtml();
    }
  } else if (!_activityFeedState.items.length && els.activityFeed) {
    if (!paintActivityFeedSnapshotIfFresh()) {
      els.activityFeed.innerHTML = activitySkeletonHtml();
    }
  }
  if (els.activityStatus) {
    els.activityStatus.hidden = true;
    els.activityStatus.textContent = "";
  }
  await fetchActivityBatch();
  const unread = _activityFeedState.items.filter((n) => !n?.read_at).length;
  if (unread) {
    void socialApi("/api/social", {
      method: "POST",
      body: JSON.stringify({ action: "mark_notifications_read" }),
    }).then(() => {
      _activityFeedState.items.forEach((n) => {
        if (!n.read_at) n.read_at = new Date().toISOString();
      });
      updateNotificationsEntryBadges(0);
      renderActivityFeedFromState();
      if (els.activityLead) els.activityLead.textContent = "Follows, likes, comments, milestones, and remixes.";
    }).catch(() => {});
  }
}

function bindActivityPageOnce() {
  if (_activityFeedState.bound) return;
  _activityFeedState.bound = true;
  const filterRoot = document.getElementById("activityFilterTabs");
  if (filterRoot && filterRoot.dataset.boundActivityFilters !== "1") {
    filterRoot.dataset.boundActivityFilters = "1";
    filterRoot.addEventListener("click", (ev) => {
      const tabBtn = ev.target?.closest?.("[data-activity-filter]");
      if (!tabBtn || !filterRoot.contains(tabBtn)) return;
      ev.preventDefault();
      const tab = String(tabBtn.getAttribute("data-activity-filter") || "").trim();
      if (!tab || tab === _activityFilterTab) return;
      haptic("light");
      _activityFilterTab = tab;
      try { sessionStorage.setItem(ACTIVITY_FILTER_TAB_KEY, tab); } catch {}
      renderActivityFeedFromState();
    });
  }
  els.activityFeed?.addEventListener("click", (ev) => {
    const row = ev.target.closest("[data-activity-href]");
    if (!row) return;
    const href = row.getAttribute("data-activity-href") || "";
    if (!href) return;
    ev.preventDefault();
    const notifId = row.getAttribute("data-activity-id") || "";
    const n = notifId ? _activityFeedState.items.find((item) => String(item?.id || "") === notifId) : null;
    if (n) void openActivityNotificationTarget(n);
    else void openActivityTargetFromHref(href);
  });
  if (els.activityLoadMore && typeof IntersectionObserver !== "undefined") {
    _activityFeedState.observer = new IntersectionObserver((entries) => {
      if (!entries.some((e) => e.isIntersecting)) return;
      if (_activityFeedState.loading || !_activityFeedState.hasMore) return;
      if (Date.now() - _activityFeedLastFetchAt < ACTIVITY_MIN_FETCH_GAP_MS) return;
      void fetchActivityBatch();
    }, { root: null, rootMargin: "160px", threshold: 0 });
    _activityFeedState.observer.observe(els.activityLoadMore);
  }
}

const _mashupState = {
  slotA: null,
  slotB: null,
  pickerSlot: "",
  pickerTab: "library",
  pickerCandidates: [],
  discoverCache: null,
  lastSuggestedTitle: "",
  lyricsPreviewGen: 0,
  lyricsCache: new Map(),
  generating: false,
  starting: false,
  taskId: "",
  pollTimer: null,
  bound: false,
};

const MASHUP_PREFILL_KEY = "mas:mashup:prefill:v1";

function mashupSongCloudId(track) {
  const cloud = String(track?.cloudSongId || track?.songId || "").trim();
  if (cloud && isShareUuid(cloud)) return cloud;
  const id = String(track?.id || "").trim();
  if (isShareUuid(id)) return id;
  return "";
}

function mashupTrackKey(ref) {
  if (!ref) return "";
  if (ref.sourceType === "public") {
    return `pub:${String(ref.ownerUserId || "").trim()}:${String(ref.songId || "").trim()}`;
  }
  return `lib:${String(ref.songId || mashupSongCloudId(ref) || "").trim()}`;
}

function mashupRefsEqual(a, b) {
  if (!a || !b) return false;
  return mashupTrackKey(a) === mashupTrackKey(b);
}

function mashupRefFromLibraryTrack(t) {
  const songId = mashupSongCloudId(t);
  if (!songId) return null;
  return {
    sourceType: "library",
    songId,
    id: String(t?.id || "").trim(),
    title: String(t?.title || "Song").trim() || "Song",
    artUrl: mashupCoverForTrack(t),
    url: String(t?.url || "").trim(),
    taskId: String(t?.taskId || "").trim(),
    audioId: String(t?.audioId || "").trim(),
    kind: String(t?.kind || "full"),
    meta: t?.meta || null,
  };
}

function mashupRefFromDiscoverTrack(t, handle = "") {
  const songId = String(t?.id || t?.songId || "").trim();
  const ownerUserId = String(t?.userId || t?.ownerUserId || "").trim();
  if (!songId || !ownerUserId || !isShareUuid(songId)) return null;
  if (String(t?.kind || "full") !== "full") return null;
  if (!String(t?.url || "").trim()) return null;
  return {
    sourceType: "public",
    songId,
    ownerUserId,
    title: String(t?.title || "Song").trim() || "Song",
    artUrl: mashupCoverForTrack(t),
    url: String(t?.url || "").trim(),
    taskId: String(t?.taskId || "").trim(),
    audioId: String(t?.audioId || "").trim(),
    creatorHandle: String(handle || t?.username || t?.creator || "").replace(/^@/, "").trim(),
  };
}

function mashupRefFromPlayerTrack(t) {
  if (!t) return null;
  const url = String(t?.url || "").trim();
  if (!url) return null;
  const songId = String(t?.songId || t?.cloudSongId || t?.id || "").trim();
  const ownerUserId = String(t?.ownerUserId || "").trim();
  const authId = String(authSession?.user?.id || "").trim();
  if (!playerSourceIsExternalListenOnly()) {
    const libHit = loadLibrary().find((row) => {
      if (String(row?.id || "") === String(t?.trackId || t?.id || "")) return true;
      if (songId && mashupSongCloudId(row) === songId) return true;
      const u = String(row?.url || "").trim();
      return u && audioUrlsEquivalent(u, url);
    });
    if (libHit) return mashupRefFromLibraryTrack(libHit);
    if (songId && isShareUuid(songId) && authId) {
      return mashupRefFromLibraryTrack({
        ...t,
        cloudSongId: songId,
        id: t?.trackId || t?.id || songId,
      });
    }
  }
  if (songId && ownerUserId && isShareUuid(songId)) {
    return mashupRefFromDiscoverTrack(
      {
        ...t,
        id: songId,
        userId: ownerUserId,
        url,
        title: t?.title || els.playerTitle?.textContent || "Song",
        artUrl: t?.artUrl || els.playerArt?.src || "",
        taskId: t?.taskId || t?.meta?.taskId || "",
        audioId: t?.audioId || t?.meta?.audioId || "",
      },
      String(t?.byLine || t?.creator || "").replace(/^@/, ""),
    );
  }
  return null;
}

function mashupSourcePayload(ref) {
  if (!ref?.songId) return null;
  if (ref.sourceType === "public") {
    return {
      type: "public",
      songId: ref.songId,
      ownerUserId: String(ref.ownerUserId || "").trim(),
    };
  }
  return { type: "library", songId: ref.songId };
}

function mashupMetaEntry(ref) {
  return {
    songId: ref?.songId || "",
    title: ref?.title || "",
    artUrl: mashupCoverForTrack(ref),
    sourceType: ref?.sourceType || "library",
    ownerUserId: ref?.ownerUserId || undefined,
    creatorUsername: ref?.creatorHandle || undefined,
    localId: ref?.id || undefined,
  };
}

function mashupSlotSourceLabel(ref) {
  if (!ref) return "";
  if (ref.sourceType === "public") {
    const h = String(ref.creatorHandle || "").trim();
    return h ? `Discover · @${h}` : "Discover · public";
  }
  return "Library · full track";
}

function openMashupWithPrefill(trackRef, slot = "a") {
  if (!trackRef?.songId) {
    try { location.hash = "#/mashup"; } catch {}
    return;
  }
  try {
    sessionStorage.setItem(
      MASHUP_PREFILL_KEY,
      JSON.stringify({ slot: slot === "b" ? "b" : "a", track: trackRef }),
    );
  } catch {}
  try { location.hash = "#/mashup"; } catch {}
}

function applyMashupPrefillFromSession() {
  try {
    const raw = sessionStorage.getItem(MASHUP_PREFILL_KEY);
    if (!raw) return;
    sessionStorage.removeItem(MASHUP_PREFILL_KEY);
    const data = JSON.parse(raw);
    const slot = data?.slot === "b" ? "b" : "a";
    const track = data?.track;
    if (!track?.songId) return;
    if (slot === "a") _mashupState.slotA = track;
    else _mashupState.slotB = track;
    maybeSuggestMashupTitle();
  } catch {}
}

function mashupEligibleLibraryTracks() {
  return loadLibrary()
    .filter((t) => String(t?.kind || "full") === "full")
    .filter((t) => String(t?.url || "").trim())
    .map((t) => {
      const ref = mashupRefFromLibraryTrack(t);
      if (ref) ref.ts = Number(t?.ts || 0);
      return ref;
    })
    .filter(Boolean)
    .sort((a, b) => Number(b?.ts || 0) - Number(a?.ts || 0));
}

function mashupCoverForTrack(t) {
  const raw = String(t?.artUrl || t?.meta?.imageUrl || "").trim();
  return raw && /^https?:\/\//i.test(raw) ? raw : "./assets/nabadai-logo.png";
}

function mashupSlotEls(slot) {
  if (slot === "b") {
    return {
      btn: els.mashupSlotB,
      art: els.mashupSlotArtB,
      title: els.mashupSlotTitleB,
    };
  }
  return {
    btn: els.mashupSlotA,
    art: els.mashupSlotArtA,
    title: els.mashupSlotTitleA,
  };
}

function renderMashupSlot(slot, track) {
  const { btn, art, title } = mashupSlotEls(slot);
  if (!btn || !art || !title) return;
  if (!track) {
    btn.classList.remove("isFilled");
    art.style.backgroundImage = "";
    title.textContent = "Tap to choose";
    return;
  }
  btn.classList.add("isFilled");
  const cover = mashupCoverForTrack(track);
  art.style.backgroundImage = `url("${cover.replace(/"/g, '\\"')}")`;
  const name = String(track.title || "Song").trim() || "Song";
  const source = mashupSlotSourceLabel(track);
  title.innerHTML = `${escapeHtml(name)}<span class="mashupSlotSource">${escapeHtml(source)}</span>`;
}

function maybeSuggestMashupTitle() {
  if (!els.mashupTitleInput) return;
  if (!_mashupState.slotA || !_mashupState.slotB) {
    if (!String(els.mashupTitleInput.value || "").trim()) {
      els.mashupTitleInput.value = "";
      _mashupState.lastSuggestedTitle = "";
    }
    return;
  }
  const suggested = mashupDefaultTitle();
  const current = String(els.mashupTitleInput.value || "").trim();
  if (!current || current === _mashupState.lastSuggestedTitle) {
    els.mashupTitleInput.value = suggested;
    _mashupState.lastSuggestedTitle = suggested;
  }
}

function renderMashupPage() {
  renderMashupSlot("a", _mashupState.slotA);
  renderMashupSlot("b", _mashupState.slotB);
  const ready = Boolean(_mashupState.slotA && _mashupState.slotB) && !_mashupState.generating && !_mashupState.starting;
  if (els.btnMashupGenerate) {
    els.btnMashupGenerate.disabled = !ready;
    if (!_mashupState.generating && !_mashupState.starting) {
      els.btnMashupGenerate.textContent = "Mashup · 12 credits";
      els.btnMashupGenerate.classList.remove("isStarting");
    }
  }
  if (els.mashupLead && !_mashupState.generating && !_mashupState.starting) {
    const libN = mashupEligibleLibraryTracks().length;
    els.mashupLead.textContent = libN >= 2
      ? "Pick two songs from Library or Discover — we blend them into one new track."
      : "Choose any two full tracks from Library or Discover to mash up.";
  }
  void syncMashupLyricsPreview();
}

function enterMashupRoute() {
  if (!_mashupState.pollTimer && !_mashupState.taskId) {
    _mashupState.generating = false;
    _mashupState.starting = false;
    setMashupBlending(false);
    setMashupStatus("");
  }
  applyMashupPrefillFromSession();
  maybeSuggestMashupTitle();
  renderMashupPage();
}

function mashupLyricsLookupRef(ref) {
  if (!ref) return null;
  return {
    id: ref.id || ref.songId || "",
    songId: ref.songId || "",
    ownerUserId: ref.ownerUserId || (ref.sourceType === "library" ? authSession?.user?.id : ""),
    url: ref.url || "",
    title: ref.title || "",
    taskId: ref.taskId || "",
    audioId: ref.audioId || "",
    meta: ref.meta || null,
  };
}

function mashupStyleFromRef(ref) {
  const meta = ref?.meta && typeof ref.meta === "object" ? ref.meta : {};
  return String(meta.styleInput || meta.styleSent || meta.style || "").trim();
}

function mergeMashupSourceLyrics(titleA, titleB, lyricsA, lyricsB, hint = "") {
  const parts = [];
  const direction = String(hint || "").trim();
  if (direction) parts.push(direction);
  parts.push(`[Mashup of "${titleA}" × "${titleB}"]`);
  parts.push(`--- ${titleA} ---`);
  parts.push(String(lyricsA || "").trim());
  parts.push(`--- ${titleB} ---`);
  parts.push(String(lyricsB || "").trim());
  return parts.join("\n\n").slice(0, 5000);
}

function mashupDefaultTitle() {
  const titleA = String(_mashupState.slotA?.title || "Song A").trim() || "Song A";
  const titleB = String(_mashupState.slotB?.title || "Song B").trim() || "Song B";
  return `${titleA} × ${titleB}`.slice(0, 100);
}

async function resolveMashupTrackLyrics(ref) {
  const row = mashupLyricsLookupRef(ref);
  if (!row) return "";
  try {
    return String(await resolveLyricsForTrackRef(row)).trim();
  } catch {
    return "";
  }
}

async function resolveMashupTrackLyricsCached(ref) {
  const key = mashupTrackKey(ref);
  if (!key) return "";
  if (_mashupState.lyricsCache.has(key)) {
    return String(_mashupState.lyricsCache.get(key) || "").trim();
  }
  const lyrics = await resolveMashupTrackLyrics(ref);
  _mashupState.lyricsCache.set(key, lyrics);
  return lyrics;
}

function renderMashupLyricsPreviewHtml(titleA, titleB, lyricsA, lyricsB) {
  if (!lyricsA && !lyricsB) {
    return `<p class="mashupBlendLyricsEmpty">No saved lyrics for these tracks — Suno will write fresh words for the blend.</p>`;
  }
  const blocks = [];
  if (lyricsA) {
    blocks.push(`
      <div class="mashupBlendLyricsBlock">
        <strong>${escapeHtml(titleA)}</strong>
        <pre>${escapeHtml(lyricsA.slice(0, 1800))}${lyricsA.length > 1800 ? "…" : ""}</pre>
      </div>`);
  }
  if (lyricsB) {
    blocks.push(`
      <div class="mashupBlendLyricsBlock">
        <strong>${escapeHtml(titleB)}</strong>
        <pre>${escapeHtml(lyricsB.slice(0, 1800))}${lyricsB.length > 1800 ? "…" : ""}</pre>
      </div>`);
  }
  return blocks.join("");
}

async function syncMashupLyricsPreview() {
  if (!els.mashupBlendRecap || !els.mashupBlendLyrics) return;
  if (!_mashupState.slotA || !_mashupState.slotB) {
    clearMashupBlendRecap();
    return;
  }
  const gen = ++_mashupState.lyricsPreviewGen;
  els.mashupBlendRecap.hidden = false;
  els.mashupBlendRecap.setAttribute("aria-hidden", "false");
  if (els.mashupBlendRecapMode) {
    els.mashupBlendRecapMode.textContent = _mashupState.generating || _mashupState.starting
      ? "Your blend"
      : "Source lyrics";
  }
  els.mashupBlendLyrics.innerHTML = `<p class="mashupBlendLyricsLoading">Loading lyrics from both tracks…</p>`;
  const titleA = String(_mashupState.slotA?.title || "Track A").trim() || "Track A";
  const titleB = String(_mashupState.slotB?.title || "Track B").trim() || "Track B";
  const [lyricsA, lyricsB] = await Promise.all([
    resolveMashupTrackLyricsCached(_mashupState.slotA),
    resolveMashupTrackLyricsCached(_mashupState.slotB),
  ]);
  if (gen !== _mashupState.lyricsPreviewGen) return;
  els.mashupBlendLyrics.innerHTML = renderMashupLyricsPreviewHtml(titleA, titleB, lyricsA, lyricsB);
}

async function buildSimpleMashupRequest(directionPrompt) {
  const titleA = String(_mashupState.slotA?.title || "Song A").trim() || "Song A";
  const titleB = String(_mashupState.slotB?.title || "Song B").trim() || "Song B";
  const mashupTitle = String(els.mashupTitleInput?.value || "").trim() || mashupDefaultTitle();
  const direction = String(directionPrompt || "").trim()
    || `A mashup blending "${titleA}" with "${titleB}" — weave both melodies together.`;
  const [lyricsA, lyricsB] = await Promise.all([
    resolveMashupTrackLyricsCached(_mashupState.slotA),
    resolveMashupTrackLyricsCached(_mashupState.slotB),
  ]);
  const styleBits = [mashupStyleFromRef(_mashupState.slotA), mashupStyleFromRef(_mashupState.slotB)]
    .filter(Boolean);
  const mergedStyle = (styleBits.length
    ? `${styleBits.join(", ")}, mashup blend`
    : "Mashup blend, energetic crossover"
  ).slice(0, 1000);

  if (lyricsA && lyricsB) {
    return {
      customMode: true,
      title: mashupTitle,
      style: mergedStyle,
      prompt: mergeMashupSourceLyrics(titleA, titleB, lyricsA, lyricsB, direction),
      instrumental: false,
      lyricsMerged: true,
    };
  }
  return {
    customMode: false,
    title: "",
    style: "",
    prompt: direction,
    instrumental: false,
    lyricsMerged: false,
  };
}

async function populateMashupBlendRecap() {
  await syncMashupLyricsPreview();
}

function clearMashupBlendRecap() {
  if (els.mashupBlendRecap) {
    els.mashupBlendRecap.hidden = true;
    els.mashupBlendRecap.setAttribute("aria-hidden", "true");
  }
  if (els.mashupBlendLyrics) els.mashupBlendLyrics.innerHTML = "";
}

function setMashupBlending(active, message = "") {
  const on = Boolean(active);
  els.mashupPage?.classList.toggle("isBlending", on);
  if (els.mashupBlendStage) {
    els.mashupBlendStage.hidden = !on;
    els.mashupBlendStage.classList.toggle("isActive", on);
    els.mashupBlendStage.setAttribute("aria-hidden", on ? "false" : "true");
  }
  if (on) {
    const coverA = mashupCoverForTrack(_mashupState.slotA);
    const coverB = mashupCoverForTrack(_mashupState.slotB);
    if (els.mashupBlendCoverA) els.mashupBlendCoverA.src = coverA;
    if (els.mashupBlendCoverB) els.mashupBlendCoverB.src = coverB;
    void populateMashupBlendRecap();
  } else if (_mashupState.slotA && _mashupState.slotB) {
    void syncMashupLyricsPreview();
  } else {
    clearMashupBlendRecap();
  }
  if (els.mashupBlendStatus) {
    els.mashupBlendStatus.textContent = String(message || "Blending your tracks…").trim();
  }
  if (els.btnMashupGenerate) {
    els.btnMashupGenerate.disabled = on || _mashupState.starting || !_mashupState.slotA || !_mashupState.slotB;
    if (on) els.btnMashupGenerate.textContent = "Blending…";
  }
}

function setMashupStatus(msg, { show = true } = {}) {
  if (!els.mashupStatus) return;
  const text = String(msg || "").trim();
  if (!text || !show) {
    els.mashupStatus.hidden = true;
    els.mashupStatus.textContent = "";
    return;
  }
  els.mashupStatus.hidden = false;
  els.mashupStatus.textContent = text;
}

function setMashupProgress() {}

function openMashupPicker(slot, tab = _mashupState.pickerTab || "library") {
  _mashupState.pickerSlot = slot === "b" ? "b" : "a";
  _mashupState.pickerTab = tab === "discover" ? "discover" : "library";
  if (els.mashupPickerTitle) {
    els.mashupPickerTitle.textContent = _mashupState.pickerSlot === "b" ? "Choose track B" : "Choose track A";
  }
  els.mashupPickerTabLibrary?.classList.toggle("isActive", _mashupState.pickerTab === "library");
  els.mashupPickerTabDiscover?.classList.toggle("isActive", _mashupState.pickerTab === "discover");
  if (els.mashupPickerTabLibrary) els.mashupPickerTabLibrary.setAttribute("aria-selected", _mashupState.pickerTab === "library" ? "true" : "false");
  if (els.mashupPickerTabDiscover) els.mashupPickerTabDiscover.setAttribute("aria-selected", _mashupState.pickerTab === "discover" ? "true" : "false");
  if (els.mashupPickerSheet) {
    els.mashupPickerSheet.hidden = false;
    els.mashupPickerSheet.setAttribute("aria-hidden", "false");
  }
  void renderMashupPickerList();
}

async function renderMashupPickerList() {
  if (!els.mashupPickerList) return;
  const other = _mashupState.pickerSlot === "a" ? _mashupState.slotB : _mashupState.slotA;
  const otherKey = mashupTrackKey(other);
  const selectedRef = _mashupState.pickerSlot === "a" ? _mashupState.slotA : _mashupState.slotB;
  const selectedKey = mashupTrackKey(selectedRef);

  if (_mashupState.pickerTab === "discover") {
    els.mashupPickerList.innerHTML = `<div class="mashupPickerEmpty">Loading Discover songs…</div>`;
    let tracks = Array.isArray(_mashupState.discoverCache) ? _mashupState.discoverCache : null;
    if (!tracks) {
      const raw = await supabaseFetchDiscoveryPublicSongs(60);
      const ids = raw.map((t) => String(t.userId || "").trim()).filter(Boolean);
      const profMap = await fetchProfilesByUserIdsMap(ids);
      tracks = raw
        .map((t) => mashupRefFromDiscoverTrack(t, resolveProfileForFeedCreator(String(t.userId || ""), profMap)?.username || ""))
        .filter(Boolean);
      _mashupState.discoverCache = tracks;
    }
    const list = tracks.filter((t) => mashupTrackKey(t) !== otherKey);
    _mashupState.pickerCandidates = list;
    if (!list.length) {
      els.mashupPickerList.innerHTML = `<div class="mashupPickerEmpty">No public Discover songs right now. Try Library or check back later.</div>`;
      return;
    }
    els.mashupPickerList.innerHTML = list.map((t, idx) => {
      const key = mashupTrackKey(t);
      const selected = key && key === selectedKey;
      const sub = mashupSlotSourceLabel(t);
      return `
        <button type="button" class="mashupPickerRow${selected ? " isSelected" : ""}" data-mashup-pick-idx="${idx}" role="option">
          <img class="mashupPickerRowArt" src="${escapeHtml(mashupCoverForTrack(t))}" alt="" loading="lazy" decoding="async" />
          <span class="mashupPickerRowBody">
            <strong>${escapeHtml(String(t.title || "Song").trim() || "Song")}</strong>
            <span>${escapeHtml(sub)}</span>
          </span>
        </button>`;
    }).join("");
    return;
  }

  const tracks = mashupEligibleLibraryTracks();
  const list = tracks.filter((t) => mashupTrackKey(t) !== otherKey);
  _mashupState.pickerCandidates = list;
  if (!list.length) {
    els.mashupPickerList.innerHTML = `<div class="mashupPickerEmpty">No eligible library songs yet. Generate a couple of tracks first — they'll show up here once saved to Library.</div>`;
    return;
  }
  els.mashupPickerList.innerHTML = list.map((t, idx) => {
    const key = mashupTrackKey(t);
    const selected = key && key === selectedKey;
    return `
      <button type="button" class="mashupPickerRow${selected ? " isSelected" : ""}" data-mashup-pick-idx="${idx}" role="option">
        <img class="mashupPickerRowArt" src="${escapeHtml(mashupCoverForTrack(t))}" alt="" loading="lazy" decoding="async" />
        <span class="mashupPickerRowBody">
          <strong>${escapeHtml(String(t.title || "Song").trim() || "Song")}</strong>
          <span>${escapeHtml(mashupSlotSourceLabel(t))}</span>
        </span>
      </button>`;
  }).join("");
}

function closeMashupPicker() {
  _mashupState.pickerSlot = "";
  if (els.mashupPickerSheet) {
    els.mashupPickerSheet.hidden = true;
    els.mashupPickerSheet.setAttribute("aria-hidden", "true");
  }
}

function selectMashupTrackByIndex(idx) {
  const n = Number(idx);
  const track = _mashupState.pickerCandidates[n];
  if (!track || !_mashupState.pickerSlot) return;
  if (_mashupState.pickerSlot === "a") _mashupState.slotA = track;
  else _mashupState.slotB = track;
  closeMashupPicker();
  maybeSuggestMashupTitle();
  renderMashupPage();
  setMashupStatus("");
}

function stopMashupPolling() {
  if (_mashupState.pollTimer) clearInterval(_mashupState.pollTimer);
  _mashupState.pollTimer = null;
}

async function pollMashupTask(taskId, metaBase) {
  const tid = String(taskId || "").trim();
  if (!tid) return;
  stopMashupPolling();
  let tries = 0;
  const maxTries = 160;
  _mashupState.pollTimer = setInterval(async () => {
    tries += 1;
    try {
      const r = await fetch(apiUrl(`/api/suno/status?taskId=${encodeURIComponent(tid)}`), { cache: "no-store" });
      const data = await r.json().catch(() => ({}));
      if (!r.ok) throw new Error(data?.error || "Status check failed");
      const parsed = parseSunoGenerationRecordInfo(data);
      if (parsed.status === "FAILED") {
        stopMashupPolling();
        _mashupState.generating = false;
        setMashupBlending(false);
        setMashupProgress(false);
        setMashupStatus("Mashup generation failed. Try different songs or tweak the blend direction.");
        renderMashupPage();
        return;
      }
      if (parsed.status === "SUCCESS" && parsed.hasAudio) {
        stopMashupPolling();
        _mashupState.generating = false;
        _mashupState.taskId = "";
        setMashupBlending(false, "Mashup ready");
        const mashupTitle = String(els.mashupTitleInput?.value || "").trim() || mashupDefaultTitle();
        const genMeta = {
          ...(metaBase || {}),
          engine: "mashup",
          model: LATEST_SUNO_MODEL,
          customMode: Boolean(metaBase?.customMode),
        };
        const saved = [];
        if (parsed.first?.audioUrl) {
          saved.push(addToLibrary({
            title: mashupTitle,
            artUrl: parsed.first.imageUrl || mashupCoverForTrack(_mashupState.slotA),
            url: toAudioProxyUrl(parsed.first.audioUrl) || parsed.first.audioUrl,
            taskId: tid,
            audioId: parsed.first.audioId || "",
            kind: "full",
            meta: genMeta,
          }));
        }
        if (parsed.second?.audioUrl) {
          saved.push(addToLibrary({
            title: `${mashupTitle} B`.slice(0, 100),
            artUrl: parsed.second.imageUrl || mashupCoverForTrack(_mashupState.slotB),
            url: toAudioProxyUrl(parsed.second.audioUrl) || parsed.second.audioUrl,
            taskId: tid,
            audioId: parsed.second.audioId || "",
            kind: "full",
            meta: genMeta,
          }));
        }
        setMashupProgress(false);
        setMashupStatus("Mashup ready — saved to Library.");
        renderMashupPage();
        void refreshSunoCredits();
        showToast("Mashup saved to Library.", { icon: "♪", durationMs: 3600 });
        const playTrack = saved[0];
        if (playTrack?.url) {
          setPlayerMeta({
            title: playTrack.title || mashupTitle,
            subtitle: "Mashup",
            artUrl: playTrack.artUrl || mashupCoverForTrack(_mashupState.slotA),
          });
          location.hash = "#/player";
          await playInline(normalizeAudioUrlForPlayback(playTrack.url), playTrack.title || mashupTitle, {
            type: "library",
            trackId: playTrack.id,
          });
        }
        return;
      }
      if (tries >= maxTries) {
        stopMashupPolling();
        _mashupState.generating = false;
        setMashupBlending(false);
        setMashupProgress(false);
        setMashupStatus("Still blending in the background — check Library in a minute, or try again.");
        renderMashupPage();
      }
    } catch {
      if (tries >= 10) {
        stopMashupPolling();
        _mashupState.generating = false;
        setMashupBlending(false);
        setMashupProgress(false);
        setMashupStatus("Lost connection while checking mashup status. Try again in a moment.");
        renderMashupPage();
      }
    }
  }, 4500);
}

async function startMashupGeneration() {
  if (_mashupState.generating || _mashupState.starting) return;
  if (!authSession?.user?.id) {
    location.hash = "#/auth";
    return;
  }
  const sourceA = mashupSourcePayload(_mashupState.slotA);
  const sourceB = mashupSourcePayload(_mashupState.slotB);
  if (!sourceA || !sourceB) {
    setMashupStatus("Pick two songs first.");
    return;
  }
  if (mashupRefsEqual(_mashupState.slotA, _mashupState.slotB)) {
    setMashupStatus("Choose two different songs.");
    return;
  }
  const prompt = String(els.mashupPromptInput?.value || "").trim()
    || "A dynamic mashup blending two songs together";
  const requestPayload = await buildSimpleMashupRequest(prompt);
  _mashupState.starting = true;
  _mashupState.generating = false;
  setMashupBlending(false);
  setMashupProgress(false);
  setMashupStatus("");
  if (els.btnMashupGenerate) {
    els.btnMashupGenerate.disabled = true;
    els.btnMashupGenerate.textContent = "Starting…";
    els.btnMashupGenerate.classList.add("isStarting");
  }
  renderMashupPage();
  haptic("medium");
  try {
    const token = getSupabaseAuthToken();
    const r = await fetch(apiUrl("/api/music/mashup"), {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        ...(token ? { Authorization: `Bearer ${token}` } : {}),
      },
      body: JSON.stringify({
        sourceA,
        sourceB,
        prompt: requestPayload.prompt,
        customMode: requestPayload.customMode,
        style: requestPayload.style,
        title: requestPayload.title,
        instrumental: requestPayload.instrumental,
      }),
    });
    const d = await r.json().catch(() => ({}));
    if (r.status === 402 || d?.code === "insufficient_credits") {
      const need = Number(d?.needed ?? FULL_SONG_CREDIT_COST);
      const have = Number(d?.balance || 0);
      throw new Error(`Not enough credits (you have ${formatCreditsAmount(have)}, need ${formatCreditsAmount(need)}).`);
    }
    if (r.status === 401) throw new Error("Sign in to create a mashup.");
    if (!r.ok) throw new Error(d?.error || "Mashup failed to start");
    if (d?._credits && Number.isFinite(Number(d._credits.balance))) {
      setCreditsBalance(Number(d._credits.balance));
      creditsState.loaded = true;
    }
    const taskId = String(d?.taskId || d?.data?.taskId || extractTaskIdLoose(d) || "").trim();
    if (!taskId) throw new Error("Mashup started but no task id came back.");
    _mashupState.taskId = taskId;
    _mashupState.starting = false;
    _mashupState.generating = true;
    if (els.btnMashupGenerate) els.btnMashupGenerate.classList.remove("isStarting");
    saveRecoverableGenerationTask(taskId, `${_mashupState.slotA?.title || "A"} × ${_mashupState.slotB?.title || "B"}`);
    const metaBase = {
      mashupOf: [mashupMetaEntry(_mashupState.slotA), mashupMetaEntry(_mashupState.slotB)],
      mashupPrompt: requestPayload.prompt,
      customMode: requestPayload.customMode,
      mashupLyricsMerged: Boolean(requestPayload.lyricsMerged),
      ...(requestPayload.customMode && requestPayload.style ? { styleInput: requestPayload.style } : {}),
    };
    setMashupBlending(true, "Blending your tracks — weaving A and B together…");
    pollMashupTask(taskId, metaBase);
  } catch (e) {
    _mashupState.generating = false;
    _mashupState.starting = false;
    _mashupState.taskId = "";
    setMashupBlending(false);
    setMashupProgress(false);
    if (els.btnMashupGenerate) els.btnMashupGenerate.classList.remove("isStarting");
    setMashupStatus(e?.message || "Mashup failed.");
    renderMashupPage();
    showToast(String(e?.message || "Mashup failed"), { icon: "!", durationMs: 4200 });
  }
}

function bindMashupPageOnce() {
  if (_mashupState.bound) return;
  _mashupState.bound = true;
  els.btnMashupBack?.addEventListener("click", () => {
    haptic("light");
    location.hash = "#/challenges";
  });
  els.mashupSlotA?.addEventListener("click", () => {
    if (_mashupState.generating || _mashupState.starting) return;
    haptic("light");
    openMashupPicker("a");
  });
  els.mashupSlotB?.addEventListener("click", () => {
    if (_mashupState.generating || _mashupState.starting) return;
    haptic("light");
    openMashupPicker("b");
  });
  els.btnMashupGenerate?.addEventListener("click", () => {
    void startMashupGeneration();
  });
  els.mashupPickerTabLibrary?.addEventListener("click", () => {
    haptic("light");
    _mashupState.pickerTab = "library";
    openMashupPicker(_mashupState.pickerSlot || "a", "library");
  });
  els.mashupPickerTabDiscover?.addEventListener("click", () => {
    haptic("light");
    _mashupState.pickerTab = "discover";
    openMashupPicker(_mashupState.pickerSlot || "a", "discover");
  });
  els.mashupPickerSheet?.addEventListener("click", (ev) => {
    const dismiss = ev.target?.closest?.("[data-mashup-picker-dismiss]");
    if (dismiss) {
      ev.preventDefault();
      closeMashupPicker();
      return;
    }
    const pick = ev.target?.closest?.("[data-mashup-pick-idx]");
    if (!pick) return;
    selectMashupTrackByIndex(pick.getAttribute("data-mashup-pick-idx"));
  });
}

function openNotificationsCenterShell() {
  const modal = els.notificationsCenter;
  if (!modal) return;
  modal.hidden = false;
  modal.setAttribute("aria-hidden", "false");
  document.body.classList.add("notificationsCenterOpen");
  if (els.notificationsCenterStatus) {
    els.notificationsCenterStatus.hidden = false;
    els.notificationsCenterStatus.textContent = "Loading latest updates...";
  }
  if (els.notificationsCenterList) {
    els.notificationsCenterList.innerHTML = `
      <div class="notificationsLoading" aria-hidden="true">
        <span></span><span></span><span></span>
      </div>`;
  }
}

function closeNotificationsCenter() {
  const modal = els.notificationsCenter;
  if (!modal) return;
  modal.hidden = true;
  modal.setAttribute("aria-hidden", "true");
  document.body.classList.remove("notificationsCenterOpen");
}

async function refreshNotificationsCenter() {
  if (!authSession?.user?.id) {
    showToast("Sign in to view notifications.");
    location.hash = "#/auth";
    return;
  }
  openNotificationsCenterShell();
  try {
    const data = await socialApi("/api/social?type=notifications");
    const list = Array.isArray(data?.notifications) ? data.notifications : [];
    const unread = list.filter((n) => !n?.read_at).length;
    if (els.notificationsCenterLead) {
      els.notificationsCenterLead.textContent = unread
        ? `${unread} unread ${unread === 1 ? "update" : "updates"} from your music circle.`
        : "You are caught up. New follows and creator activity will appear here.";
    }
    if (els.notificationsCenterStatus) {
      els.notificationsCenterStatus.hidden = true;
      els.notificationsCenterStatus.textContent = "";
    }
    renderNotificationRows(list);
    updateNotificationsEntryBadges(unread);
    if (unread) void socialApi("/api/social", {
      method: "POST",
      body: JSON.stringify({ action: "mark_notifications_read" }),
    }).then(() => updateNotificationsEntryBadges(0)).catch(() => {});
  } catch (e) {
    if (els.notificationsCenterStatus) {
      els.notificationsCenterStatus.hidden = false;
      els.notificationsCenterStatus.textContent = e?.message || "Could not load notifications.";
    }
    if (els.notificationsCenterList) els.notificationsCenterList.innerHTML = "";
    showToast(e?.message || "Could not load notifications.");
  }
}

async function showNotificationsSummary() {
  return refreshNotificationsCenter();
}

let _ownSocialStatsInFlight = false;
let _ownSocialStatsLastUserId = "";
let _ownSocialStatsFollowers = null;
let _ownSocialStatsPlays = null;
let _ownSocialStatsLastFetchAt = 0;
const OWN_SOCIAL_STATS_MIN_GAP_MS = 30000;
async function refreshOwnProfileSocialStats({ force = false } = {}) {
  const uid = String(authSession?.user?.id || activeProfile?.id || "").trim();
  if (!uid || uid === "guest") return;
  if (_ownSocialStatsLastUserId !== uid) {
    _ownSocialStatsLastUserId = uid;
    _ownSocialStatsFollowers = null;
    _ownSocialStatsPlays = null;
    _ownSocialStatsLastFetchAt = 0;
  }
  if (_ownSocialStatsFollowers != null && els.profileStatPillLikesValue) {
    els.profileStatPillLikesValue.textContent = formatStatCount(_ownSocialStatsFollowers);
  }
  if (_ownSocialStatsPlays != null && els.profileStatPillPublicValue) {
    els.profileStatPillPublicValue.textContent = formatStatCount(_ownSocialStatsPlays);
  }
  if (
    !force &&
    _ownSocialStatsLastFetchAt &&
    Date.now() - _ownSocialStatsLastFetchAt < OWN_SOCIAL_STATS_MIN_GAP_MS
  ) {
    return;
  }
  if (_ownSocialStatsInFlight && !force) return;
  _ownSocialStatsInFlight = true;
  try {
    const data = await fetchSocialStatsForProfile({ userId: uid });
    const followers = Number(data?.stats?.followers || 0);
    const plays = Number(data?.stats?.plays || 0);
    _ownSocialStatsFollowers = followers;
    _ownSocialStatsPlays = plays;
    _ownSocialStatsLastFetchAt = Date.now();
    if (els.profileStatPillLikesValue) {
      els.profileStatPillLikesValue.textContent = formatStatCount(followers);
    }
    if (els.profileStatPillPublicValue) {
      els.profileStatPillPublicValue.textContent = formatStatCount(plays);
    }
  } finally {
    _ownSocialStatsInFlight = false;
  }
}

let _publicPlayTrackState = null;

function resetPublicPlayTracking(source) {
  const songId = String(source?.songId || "").trim();
  const ownerUserId = String(source?.ownerUserId || "").trim();
  if (!songId || !ownerUserId) {
    _publicPlayTrackState = null;
    return;
  }
  _publicPlayTrackState = {
    key: `${songId}:${ownerUserId}`,
    songId,
    ownerUserId,
    counted: false,
  };
}

function countedPlayThresholdSec(durationSec) {
  const dur = Number(durationSec || 0);
  if (Number.isFinite(dur) && dur > 0 && dur < 50) {
    return Math.max(8, Math.ceil(dur * 0.6));
  }
  return 30;
}

function maybeRecordQualifiedPublicPlay() {
  const state = _publicPlayTrackState;
  if (!state || state.counted) return;
  if (!authSession?.user?.id) return;
  if (String(authSession.user.id) === String(state.ownerUserId)) return;
  const a = playerEl;
  if (!a || a.paused || a.ended) return;
  const current = Number(a.currentTime || 0);
  const duration = getPlayerDuration();
  if (current < countedPlayThresholdSec(duration)) return;
  state.counted = true;
  /* Discover survival scoring paused — only social play counts shown in UI for now. */
  void socialApi("/api/social", {
    method: "POST",
    body: JSON.stringify({
      action: "record_play",
      songId: state.songId,
      listenedSeconds: Math.floor(current),
    }),
  }).then((data) => {
    if (data?.counted && data?.ownerUserId === String(authSession?.user?.id || "")) {
      void refreshOwnProfileSocialStats({ force: true });
    }
  }).catch(() => {});
}

/** Recent `user_songs` rows anyone marked public (RLS: `public_on_profile` select). */
async function supabaseFetchDiscoveryPublicSongs(limit) {
  const lim = Math.max(1, Math.min(80, Number(limit) || 48));
  if (!SUPABASE_URL || !SUPABASE_ANON_KEY) return [];
  const colsWithPublished = "id,created_at,published_at,title,song_url,task_id,audio_id,kind,art_url,user_id,meta_remix_of:meta->remixOf,meta_mashup_of:meta->mashupOf,meta_release_caption:meta->>releaseCaption,meta_challenge:meta->challenge,meta_style:meta->>styleInput,meta_style_sent:meta->>styleSent,meta_template_id:meta->>searchTemplateId,meta_template_title:meta->>searchTemplateTitle,meta_dialect:meta->>dialect,meta_lyrics:meta->>lyricsInput,meta_final_prompt:meta->>finalPrompt,meta_nabad_verification:meta->>nabadVerification,meta_tags:meta->tags,meta_allow_remix:meta->allowRemix,meta_allow_mashup:meta->allowMashup,meta_deleted_at:meta->>deletedAt";
  const colsLegacy = "id,created_at,title,song_url,task_id,audio_id,kind,art_url,user_id,meta_remix_of:meta->remixOf,meta_mashup_of:meta->mashupOf,meta_release_caption:meta->>releaseCaption,meta_challenge:meta->challenge,meta_style:meta->>styleInput,meta_style_sent:meta->>styleSent,meta_template_id:meta->>searchTemplateId,meta_template_title:meta->>searchTemplateTitle,meta_dialect:meta->>dialect,meta_lyrics:meta->>lyricsInput,meta_final_prompt:meta->>finalPrompt,meta_nabad_verification:meta->>nabadVerification,meta_tags:meta->tags,meta_allow_remix:meta->allowRemix,meta_allow_mashup:meta->allowMashup,meta_deleted_at:meta->>deletedAt";
  const artUrlGuard = `&or=${encodeURIComponent("(art_url.is.null,art_url.not.like.data:*)")}`;
  try {
    let r = await fetch(
      `${SUPABASE_URL}/rest/v1/user_songs?public_on_profile=eq.true&select=${colsWithPublished}&order=published_at.desc.nullslast,created_at.desc&limit=${lim}${artUrlGuard}`,
      { headers: { apikey: SUPABASE_ANON_KEY, Accept: "application/json" }, cache: "no-store" },
    );
    let selectedPublishedAt = true;
    if (!r.ok) {
      const txt = await r.clone().text().catch(() => "");
      if (/published_at|42703|column/i.test(txt)) {
        selectedPublishedAt = false;
        r = await fetch(
          `${SUPABASE_URL}/rest/v1/user_songs?public_on_profile=eq.true&select=${colsLegacy}&order=created_at.desc&limit=${lim}${artUrlGuard}`,
          { headers: { apikey: SUPABASE_ANON_KEY, Accept: "application/json" }, cache: "no-store" },
        );
      }
    }
    if (!r.ok) {
      const det = await r.text().catch(() => "");
      console.warn("[discovery/user_songs]", r.status, det.slice(0, 280));
      return [];
    }
    const arr = dedupePublicSongRowsRaw(await r.json().catch(() => []));
    if (!Array.isArray(arr)) return [];
    return arr
      .filter((s) => !String(s?.meta_deleted_at || "").trim())
      .map((s) =>
        attachDiscoverFieldsToTrack(
          {
            id: String(s.id || ""),
            ts: selectedPublishedAt ? userSongPublishedTs(s) : new Date(s.created_at || Date.now()).getTime(),
            createdTs: new Date(s.created_at || Date.now()).getTime(),
            publishedAt: selectedPublishedAt ? userSongPublishedAtValue(s) : "",
            title: s.title || "Generated song",
            artUrl: String(s.art_url || "").trim(),
            url: String(s.song_url || "").trim(),
            taskId: String(s.task_id || ""),
            audioId: String(s.audio_id || ""),
            kind: s.kind || "full",
            userId: String(s.user_id || "").trim(),
            meta: {
              ...(s.meta_remix_of ? { remixOf: s.meta_remix_of } : {}),
              ...(s.meta_mashup_of ? { mashupOf: s.meta_mashup_of } : {}),
              ...(String(s.meta_release_caption || "").trim() ? { releaseCaption: String(s.meta_release_caption).trim() } : {}),
              ...(s.meta_challenge ? { challenge: s.meta_challenge } : {}),
              ...(String(s.meta_style || "").trim() ? { styleInput: String(s.meta_style).trim() } : {}),
              ...(String(s.meta_style_sent || "").trim() ? { styleSent: String(s.meta_style_sent).trim() } : {}),
              ...(String(s.meta_template_id || "").trim() ? { searchTemplateId: String(s.meta_template_id).trim() } : {}),
              ...(String(s.meta_template_title || "").trim() ? { searchTemplateTitle: String(s.meta_template_title).trim() } : {}),
              ...(String(s.meta_dialect || "").trim() ? { dialect: String(s.meta_dialect).trim() } : {}),
              ...(String(s.meta_lyrics || "").trim() ? { lyricsInput: String(s.meta_lyrics).trim() } : {}),
              ...(String(s.meta_final_prompt || "").trim() ? { finalPrompt: String(s.meta_final_prompt).trim() } : {}),
              ...(String(s.meta_nabad_verification || "").trim() ? { nabadVerification: String(s.meta_nabad_verification).trim() } : {}),
              ...(Array.isArray(s.meta_tags) ? { tags: s.meta_tags } : {}),
              ...(s.meta_allow_remix === false ? { allowRemix: false } : {}),
              ...(s.meta_allow_mashup === false ? { allowMashup: false } : {}),
            },
          },
          s,
        ),
      )
      .sort((a, b) => Number(b.ts || 0) - Number(a.ts || 0));
  } catch (e) {
    console.warn("[discovery/user_songs]", e);
    return [];
  }
}

async function fetchProfilesByUserIdsMap(userIds) {
  const ids = [...new Set((userIds || []).map((x) => String(x || "").trim()).filter(Boolean))];
  if (!ids.length || !SUPABASE_URL || !SUPABASE_ANON_KEY) return new Map();
  const now = Date.now();
  const m = new Map();
  const missing = [];
  for (const uid of ids) {
    const cached = _profileRowCache.get(uid);
    if (cached && now - cached.at < PROFILE_ROW_CACHE_MS) {
      m.set(uid, cached.row);
    } else {
      missing.push(uid);
    }
  }
  if (!missing.length) return m;
  const inClause = missing.map((id) => encodeURIComponent(id)).join(",");
  const ctrl = new AbortController();
  const timer = setTimeout(() => ctrl.abort(), supabaseRestTimeoutMs());
  try {
    const r = await fetch(
      `${SUPABASE_URL}/rest/v1/profiles?user_id=in.(${inClause})&select=user_id,username,avatar`,
      {
        headers: { apikey: SUPABASE_ANON_KEY, Accept: "application/json" },
        cache: "no-store",
        signal: ctrl.signal,
      },
    );
    if (!r.ok) return m;
    const arr = await r.json().catch(() => []);
    for (const row of Array.isArray(arr) ? arr : []) {
      const uid = String(row?.user_id || "").trim();
      if (!uid) continue;
      m.set(uid, row);
      _profileRowCache.set(uid, { row, at: now });
    }
    return m;
  } catch {
    return m;
  } finally {
    clearTimeout(timer);
  }
}

function autoUsernameMatchesAuthUser(username, userId) {
  if (!isAutoGeneratedUsername(username)) return false;
  const seed = String(userId || "").replace(/-/g, "").slice(0, 6).toLowerCase();
  return String(username || "").trim().toLowerCase() === `user_${seed}`;
}

function chosenUsernameForAuthUser() {
  const local = String(activeProfile?.username || "").trim();
  if (!isPlaceholderUsername(local)) return local;
  if (isFounderBadgeEmail(authSession?.user?.email)) return "samynaoum";
  return "";
}

function personalizedUsernameForAuthUser() {
  return chosenUsernameForAuthUser();
}

/** Founder account — cloud profile can still say user_683f93 while public
 *  handle is @samynaoum. Used so Discover shows one name for everyone. */
function isFounderUserId(userId) {
  const uid = String(userId || "").trim().toLowerCase().replace(/-/g, "");
  if (!uid) return false;
  if (uid.startsWith("683f93")) return true;
  const authId = String(authSession?.user?.id || "").trim().toLowerCase().replace(/-/g, "");
  if (authId && uid === authId) {
    return isFounderBadgeEmail(authSession?.user?.email) || isFounderBadgeUsername(activeProfile?.username);
  }
  return false;
}

function founderPublicUsername() {
  return "samynaoum";
}

/** Discover/Friends read usernames from cloud profiles. When the cloud row
 *  is still the auto `user_683f93` default, show @samynaoum for the founder
 *  account (every viewer), and use the chosen handle for the signed-in owner. */
function resolveProfileForFeedCreator(userId, profMap) {
  const uid = String(userId || "").trim();
  if (!uid) return null;
  const prof = profMap?.get?.(uid) || null;
  const cloudName = String(prof?.username || "").trim();
  const authId = String(authSession?.user?.id || "").trim();

  if (prof && autoUsernameMatchesAuthUser(cloudName, uid) && isFounderUserId(uid)) {
    return {
      ...prof,
      user_id: uid,
      username: founderPublicUsername(),
      avatar: String(prof?.avatar || "").trim(),
    };
  }

  const chosen = authId && uid === authId ? chosenUsernameForAuthUser() : "";
  if (chosen && (!cloudName || isPlaceholderUsername(cloudName) || autoUsernameMatchesAuthUser(cloudName, authId))) {
    return {
      ...(prof || {}),
      user_id: uid,
      username: chosen,
      avatar: String(activeProfile?.avatar || prof?.avatar || "").trim() || prof?.avatar || "",
    };
  }
  return prof;
}

async function ensurePersonalizedUsernameSyncedToCloud() {
  if (!authSession?.user?.id) return;
  const chosen = chosenUsernameForAuthUser();
  if (!chosen) return;
  try {
    if (isPlaceholderUsername(activeProfile?.username) || activeProfile?.username !== chosen) {
      activeProfile = { ...activeProfile, username: chosen };
      saveProfile(activeProfile);
      try { renderProfilePreviewFromInputs(); } catch {}
    }
    const cloud = await supabaseLoadProfile();
    const cloudName = String(cloud?.username || "").trim();
    if (cloudName === chosen) return;
    if (
      cloudName &&
      !isPlaceholderUsername(cloudName) &&
      !autoUsernameMatchesAuthUser(cloudName, authSession.user.id)
    ) {
      return;
    }
    await supabaseUpsertProfile({ ...activeProfile, username: chosen });
    if ((document.body.getAttribute("data-route") || "") === "discover") {
      void refreshDiscoverFeed();
    }
  } catch {}
}

