function dismissDiscoverFeedPlayback() {
  if (miniSource?.type !== "discover_feed" && miniSource?.type !== "discover_playlist") return;
  try {
    if (playerEl) {
      playerEl.pause();
      playerEl.currentTime = 0;
      try {
        playerEl.removeAttribute("src");
        playerEl.load();
      } catch {}
    }
  } catch {}
  miniSource = null;
  currentPlayerTrackRef = null;
  hubNowMeta = null;
  _discoverPlaylistQueue = [];
  _discoverPlaylistQueueSlug = "";
  try {
    syncPlayerUI();
  } catch {}
  try {
    syncPlayerToggleUI();
  } catch {}
  try {
    updateBrandPulse();
  } catch {}
  try {
    renderHubNowPlaying();
  } catch {}
  try {
    syncDiscoveryPlayingHighlights();
  } catch {}
}

function dismissMiniPlayer({ muteHubAutoplay = true } = {}) {
  const srcType = miniSource?.type;
  const mutedHubId = hubAudioPostId;

  if (srcType === "hub" || hubAudioPostId) {
    stopHubPlayback();
    if (muteHubAutoplay && mutedHubId) hubAutoplayMutedPostId = mutedHubId;
    return;
  }

  if (srcType === "discover_feed" || srcType === "discover_playlist") {
    dismissDiscoverFeedPlayback();
    hubNowMeta = null;
    try {
      renderHubNowPlaying();
    } catch {}
    return;
  }

  try {
    const a = getMiniPlayerAudio();
    if (a) a.pause();
    if (playerEl && playerEl !== a) playerEl.pause();
  } catch {}

  hubNowMeta = null;
  miniSource = null;
  currentPlayerTrackRef = null;
  libraryNowPlayingId = null;

  try {
    refreshOwnSongsUi({ soft: true });
  } catch {}
  try {
    syncPlayerUI();
  } catch {}
  try {
    syncPlayerToggleUI();
  } catch {}
  try {
    updateBrandPulse();
  } catch {}
  try {
    renderHubNowPlaying();
  } catch {}
  try {
    syncDiscoveryPlayingHighlights();
  } catch {}
  try {
    void clearLockScreenNowPlaying();
  } catch {}
}

function decodeDiscoveryUserLibUrl(el) {
  const raw = el?.getAttribute?.("data-user-lib-url") || "";
  if (!raw) return "";
  try {
    return decodeURIComponent(raw);
  } catch {
    return String(raw);
  }
}

function decodeDiscoveryPlayUrl(el) {
  const userLib = decodeDiscoveryUserLibUrl(el);
  if (userLib) return userLib;
  return decodeDiscoverDataAttr(el, "data-challenge-entry-play");
}

function decodeDiscoverDataAttr(el, attrName) {
  const raw = el?.getAttribute?.(attrName);
  if (raw == null || raw === "") return "";
  try {
    return decodeURIComponent(raw);
  } catch {
    return String(raw);
  }
}

function publicPlaySourceFromEl(el) {
  const songId = String(decodeDiscoverDataAttr(el, "data-play-song-id") || "").trim();
  const ownerUserId = String(decodeDiscoverDataAttr(el, "data-play-owner-id") || "").trim();
  const taskId = String(decodeDiscoverDataAttr(el, "data-play-task-id") || "").trim();
  const audioId = String(decodeDiscoverDataAttr(el, "data-play-audio-id") || "").trim();
  const releaseCaption = String(decodeDiscoverDataAttr(el, "data-play-release-caption") || "").trim();
  if (!songId || !ownerUserId) return null;
  return { type: "public_song", songId, ownerUserId, taskId, audioId, releaseCaption };
}

/** Build a share URL for a Discover row (creator profile when we know the handle). */
function discoverSharePageUrl(ctx) {
  const pathBase = `${location.origin.replace(/\/$/, "")}${location.pathname.replace(/\/$/, "")}`;
  const handle = String(ctx?.handle || "").trim();
  if (handle) return `${pathBase}#/u/${encodeURIComponent(handle)}`;
  return `${pathBase}#/discover`;
}

/** Public song link (`/s/:id`) when we know the cloud song id. */
function discoverSongShareUrl(ctx) {
  const songId = String(ctx?.songId || "").trim();
  if (songId && isShareUuid(songId)) return buildPublicShareUrl(songId);
  return discoverSharePageUrl(ctx);
}

function isTrackSheetOtherUserSong(ctx) {
  const ownerId = String(ctx?.ownerUserId || "").trim();
  if (!ownerId) return false;
  const uid = String(authSession?.user?.id || "").trim();
  if (!uid) return true;
  return ownerId !== uid;
}

function publicTrackSheetRowHtml(action, label, extraAttrs = "") {
  return `<button type="button" class="discoverTrackSheetRow" data-track-sheet-action="${escapeHtml(action)}"${extraAttrs}><span class="discoverTrackSheetRowLabel">${escapeHtml(label)}</span></button>`;
}

async function refreshPublicTrackSheetFollowRow(ctx) {
  const btn = document.getElementById("publicSheetRowFollow");
  if (!btn || ctx?.mode !== "public") return;
  const ownerId = String(ctx.ownerUserId || "").trim();
  if (!ownerId) {
    btn.hidden = true;
    return;
  }
  btn.hidden = false;
  const labelEl = btn.querySelector(".discoverTrackSheetRowLabel");
  if (!authSession?.user?.id) {
    if (labelEl) labelEl.textContent = "Follow Creator";
    btn.dataset.following = "0";
    return;
  }
  try {
    const ids = await fetchFollowingUserIdsForFeed();
    const following = ids.includes(ownerId);
    if (labelEl) labelEl.textContent = following ? "Following" : "Follow Creator";
    btn.dataset.following = following ? "1" : "0";
  } catch {
    if (labelEl) labelEl.textContent = "Follow Creator";
    btn.dataset.following = "0";
  }
}

async function handlePublicTrackSheetFollow(ctx) {
  const targetUserId = String(ctx?.ownerUserId || "").trim();
  const handle = String(ctx?.handle || "").trim();
  if (!targetUserId) return;
  if (!authSession?.user?.id || !getSupabaseAuthToken()) {
    showToast("Sign in to follow creators.");
    try {
      location.hash = "#/auth";
    } catch {}
    return;
  }
  const btn = document.getElementById("publicSheetRowFollow");
  const wasFollowing = btn?.dataset.following === "1";
  if (wasFollowing) {
    const who = handle ? `@${handle}` : "this creator";
    let ok = true;
    try {
      ok = window.confirm(`Unfollow ${who}?`);
    } catch {
      ok = true;
    }
    if (!ok) return;
  }
  if (btn) btn.disabled = true;
  try {
    await socialApi("/api/social", {
      method: "POST",
      body: JSON.stringify({
        action: wasFollowing ? "unfollow" : "follow",
        targetUserId,
      }),
    });
    _followingListCache = null;
    _followingListCacheAt = 0;
    showToast(wasFollowing ? "Unfollowed creator." : handle ? `Following @${handle}.` : "Following creator.");
    if (_trackSheetCtx?.mode === "public") void refreshPublicTrackSheetFollowRow(_trackSheetCtx);
  } catch (e) {
    showToast(e?.message || "Could not update follow.");
  } finally {
    if (btn) btn.disabled = false;
  }
}

/** Read `data-dp-*` from a Discover ⋯ control into sheet + action context. */
function readDiscoverSheetPayload(el) {
  if (!el?.getAttribute) return null;
  const encUrl = el.getAttribute("data-dp-url");
  if (encUrl == null || encUrl === "") return null;
  let url = "";
  try {
    url = decodeURIComponent(encUrl);
  } catch {
    url = String(encUrl);
  }
  url = String(url || "").trim();
  if (!url) return null;
  const title = decodeDiscoverDataAttr(el, "data-dp-title") || "Song";
  const art = decodeDiscoverDataAttr(el, "data-dp-art") || "";
  const by = decodeDiscoverDataAttr(el, "data-dp-by") || "";
  const handle = String(decodeDiscoverDataAttr(el, "data-dp-handle") || "").trim();
  const songId = String(decodeDiscoverDataAttr(el, "data-dp-song-id") || "").trim();
  const ownerUserId = String(decodeDiscoverDataAttr(el, "data-dp-owner-id") || "").trim();
  const taskId = String(decodeDiscoverDataAttr(el, "data-dp-task-id") || "").trim();
  const audioId = String(decodeDiscoverDataAttr(el, "data-dp-audio-id") || "").trim();
  return { url, title, art, by, handle, songId, ownerUserId, taskId, audioId };
}

